    public MainWindow(bool startHiddenRequested = false) {
        _startHiddenRequested = startHiddenRequested;
        InitializeComponent();
        ConfigureWebUiBrowser();
        ConfigureSessionLogViewer();
        ConfigureModelDownloaderControl();
        if (_startHiddenRequested) {
            ShowInTaskbar = false;
            WindowState = WindowState.Minimized;
        }
    }

    private bool TryBeginOnUi(Action action, string source = "UI dispatch", DispatcherPriority priority = DispatcherPriority.Background) {
        if (action == null || _shutdownCompleted || _isStopping)
            return false;

        try {
            if (Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished)
                return false;

            if (Dispatcher.CheckAccess()) {
                try {
                    action();
                    return true;
                } catch (Exception ex) {
                    App.WriteCrashLog(source + " action failed", ex);
                    return false;
                }
            }

            Dispatcher.BeginInvoke(new Action(() => {
                if (_shutdownCompleted || _isStopping || Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished)
                    return;

                try {
                    action();
                } catch (Exception ex) {
                    App.WriteCrashLog(source + " action failed", ex);
                }
            }), priority);
            return true;
        } catch (Exception ex) {
            App.WriteCrashLog(source + " could not post to WPF dispatcher", ex);
            return false;
        }
    }

    private bool TryBeginOnUi(Func<Task> action, string source = "UI dispatch", DispatcherPriority priority = DispatcherPriority.Background) {
        if (action == null || _shutdownCompleted || _isStopping)
            return false;

        try {
            if (Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished)
                return false;

            if (Dispatcher.CheckAccess()) {
                _ = RunUiAsyncAction(action, source);
                return true;
            }

            _ = Dispatcher.BeginInvoke(new Action(async () => {
                if (_shutdownCompleted || _isStopping || Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished)
                    return;

                await RunUiAsyncAction(action, source).ConfigureAwait(true);
            }), priority);
            return true;
        } catch (Exception ex) {
            App.WriteCrashLog(source + " could not post async work to WPF dispatcher", ex);
            return false;
        }
    }

    private async Task<bool> TryInvokeOnUiAsync(Action action, string source = "UI dispatch", DispatcherPriority priority = DispatcherPriority.Background) {
        if (action == null || _shutdownCompleted || _isStopping)
            return false;

        try {
            if (Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished)
                return false;

            if (Dispatcher.CheckAccess()) {
                try {
                    action();
                    return true;
                } catch (Exception ex) {
                    App.WriteCrashLog(source + " action failed", ex);
                    return false;
                }
            }

            await Dispatcher.InvokeAsync(new Action(() => {
                if (_shutdownCompleted || _isStopping || Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished)
                    return;

                action();
            }), priority);
            return true;
        } catch (Exception ex) {
            App.WriteCrashLog(source + " could not invoke WPF dispatcher", ex);
            return false;
        }
    }

    private async Task<bool> TryInvokeOnUiAsync(Func<Task> action, string source = "UI dispatch", DispatcherPriority priority = DispatcherPriority.Background) {
        if (action == null || _shutdownCompleted || _isStopping)
            return false;

        if (Dispatcher.CheckAccess())
            return await RunUiAsyncAction(action, source).ConfigureAwait(true);

        var completion = new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);
        try {
            if (Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished)
                return false;

            _ = Dispatcher.BeginInvoke(new Action(async () => {
                if (_shutdownCompleted || _isStopping || Dispatcher.HasShutdownStarted || Dispatcher.HasShutdownFinished) {
                    completion.TrySetResult(false);
                    return;
                }

                bool result = await RunUiAsyncAction(action, source).ConfigureAwait(true);
                completion.TrySetResult(result);
            }), priority);
        } catch (Exception ex) {
            App.WriteCrashLog(source + " could not invoke async WPF dispatcher", ex);
            return false;
        }

        return await completion.Task.ConfigureAwait(false);
    }

    private async Task<bool> RunUiAsyncAction(Func<Task> action, string source) {
        try {
            await action().ConfigureAwait(true);
            return true;
        } catch (Exception ex) {
            App.WriteCrashLog(source + " async action failed", ex);
            return false;
        }
    }

    private sealed class InlineProgress<T> : IProgress<T> {
        private readonly Action<T> _handler;

        public InlineProgress(Action<T> handler) {
            _handler = handler;
        }

        public void Report(T value) {
            _handler(value);
        }
    }

    private void ConfigureWebUiBrowser() {
        if (WebUiBrowserHost == null)
            return;

        if (IsWineSafeWpfMode() || IsWineEnvironment()) {
            UseWebUiFallbackViewer("Embedded WebView2 is unavailable in this host.");
            return;
        }

        _webUiBrowser = new Microsoft.Web.WebView2.Wpf.WebView2();
        _webUiBrowser.Loaded += WebUiBrowser_Loaded;
        WebUiBrowserHost.Content = _webUiBrowser;
    }

    private void UseWebUiFallbackViewer(string message) {
        _webUiUsesFallbackViewer = true;
        _webUiBrowserReady = false;
        _webUiBrowserInitializing = false;
        _webUiNavigationInProgress = false;
        _webUiHasLoadedPage = false;
        _webUiCurrentUrl = "";
        _webUiBrowser = null;

        var panel = new StackPanel {
            Margin = new Thickness(18),
            VerticalAlignment = VerticalAlignment.Center,
            HorizontalAlignment = HorizontalAlignment.Center,
            MaxWidth = 720
        };

        panel.Children.Add(new TextBlock {
            Text = string.IsNullOrWhiteSpace(message) ? "Embedded browser unavailable." : message,
            Foreground = new SolidColorBrush(Color.FromRgb(226, 232, 240)),
            FontSize = 16,
            FontWeight = FontWeights.SemiBold,
            TextAlignment = TextAlignment.Center,
            TextWrapping = TextWrapping.Wrap
        });

        _webUiFallbackStatusText = new TextBlock {
            Text = "Start JACK to load the local Web UI.",
            Foreground = new SolidColorBrush(Color.FromRgb(148, 163, 184)),
            FontFamily = new FontFamily("Consolas"),
            FontSize = 12,
            TextAlignment = TextAlignment.Center,
            TextWrapping = TextWrapping.Wrap,
            Margin = new Thickness(0, 8, 0, 0)
        };
        panel.Children.Add(_webUiFallbackStatusText);

        WebUiBrowserHost.Content = panel;
    }

    private void ConfigureSessionLogViewer() {
        if (SessionLogBrowserHost == null)
            return;

        if (IsWineSafeWpfMode() || IsWineEnvironment()) {
            _sessionLogUsesFallbackViewer = true;
            _sessionLogBrowserReady = true;
            _sessionLogFallbackTextBox = new TextBox {
                IsReadOnly = true,
                TextWrapping = TextWrapping.Wrap,
                AcceptsReturn = true,
                VerticalScrollBarVisibility = ScrollBarVisibility.Auto,
                HorizontalScrollBarVisibility = ScrollBarVisibility.Auto,
                BorderThickness = new Thickness(0),
                Background = new SolidColorBrush(Color.FromRgb(11, 17, 28)),
                Foreground = new SolidColorBrush(Color.FromRgb(226, 232, 240)),
                CaretBrush = Brushes.Transparent,
                Padding = new Thickness(10),
                FontFamily = new FontFamily("Consolas"),
                FontSize = 12
            };
            SessionLogBrowserHost.Content = _sessionLogFallbackTextBox;
            return;
        }

        _sessionLogBrowser = new Microsoft.Web.WebView2.Wpf.WebView2();
        SessionLogBrowserHost.Content = _sessionLogBrowser;
    }

    public static async Task<MainWindow> CreateAsync(
        bool startHiddenRequested = false,
        IProgress<StartupLoadingProgress>? startupProgress = null,
        CancellationToken cancellationToken = default) {
        var window = new MainWindow(startHiddenRequested);
        await window.InitializeStartupAsync(startupProgress, cancellationToken);
        return window;
    }

    private async Task InitializeStartupAsync(IProgress<StartupLoadingProgress>? startupProgress, CancellationToken cancellationToken) {
        ReportStartup(startupProgress, 6, "Preparing JackLLM Workstation...", "Loading WPF controls and startup state.");
        await YieldStartupAsync(cancellationToken);

        ReportStartup(startupProgress, 14, "Loading SocketJack services", "Creating JACK and web chat services.");
        _proxy = await Task.Run(() => {
            cancellationToken.ThrowIfCancellationRequested();
            var proxy = new SocketJack.Net.LmVsProxy("localhost", LocalLmStudioProxyPort, ServerPort, ChatServerPort) {
                MobileAccessEnabled = string.Equals(Environment.GetEnvironmentVariable("JACKLLM_MOBILE_ACCESS"), "true", StringComparison.OrdinalIgnoreCase),
                PromptTimeout = TimeSpan.FromMinutes(30),
                StoreLocalWebAuthAccounts = false,
                EnsureLmStudioStartedAsync = EnsureLmStudioProviderForPromptAsync
            };
            proxy.UseStripePaymentsFromEnvironment();
            proxy.PcAccessCaptureJpeg = CapturePcAccessDesktopJpeg;
            proxy.PcAccessInput = ApplyPcAccessInput;
            proxy.PcAccessStartRtmp = StartPcAccessRtmpPublisher;
            proxy.PcAccessStopRtmp = StopPcAccessRtmpPublisher;
            proxy.PcAccessDesktopState = GetPcAccessDesktopState;
            return proxy;
        }, cancellationToken);
        _lmStudioRuntime = await Task.Run(
            () => new HttpLmVsProxyModelRuntime("LM Studio", "http://localhost:" + LocalLmStudioProxyPort.ToString(CultureInfo.InvariantCulture), EnsureLmStudioProviderForPromptAsync),
            cancellationToken);

        ReportStartup(startupProgress, 24, "Loading local settings database", "Reading JackLLM workstation settings before model services start.");
        _settings = await LoadSettingsAsync(cancellationToken);
        ApplyModelsLocationEnvironment(_settings);
        WriteModelsLocationEnvironmentHint(_settings);
        PromptForDreamHardwareRecommendation();
        await YieldStartupAsync(cancellationToken);

        ReportStartup(startupProgress, 28, "Loading JackONNX providers", "Preparing CPU, DirectML, and CUDA provider discovery.");
        (_jackOnnxRuntime, _jackOnnxToolDefinitions) = await Task.Run(() => {
            cancellationToken.ThrowIfCancellationRequested();
            JackOnnxRuntimeEngine runtime = JackOnnxRuntimeEngine.Create(CreateJackOnnxOptions(), CreateJackOnnxProviders());
            IReadOnlyList<LlmToolDefinition> toolDefinitions = JackOnnxLlmRuntimeToolRegistration.CreateDefinitions(_jackOnnxToolOptions);
            return (runtime, toolDefinitions);
        }, cancellationToken);
        _proxy.JackDirectorMediaExecutor = new JackOnnxJackDirectorMediaExecutor(_jackOnnxRuntime);

        ReportStartup(startupProgress, 42, "Connecting runtime services", "Registering SocketJack, LlmRuntime, and JackONNX callbacks.");
        _proxy.ModelRuntimeFallbackReporterAsync = ReportModelRuntimeFallbackToSocketJackAsync;
        _proxy.LocalModelRuntime = _lmStudioRuntime;
        _proxy.OutputLog += OnProxyOutputLog;
        _jackOnnxRuntime.GenerationRequested += OnJackOnnxGenerationRequested;
        _jackOnnxRuntime.ProgressReported += OnJackOnnxProgressReported;
        _proxy.FilesystemPermissionRequested += OnFilesystemPermissionRequested;
        _proxy.TerminalPermissionRequested += OnTerminalPermissionRequested;
        _proxy.WebAuthRegistrationRequested += OnWebAuthRegistrationRequested;
        _proxy.TokenRateRequestRequested += OnTokenRateRequestRequested;
        _proxy.RemoteSessionFileCloneChanged += OnRemoteSessionFileCloneChanged;
        PreviewKeyDown += MainWindow_PreviewKeyDown;

        _metricsTimer = new DispatcherTimer {
            Interval = TimeSpan.FromSeconds(1)
        };
        _metricsTimer.Tick += (_, _) => RefreshMetrics();
        _masterServerRefreshTimer = new DispatcherTimer {
            Interval = MasterServerRefreshInterval
        };
        _masterServerRefreshTimer.Tick += (_, _) => _ = RefreshMasterServerListIfDueAsync(false);
        _updaterStatusTimer = new DispatcherTimer {
            Interval = UpdaterStatusRefreshInterval
        };
        _updaterStatusTimer.Tick += (_, _) => HandleUpdaterStatusTimerTick();
        _dreamManagementTimer = new DispatcherTimer { Interval = TimeSpan.FromSeconds(2.5) };
        _dreamManagementTimer.Tick += (_, _) => { if (IsServerManagementTabSelected()) RefreshDreamManagement(false); };
        _dreamManagementTimer.Start();
        _trayTooltipDelayTimer = new DispatcherTimer {
            Interval = TimeSpan.FromMilliseconds(50)
        };
        _trayTooltipDelayTimer.Tick += (_, _) => {
            _trayTooltipDelayTimer.Stop();
            ShowTrayStatusTooltip();
        };
        _trayTooltipHideTimer = new DispatcherTimer {
            Interval = TimeSpan.FromMilliseconds(250)
        };
        _trayTooltipHideTimer.Tick += (_, _) => CheckTrayStatusTooltipHover();
        _coachmarkTimer = new DispatcherTimer {
            Interval = TimeSpan.FromSeconds(6)
        };
        _coachmarkTimer.Tick += (_, _) => ShowNextCoachmark();

        ReportStartup(startupProgress, 52, "Binding workstation panels", "Preparing sessions, files, diagnostics, and server management views.");
        await YieldStartupAsync(cancellationToken);
        SessionsListBox.ItemsSource = _sessionItems;
        ServerSessionsListBox.ItemsSource = _serverSessionItems;
        WorkspaceTreeView.ItemsSource = _workspaceTreeItems;
        ServerWorkspaceTreeView.ItemsSource = _workspaceTreeItems;
        AccessibleDirectoriesListBox.ItemsSource = _accessibleDirectoryItems;
        ServerAccessibleDirectoriesListBox.ItemsSource = _accessibleDirectoryItems;
        ServicesListBox.ItemsSource = _serviceMetricItems;
        PipelineItemsControl.ItemsSource = _pipelineItems;
        FilesystemPermissionRequestsControl.ItemsSource = _filesystemPermissionRequests;
        TerminalPermissionRequestsControl.ItemsSource = _terminalPermissionRequests;
        ServerBrowserListBox.ItemsSource = _serverBrowserItems;
        MyListingsListBox.ItemsSource = _myListingItems;
        ModelBenchmarkComboBox.ItemsSource = _modelBenchmarkItems;
        _modelBenchmarkItems.CollectionChanged += ModelBenchmarkItems_CollectionChanged;
        ModelReconfigurationListBox.ItemsSource = _modelReconfigurationItems;
        RequestsListBox.ItemsSource = _serverManagementRequestItems;
        SessionsRequestsListBox.ItemsSource = _serverManagementRequestItems;
        WebAuthUsersListBox.ItemsSource = _webAuthUserItems;
        TrustAbuseCasesListBox.ItemsSource = _trustAbuseCaseItems;
        ShellInstancesListBox.ItemsSource = _shellRelayItems;
        ServerPickerListView.ItemsSource = _serverPickerItems;
        RemoteCloneListView.ItemsSource = _remoteCloneItems;
        WpfChatListBox.ItemsSource = _wpfChatMessages;
        WpfChatAttachmentListBox.ItemsSource = _wpfChatAttachments;
        WpfChatSuggestionListBox.ItemsSource = _wpfChatSuggestions;
        RenderSessionLogPlaceholder("Select a session to render its chat log.");
        InitializeStaticText();
        InitializeWpfChatVoice();
        InitializeWpfChatIntellisense();

        ReportStartup(startupProgress, 62, "Settings loaded", "Preparing saved workstation settings for the visible controls.");
        ApplyServicePropertyOverridesToKnownTargets("settings load");
        await YieldStartupAsync(cancellationToken);

        ReportStartup(startupProgress, 70, "Applying workstation settings", "Configuring providers, storage, and server browser defaults.");
        ApplySettingsToUi(_settings);
        InitializeLinuxNativeBackendSupervisorIfNeeded();
        ApplyModelRuntimeProviderToProxy(_settings.ModelRuntimeProvider, startEmbeddedRuntime: false);
        ApplyServicePropertyOverridesToKnownTargets("runtime creation");
        ApplyStorageSettingsToProxy(_settings);
        ApplyOpenRegistrationSettingToProxy(_settings);
        ApplyTokenRateRequestPolicyToProxy(_settings);
        ApplyChatThroughputSettingToProxy(_settings);
        ApplyWebChatModelLoadApiSettingToProxy(_settings);
        ApplyServerBrowserProfileToProxy(_settings);
        ReportStartup(startupProgress, 76, "Detecting host hardware", "Checking GPU billing metadata and local runtime capacity.");
        await ApplyDetectedGpuTdpToProxyAsync(cancellationToken);
        _portForwardingEnabled = false;
        _uiReady = true;
        LmVsProxyWpfRemoteControl.RegisterAdminPanel(this);
        ConfigureRemoteCursorDiagnostics();

        ReportStartup(startupProgress, 82, "Loading SocketJack local databases", "Refreshing pending requests, local users, trust cases, and server lists.");
        await LoadStartupLocalStateAsync(startupProgress, cancellationToken);
        BeginAutoFillPublicHostIfNeeded();
        _ = RefreshShellInstancesAsync();
        UpdateWindowChromeState();
        UpdateResponsiveLayout();

        ReportStartup(startupProgress, 88, "Preparing Python image assets", "Checking bundled Python and JackONNX image dependencies.");
        if (IsWineSafeWpfMode()) {
            UpdateImagePipelineStatus("Image bootstrap deferred until the Wine workstation window is visible.", false);
            AppendLog("Wine-safe startup deferred JackONNX Python/CUDA bootstrap until after the workstation window opens.");
        } else {
            await StartImageRuntimeBootstrapAsync(startupProgress, cancellationToken, waitForCompletion: true);
        }
        if (IsWineSafeWpfMode()) {
            ReportStartup(startupProgress, 98, "JACK start deferred", "Wine-safe startup opens the workstation window before starting local services.");
            SetStatus("Ready. JACK start deferred for Wine-safe startup.");
            AppendLog("Wine-safe startup deferred JACK autostart so the workstation window can open first.");
        } else {
            await StartProxyDuringStartupAsync(startupProgress, cancellationToken);
        }
        ReportStartup(startupProgress, 99, "Finalizing JackLLM Workstation", "Startup services are ready.");
    }

    private static void ReportStartup(
        IProgress<StartupLoadingProgress>? startupProgress,
        double value,
        string message,
        string detail = "",
        bool isIndeterminate = false) {
        startupProgress?.Report(new StartupLoadingProgress(value, message, detail, isIndeterminate));
    }

    private static async Task YieldStartupAsync(CancellationToken cancellationToken) {
        cancellationToken.ThrowIfCancellationRequested();
        await Task.Yield();
        cancellationToken.ThrowIfCancellationRequested();
    }

    private async Task ApplyDetectedGpuTdpToProxyAsync(CancellationToken cancellationToken) {
        try {
            GpuTdpDetectionSnapshot snapshot = await Task.Run(() => _proxy.DetectAndApplyNvidiaGpuTdpWatts(), cancellationToken);
            if (snapshot.TdpWatts <= 0 && (IsWineSafeWpfMode() || IsWineEnvironment())) {
                AppendLog("NVIDIA GPU TDP was not visible from Wine; trying Linux nvidia-smi through bash.");
                snapshot = await Task.Run(() => DetectAndApplyLinuxNvidiaGpuTdpViaShell(), cancellationToken);
            }
            if (snapshot.TdpWatts > 0) {
                string watts = snapshot.TdpWatts.ToString("0.#", CultureInfo.InvariantCulture);
                _gpuTdpText = watts + "W | " + TrimForDisplay(snapshot.GpuName, 36);
                UpdateGpuTdpBillingText();
                AppendLog("Detected NVIDIA GPU TDP: " + snapshot.GpuName + " -> " + watts + "W (" + snapshot.Source + ").");
                return;
            }

            _gpuTdpText = "GPU TDP: no NVIDIA GPU detected";
            UpdateGpuTdpBillingText();
            AppendLog("No NVIDIA GPU TDP detected. Intel, AMD, and integrated graphics are ignored.");
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            _gpuTdpText = "detection failed";
            UpdateGpuTdpBillingText();
            AppendLog("NVIDIA GPU TDP detection failed: " + TrimForDisplay(ex.Message, 180));
        }
    }

    private GpuTdpDetectionSnapshot DetectAndApplyLinuxNvidiaGpuTdpViaShell() {
        string output = RunLinuxNvidiaSmiTdpQuery();
        if (string.IsNullOrWhiteSpace(output)) {
            return new GpuTdpDetectionSnapshot {
                GpuName = "",
                TdpWatts = 0,
                Source = "linux nvidia-smi",
                Detail = "Linux nvidia-smi did not return GPU TDP data.",
                IsNvidia = false
            };
        }

        return _proxy.DetectAndApplyNvidiaGpuTdpWattsFromNvidiaSmiOutput(output, "linux nvidia-smi");
    }

    private static string RunLinuxNvidiaSmiTdpQuery() {
        string script =
            "SMI=\"${JACKLLM_NVIDIA_SMI:-$(command -v nvidia-smi 2>/dev/null || true)}\"\n" +
            "if [ -z \"$SMI\" ] && [ -x /usr/bin/nvidia-smi ]; then SMI=/usr/bin/nvidia-smi; fi\n" +
            "if [ -z \"$SMI\" ]; then exit 0; fi\n" +
            "\"$SMI\" --query-gpu=index,name,power.limit,power.default_limit,power.max_limit --format=csv,noheader,nounits 2>/dev/null || " +
            "\"$SMI\" --query-gpu=index,name,power.limit --format=csv,noheader,nounits 2>/dev/null\n";

        using Process process = new Process();
        var startInfo = new ProcessStartInfo {
            FileName = IsWineEnvironment() || IsWineSafeWpfMode() ? ConvertUnixPathToWinePath("/bin/bash") : "/bin/bash",
            UseShellExecute = false,
            CreateNoWindow = true,
            RedirectStandardOutput = true,
            RedirectStandardError = true
        };
        startInfo.ArgumentList.Add("-lc");
        startInfo.ArgumentList.Add(script);
        process.StartInfo = startInfo;
        if (!process.Start())
            return "";

        string output = process.StandardOutput.ReadToEnd();
        if (!process.WaitForExit(3000)) {
            try { process.Kill(); } catch { }
            return "";
        }

        return output ?? "";
    }

    private async Task LoadStartupLocalStateAsync(IProgress<StartupLoadingProgress>? startupProgress, CancellationToken cancellationToken) {
        cancellationToken.ThrowIfCancellationRequested();
        PublishCurrentHostProfile(false);
        RefreshMetrics();

        ReportStartup(startupProgress, 83, "Loading remote file clone state", "Reading SocketJack companion file mirrors.");
        try {
            List<RemoteSessionFileCloneItem> cloneItems = await Task.Run(() =>
                _proxy.GetRemoteSessionFileClones()
                    .Select(snapshot => new RemoteSessionFileCloneItem(snapshot))
                    .ToList(),
                cancellationToken);
            _remoteCloneItems.Clear();
            foreach (RemoteSessionFileCloneItem item in cloneItems)
                _remoteCloneItems.Add(item);
            UpdateCopilotFilesStatus();
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            if (RemoteCloneStatusText != null)
                RemoteCloneStatusText.Text = "Remote clone refresh failed: " + TrimForDisplay(ex.Message, 160);
        }

        ReportStartup(startupProgress, 84.5, "Loading server management requests", "Reading pending registration and token-rate requests.");
        try {
            List<RegistrationRequestItem> registrationItems = await Task.Run(() =>
                _proxy.GetPendingWebAuthRegistrationRequests()
                    .Select(RegistrationRequestItem.FromSnapshot)
                    .ToList(),
                cancellationToken);
            _registrationRequestItems.Clear();
            foreach (RegistrationRequestItem item in registrationItems)
                _registrationRequestItems.Add(item);
            RebuildServerManagementRequests();
            foreach (RegistrationRequestItem request in _registrationRequestItems)
                ShowRegistrationRequestToast(request);
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            AppendLog("Registration requests unavailable: " + TrimForDisplay(ex.Message, 180));
        }

        try {
            List<TokenRateRequestItem> tokenRateItems = await Task.Run(() =>
                _proxy.GetPendingTokenRateRequests()
                    .Select(TokenRateRequestItem.FromSnapshot)
                    .ToList(),
                cancellationToken);
            _tokenRateRequestItems.Clear();
            foreach (TokenRateRequestItem item in tokenRateItems)
                _tokenRateRequestItems.Add(item);
            RebuildServerManagementRequests();
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            AppendLog("Token-rate requests unavailable: " + TrimForDisplay(ex.Message, 180));
        }

        ReportStartup(startupProgress, 86, "Loading permissions and users", "Reading terminal permissions and web auth diagnostics.");
        try {
            List<TerminalPermissionRequestItem> terminalItems = await Task.Run(() =>
                _proxy.GetPendingTerminalPermissionRequests()
                    .Select(TerminalPermissionRequestItem.FromSnapshot)
                    .ToList(),
                cancellationToken);
            foreach (TerminalPermissionRequestItem item in terminalItems) {
                if (_terminalPermissionRequests.Any(existing => existing.Id == item.Id))
                    continue;

                _terminalPermissionRequests.Insert(0, item);
                ShowTerminalPermissionToast(item);
            }
            RefreshSessionsPanel(true);
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            AppendLog("Terminal permission requests unavailable: " + TrimForDisplay(ex.Message, 180));
        }

        try {
            List<WebAuthUserItem> webAuthItems = await Task.Run(BuildServerManagementUserItems,
                cancellationToken);
            _webAuthUserItems.Clear();
            foreach (WebAuthUserItem item in webAuthItems)
                _webAuthUserItems.Add(item);
            UpdateSelectedWebAuthUserText();
            LoadSelectedWebAuthUserPermissions();
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            if (ServerManagementStatusText != null)
                ServerManagementStatusText.Text = "WebAuth user refresh failed: " + TrimForDisplay(ex.Message, 160);
        }

        ReportStartup(startupProgress, 87.5, "Loading trust and server lists", "Reading trust cases and refreshing server filters.");
        try {
            (List<TrustAbuseCaseItem> Items, TrustAbuseSummarySnapshot Summary) trustState = await Task.Run(() => {
                List<TrustAbuseCaseItem> items = _proxy.GetTrustAbuseCases()
                    .Select(TrustAbuseCaseItem.FromSnapshot)
                    .ToList();
                TrustAbuseSummarySnapshot summary = _proxy.GetTrustAbuseSummary();
                return (items, summary);
            }, cancellationToken);
            _trustAbuseCaseItems.Clear();
            foreach (TrustAbuseCaseItem item in trustState.Items)
                _trustAbuseCaseItems.Add(item);
            TrustAbuseSummarySnapshot summary = trustState.Summary;
            if (TrustAbuseSummaryText != null)
                TrustAbuseSummaryText.Text = "Reputation " + summary.ReputationScore.ToString(CultureInfo.InvariantCulture) + "/100 (" + summary.ReputationTier + ")" +
                                             " | open " + summary.OpenCases.ToString(CultureInfo.InvariantCulture) +
                                             " | disputes " + summary.DisputeCount.ToString(CultureInfo.InvariantCulture) +
                                             " | host " + summary.HostVerificationStatus +
                                             " | renter identity " + summary.RenterIdentityStatus +
                                             " | commands " + (summary.CommandsBlocked ? "blocked" : "allowed");
            if (TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = _trustAbuseCaseItems.Count.ToString(CultureInfo.InvariantCulture) + " trust case(s) loaded.";
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            AppendLog("Trust and abuse refresh failed: " + TrimForDisplay(ex.Message, 180));
            if (TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = "Trust refresh failed: " + TrimForDisplay(ex.Message, 160);
        }

        RefreshServerPickerItems();
        await YieldStartupAsync(cancellationToken);
    }

    private async Task StartProxyDuringStartupAsync(IProgress<StartupLoadingProgress>? startupProgress, CancellationToken cancellationToken) {
        cancellationToken.ThrowIfCancellationRequested();
        if (!StartByDefaultCheckBox.IsChecked.GetValueOrDefault(true)) {
            ReportStartup(startupProgress, 98, "JACK start disabled", "JackLLM Workstation will open with JACK stopped.");
            SetStatus("Ready. JACK is stopped.");
            return;
        }

        ReportStartup(startupProgress, 97, "Starting JACK", "Starting JACK before opening the workstation.");
        AppendLog("Start by default enabled. Starting JACK.");
        await StartProxyAsync(startupProgress, cancellationToken);
    }

    public void ShutdownProxy() {
        if (_isStopping || _shutdownCompleted)
            return;

        _isStopping = true;
        try {
            SaveSettings();
            StopUiTimers();
            CancelPendingUiOperations();
            CancelImageRuntimeBootstrap();
            StopImagePipelineStatusAnimation();
            try {
                if (_pipelineStatusFadeStoryboard != null) {
                    _pipelineStatusFadeStoryboard.Stop();
                    _pipelineStatusFadeStoryboard = null;
                }
            } catch {
            }
            try { _pythonBootstrapCancellation?.Dispose(); } catch { }
            PreviewKeyDown -= MainWindow_PreviewKeyDown;
            LmVsProxyWpfRemoteControl.RemoteCursorHiddenChanged -= RemoteCursorHiddenChanged;
            _proxy.OutputLog -= OnProxyOutputLog;
            if (_jackOnnxRuntime != null) {
                _jackOnnxRuntime.GenerationRequested -= OnJackOnnxGenerationRequested;
                _jackOnnxRuntime.ProgressReported -= OnJackOnnxProgressReported;
            }
            _proxy.FilesystemPermissionRequested -= OnFilesystemPermissionRequested;
            _proxy.TerminalPermissionRequested -= OnTerminalPermissionRequested;
            _proxy.WebAuthRegistrationRequested -= OnWebAuthRegistrationRequested;
            _proxy.TokenRateRequestRequested -= OnTokenRateRequestRequested;
            _proxy.RemoteSessionFileCloneChanged -= OnRemoteSessionFileCloneChanged;
            UnregisterPortForwardingEvents();
            foreach (Window toast in _terminalPermissionToasts.Values.ToList()) {
                try { toast.Close(); } catch { }
            }
            _terminalPermissionToasts.Clear();
            foreach (Window toast in _registrationRequestToasts.Values.ToList()) {
                try { toast.Close(); } catch { }
            }
            _registrationRequestToasts.Clear();
            ClosePersonaPlexInstallToast();
            DisposeWpfChatVoice();
            try { StopShellMode(updateCheckbox: false); } catch { }
            StopLinuxNativeBackendSupervisor();
            StopPcAccessRtmpPublisher();
            try {
                if (_proxy.IsListening || (_proxy.IsChatServerCreated && _proxy.ChatServer.IsListening))
                    _proxy.Stop();
            } catch { }
            StopRemoteLmStudioProxy();
            DisposeEmbeddedLlmRuntime();
            try { _proxy.Dispose(); } catch { }
            CloseStartedCompanionProcess();
            DisposeTrayIcon();
            SocketJack.ThreadManager.Shutdown();
            _shutdownCompleted = true;
        } finally {
            _isStopping = false;
        }
    }

    private void StopUiTimers() {
        _metricsTimer.Stop();
        _masterServerRefreshTimer.Stop();
        _updaterStatusTimer.Stop();
        _trayTooltipDelayTimer.Stop();
        _trayTooltipHideTimer.Stop();
        _coachmarkTimer.Stop();
        _remoteCursorDiagnosticsTimer?.Stop();
        _wpfChatIntellisenseTimer?.Stop();
    }

    private void CancelPendingUiOperations() {
        try { _modelBenchmarkCancellationSource?.Cancel(); } catch { }
        try { _modelBenchmarkCancellationSource?.Dispose(); } catch { }
        _modelBenchmarkCancellationSource = null;

        try { _wpfChatCancellationSource?.Cancel(); } catch { }
        try { _wpfChatCancellationSource?.Dispose(); } catch { }
        _wpfChatCancellationSource = null;
        _wpfChatInProgress = false;
        _wpfChatListening = false;
    }

    private void Window_Loaded(object sender, RoutedEventArgs e) {
        _metricsTimer.Start();
        _masterServerRefreshTimer.Start();
        _updaterStatusTimer.Start();
        StartInitialUpdaterCheck();
        RefreshUpdaterStatus();
        RefreshSessionsPanel(true);
        RefreshWorkspaceExplorer(true);
        if (!StartByDefaultCheckBox.IsChecked.GetValueOrDefault(true) && !_proxy.IsListening)
            _ = ProbeLmStudioAsync();
        if (IsWineSafeWpfMode() && StartByDefaultCheckBox.IsChecked.GetValueOrDefault(true) && !_proxy.IsListening) {
            SetStatus("Ready. Starting JACK after Wine-safe GUI load.");
            TryBeginOnUi(() => _ = StartProxyAsync(), "Wine-safe JACK startup", DispatcherPriority.ApplicationIdle);
        }
        if (IsWineSafeWpfMode())
            TryBeginOnUi(StartWineSafeDeferredImageBootstrap, "Wine-safe deferred image bootstrap", DispatcherPriority.ApplicationIdle);
        EnsureTrayIcon();
        if (IsServerListTabSelected())
            _ = RefreshMasterServerListIfDueAsync(true);
        if (ServerBrowserTab?.IsSelected == true)
