    private static bool IsCodexExeRunning() {
        foreach (string processName in new[] { "codex", "Codex" }) {
            Process[] processes;
            try {
                processes = Process.GetProcessesByName(processName);
            } catch {
                continue;
            }

            foreach (Process process in processes) {
                using (process) {
                    if (IsCodexExecutable(process))
                        return true;
                }
            }
        }

        return false;
    }

    private static bool IsCodexExecutable(Process process) {
        try {
            string? fileName = null;
            try {
                fileName = Path.GetFileName(process.MainModule?.FileName);
            } catch {
                fileName = null;
            }

            if (fileName != null && fileName.Equals("codex.exe", StringComparison.OrdinalIgnoreCase))
                return true;

            return process.ProcessName.Equals("codex", StringComparison.OrdinalIgnoreCase) ||
                   process.ProcessName.Equals("Codex", StringComparison.OrdinalIgnoreCase);
        } catch {
            return false;
        }
    }

