    private void StartInitialUpdaterCheck() {
        string updaterPath = ResolveUpdaterExecutablePath();
        if (string.IsNullOrWhiteSpace(updaterPath)) {
            SetUpdaterStatusText("updates: updater missing", false);
            return;
        }

        StopStaleUpdaterProcesses(updaterPath);
        _lastUpdaterCheckStartedUtc = DateTimeOffset.UtcNow;
        if (!StartUpdaterProcess("--check"))
            SetUpdaterStatusText("updates: updater missing", false);
    }

    private void CheckUpdaterNow() {
        _lastUpdaterCheckStartedUtc = DateTimeOffset.UtcNow;
        if (!StartUpdaterProcess("--check")) {
            SetUpdaterStatusText("updates: updater missing", false);
            return;
        }
        SetUpdaterStatusText("updates: checking", false);
        TryBeginOnUi(RefreshUpdaterStatus, "Updater status refresh");
    }

    private void ForceUpdaterApply() {
        _lastUpdaterCheckStartedUtc = DateTimeOffset.UtcNow;
        if (!StartUpdaterProcess("--force")) {
            SetUpdaterStatusText("updates: updater missing", false);
            return;
        }
        SetUpdaterStatusText("updates: downloading", true);
        TryBeginOnUi(RefreshUpdaterStatus, "Updater status refresh");
    }

    private void HandleUpdaterStatusTimerTick() {
        RefreshUpdaterStatus();
        DateTimeOffset now = DateTimeOffset.UtcNow;
        bool statusIsFresh = (now - _lastUpdaterStatusUtc) < UpdaterCheckInterval + TimeSpan.FromSeconds(20);
        bool launchedRecently = (now - _lastUpdaterCheckStartedUtc) < UpdaterCheckInterval;
        if (!statusIsFresh && !launchedRecently)
            CheckUpdaterNow();
    }

    private bool StartUpdaterProcess(string modeArgs) {
        string updaterPath = ResolveUpdaterExecutablePath();
        if (string.IsNullOrWhiteSpace(updaterPath)) {
            AppendLog("JackLLM Workstation updater executable was not found.");
            return false;
        }

        try {
            string args = modeArgs +
                          " --target " + QuoteArgument(AppContext.BaseDirectory) +
                          " --manifest " + QuoteArgument(DefaultUpdateManifestUrl) +
                          " --status " + QuoteArgument(GetUpdaterStatusPath()) +
                          " --interval-seconds " + ((int)Math.Round(UpdaterCheckInterval.TotalSeconds)).ToString(CultureInfo.InvariantCulture);
            if (modeArgs.IndexOf("--watch", StringComparison.OrdinalIgnoreCase) >= 0)
                args += " --parent-pid " + Environment.ProcessId.ToString(CultureInfo.InvariantCulture);
            Process.Start(new ProcessStartInfo(updaterPath, args) {
                UseShellExecute = false,
                CreateNoWindow = true,
                WorkingDirectory = AppContext.BaseDirectory
            });
            return true;
        } catch (Exception ex) {
            AppendLog("Updater launch failed: " + TrimForDisplay(ex.Message, 180));
            SetUpdaterStatusText("updates: launch failed", false);
            return false;
        }
    }

    private void RefreshUpdaterStatus() {
        try {
            string statusPath = GetUpdaterStatusPath();
            if (!File.Exists(statusPath)) {
                if ((DateTimeOffset.UtcNow - _lastUpdaterStatusUtc) > TimeSpan.FromSeconds(30))
                    SetUpdaterStatusText("updates: checking", false);
                return;
            }

            _lastUpdaterStatusUtc = DateTimeOffset.UtcNow;
            LmVsProxyUpdaterStatus? status = JsonSerializer.Deserialize<LmVsProxyUpdaterStatus>(File.ReadAllText(statusPath), new JsonSerializerOptions {
                PropertyNameCaseInsensitive = true
            });
            if (status == null) {
                SetUpdaterStatusText("updates: unavailable", false);
                SetCompanionUpdateStatus(null);
                return;
            }

            bool companionBusy = status.CompanionIsDownloading || !string.IsNullOrWhiteSpace(status.CompanionCurrentFile);
            bool jackUpdateVisible = status.UpdateAvailable ||
                                     status.PendingFiles > 0 ||
                                     status.CompanionUpdateAvailable ||
                                     status.CompanionPendingFiles > 0;
            bool becameAvailable = jackUpdateVisible && !_lastUpdateAvailableVisible;
            string text = status.HasError
                ? "updates: offline"
                : companionBusy
                    ? "updates: companion"
                    : jackUpdateVisible
                    ? status.PendingFiles > 0 ? "updates: restart to finish" : "updates: available"
                    : "updates: current";
            if (UpdateStatusText != null)
                UpdateStatusText.ToolTip = BuildUpdaterStatusTooltip(status);
            if (UpdateNowButton != null)
                UpdateNowButton.ToolTip = BuildUpdaterStatusTooltip(status);
            SetUpdaterStatusText(text, jackUpdateVisible && !companionBusy);
            SetCompanionUpdateStatus(status);
            if (becameAvailable && !companionBusy)
                ShowJackUpdateAvailableNotice(status);
            _lastUpdateAvailableVisible = jackUpdateVisible;
            UpdateTrayIconStatusText();
        } catch (Exception ex) {
            SetUpdaterStatusText("updates: status error", false);
            SetCompanionUpdateStatus(null);
            AppendLog("Updater status read failed: " + TrimForDisplay(ex.Message, 180));
        }
    }

    private void SetUpdaterStatusText(string text, bool updateAvailable) {
        if (UpdateStatusText != null) {
            UpdateStatusText.Text = text;
            UpdateStatusText.Foreground = updateAvailable
                ? new SolidColorBrush(Color.FromRgb(111, 242, 166))
                : (Brush)FindResource("SubtleTextBrush");
        }
        if (UpdateNowButton != null)
            UpdateNowButton.Visibility = updateAvailable ? Visibility.Visible : Visibility.Collapsed;
        SetStatus(text);
    }

    private void SetCompanionUpdateStatus(LmVsProxyUpdaterStatus? status) {
        if (CompanionUpdateStatusPanel == null || CompanionUpdateFileText == null)
            return;

        bool visible = status != null &&
                       (status.CompanionIsDownloading || !string.IsNullOrWhiteSpace(status.CompanionCurrentFile));
        CompanionUpdateStatusPanel.Visibility = Visibility.Collapsed;
        if (!visible) {
            CompanionUpdateFileText.Text = "";
            CompanionUpdateStatusPanel.ToolTip = null;
            return;
        }

        string file = status?.CompanionCurrentFile ?? "";
        string text = string.IsNullOrWhiteSpace(file)
            ? "Companion: " + ((status?.CompanionMessage ?? "").Trim())
            : "Companion: downloading " + file;
        CompanionUpdateFileText.Text = text.Trim();
        CompanionUpdateStatusPanel.ToolTip = BuildUpdaterStatusTooltip(status!);
        SetStatus(text);
    }

    private static string BuildUpdaterStatusTooltip(LmVsProxyUpdaterStatus status) {
        if (status == null)
            return "";

        var lines = new List<string>();
        if (!string.IsNullOrWhiteSpace(status.Message))
            lines.Add(status.Message);
        if (!string.IsNullOrWhiteSpace(status.CompanionMessage))
            lines.Add(status.CompanionMessage);
        if (!string.IsNullOrWhiteSpace(status.CompanionCurrentFile))
            lines.Add("Companion file: " + status.CompanionCurrentFile);
        return string.Join(Environment.NewLine, lines);
    }

    private void ShowJackUpdateAvailableNotice(LmVsProxyUpdaterStatus status) {
        string message = string.IsNullOrWhiteSpace(status.Message)
            ? "JackLLM Workstation update is available."
            : status.Message;
        AppendLog("Updater: " + TrimForDisplay(message, 180));
        SetStatus("Update available. Apply the SocketJack /update/meta files now.");
        try {
            if (_trayIcon != null) {
                _trayIcon.BalloonTipTitle = "JackLLM Workstation update available";
                _trayIcon.BalloonTipText = TrimForDisplay(message, 180);
                _trayIcon.ShowBalloonTip(6000);
            }
        } catch { }
        ShowJackUpdateApplyPrompt(status, message);
    }

    private void ShowJackUpdateApplyPrompt(LmVsProxyUpdaterStatus status, string message) {
        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (_updatePromptVisible || now - _lastUpdaterPromptUtc < TimeSpan.FromMinutes(15))
            return;

        _updatePromptVisible = true;
        _lastUpdaterPromptUtc = now;
        TryBeginOnUi(() => {
            try {
                if (WindowState == WindowState.Minimized)
                    WindowState = WindowState.Normal;
                Show();
                Activate();
                string detail = TrimForDisplay(message, 420);
                MessageBoxResult result = System.Windows.MessageBox.Show(
                    this,
                    detail + Environment.NewLine + Environment.NewLine + "Apply the update from SocketJack /update/meta now?",
                    "JackLLM Workstation Update Available",
                    MessageBoxButton.YesNo,
                    MessageBoxImage.Warning,
                    MessageBoxResult.Yes);
                if (result == MessageBoxResult.Yes)
                    ForceUpdaterApply();
            } catch (Exception ex) {
                AppendLog("Updater prompt failed: " + TrimForDisplay(ex.Message, 180));
            } finally {
                _updatePromptVisible = false;
            }
        }, "Updater apply prompt");
    }

    private static string GetUpdaterStatusPath() {
        return Path.Combine(GetGuiUserDataRoot(), "updater-status.json");
    }

    private static string GetSettingsPath() {
        return Path.Combine(GetGuiUserDataRoot(), "JackLLM.settings.json");
    }

    private static string GetLegacySettingsPath() {
        return Path.Combine(AppContext.BaseDirectory, "JackLLM.settings.json");
    }

    private static string GetGuiUserDataRoot() {
        string localAppData = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
        if (string.IsNullOrWhiteSpace(localAppData))
            localAppData = Path.GetTempPath();
        return Path.Combine(localAppData, "SocketJack", "JackLLM");
    }

    private static string ResolveUpdaterExecutablePath() {
        string local = Path.Combine(AppContext.BaseDirectory, "JackLLMUpdater.exe");
        if (File.Exists(local))
            return local;

        string devPath = Path.GetFullPath(Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "..", "JackLLMUpdater", "bin", "Debug", "net8.0-windows7.0", "JackLLMUpdater.exe"));
        return File.Exists(devPath) ? devPath : "";
    }

    private static void StopStaleUpdaterProcesses(string updaterPath) {
        string targetPath;
        try {
            targetPath = Path.GetFullPath(updaterPath);
        } catch {
            return;
        }

        string processName = Path.GetFileNameWithoutExtension(targetPath);
        if (string.IsNullOrWhiteSpace(processName))
            return;

        foreach (Process process in Process.GetProcessesByName(processName)) {
            try {
                if (process.Id == Environment.ProcessId || process.HasExited)
                    continue;

                string processPath = "";
                try { processPath = process.MainModule?.FileName ?? ""; } catch { }
                if (string.IsNullOrWhiteSpace(processPath) || !PathsEqual(processPath, targetPath))
                    continue;

                DateTime startTime;
                try { startTime = process.StartTime; } catch { continue; }
                if (DateTime.Now - startTime < TimeSpan.FromMinutes(2))
                    continue;

                process.Kill(entireProcessTree: true);
                try { process.WaitForExit(1500); } catch { }
            } catch {
            } finally {
                process.Dispose();
            }
        }
    }

    private static bool PathsEqual(string left, string right) {
        try {
            return string.Equals(Path.GetFullPath(left), Path.GetFullPath(right), StringComparison.OrdinalIgnoreCase);
        } catch {
            return string.Equals(left, right, StringComparison.OrdinalIgnoreCase);
        }
    }

    private static string QuoteArgument(string value) {
        return "\"" + (value ?? "").Replace("\"", "\\\"", StringComparison.Ordinal) + "\"";
    }

