    private void ModelBenchmarkListBox_PreviewMouseWheel(object sender, MouseWheelEventArgs e) {
        if (sender is not DependencyObject source)
            return;

        ScrollViewer? scrollViewer = FindVisualChild<ScrollViewer>(source);
        if (scrollViewer == null)
            return;

        bool canScrollInside = e.Delta > 0
            ? scrollViewer.VerticalOffset > 0
            : scrollViewer.VerticalOffset < scrollViewer.ScrollableHeight;
        if (canScrollInside)
            return;

        e.Handled = true;
        if (sender is UIElement element) {
            var forwarded = new MouseWheelEventArgs(e.MouseDevice, e.Timestamp, e.Delta) {
                RoutedEvent = UIElement.MouseWheelEvent,
                Source = sender
            };
            element.RaiseEvent(forwarded);
        }
    }

    private async void BenchmarkAllModelsButton_Click(object sender, RoutedEventArgs e) {
        if (_benchmarkAllInProgress) {
            CancelActiveModelBenchmarks();
            return;
        }

        if (_modelBenchmarkInProgress)
            return;

        List<ModelBenchmarkItem> benchmarkItems = _modelBenchmarkItems
            .Where(item => !string.IsNullOrWhiteSpace(item.ModelId))
            .ToList();
        if (benchmarkItems.Count == 0) {
            SetBenchmarkStatus("No models are available to benchmark.");
            NotifyModelsUnavailable("No models are available to benchmark. Load a model in LM Studio or refresh the embedded LlmRuntime model list.", force: true);
            return;
        }

        _benchmarkAllInProgress = true;
        _modelBenchmarkInProgress = true;
        _modelBenchmarkCancellationSource = new CancellationTokenSource();
        CancellationToken cancellationToken = _modelBenchmarkCancellationSource.Token;
        SetBenchmarkControlsBusy(true, true, "Benchmarking 0/" + benchmarkItems.Count.ToString(CultureInfo.InvariantCulture) + " models...");
        foreach (ModelBenchmarkItem item in benchmarkItems)
            item.Status = "Queued";

        try {
            for (int i = 0; i < benchmarkItems.Count; i++) {
                cancellationToken.ThrowIfCancellationRequested();
                ModelBenchmarkItem item = benchmarkItems[i];
                await BenchmarkModelAsync(item.ModelId, cancellationToken, true, i + 1, benchmarkItems.Count);
            }

            SetBenchmarkStatus("Benchmarked " + benchmarkItems.Count.ToString(CultureInfo.InvariantCulture) + " models.");
            PublishCurrentHostProfile(true);
            await PublishEnabledHostsToMasterServerAsync(true, "model benchmark batch");
        } catch (OperationCanceledException) {
            foreach (ModelBenchmarkItem item in benchmarkItems.Where(item => item.Status.Equals("Queued", StringComparison.OrdinalIgnoreCase)))
                item.CancelBenchmark();
            SetBenchmarkStatus("Benchmark run canceled.");
        } finally {
            _modelBenchmarkCancellationSource?.Dispose();
            _modelBenchmarkCancellationSource = null;
            _benchmarkAllInProgress = false;
            _modelBenchmarkInProgress = false;
            SetBenchmarkControlsBusy(false, false);
        }
    }

