    private async void ApplyMagicWorkflowControlButton_Click(object sender, RoutedEventArgs e) {
        if (!_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening) {
            SetMagicWorkflowStatus("Magic workflow: chat server not running.");
            return;
        }

        string action = "status";
        if (MagicWorkflowControlComboBox?.SelectedItem is ComboBoxItem item)
            action = Convert.ToString(item.Content, CultureInfo.InvariantCulture) ?? "status";

        try {
            SetMagicWorkflowBusy(true);
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/sockjackdml/tools/execution/control";
            using var content = new StringContent(JsonSerializer.Serialize(new { action }), Encoding.UTF8, "application/json");
            using HttpResponseMessage response = await client.PostAsync(endpoint, content);
            string json = await response.Content.ReadAsStringAsync();
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
            if (!response.IsSuccessStatusCode || document.RootElement.TryGetProperty("ok", out JsonElement ok) && ok.ValueKind == JsonValueKind.False)
                throw new InvalidOperationException(GetJsonString(document.RootElement, "error", "SockJackDml execution control failed."));

            SetMagicWorkflowStatus("Magic workflow control applied: " + FirstNonEmpty(GetJsonString(document.RootElement, "status", ""), action) + ".");
            await RefreshMagicWorkflowStatusAsync(false);
        } catch (Exception ex) {
            SetMagicWorkflowStatus("Magic workflow control failed: " + TrimForDisplay(ex.Message, 160));
        } finally {
            SetMagicWorkflowBusy(false);
        }
    }

    private async Task RefreshMagicWorkflowStatusAsync(bool announce) {
        if (!_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening) {
            SetMagicWorkflowStatus("Magic workflow: chat server not running.");
            return;
        }

        try {
            SetMagicWorkflowBusy(true);
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/sockjackdml/tools/workflow/status";
            using HttpResponseMessage response = await client.GetAsync(endpoint);
            string json = await response.Content.ReadAsStringAsync();
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
            if (!response.IsSuccessStatusCode || document.RootElement.TryGetProperty("ok", out JsonElement ok) && ok.ValueKind == JsonValueKind.False)
                throw new InvalidOperationException(GetJsonString(document.RootElement, "error", "SockJackDml workflow status failed."));

            string status = GetJsonString(document.RootElement, "latestStatus", "none");
            string blocker = GetJsonString(document.RootElement, "latestBlocker", "");
            string next = GetJsonString(document.RootElement, "nextAction", "");
            int planCount = GetJsonInt(document.RootElement, "planCount", 0);
            int progressCount = GetJsonInt(document.RootElement, "progressCount", 0);
            int executionCount = GetJsonInt(document.RootElement, "executionCount", 0);
            string line = "Magic workflow: " + status +
                          " | plans " + planCount.ToString(CultureInfo.InvariantCulture) +
                          " | progress " + progressCount.ToString(CultureInfo.InvariantCulture) +
                          " | executions " + executionCount.ToString(CultureInfo.InvariantCulture);
            if (!string.IsNullOrWhiteSpace(blocker))
                line += " | blocker " + TrimForDisplay(blocker, 80);
            else if (!string.IsNullOrWhiteSpace(next))
                line += " | next " + TrimForDisplay(next, 80);
            SetMagicWorkflowStatus(line);
            if (announce)
                SetStatus(line);
        } catch (Exception ex) {
            SetMagicWorkflowStatus("Magic workflow status failed: " + TrimForDisplay(ex.Message, 160));
        } finally {
            SetMagicWorkflowBusy(false);
        }
    }

    private void SetMagicWorkflowStatus(string text) {
        if (MagicWorkflowStatusText != null)
            MagicWorkflowStatusText.Text = text;
        SetStatus(text);
    }

    private void SetMagicWorkflowBusy(bool busy) {
        if (RefreshMagicWorkflowButton != null)
            RefreshMagicWorkflowButton.IsEnabled = !busy && _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening;
        if (ApplyMagicWorkflowControlButton != null)
            ApplyMagicWorkflowControlButton.IsEnabled = !busy && _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening;
        if (MagicWorkflowControlComboBox != null)
            MagicWorkflowControlComboBox.IsEnabled = !busy && _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening;
    }

    private async void StartCompanionButton_Click(object sender, RoutedEventArgs e) {
        string? path = FindCompanionExecutablePath();
        if (string.IsNullOrWhiteSpace(path)) {
            SetStatus("JackLLM Workstation Companion executable was not found. Build JackLLMCompanion first.");
            return;
        }

        try {
            _companionProcess = Process.Start(new ProcessStartInfo(path, "--tray --parent-pid " + Environment.ProcessId.ToString(CultureInfo.InvariantCulture)) {
                UseShellExecute = true,
                WindowStyle = ProcessWindowStyle.Hidden
            });
            SetStatus("Starting SocketJack Companion.");
            await Task.Delay(1800);
            await ProbeCompanionStatusAsync(force: true);
        } catch (Exception ex) {
            SetStatus("Companion start failed: " + ex.Message);
        }
    }

    private void CloseStartedCompanionProcess() {
        Process? process = _companionProcess;
        _companionProcess = null;
        if (process == null)
            return;

        try {
            if (!process.HasExited)
                process.CloseMainWindow();
        } catch {
        } finally {
            process.Dispose();
        }
    }

