    private void OnRemoteSessionFileCloneChanged(object? sender, RemoteSessionFileCloneChangedEventArgs e) {
        TryBeginOnUi(() => {
            UpsertRemoteCloneItem(e.Snapshot);
            UpdateCopilotFilesStatus();
        }, "Remote session clone refresh");
    }

    private void RefreshRemoteCloneItems() {
        try {
            IReadOnlyList<RemoteSessionFileCloneSnapshot> clones = _proxy.GetRemoteSessionFileClones();
            _remoteCloneItems.Clear();
            foreach (RemoteSessionFileCloneSnapshot clone in clones)
                _remoteCloneItems.Add(new RemoteSessionFileCloneItem(clone));
            UpdateCopilotFilesStatus();
        } catch (Exception ex) {
            if (RemoteCloneStatusText != null)
                RemoteCloneStatusText.Text = "Remote clone refresh failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private void UpsertRemoteCloneItem(RemoteSessionFileCloneSnapshot snapshot) {
        if (snapshot == null || string.IsNullOrWhiteSpace(snapshot.Id))
            return;

        RemoteSessionFileCloneItem? existing = _remoteCloneItems.FirstOrDefault(item => item.Id.Equals(snapshot.Id, StringComparison.Ordinal));
        if (existing == null) {
            _remoteCloneItems.Insert(0, new RemoteSessionFileCloneItem(snapshot));
            return;
        }

        existing.Update(snapshot);
        int index = _remoteCloneItems.IndexOf(existing);
        if (index > 0) {
            _remoteCloneItems.RemoveAt(index);
            _remoteCloneItems.Insert(0, existing);
        }
    }

    private void UpdateCopilotFilesStatus() {
        if (CopilotDuplicatorStatusText == null || RemoteCloneStatusText == null)
            return;

        LmVsProxyRemoteModelServerSelection selection = _proxy.GetRemoteModelServerSelection();
        string target = selection.Enabled
            ? FirstNonEmpty(selection.ServerName, selection.OwnerUserName, selection.OpenAiBaseUrl)
            : "local LM Studio";
        string lease = selection.Enabled
            ? " Lease " + FirstNonEmpty(selection.LeaseStatus, selection.LeaseRequired ? "pending_payment" : "active") + "."
            : "";
        CopilotDuplicatorStatusText.Text = "Port " + _proxy.CopilotDuplicatorPort.ToString(CultureInfo.InvariantCulture) +
                                           (_proxy.IsCopilotDuplicatorListening ? " is listening" : " is stopped") +
                                           " and routing Copilot to " + target + "." + lease;
        RemoteCloneRootText.Text = "Local mirror root: " + _proxy.RemoteSessionCloneRoot;

        int running = _remoteCloneItems.Count(item => item.IsCancelable);
        int complete = _remoteCloneItems.Count(item => item.Status.Equals("Complete", StringComparison.OrdinalIgnoreCase));
        RemoteCloneStatusText.Text = _remoteCloneItems.Count == 0
            ? "No remote files cloned yet."
            : _remoteCloneItems.Count.ToString(CultureInfo.InvariantCulture) + " item(s), " +
              running.ToString(CultureInfo.InvariantCulture) + " active, " +
              complete.ToString(CultureInfo.InvariantCulture) + " complete.";

        CancelSelectedRemoteClonesButton.IsEnabled = RemoteCloneListView.SelectedItems.Count > 0 && GetSelectedRemoteCloneItems().Any(item => item.IsCancelable);
        CancelAllRemoteClonesButton.IsEnabled = running > 0;
        ClearCompletedRemoteClonesButton.IsEnabled = _remoteCloneItems.Any(item => item.IsTerminal);
    }

