    private void RefreshServerPickerItems() {
        if (ServerPickerListView == null)
            return;

        string selectedKey = ServerPickerListView.SelectedItem is ServerBrowserItem selected
            ? BuildServerBrowserEntryKey(selected.ToEntry())
            : "";
        List<ServerBrowserItem> filtered = _serverBrowserItems
            .Where(ServerMatchesPickerFilters)
            .OrderByDescending(item => item.ToEntry().IsOnline)
            .ThenByDescending(item => item.ToEntry().FromMasterList)
            .ThenBy(item => item.DisplayName, StringComparer.CurrentCultureIgnoreCase)
            .ToList();

        _serverPickerItems.Clear();
        foreach (ServerBrowserItem item in filtered)
            _serverPickerItems.Add(item);

        if (!string.IsNullOrWhiteSpace(selectedKey))
        {
            ServerBrowserItem? restored = _serverPickerItems.FirstOrDefault(item => string.Equals(BuildServerBrowserEntryKey(item.ToEntry()), selectedKey, StringComparison.OrdinalIgnoreCase));
            if (restored != null)
                ServerPickerListView.SelectedItem = restored;
        }
        if (ServerPickerListView.SelectedItem == null && _serverPickerItems.Count > 0)
            ServerPickerListView.SelectedIndex = 0;

        UpdateServerPickerStatus();
    }

    private void RefreshMyListingsItems() {
        if (MyListingsListBox == null)
            return;

        string selectedKey = MyListingsListBox.SelectedItem is ServerBrowserItem selected
            ? BuildServerBrowserEntryKey(selected.ToEntry())
            : "";
        if (string.IsNullOrWhiteSpace(selectedKey) && ServerBrowserListBox?.SelectedItem is ServerBrowserItem browserSelected)
            selectedKey = BuildServerBrowserEntryKey(browserSelected.ToEntry());

        _myListingItems.Clear();
        foreach (ServerBrowserItem item in _serverBrowserItems) {
            if (IsServerBrowserItemOwnedByCurrentUser(item))
                _myListingItems.Add(item);
        }

        if (!string.IsNullOrWhiteSpace(selectedKey)) {
            ServerBrowserItem? restored = _myListingItems.FirstOrDefault(item => string.Equals(BuildServerBrowserEntryKey(item.ToEntry()), selectedKey, StringComparison.OrdinalIgnoreCase));
            if (restored != null) {
                MyListingsListBox.SelectedItem = restored;
                return;
            }
        }

        if (ServerBrowserListBox?.SelectedItem is ServerBrowserItem current && _myListingItems.Contains(current)) {
            MyListingsListBox.SelectedItem = current;
            return;
        }

        if (_myListingItems.Count > 0)
            MyListingsListBox.SelectedIndex = 0;
        else
            MyListingsListBox.SelectedItem = null;
    }

    private bool IsServerBrowserItemOwnedByCurrentUser(ServerBrowserItem item) {
        return item != null && IsServerBrowserEntryOwnedByCurrentUser(item.ToEntry());
    }

    private bool IsServerBrowserEntryOwnedByCurrentUser(ServerBrowserEntry entry) {
        if (entry == null)
            return false;

        entry.Normalize();
        if (entry.IsLocalHost)
            return true;

        string currentUser = NormalizeSocketJackAccountName(GetSocketJackUserName());
        if (string.IsNullOrWhiteSpace(currentUser))
            return false;

        return string.Equals(NormalizeSocketJackAccountName(entry.OwnerUserName), currentUser, StringComparison.OrdinalIgnoreCase);
    }

    private static string NormalizeSocketJackAccountName(string value) {
        return (value ?? "").Trim();
    }

    private bool ServerMatchesPickerFilters(ServerBrowserItem item) {
        if (item == null)
            return false;
        ServerBrowserEntry entry = item.ToEntry();
        string hardware = FirstNonEmpty(ServerFilterHardwareTextBox?.Text, "").Trim().ToLowerInvariant();
        string title = FirstNonEmpty(ServerFilterTitleTextBox?.Text, "").Trim().ToLowerInvariant();
        string owner = FirstNonEmpty(ServerFilterOwnerTextBox?.Text, "").Trim().ToLowerInvariant();
        string ip = FirstNonEmpty(ServerFilterExternalIpTextBox?.Text, "").Trim().ToLowerInvariant();
        string model = FirstNonEmpty(ServerFilterModelTextBox?.Text, "").Trim().ToLowerInvariant();
        string availability = GetComboBoxFilterValue(ServerFilterAvailabilityComboBox, "any");
        string payment = GetComboBoxFilterValue(ServerFilterPaymentComboBox, "any");
        decimal? maxPrice = TryReadCurrencyFilter(ServerFilterMaxPriceTextBox?.Text);

        if (hardware.Length > 0 && BuildServerHardwareSearchText(entry).IndexOf(hardware, StringComparison.OrdinalIgnoreCase) < 0)
            return false;
        if (title.Length > 0 && (entry.DisplayName + " " + entry.AvailableModels + " " + entry.LastStatus).IndexOf(title, StringComparison.OrdinalIgnoreCase) < 0)
            return false;
        if (owner.Length > 0 && entry.OwnerUserName.IndexOf(owner, StringComparison.OrdinalIgnoreCase) < 0)
            return false;
        if (ip.Length > 0 && (entry.ConnectHost + " " + entry.Endpoint).IndexOf(ip, StringComparison.OrdinalIgnoreCase) < 0)
            return false;
        if (model.Length > 0 && BuildServerModelSearchText(entry).IndexOf(model, StringComparison.OrdinalIgnoreCase) < 0)
            return false;
        if (!ServerMatchesAvailabilityFilter(entry, availability))
            return false;
        if (!ServerMatchesPaymentFilter(entry, payment))
            return false;
        if (maxPrice.HasValue && !ServerMatchesMaxPriceFilter(entry, maxPrice.Value))
            return false;
        return true;
    }

    private string BuildServerHardwareSearchText(ServerBrowserEntry entry) {
        if (entry == null)
            return "";
        return string.Join(" ", new[] {
            entry.GpuName,
            entry.GpuAvailable,
            entry.AvailableVram,
            entry.CpuName,
            entry.CpuAvailable,
            entry.RamAvailable,
            entry.StorageAvailable,
            entry.AvailableResources,
            entry.AvailableModels,
            entry.ToolsAllowed,
            entry.ModelBenchmarksJson
        }.Where(value => !string.IsNullOrWhiteSpace(value)));
    }

    private string BuildServerModelSearchText(ServerBrowserEntry entry) {
        if (entry == null)
            return "";
        return string.Join(" ", new[] {
            entry.AvailableModels,
            entry.ToolsAllowed,
            entry.ModelCapabilitiesJson,
            entry.ModelBenchmarksJson,
            entry.MaxTokens > 0 ? entry.MaxTokens.ToString(CultureInfo.InvariantCulture) : "",
            entry.HealthTier,
            entry.TrustTier
        }.Where(value => !string.IsNullOrWhiteSpace(value)));
    }

    private static string GetComboBoxFilterValue(System.Windows.Controls.ComboBox comboBox, string fallback) {
        if (comboBox?.SelectedItem is ComboBoxItem item) {
            string value = (item.Tag as string) ?? item.Content?.ToString() ?? "";
            if (!string.IsNullOrWhiteSpace(value))
                return value.Trim().ToLowerInvariant().Replace(' ', '_').Replace('-', '_');
        }

        return string.IsNullOrWhiteSpace(fallback) ? "any" : fallback.Trim().ToLowerInvariant();
    }

    private static decimal? TryReadCurrencyFilter(string? text) {
        text = (text ?? "").Trim();
        if (string.IsNullOrWhiteSpace(text))
            return null;

        text = text.Replace("$", "", StringComparison.Ordinal)
                   .Replace(",", "", StringComparison.Ordinal)
                   .Trim();
        return decimal.TryParse(text, NumberStyles.Number | NumberStyles.AllowDecimalPoint, CultureInfo.CurrentCulture, out decimal current) ||
               decimal.TryParse(text, NumberStyles.Number | NumberStyles.AllowDecimalPoint, CultureInfo.InvariantCulture, out current)
            ? Math.Max(0, current)
            : null;
    }

    private static bool ServerMatchesAvailabilityFilter(ServerBrowserEntry entry, string filter) {
        filter = string.IsNullOrWhiteSpace(filter) ? "any" : filter.Trim().ToLowerInvariant();
        bool online = entry.IsOnline && !IsServerBrowserOfflineStatus(entry.LastStatus);
        bool blocked = ServerEntryHasStatusToken(entry, "suspended", "blocked", "ban", "abuse", "intervention");
        bool watch = ServerEntryHasStatusToken(entry, "watch", "risk", "degraded", "warning", "stale", "review") ||
                     (!string.IsNullOrWhiteSpace(entry.HealthTier) &&
                      !entry.HealthTier.Equals("healthy", StringComparison.OrdinalIgnoreCase) &&
                      !entry.HealthTier.Equals("ok", StringComparison.OrdinalIgnoreCase));

        return filter switch {
            "online" => online,
            "available" => online && !blocked && !watch,
            "healthy" => online && !blocked && !watch && (entry.HealthScore <= 0 || entry.HealthScore >= 75),
            "watch" or "watch_/_at_risk" => watch && !blocked,
            "offline" => !online,
            "blocked" or "suspended_/_blocked" => blocked,
            _ => true
        };
    }

    private static bool ServerMatchesPaymentFilter(ServerBrowserEntry entry, string filter) {
        filter = string.IsNullOrWhiteSpace(filter) ? "any" : filter.Trim().ToLowerInvariant();
        bool paid = entry.RequiresPayment;
        bool checkoutReady = ServerHasCheckoutConfigured(entry);

        return filter switch {
            "free" => !paid,
            "paid" => paid,
            "checkout" or "checkout_ready" => paid && checkoutReady,
            "needs_setup" => paid && !checkoutReady,
            _ => true
        };
    }

    private static bool ServerMatchesMaxPriceFilter(ServerBrowserEntry entry, decimal maxPriceUsd) {
        if (!entry.RequiresPayment)
            return true;
        decimal price = GetServerPriceUsd(entry);
        return price > 0 && price <= maxPriceUsd;
    }

    private static bool ServerHasCheckoutConfigured(ServerBrowserEntry entry) {
        if (entry == null)
            return false;
        return !string.IsNullOrWhiteSpace(entry.StripePriceId) ||
               entry.StripeUnitAmountCents > 0 ||
               !string.IsNullOrWhiteSpace(entry.StripeAccount);
    }

    private static decimal GetServerPriceUsd(ServerBrowserEntry entry) {
        if (entry == null || entry.StripeUnitAmountCents <= 0)
            return 0;
        return entry.StripeUnitAmountCents / 100m;
    }

    private static bool ServerEntryHasStatusToken(ServerBrowserEntry entry, params string[] tokens) {
        string haystack = string.Join(" ", new[] {
            entry?.LastStatus,
            entry?.HealthTier,
            entry?.TrustTier,
            entry?.PaymentStatus,
            entry?.LeaseStatus
        }.Where(value => !string.IsNullOrWhiteSpace(value)));
        return tokens.Any(token => haystack.IndexOf(token, StringComparison.OrdinalIgnoreCase) >= 0);
    }

    private void UseSelectedServerForCopilot() {
        if (ServerPickerListView?.SelectedItem is not ServerBrowserItem item) {
            ServerPickerStatusText.Text = "Select a server before routing Copilot.";
            return;
        }

        ServerBrowserEntry entry = item.ToEntry();
        string baseUrl = BuildServerOpenAiBaseUrl(entry);
        if (string.IsNullOrWhiteSpace(baseUrl)) {
            ServerPickerStatusText.Text = item.DisplayName + " does not advertise a usable OpenAI-compatible endpoint.";
            return;
        }

        var selection = new LmVsProxyRemoteModelServerSelection {
            Enabled = true,
            ServerId = entry.Id,
            ServerName = entry.DisplayName,
            OwnerUserName = entry.OwnerUserName,
            ExternalIp = entry.ConnectHost,
            Endpoint = entry.Endpoint,
            OpenAiBaseUrl = baseUrl,
            HardwareSummary = BuildServerHardwareSummary(entry),
            SelectedModel = GetFirstServerModel(entry),
            LeaseId = BuildServerLeaseId(entry, baseUrl),
            LeaseRequired = entry.RequiresPayment,
            LeaseStatus = entry.RequiresPayment ? "pending_payment" : "active",
            LeasePaymentStatus = entry.RequiresPayment ? "payment_required" : "not_required",
            LeaseStartedUtc = DateTimeOffset.UtcNow.ToString("O"),
            LeaseExpiresUtc = entry.RequiresPayment ? "" : DateTimeOffset.UtcNow.AddHours(12).ToString("O"),
            LeaseSource = "wpf-server-picker",
            LeaseMode = "local-model-illusion",
            SelectedUtc = DateTimeOffset.UtcNow.ToString("O")
        };
        _proxy.ConfigureRemoteModelServerSelection(selection);
        UpdateCopilotFilesStatus();
        UpdateServerPickerStatus();
        ServerPickerStatusText.Text = "Copilot duplicator selected " + item.DisplayName + " through localhost:" +
                                      _proxy.CopilotDuplicatorPort.ToString(CultureInfo.InvariantCulture) + ". " +
                                      BuildServerLeaseStatusText(selection);
    }

    private string BuildServerOpenAiBaseUrl(ServerBrowserEntry entry) {
        if (entry == null)
            return "";

        string endpoint = FirstNonEmpty(entry.Endpoint, BuildServerBrowserEndpoint(entry.ConnectHost, entry.ProxyPort));
        string normalized = LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(endpoint);
        if (!string.IsNullOrWhiteSpace(normalized))
            return normalized;

        string host = NormalizeServerBrowserHost(entry.ConnectHost);
        if (string.IsNullOrWhiteSpace(host))
            host = NormalizeServerBrowserHost(entry.Endpoint);
        if (string.IsNullOrWhiteSpace(host))
            return "";

        return LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(BuildServerBrowserEndpoint(host, entry.ProxyPort));
    }

    private string BuildServerHardwareSummary(ServerBrowserEntry entry) {
        if (entry == null)
            return "";
        return string.Join(" | ", new[] {
            string.IsNullOrWhiteSpace(entry.GpuName) ? "" : "GPU " + entry.GpuName,
            string.IsNullOrWhiteSpace(entry.AvailableVram) ? "" : "VRAM " + entry.AvailableVram,
            string.IsNullOrWhiteSpace(entry.CpuName) ? "" : "CPU " + entry.CpuName,
            string.IsNullOrWhiteSpace(entry.RamAvailable) ? "" : "RAM " + entry.RamAvailable,
            string.IsNullOrWhiteSpace(entry.StorageAvailable) ? "" : "Storage " + entry.StorageAvailable
        }.Where(value => !string.IsNullOrWhiteSpace(value)));
    }

    private string GetFirstServerModel(ServerBrowserEntry entry) {
        if (entry == null || string.IsNullOrWhiteSpace(entry.AvailableModels))
            return "";
        foreach (string part in entry.AvailableModels.Split(new[] { ',', ';', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)) {
            string model = part.Trim();
            if (!string.IsNullOrWhiteSpace(model))
                return model;
        }
        return "";
    }

    private static string BuildServerLeaseId(ServerBrowserEntry entry, string baseUrl) {
        string seed = string.Join("|", new[] {
            entry?.Id,
            entry?.OwnerUserName,
            entry?.DisplayName,
            baseUrl,
            DateTimeOffset.UtcNow.ToUnixTimeMilliseconds().ToString(CultureInfo.InvariantCulture)
        }.Where(value => !string.IsNullOrWhiteSpace(value)));
        if (string.IsNullOrWhiteSpace(seed))
            seed = Guid.NewGuid().ToString("N");

        byte[] hash = SHA256.HashData(Encoding.UTF8.GetBytes(seed));
        return "lease_" + Convert.ToHexString(hash, 0, 8).ToLowerInvariant();
    }

    private static string BuildServerLeaseStatusText(LmVsProxyRemoteModelServerSelection selection) {
        if (selection == null || !selection.Enabled)
            return "Local LM Studio remains the active target.";
        if (selection.LeaseRequired)
            return "Paid lease is pending; the duplicator keeps the local endpoint stable and will only route remote traffic after the lease is active.";
        return "Free lease is active; Visual Studio sees the local endpoint while SocketJack routes through the peer.";
    }

    private void UpdateServerPickerStatus() {
        if (ServerPickerStatusText == null || ServerPickerSelectedText == null)
            return;

        LmVsProxyRemoteModelServerSelection selection = _proxy.GetRemoteModelServerSelection();
        string target = selection.Enabled
            ? FirstNonEmpty(selection.ServerName, selection.OwnerUserName, selection.OpenAiBaseUrl)
            : "local LM Studio";
        string lease = selection.Enabled
            ? " | Lease: " + FirstNonEmpty(selection.LeaseStatus, selection.LeaseRequired ? "pending_payment" : "active")
            : "";
        int total = _serverBrowserItems.Count;
        int shown = _serverPickerItems.Count;
        ServerPickerSelectedText.Text = "Copilot target: " + target + lease + " | Local endpoint: http://localhost:" + _proxy.CopilotDuplicatorPort.ToString(CultureInfo.InvariantCulture) + "/v1/chat/completions";
        ServerPickerStatusText.Text = shown.ToString(CultureInfo.InvariantCulture) + " of " + total.ToString(CultureInfo.InvariantCulture) + " server(s) shown.";
        UseSelectedServerForCopilotButton.IsEnabled = ServerPickerListView?.SelectedItem is ServerBrowserItem;
        OpenSelectedServerButton.IsEnabled = ServerPickerListView?.SelectedItem is ServerBrowserItem;
    }

    private void RemoteCloneListView_PreviewMouseLeftButtonDown(object sender, MouseButtonEventArgs e) {
        if (FindVisualParent<System.Windows.Controls.ListViewItem>(e.OriginalSource as DependencyObject) is System.Windows.Controls.ListViewItem item &&
            item.DataContext is RemoteSessionFileCloneItem cloneItem) {
            _remoteCloneDragAnchor = cloneItem;
            _remoteCloneDragSelecting = true;
            RemoteCloneListView.CaptureMouse();
        }
    }

    private void RemoteCloneListView_PreviewMouseMove(object sender, System.Windows.Input.MouseEventArgs e) {
        if (!_remoteCloneDragSelecting || _remoteCloneDragAnchor == null || e.LeftButton != MouseButtonState.Pressed)
            return;

        if (FindVisualParent<System.Windows.Controls.ListViewItem>(e.OriginalSource as DependencyObject) is not System.Windows.Controls.ListViewItem item ||
            item.DataContext is not RemoteSessionFileCloneItem current)
            return;

        int anchorIndex = _remoteCloneItems.IndexOf(_remoteCloneDragAnchor);
        int currentIndex = _remoteCloneItems.IndexOf(current);
        if (anchorIndex < 0 || currentIndex < 0)
            return;

        int start = Math.Min(anchorIndex, currentIndex);
        int end = Math.Max(anchorIndex, currentIndex);
        RemoteCloneListView.SelectedItems.Clear();
        for (int i = start; i <= end; i++)
            RemoteCloneListView.SelectedItems.Add(_remoteCloneItems[i]);
    }

    private void RemoteCloneListView_PreviewMouseLeftButtonUp(object sender, MouseButtonEventArgs e) {
        _remoteCloneDragSelecting = false;
        _remoteCloneDragAnchor = null;
        if (RemoteCloneListView.IsMouseCaptured)
            RemoteCloneListView.ReleaseMouseCapture();
    }

    private List<RemoteSessionFileCloneItem> GetSelectedRemoteCloneItems() {
        return RemoteCloneListView?.SelectedItems
            .OfType<RemoteSessionFileCloneItem>()
            .ToList() ?? new List<RemoteSessionFileCloneItem>();
    }

    private RemoteSessionFileCloneItem? GetPrimaryRemoteCloneItem(object sender) {
        if ((sender as FrameworkElement)?.DataContext is RemoteSessionFileCloneItem contextItem)
            return contextItem;
        if (RemoteCloneListView?.SelectedItem is RemoteSessionFileCloneItem selected)
            return selected;
        return _remoteCloneItems.FirstOrDefault();
    }

    private void OpenFolderPath(string path) {
        try {
            if (string.IsNullOrWhiteSpace(path))
                return;
            Directory.CreateDirectory(path);
            Process.Start(new ProcessStartInfo(path) { UseShellExecute = true });
        } catch (Exception ex) {
            RemoteCloneStatusText.Text = "Open folder failed: " + TrimForDisplay(ex.Message, 140);
        }
    }

    private void OpenContainingFolder(string path) {
        try {
            if (string.IsNullOrWhiteSpace(path)) {
                OpenFolderPath(_proxy.RemoteSessionCloneRoot);
                return;
            }

            string folder = Directory.Exists(path) ? path : Path.GetDirectoryName(path) ?? _proxy.RemoteSessionCloneRoot;
            if (File.Exists(path)) {
                Process.Start(new ProcessStartInfo("explorer.exe", "/select,\"" + path + "\"") { UseShellExecute = true });
                return;
            }

            OpenFolderPath(folder);
        } catch (Exception ex) {
            RemoteCloneStatusText.Text = "Open containing folder failed: " + TrimForDisplay(ex.Message, 140);
        }
    }

    private static T? FindVisualParent<T>(DependencyObject? child) where T : DependencyObject {
        while (child != null) {
            if (child is T match)
                return match;
            child = VisualTreeHelper.GetParent(child);
        }
        return null;
    }

    private async void WpfChatSendButton_Click(object sender, RoutedEventArgs e) {
        if (_wpfChatInProgress) {
            StopWpfChatGeneration();
            return;
        }

        await SendWpfChatPromptAsync();
    }

    private async void WpfChatPromptTextBox_KeyDown(object sender, System.Windows.Input.KeyEventArgs e) {
        if (WpfChatSuggestionListBox.Visibility == Visibility.Visible) {
            if (e.Key == Key.Down) {
                e.Handled = true;
                MoveWpfChatSuggestionSelection(1);
                return;
            }
            if (e.Key == Key.Up) {
                e.Handled = true;
                MoveWpfChatSuggestionSelection(-1);
                return;
            }
            if (e.Key == Key.Tab) {
                e.Handled = true;
                ApplySelectedWpfChatSuggestion();
                return;
            }
            if (e.Key == Key.Escape) {
                e.Handled = true;
                HideWpfChatSuggestions();
                return;
            }
        }

        if ((e.Key == Key.Enter || e.Key == Key.Return) && (Keyboard.Modifiers & ModifierKeys.Shift) != ModifierKeys.Shift) {
            e.Handled = true;
            await SendWpfChatPromptAsync();
        }
    }

