    private void WpfChatVoiceButton_Click(object sender, RoutedEventArgs e) {
        if (_wpfChatListening) {
            StopWpfChatDictation("Dictation stopped.");
            return;
        }

        StartWpfChatDictation();
    }

    private async Task SendWpfChatPromptAsync() {
        if (_wpfChatInProgress)
            return;

        string promptText = (WpfChatPromptTextBox.Text ?? "").Trim();
        if (string.IsNullOrWhiteSpace(promptText) && _wpfChatAttachments.Count == 0)
            return;

        if (_wpfChatListening)
            StopWpfChatDictation("Sending dictated prompt...");

        if (!_proxy.IsListening || !_proxy.ChatServer.IsListening)
            await StartProxyAsync();
        if (!_proxy.IsListening || !_proxy.ChatServer.IsListening) {
            WpfChatStatusText.Text = "Start JACK before sending chat messages.";
            return;
        }

        await EnsureLmStudioForPromptAsync();
        WpfChatPromptTextBox.Clear();
        HideWpfChatSuggestions();
        List<WpfChatAttachmentItem> attachments = _wpfChatAttachments.ToList();
        _wpfChatAttachments.Clear();
        UpdateWpfChatAttachmentVisibility();
        _lastWpfChatPromptText = promptText;
        WpfChatResendButton.IsEnabled = !string.IsNullOrWhiteSpace(_lastWpfChatPromptText);
        string userDisplay = BuildWpfChatUserDisplayText(promptText, attachments);
        _wpfChatMessages.Add(WpfChatMessageItem.User(userDisplay));
        ScrollWpfChatToEnd();
        SetWpfChatBusy(true, "Opening " + GetModelRuntimeServiceName() + " stream...");

        try {
            List<WpfUploadedChatFile> uploadedFiles = await UploadWpfChatFilesAsync(attachments.Where(item => !item.IsImage).ToList());
            string requestJson = BuildWpfChatStreamRequestJson(promptText, attachments, uploadedFiles);
            WpfChatMessageItem pendingAssistant = WpfChatMessageItem.Assistant("", "");
            _wpfChatMessages.Add(pendingAssistant);
            ScrollWpfChatToEnd();
            WpfChatStreamResult result = await StreamWpfChatWithRetryAsync(requestJson, pendingAssistant);
            if (string.IsNullOrWhiteSpace(result.Content) && string.IsNullOrWhiteSpace(result.Reasoning))
                result.Content = "(empty response)";
            bool suppressReasoning = IsPlainWpfChatRequest(requestJson);
            string visibleContent = result.VisibleContent;
            string visibleReasoning = suppressReasoning ? "" : result.VisibleReasoning;
            pendingAssistant.UpdateAssistant(visibleContent, visibleReasoning);
            _wpfChatHistory.Add(new WpfChatHistoryMessage("user", userDisplay));
            _wpfChatHistory.Add(new WpfChatHistoryMessage("assistant", visibleContent));
            WpfChatStatusText.Text = "Response received.";
            SpeakWpfChatResponse(visibleContent);
        } catch (Exception ex) {
            if (ex is OperationCanceledException) {
                WpfChatStatusText.Text = "Generation stopped.";
                return;
            }

            string error = "Chat failed: " + TrimForDisplay(ex.Message, 240);
            _wpfChatMessages.Add(WpfChatMessageItem.Error(error));
            WpfChatStatusText.Text = error;
            AppendLog(error);
        } finally {
            SetWpfChatBusy(false, null);
            _wpfChatActiveStreamId = "";
            _wpfChatCancellationSource?.Dispose();
            _wpfChatCancellationSource = null;
            ScheduleWpfChatPromptReadyGlowRefresh();
            WpfChatPromptTextBox.Focus();
        }
    }

    private void SetWpfChatBusy(bool busy, string? status) {
        _wpfChatInProgress = busy;
        WpfChatSendButton.IsEnabled = true;
        WpfChatPromptTextBox.IsEnabled = !busy;
        WpfChatAttachFileButton.IsEnabled = !busy;
        WpfChatAttachImageButton.IsEnabled = !busy;
        WpfChatResendButton.IsEnabled = !busy && !string.IsNullOrWhiteSpace(_lastWpfChatPromptText);
        WpfChatSendButton.Content = busy ? "Stop" : "Send";
        if (!string.IsNullOrWhiteSpace(status))
            WpfChatStatusText.Text = status;
    }

    private void StopWpfChatGeneration() {
        try { _wpfChatCancellationSource?.Cancel(); } catch { }
        string streamId = _wpfChatActiveStreamId;
        if (!string.IsNullOrWhiteSpace(streamId)) {
            _ = Task.Run(async () => {
                try {
                    using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(5));
                    string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/chat-stream/stop";
                    using var content = new StringContent(JsonSerializer.Serialize(new { streamId }), Encoding.UTF8, "application/json");
                    await client.PostAsync(endpoint, content);
                } catch {
                }
            });
        }
        WpfChatStatusText.Text = "Stopping generation...";
    }

    private async Task<WpfChatStreamResult> StreamWpfChatWithRetryAsync(string requestJson, WpfChatMessageItem pendingAssistant) {
        int attempt = 0;
        while (true) {
            attempt++;
            try {
                if (attempt > 1)
                    pendingAssistant.UpdateAssistant("", "Retrying prompt, attempt " + attempt.ToString(CultureInfo.InvariantCulture) + "...");
                return await StreamWpfChatAsync(requestJson, pendingAssistant);
            } catch (Exception ex) when (WpfChatRetryCheckBox.IsChecked.GetValueOrDefault(false) && ex is not OperationCanceledException) {
                int delayMs = Math.Min(30000, 1200 + Math.Min(12, attempt) * 1600);
                string status = "Attempt " + attempt.ToString(CultureInfo.InvariantCulture) + " failed. Retrying in " + Math.Ceiling(delayMs / 1000.0).ToString("0", CultureInfo.InvariantCulture) + "s: " + TrimForDisplay(ex.Message, 120);
                pendingAssistant.UpdateAssistant("", status);
                WpfChatStatusText.Text = status;
                await Task.Delay(delayMs, _wpfChatCancellationSource?.Token ?? CancellationToken.None);
            }
        }
    }

    private async Task<WpfChatStreamResult> StreamWpfChatAsync(string requestJson, WpfChatMessageItem pendingAssistant) {
        _wpfChatCancellationSource?.Dispose();
        _wpfChatCancellationSource = new CancellationTokenSource();
        CancellationToken cancellationToken = _wpfChatCancellationSource.Token;
        string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/chat-stream";
        using var client = CreateNetworkHttpClient(TimeSpan.FromMinutes(30));
        using var content = new StringContent(requestJson, Encoding.UTF8, "application/json");
        using var request = new HttpRequestMessage(HttpMethod.Post, endpoint) { Content = content };
        using HttpResponseMessage response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, cancellationToken).ConfigureAwait(false);
        if (!response.IsSuccessStatusCode)
            throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase);

        await using Stream stream = await response.Content.ReadAsStreamAsync(cancellationToken).ConfigureAwait(false);
        using var reader = new StreamReader(stream, Encoding.UTF8);
        var result = new WpfChatStreamResult();
        var contentBuilder = new StringBuilder();
        var reasoningBuilder = new StringBuilder();
        bool suppressReasoning = IsPlainWpfChatRequest(requestJson);
        var assistantUpdateStopwatch = Stopwatch.StartNew();
        var statusUpdateStopwatch = Stopwatch.StartNew();
        TimeSpan assistantUpdateInterval = TimeSpan.FromMilliseconds(90);
        TimeSpan statusUpdateInterval = TimeSpan.FromMilliseconds(200);
        async Task PublishAssistantUpdateAsync(bool force = false) {
            if (!force && assistantUpdateStopwatch.Elapsed < assistantUpdateInterval)
                return;

            assistantUpdateStopwatch.Restart();
            result.Content = contentBuilder.ToString();
            result.Reasoning = reasoningBuilder.ToString();
            string visibleContent = result.VisibleContent;
            string visibleReasoning = suppressReasoning ? "" : result.VisibleReasoning;
            await Dispatcher.InvokeAsync(() => {
                pendingAssistant.UpdateAssistant(visibleContent, visibleReasoning);
                ScrollWpfChatToEnd();
            }, DispatcherPriority.Background);
        }

        async Task PublishStatusUpdateAsync(string text, bool force = false) {
            if (!force && statusUpdateStopwatch.Elapsed < statusUpdateInterval)
                return;

            statusUpdateStopwatch.Restart();
            await Dispatcher.InvokeAsync(() => WpfChatStatusText.Text = text, DispatcherPriority.Background);
        }

        while (true) {
            cancellationToken.ThrowIfCancellationRequested();
            string? line = await reader.ReadLineAsync(cancellationToken).ConfigureAwait(false);
            if (line == null)
                break;
            if (string.IsNullOrWhiteSpace(line))
                continue;

            using JsonDocument document = JsonDocument.Parse(line);
            JsonElement root = document.RootElement;
            string type = GetJsonString(root, "type", "delta");
            if (type.Equals("error", StringComparison.OrdinalIgnoreCase))
                throw new InvalidOperationException(FirstNonEmpty(GetJsonString(root, "content", ""), GetJsonString(root, "body", ""), "LM Studio streaming request failed."));
            if (type.Equals("done", StringComparison.OrdinalIgnoreCase))
                break;
            if (type.Equals("progress", StringComparison.OrdinalIgnoreCase)) {
                string status = GetJsonString(root, "status", "Processing prompt...");
                double progress = GetJsonDouble(root, "progress", -1);
                string statusText = progress >= 0
                    ? status + " " + Math.Round(progress).ToString("0", CultureInfo.InvariantCulture) + "%"
                    : status;
                await PublishStatusUpdateAsync(statusText).ConfigureAwait(false);
                continue;
            }
            if (type.Equals("usage", StringComparison.OrdinalIgnoreCase))
                continue;

            contentBuilder.Append(GetJsonString(root, "content", ""));
            reasoningBuilder.Append(GetJsonString(root, "reasoning", ""));
            await PublishAssistantUpdateAsync().ConfigureAwait(false);
        }

        await PublishAssistantUpdateAsync(force: true).ConfigureAwait(false);
        return result;
    }

    private static bool IsPlainWpfChatRequest(string requestJson) {
        if (string.IsNullOrWhiteSpace(requestJson))
            return true;
        try {
            using JsonDocument document = JsonDocument.Parse(requestJson);
            string service = GetJsonString(document.RootElement, "service", "");
            return string.IsNullOrWhiteSpace(service);
        } catch {
            return true;
        }
    }

    private string BuildWpfChatStreamRequestJson(string promptText, IReadOnlyList<WpfChatAttachmentItem> attachments, IReadOnlyList<WpfUploadedChatFile> uploadedFiles) {
        _wpfChatActiveStreamId = "wpf_" + Guid.NewGuid().ToString("N");
        var messages = new List<object>();
        foreach (WpfChatHistoryMessage item in _wpfChatHistory)
            messages.Add(new { role = item.Role, content = item.Content });

        bool agentMode = string.Equals(GetSelectedWpfChatService(), "agent", StringComparison.OrdinalIgnoreCase);
        object userContent = BuildWpfChatUserContent(promptText, attachments, uploadedFiles, agentMode);
        messages.Add(new { role = "user", content = userContent });

        var payload = new Dictionary<string, object?> {
            ["model"] = GetSelectedWpfChatModel(),
            ["sessionId"] = _wpfChatSessionId,
            ["streamId"] = _wpfChatActiveStreamId,
            ["messages"] = messages,
            ["files"] = uploadedFiles
        };
        string service = GetSelectedWpfChatService();
        if (!string.IsNullOrWhiteSpace(service))
            payload["service"] = service;
        if (TryReadDouble(WpfChatTemperatureTextBox.Text, out double temperature))
            payload["temperature"] = Math.Max(0, Math.Min(2, temperature));
        if (TryReadDouble(WpfChatTopPTextBox.Text, out double topP))
            payload["top_p"] = Math.Max(0, Math.Min(1, topP));
        if (int.TryParse(WpfChatMaxTokensTextBox.Text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int maxTokens) && maxTokens > 0)
            payload["max_tokens"] = maxTokens;

        return JsonSerializer.Serialize(payload);
    }

    private object BuildWpfChatUserContent(string promptText, IReadOnlyList<WpfChatAttachmentItem> attachments, IReadOnlyList<WpfUploadedChatFile> uploadedFiles, bool requireFileRead) {
        var text = new StringBuilder((promptText ?? "").Trim());
        foreach (WpfChatAttachmentItem file in attachments.Where(item => !item.IsImage)) {
            WpfUploadedChatFile? uploaded = uploadedFiles.FirstOrDefault(item => string.Equals(item.name, file.Name, StringComparison.OrdinalIgnoreCase));
            if (text.Length > 0)
                text.AppendLine().AppendLine();
            text.Append("[Attached file: ").Append(file.Name).Append(" | ").Append(file.Type).Append(" | ").Append(FormatBytes(file.Size)).AppendLine("]");
            if (uploaded != null && !string.IsNullOrWhiteSpace(uploaded.path))
                text.Append("Session file path: ").AppendLine(uploaded.path);
            if (!requireFileRead && !string.IsNullOrWhiteSpace(file.TextPreview))
                text.Append("```").Append(LanguageForFile(file.Name)).AppendLine().Append(file.TextPreview).AppendLine().Append("```");
            else if (uploaded != null)
                text.Append(requireFileRead ? "Use read_file with this exact path before answering about this uploaded file." : "Use read_file with this exact path if you need to inspect the uploaded file.");
        }

        var imageParts = attachments.Where(item => item.IsImage && !string.IsNullOrWhiteSpace(item.DataUrl)).ToList();
        if (imageParts.Count == 0)
            return text.ToString();
        if (text.Length > 0)
            text.AppendLine().AppendLine();
        text.Append("[Attached image").Append(imageParts.Count == 1 ? ": " : "s: ").Append(string.Join(", ", imageParts.Select(item => item.Name))).Append("]");

        var parts = new List<object> {
            new { type = "text", text = text.ToString().Trim() }
        };
        foreach (WpfChatAttachmentItem image in imageParts)
            parts.Add(new { type = "image_url", image_url = new { url = image.DataUrl } });
        return parts;
    }

    private async Task<List<WpfUploadedChatFile>> UploadWpfChatFilesAsync(IReadOnlyList<WpfChatAttachmentItem> files) {
        var uploaded = new List<WpfUploadedChatFile>();
        foreach (WpfChatAttachmentItem file in files) {
            WpfChatStatusText.Text = "Uploading " + file.Name + "...";
            string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/chat-file";
            var payload = new {
                sessionId = _wpfChatSessionId,
                name = file.Name,
                type = file.Type,
                dataUrl = file.DataUrl,
                text = file.TextPreview,
                asFile = true
            };
            using var client = CreateNetworkHttpClient(TimeSpan.FromMinutes(5));
            using var content = new StringContent(JsonSerializer.Serialize(payload), Encoding.UTF8, "application/json");
            using var request = new HttpRequestMessage(HttpMethod.Post, endpoint) {
                Content = content
            };
            AddSocketJackAuthHeaders(request);
            using HttpResponseMessage response = await client.SendAsync(request);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("Upload failed: HTTP " + (int)response.StatusCode + " " + TrimForDisplay(body, 180));
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            JsonElement root = document.RootElement;
            bool ok = !root.TryGetProperty("ok", out JsonElement okElement) || okElement.ValueKind != JsonValueKind.False;
            if (!ok)
                throw new InvalidOperationException(GetJsonString(root, "error", "Upload failed."));
            if (TryGetJsonProperty(root, "file", out JsonElement fileElement))
                uploaded.Add(WpfUploadedChatFile.FromJson(fileElement));
        }
        return uploaded;
    }

    private void AddWpfChatAttachments(bool imagesOnly) {
        var dialog = new Microsoft.Win32.OpenFileDialog {
            Multiselect = true,
            Title = imagesOnly ? "Attach images" : "Attach files",
            Filter = imagesOnly
                ? "Images|*.png;*.jpg;*.jpeg;*.gif;*.webp;*.bmp;*.avif;*.heic;*.heif|All files|*.*"
                : "All files|*.*"
        };
        if (dialog.ShowDialog(this) != true)
            return;

        foreach (string path in dialog.FileNames) {
            try {
                WpfChatAttachmentItem item = WpfChatAttachmentItem.FromPath(path);
                if (imagesOnly && !item.IsImage)
                    continue;
                _wpfChatAttachments.Add(item);
            } catch (Exception ex) {
                WpfChatStatusText.Text = "Attach failed: " + TrimForDisplay(ex.Message, 160);
            }
        }
        UpdateWpfChatAttachmentVisibility();
    }

    private void UpdateWpfChatAttachmentVisibility() {
        WpfChatAttachmentListBox.Visibility = _wpfChatAttachments.Count == 0 ? Visibility.Collapsed : Visibility.Visible;
    }

    private void ScheduleWpfChatPromptReadyGlowRefresh() {
        if (WpfChatPromptTextBox == null)
            return;

        _wpfChatPromptReadyProbeCancellation?.Cancel();
        _wpfChatPromptReadyProbeCancellation?.Dispose();
        var cancellation = new CancellationTokenSource();
        _wpfChatPromptReadyProbeCancellation = cancellation;
        _ = RefreshWpfChatPromptReadyGlowAsync(cancellation.Token);
    }

    private async Task RefreshWpfChatPromptReadyGlowAsync(CancellationToken cancellationToken) {
        try {
            await Task.Delay(120, cancellationToken).ConfigureAwait(false);
            bool ready = await IsSelectedWpfChatLlmRuntimeModelReadyAsync(cancellationToken).ConfigureAwait(false);
            await Dispatcher.InvokeAsync(() => {
                if (!cancellationToken.IsCancellationRequested)
                    SetWpfChatPromptReadyGlow(ready);
            });
        } catch (OperationCanceledException) {
        } catch {
            await Dispatcher.InvokeAsync(() => SetWpfChatPromptReadyGlow(false));
        }
    }

    private async Task<bool> IsSelectedWpfChatLlmRuntimeModelReadyAsync(CancellationToken cancellationToken) {
        string provider = await Dispatcher.InvokeAsync(GetSelectedModelRuntimeProvider);
        if (!string.Equals(provider, RuntimeProviderLlmRuntime, StringComparison.OrdinalIgnoreCase))
            return false;
        if (!_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening)
            return false;

        string selectedModel = await Dispatcher.InvokeAsync(GetSelectedWpfChatModel);
        if (string.IsNullOrWhiteSpace(selectedModel))
            return false;

        using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(4));
        string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/model-runtime/models";
        using HttpResponseMessage response = await client.GetAsync(endpoint, cancellationToken).ConfigureAwait(false);
        if (!response.IsSuccessStatusCode)
            return false;

        string body = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
        using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
        if (!TryGetJsonProperty(document.RootElement, "models", out JsonElement models) || models.ValueKind != JsonValueKind.Array)
            return false;

        foreach (JsonElement model in models.EnumerateArray()) {
            if (!WpfChatRuntimeModelMatches(model, selectedModel))
                continue;
            if (!WpfChatRuntimeModelSupportsChat(model))
                return false;
            return WpfChatRuntimeModelPromptPipelineReady(model);
        }

        return false;
    }

    private static bool WpfChatRuntimeModelMatches(JsonElement model, string selectedModel) {
        string normalized = (selectedModel ?? "").Trim();
        if (string.IsNullOrWhiteSpace(normalized))
            return false;

        foreach (string key in new[] { "key", "id", "name", "model", "display_name", "displayName" }) {
            string value = GetJsonString(model, key, "");
            if (!string.IsNullOrWhiteSpace(value) && string.Equals(value.Trim(), normalized, StringComparison.OrdinalIgnoreCase))
                return true;
        }
        return false;
    }

    private static int WpfChatRuntimeModelLoadedInstances(JsonElement model) {
        foreach (string key in new[] { "loaded_instances", "loadedInstances", "loaded_models", "loadedModels" }) {
            if (!TryGetJsonProperty(model, key, out JsonElement value))
                continue;
            if (value.ValueKind == JsonValueKind.Array)
                return value.GetArrayLength();
            if (value.ValueKind == JsonValueKind.Object)
                return 1;
        }
        return Math.Max(0, GetJsonInt(model, "loaded_instance_count", GetJsonInt(model, "loadedInstanceCount", GetJsonInt(model, "loaded_count", GetJsonInt(model, "loadedCount", 0)))));
    }

    private static bool WpfChatRuntimeModelPromptPipelineReady(JsonElement model) {
        if (WpfChatRuntimeModelLoadedInstances(model) <= 0)
            return false;

        if (TryGetJsonBoolAliases(model, out bool ready, "prompt_pipeline_ready", "promptPipelineReady", "pipeline_ready", "pipelineReady", "ready_for_prompt", "readyForPrompt"))
            return ready;

        string status = FirstNonEmpty(
            GetJsonString(model, "prompt_pipeline_status", ""),
            GetJsonString(model, "promptPipelineStatus", ""),
            GetJsonString(model, "pipeline_status", ""),
            GetJsonString(model, "pipelineStatus", ""));
        if (WpfChatPromptPipelineStatusReady(status))
            return true;

        foreach (string key in new[] { "loaded_instances", "loadedInstances", "loaded_models", "loadedModels" }) {
            if (!TryGetJsonProperty(model, key, out JsonElement instances))
                continue;
            if (instances.ValueKind == JsonValueKind.Object)
                return WpfChatLoadedInstancePromptPipelineReady(instances);
            if (instances.ValueKind != JsonValueKind.Array)
                continue;

            foreach (JsonElement instance in instances.EnumerateArray()) {
                if (WpfChatLoadedInstancePromptPipelineReady(instance))
                    return true;
            }
        }

        return false;
    }

    private static bool WpfChatLoadedInstancePromptPipelineReady(JsonElement instance) {
        if (TryGetJsonBoolAliases(instance, out bool ready, "prompt_pipeline_ready", "promptPipelineReady", "pipeline_ready", "pipelineReady", "ready_for_prompt", "readyForPrompt"))
            return ready;

        string status = FirstNonEmpty(
            GetJsonString(instance, "prompt_pipeline_status", ""),
            GetJsonString(instance, "promptPipelineStatus", ""),
            GetJsonString(instance, "pipeline_status", ""),
            GetJsonString(instance, "pipelineStatus", ""));
        return WpfChatPromptPipelineStatusReady(status);
    }

    private static bool WpfChatPromptPipelineStatusReady(string status) {
        string normalized = (status ?? "").Trim().ToLowerInvariant();
        return normalized == "ready" || normalized == "warm" || normalized == "warmed" || normalized == "hot";
    }

    private static bool TryGetJsonBoolAliases(JsonElement element, out bool value, params string[] names) {
        foreach (string name in names) {
            if (TryGetJsonProperty(element, name, out JsonElement property) && TryReadJsonBooleanish(property, out value))
                return true;
        }

        value = false;
        return false;
    }

    private static bool TryReadJsonBooleanish(JsonElement element, out bool value) {
        switch (element.ValueKind) {
            case JsonValueKind.True:
                value = true;
                return true;
            case JsonValueKind.False:
                value = false;
                return true;
            case JsonValueKind.Number:
                if (element.TryGetInt64(out long numeric)) {
                    value = numeric != 0;
                    return true;
                }
                break;
            case JsonValueKind.String:
                string text = (element.GetString() ?? "").Trim().ToLowerInvariant();
                if (text == "1" || text == "true" || text == "yes" || text == "on" || text == "ready" || text == "warm" || text == "warmed" || text == "hot") {
                    value = true;
                    return true;
                }
                if (text == "0" || text == "false" || text == "no" || text == "off" || text == "cold" || text == "failed" || text == "loading" || text == "disabled") {
                    value = false;
                    return true;
                }
                break;
        }

        value = false;
        return false;
    }

    private static bool WpfChatRuntimeModelSupportsChat(JsonElement model) {
        if (TryGetJsonProperty(model, "capabilities", out JsonElement capabilities) && capabilities.ValueKind == JsonValueKind.Object) {
            if (TryGetJsonProperty(capabilities, "chat_completion", out JsonElement chatCompletion) && chatCompletion.ValueKind == JsonValueKind.False)
                return false;
            if (TryGetJsonProperty(capabilities, "chatCompletion", out JsonElement chatCompletionCamel) && chatCompletionCamel.ValueKind == JsonValueKind.False)
                return false;
        }

        string type = GetJsonString(model, "type", "").Trim().ToLowerInvariant();
        if (!string.IsNullOrWhiteSpace(type) && type != "llm" && type != "vlm")
            return false;

        string format = GetJsonString(model, "format", "").Trim().ToLowerInvariant();
        return string.IsNullOrWhiteSpace(format) || format == "gguf";
    }

    private void SetWpfChatPromptReadyGlow(bool ready) {
        if (WpfChatPromptTextBox == null || _wpfChatPromptReadyGlowActive == ready)
            return;

        _wpfChatPromptReadyGlowActive = ready;
        var effect = WpfChatPromptTextBox.Effect as DropShadowEffect;
        if (effect == null) {
            effect = new DropShadowEffect {
                Color = Color.FromRgb(0x38, 0xBD, 0xF8),
                BlurRadius = 0,
                ShadowDepth = 0,
                Opacity = 0
            };
            WpfChatPromptTextBox.Effect = effect;
        }

        effect.BeginAnimation(DropShadowEffect.BlurRadiusProperty, null);
        effect.BeginAnimation(DropShadowEffect.OpacityProperty, null);
        effect.BeginAnimation(DropShadowEffect.ColorProperty, null);
        if (!ready) {
            effect.BlurRadius = 0;
            effect.Opacity = 0;
            WpfChatPromptTextBox.ClearValue(Control.BorderBrushProperty);
            WpfChatPromptTextBox.ClearValue(Control.BorderThicknessProperty);
            WpfChatPromptTextBox.ToolTip = "Press Enter to send. Press Shift+Enter for a new line.";
            return;
        }

        WpfChatPromptTextBox.BorderBrush = new SolidColorBrush(Color.FromArgb(0xAA, 0x38, 0xBD, 0xF8));
        WpfChatPromptTextBox.BorderThickness = new Thickness(2);
        WpfChatPromptTextBox.ToolTip = "LlmRuntime model is loaded and its prompt pipeline is warmed for a fast next prompt. Press Enter to send. Press Shift+Enter for a new line.";
        effect.ShadowDepth = 0;

        if (!SystemParameters.ClientAreaAnimation) {
            effect.Color = Color.FromRgb(0x38, 0xBD, 0xF8);
            effect.BlurRadius = 9;
            effect.Opacity = 0.42;
            return;
        }

        var duration = new Duration(TimeSpan.FromMilliseconds(1400));
        effect.BeginAnimation(DropShadowEffect.BlurRadiusProperty, new DoubleAnimation(6, 13, duration) {
            AutoReverse = true,
            RepeatBehavior = RepeatBehavior.Forever,
            EasingFunction = new SineEase { EasingMode = EasingMode.EaseInOut }
        });
        effect.BeginAnimation(DropShadowEffect.OpacityProperty, new DoubleAnimation(0.28, 0.58, duration) {
            AutoReverse = true,
            RepeatBehavior = RepeatBehavior.Forever,
            EasingFunction = new SineEase { EasingMode = EasingMode.EaseInOut }
        });
        var colors = new ColorAnimationUsingKeyFrames {
            Duration = TimeSpan.FromMilliseconds(2800),
            RepeatBehavior = RepeatBehavior.Forever
        };
        colors.KeyFrames.Add(new LinearColorKeyFrame(Color.FromRgb(0x38, 0xBD, 0xF8), KeyTime.FromPercent(0)));
        colors.KeyFrames.Add(new LinearColorKeyFrame(Color.FromRgb(0xF4, 0x72, 0xB6), KeyTime.FromPercent(0.5)));
        colors.KeyFrames.Add(new LinearColorKeyFrame(Color.FromRgb(0x22, 0xC5, 0x5E), KeyTime.FromPercent(1)));
        effect.BeginAnimation(DropShadowEffect.ColorProperty, colors);
    }

    private async Task RefreshWpfChatModelsAsync(bool userInitiated) {
        if (!_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening) {
            if (userInitiated)
                await StartProxyAsync();
            else
                return;
        }

        try {
            WpfChatRefreshModelsButton.IsEnabled = false;
            string previous = GetSelectedWpfChatModel();
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(8));
            string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/models";
            using HttpResponseMessage response = await client.GetAsync(endpoint);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + TrimForDisplay(body, 160));

            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            JsonElement root = document.RootElement;
            var modelIds = new List<string>();
            if (TryGetJsonProperty(root, "models", out JsonElement models) && models.ValueKind == JsonValueKind.Array) {
                foreach (JsonElement model in models.EnumerateArray()) {
                    string id = GetJsonString(model, "id", "");
                    if (!string.IsNullOrWhiteSpace(id))
                        modelIds.Add(id);
                }
            }

            int discoveredModelCount = modelIds.Distinct(StringComparer.OrdinalIgnoreCase).Count();
            string selected = FirstNonEmpty(previous, GetJsonString(root, "selected", ""), _proxy.ChatModel, "lm-studio");
            if (!modelIds.Any(id => string.Equals(id, selected, StringComparison.OrdinalIgnoreCase)))
                modelIds.Insert(0, selected);
            WpfChatModelComboBox.ItemsSource = modelIds.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
            WpfChatModelComboBox.Text = selected;
            if (discoveredModelCount == 0) {
                string message = "No models were returned by " + endpoint + ". Load or download a local model before starting chat.";
                WpfChatStatusText.Text = "No models found; using configured model.";
                NotifyModelsUnavailable(message, userInitiated);
            } else {
                WpfChatStatusText.Text = "Models refreshed.";
            }
        } catch (Exception ex) {
            WpfChatStatusText.Text = "Model refresh failed: " + TrimForDisplay(ex.Message, 160);
            NotifyModelsUnavailable("Model discovery failed: " + ex.Message, userInitiated);
        } finally {
            WpfChatRefreshModelsButton.IsEnabled = true;
            ScheduleWpfChatPromptReadyGlowRefresh();
        }
    }

    private async Task RefreshWpfChatServicesAsync() {
        if (!_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening)
            return;

        try {
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(8));
            string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/chat-services";
            using HttpResponseMessage response = await client.GetAsync(endpoint);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                return;
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            if (!TryGetJsonProperty(document.RootElement, "services", out JsonElement services) || services.ValueKind != JsonValueKind.Array)
                return;

            string selected = GetSelectedWpfChatService();
            var items = new List<ComboBoxItem> {
                new ComboBoxItem { Content = "Assistant", Tag = "" }
            };
            foreach (JsonElement service in services.EnumerateArray()) {
                string id = GetJsonString(service, "id", "");
                string name = GetJsonString(service, "name", id);
                if (string.IsNullOrWhiteSpace(id) || string.Equals(id, "prompt_intellisense", StringComparison.OrdinalIgnoreCase))
                    continue;
                items.Add(new ComboBoxItem {
                    Content = name,
                    Tag = id,
                    IsEnabled = GetJsonBool(service, "enabled", true)
                });
            }
            WpfChatServiceComboBox.Items.Clear();
            foreach (ComboBoxItem item in items)
                WpfChatServiceComboBox.Items.Add(item);
            SelectWpfChatService(selected);
        } catch {
        }
    }

    private string GetSelectedWpfChatModel() {
        string text = WpfChatModelComboBox.Text;
        if (string.IsNullOrWhiteSpace(text) && WpfChatModelComboBox.SelectedItem is string selected)
            text = selected;
        return string.IsNullOrWhiteSpace(text) ? _proxy.ChatModel : text.Trim();
    }

    private string GetSelectedWpfChatService() {
        if (WpfChatServiceComboBox.SelectedItem is ComboBoxItem item)
            return (item.Tag?.ToString() ?? "").Trim();
        return "";
    }

    private void SelectWpfChatService(string serviceId) {
        serviceId = (serviceId ?? "").Trim();
        foreach (object item in WpfChatServiceComboBox.Items) {
            if (item is ComboBoxItem comboItem &&
                string.Equals(comboItem.Tag?.ToString() ?? "", serviceId, StringComparison.OrdinalIgnoreCase)) {
                WpfChatServiceComboBox.SelectedItem = comboItem;
                return;
            }
        }
        if (WpfChatServiceComboBox.Items.Count > 0)
            WpfChatServiceComboBox.SelectedIndex = 0;
    }

    private void InitializeWpfChatIntellisense() {
        _wpfChatIntellisenseTimer = new DispatcherTimer {
            Interval = TimeSpan.FromMilliseconds(180)
        };
        _wpfChatIntellisenseTimer.Tick += async (_, _) => {
            _wpfChatIntellisenseTimer.Stop();
            await LoadWpfChatIntellisenseAsync();
        };
    }

    private void ScheduleWpfChatIntellisense() {
        if (!_uiReady || _wpfChatInProgress)
            return;
        _wpfChatIntellisenseTimer?.Stop();
        string text = WpfChatPromptTextBox?.Text ?? "";
        if (string.IsNullOrWhiteSpace(text)) {
            HideWpfChatSuggestions();
            return;
        }
        _wpfChatIntellisenseTimer?.Start();
    }

    private async Task LoadWpfChatIntellisenseAsync() {
        string text = WpfChatPromptTextBox.Text ?? "";
        if (string.IsNullOrWhiteSpace(text) || !_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening) {
            HideWpfChatSuggestions();
            return;
        }

        int caretIndex = WpfChatPromptTextBox.CaretIndex;
        try {
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(5));
            string endpoint = _proxy.ChatServerUrl.TrimEnd('/') + "/api/prompt-intellisense";
            var payload = new {
                text,
                caretIndex,
                take = 8,
                mode = string.Equals(GetSelectedWpfChatService(), "agent", StringComparison.OrdinalIgnoreCase) ? "agent" : "assistant"
            };
            using var content = new StringContent(JsonSerializer.Serialize(payload), Encoding.UTF8, "application/json");
            using HttpResponseMessage response = await client.PostAsync(endpoint, content);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode || text != (WpfChatPromptTextBox.Text ?? ""))
                return;

            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            if (!TryGetJsonProperty(document.RootElement, "completions", out JsonElement completions) || completions.ValueKind != JsonValueKind.Array) {
                HideWpfChatSuggestions();
                return;
            }

            _wpfChatSuggestions.Clear();
            foreach (JsonElement completion in completions.EnumerateArray()) {
                var item = WpfChatSuggestionItem.FromJson(completion);
                if (!string.IsNullOrWhiteSpace(item.InsertText))
                    _wpfChatSuggestions.Add(item);
            }
            WpfChatSuggestionListBox.Visibility = _wpfChatSuggestions.Count == 0 ? Visibility.Collapsed : Visibility.Visible;
            if (_wpfChatSuggestions.Count > 0)
                WpfChatSuggestionListBox.SelectedIndex = 0;
        } catch {
            HideWpfChatSuggestions();
        }
    }

    private void HideWpfChatSuggestions() {
        _wpfChatSuggestions.Clear();
        if (WpfChatSuggestionListBox != null)
            WpfChatSuggestionListBox.Visibility = Visibility.Collapsed;
    }

    private void MoveWpfChatSuggestionSelection(int delta) {
        if (_wpfChatSuggestions.Count == 0)
            return;
        int index = WpfChatSuggestionListBox.SelectedIndex;
        if (index < 0)
            index = 0;
        index = Math.Max(0, Math.Min(_wpfChatSuggestions.Count - 1, index + delta));
        WpfChatSuggestionListBox.SelectedIndex = index;
        WpfChatSuggestionListBox.ScrollIntoView(_wpfChatSuggestions[index]);
    }

    private void ApplySelectedWpfChatSuggestion() {
        if (WpfChatSuggestionListBox.SelectedItem is not WpfChatSuggestionItem item)
            return;
        string text = WpfChatPromptTextBox.Text ?? "";
        int start = item.ReplaceStart >= 0 ? Math.Min(item.ReplaceStart, text.Length) : WpfChatPromptTextBox.CaretIndex;
        int end = item.ReplaceEnd >= start ? Math.Min(item.ReplaceEnd, text.Length) : WpfChatPromptTextBox.CaretIndex;
        WpfChatPromptTextBox.Text = text.Substring(0, start) + item.InsertText + text.Substring(end);
        WpfChatPromptTextBox.CaretIndex = start + item.InsertText.Length;
        HideWpfChatSuggestions();
        WpfChatPromptTextBox.Focus();
    }

    private static string BuildWpfChatUserDisplayText(string promptText, IReadOnlyList<WpfChatAttachmentItem> attachments) {
        var builder = new StringBuilder((promptText ?? "").Trim());
        foreach (WpfChatAttachmentItem attachment in attachments) {
            if (builder.Length > 0)
                builder.AppendLine().AppendLine();
            builder.Append(attachment.IsImage ? "[Image: " : "[File: ")
                .Append(attachment.Name)
                .Append(" | ")
                .Append(FormatBytes(attachment.Size))
                .Append("]");
        }
        return builder.Length == 0 ? "[Attachments]" : builder.ToString();
    }

    private static bool TryReadDouble(string value, out double result) {
        return double.TryParse((value ?? "").Trim(), NumberStyles.Float, CultureInfo.InvariantCulture, out result) ||
               double.TryParse((value ?? "").Trim(), NumberStyles.Float, CultureInfo.CurrentCulture, out result);
    }

    private static string LanguageForFile(string name) {
        string ext = Path.GetExtension(name ?? "").TrimStart('.').ToLowerInvariant();
        return ext switch {
            "cs" => "cs",
            "vb" => "vb",
            "js" => "js",
            "ts" => "ts",
            "css" => "css",
            "html" or "htm" => "html",
            "json" => "json",
            "xml" => "xml",
            "sql" => "sql",
            "ps1" => "ps1",
            "py" => "py",
            "md" => "md",
            _ => ""
        };
    }

    private void InitializeWpfChatVoice() {
        try {
            _wpfSpeechSynthesizer = new SpeechSynthesizer();
            _wpfSpeechSynthesizer.SetOutputToDefaultAudioDevice();
        } catch (Exception ex) {
            WpfChatStatusText.Text = "Text-to-speech unavailable: " + TrimForDisplay(ex.Message, 140);
            if (WpfChatTtsCheckBox != null)
                WpfChatTtsCheckBox.IsEnabled = false;
        }

        bool hasRecognizer = false;
        try {
            hasRecognizer = SpeechRecognitionEngine.InstalledRecognizers().Count > 0;
        } catch {
            hasRecognizer = false;
        }

        if (!hasRecognizer) {
            WpfChatVoiceButton.IsEnabled = false;
            WpfChatVoiceButton.ToolTip = "Windows speech recognition is not installed for this user.";
        }
    }

    private void StartWpfChatDictation() {
        try {
            if (_wpfSpeechRecognizer == null) {
                RecognizerInfo? recognizerInfo = SpeechRecognitionEngine.InstalledRecognizers()
                    .FirstOrDefault(info => string.Equals(info.Culture.Name, CultureInfo.CurrentCulture.Name, StringComparison.OrdinalIgnoreCase)) ??
                    SpeechRecognitionEngine.InstalledRecognizers().FirstOrDefault();
                if (recognizerInfo == null)
                    throw new InvalidOperationException("No Windows speech recognizer is installed.");

                _wpfSpeechRecognizer = new SpeechRecognitionEngine(recognizerInfo);
                _wpfSpeechRecognizer.SetInputToDefaultAudioDevice();
                _wpfSpeechRecognizer.LoadGrammar(new DictationGrammar());
                _wpfSpeechRecognizer.SpeechRecognized += WpfSpeechRecognizer_SpeechRecognized;
                _wpfSpeechRecognizer.RecognizeCompleted += WpfSpeechRecognizer_RecognizeCompleted;
            }

            _wpfChatListening = true;
            WpfChatVoiceButton.Content = "Stop";
            WpfChatStatusText.Text = "Listening. Speak your prompt, then press Stop or Send.";
            _wpfSpeechRecognizer.RecognizeAsync(RecognizeMode.Multiple);
        } catch (Exception ex) {
            _wpfChatListening = false;
            WpfChatVoiceButton.Content = "Dictate";
            WpfChatStatusText.Text = "Dictation failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private void StopWpfChatDictation(string status) {
        try {
            _wpfSpeechRecognizer?.RecognizeAsyncStop();
        } catch {
            try { _wpfSpeechRecognizer?.RecognizeAsyncCancel(); } catch { }
        }

        _wpfChatListening = false;
        WpfChatVoiceButton.Content = "Dictate";
        WpfChatStatusText.Text = status;
    }

    private void WpfSpeechRecognizer_SpeechRecognized(object? sender, SpeechRecognizedEventArgs e) {
        if (e.Result == null || string.IsNullOrWhiteSpace(e.Result.Text) || e.Result.Confidence < 0.25)
            return;

        TryBeginOnUi(() => AppendDictatedTextToWpfPrompt(e.Result.Text), "WPF chat dictation text");
    }

    private void WpfSpeechRecognizer_RecognizeCompleted(object? sender, RecognizeCompletedEventArgs e) {
        TryBeginOnUi(() => {
            _wpfChatListening = false;
            WpfChatVoiceButton.Content = "Dictate";
            if (e.Error != null)
                WpfChatStatusText.Text = "Dictation stopped: " + TrimForDisplay(e.Error.Message, 160);
        }, "WPF chat dictation completion");
    }

    private void AppendDictatedTextToWpfPrompt(string text) {
        text = (text ?? "").Trim();
        if (string.IsNullOrWhiteSpace(text))
            return;

        string current = WpfChatPromptTextBox.Text ?? "";
        string separator = string.IsNullOrWhiteSpace(current)
            ? ""
            : (current.EndsWith(" ", StringComparison.Ordinal) || current.EndsWith(Environment.NewLine, StringComparison.Ordinal) ? "" : " ");
        WpfChatPromptTextBox.Text = current + separator + text;
        WpfChatPromptTextBox.CaretIndex = WpfChatPromptTextBox.Text.Length;
        WpfChatPromptTextBox.Focus();
    }

    private void SpeakWpfChatResponse(string text) {
        if (!WpfChatTtsCheckBox.IsChecked.GetValueOrDefault(false) || _wpfSpeechSynthesizer == null)
            return;

        string speechText = TextForSpeech(text);
        if (string.IsNullOrWhiteSpace(speechText))
            return;

        try {
            _wpfSpeechSynthesizer.SpeakAsyncCancelAll();
            _wpfSpeechSynthesizer.SpeakAsync(speechText);
        } catch (Exception ex) {
            WpfChatStatusText.Text = "TTS failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private void DisposeWpfChatVoice() {
        try { _wpfSpeechRecognizer?.RecognizeAsyncCancel(); } catch { }
        if (_wpfSpeechRecognizer != null) {
            _wpfSpeechRecognizer.SpeechRecognized -= WpfSpeechRecognizer_SpeechRecognized;
            _wpfSpeechRecognizer.RecognizeCompleted -= WpfSpeechRecognizer_RecognizeCompleted;
            _wpfSpeechRecognizer.Dispose();
            _wpfSpeechRecognizer = null;
        }

        try { _wpfSpeechSynthesizer?.SpeakAsyncCancelAll(); } catch { }
        _wpfSpeechSynthesizer?.Dispose();
        _wpfSpeechSynthesizer = null;
    }

    private void ScrollWpfChatToEnd() {
        TryBeginOnUi(() => {
            if (_wpfChatMessages.Count > 0)
                WpfChatListBox.ScrollIntoView(_wpfChatMessages[^1]);
        }, "WPF chat scroll");
    }

    private static string TextForSpeech(string text) {
        text = Regex.Replace(text ?? "", "```[\\s\\S]*?```", " ");
        text = Regex.Replace(text, "`([^`]+)`", "$1");
        text = Regex.Replace(text, "!\\[[^\\]]*\\]\\([^)]+\\)", " ");
        text = Regex.Replace(text, "\\[([^\\]]+)\\]\\([^)]+\\)", "$1");
        text = Regex.Replace(text, "<[^>]+>", " ");
        text = Regex.Replace(text, "^#{1,6}\\s*", "", RegexOptions.Multiline);
        text = Regex.Replace(text, "^[>\\-*+]\\s+", "", RegexOptions.Multiline);
        text = Regex.Replace(text, "\\s+", " ").Trim();
        return text.Length <= 6000 ? text : text.Substring(0, 6000);
    }

