    private void ApplySelectedSession(ChatSessionListItem? selectedItem, bool syncLists, bool refreshNow) {
        _selectedSessionId = selectedItem?.Id ?? "";
        _selectedOwnerKey = selectedItem?.OwnerKey ?? "";
        if (syncLists)
            SyncSessionListSelections(selectedItem);
        _accessibleDirectorySignature = "";
        _workspaceTreeSignature = "";
        _sessionLogSignature = "";
        if (!refreshNow)
            return;

        RefreshAccessibleDirectories(true);
        RefreshWorkspaceExplorer(true);
        RefreshSessionLogPreview(true);
    }

    private void ApplySelectedOwnerOnly(string ownerKey, bool refreshNow) {
        _selectedSessionId = "";
        _selectedOwnerKey = string.IsNullOrWhiteSpace(ownerKey) ? "" : ownerKey.Trim();
        SyncSessionListSelections(null);
        _accessibleDirectorySignature = "";
        _workspaceTreeSignature = "";
        _sessionLogSignature = "";
        if (!refreshNow)
            return;

        RefreshAccessibleDirectories(true);
        RefreshWorkspaceExplorer(true);
        RefreshSessionLogPreview(true);
    }

    private void SyncSessionListSelections(ChatSessionListItem? selectedItem) {
        _syncingSessionSelection = true;
        try {
            if (SessionsListBox != null) {
                ChatSessionListItem? mainSelection = selectedItem != null && SessionsListBox.Items.Contains(selectedItem) ? selectedItem : null;
                if (!ReferenceEquals(SessionsListBox.SelectedItem, mainSelection))
                    SessionsListBox.SelectedItem = mainSelection;
            }
            if (ServerSessionsListBox != null) {
                ChatSessionListItem? serverSelection = selectedItem != null && ServerSessionsListBox.Items.Contains(selectedItem) ? selectedItem : null;
                if (!ReferenceEquals(ServerSessionsListBox.SelectedItem, serverSelection))
                    ServerSessionsListBox.SelectedItem = serverSelection;
            }
        } finally {
            _syncingSessionSelection = false;
        }
    }

    private void BrowseAccessibleDirectoryButton_Click(object sender, RoutedEventArgs e) {
        try {
            var dialog = new OpenFolderDialog {
                Title = "Select accessible directories",
                Multiselect = true
