            object? selectedTreeItem = ServerWorkspaceTreeView?.SelectedItem ?? WorkspaceTreeView?.SelectedItem;
            if (selectedTreeItem is FileTreeItem selected &&
                !string.IsNullOrWhiteSpace(selected.SourcePath)) {
                string initialDirectory = Directory.Exists(selected.SourcePath)
                    ? selected.SourcePath
                    : Path.GetDirectoryName(selected.SourcePath) ?? "";
