                    dialog.InitialDirectory = initialDirectory;
            }

            if (dialog.ShowDialog(this) == true)
                AddAccessibleDirectoryPaths(dialog.FolderNames);
        } catch (Exception ex) {
            SetFilesystemAccessStatusText("Add failed: " + TrimForDisplay(ex.Message, 120));
        }
