    private void ClearAccessibleDirectoriesButton_Click(object sender, RoutedEventArgs e) {
        List<string> paths = _accessibleDirectoryItems
            .Select(item => item.Path)
            .Where(path => !string.IsNullOrWhiteSpace(path))
            .ToList();
        if (paths.Count == 0) {
            SetFilesystemAccessStatusText("No accessible directories to clear.");
            return;
        }

        MessageBoxResult result = MessageBox.Show(
            this,
            "Remove access to all " + paths.Count + " listed director" + (paths.Count == 1 ? "y?" : "ies?"),
            "Clear accessible folders",
            MessageBoxButton.YesNo,
            MessageBoxImage.Warning);
        if (result != MessageBoxResult.Yes)
            return;

        RemoveAccessibleDirectoryPaths(paths);
    }

    private async void DownloadWorkspaceTreeDirectoryZipButton_Click(object sender, RoutedEventArgs e) {
        e.Handled = true;
        if ((sender as FrameworkElement)?.Tag is not FileTreeItem item ||
            string.IsNullOrWhiteSpace(item.SourcePath) ||
            !Directory.Exists(item.SourcePath)) {
            SetFilesystemAccessStatusText("ZIP failed: directory is unavailable.");
            return;
        }

        string defaultName = MakeSafeZipFileName(item.DisplayName);
        var dialog = new Microsoft.Win32.SaveFileDialog {
            Title = "Download folder as ZIP",
            Filter = "ZIP archive (*.zip)|*.zip",
            FileName = defaultName,
            AddExtension = true,
            DefaultExt = ".zip",
            OverwritePrompt = true
        };
        if (dialog.ShowDialog(this) != true)
            return;

        string sourcePath = item.SourcePath;
        string destinationPath = dialog.FileName;
        if (string.IsNullOrWhiteSpace(destinationPath))
            return;

        Button? actionButton = sender as Button;
        if (actionButton != null)
            actionButton.IsEnabled = false;
        SetFilesystemAccessStatusText("Creating ZIP: " + TrimPathForDisplay(sourcePath, 90));

        string tempZipPath = Path.Combine(Path.GetTempPath(), "LmVsProxy-" + Guid.NewGuid().ToString("N") + ".zip");
        try {
            await Task.Run(() => {
                ZipFile.CreateFromDirectory(sourcePath, tempZipPath, CompressionLevel.Fastest, includeBaseDirectory: true);
                File.Copy(tempZipPath, destinationPath, overwrite: true);
            });
            SetFilesystemAccessStatusText("ZIP saved: " + TrimPathForDisplay(destinationPath, 100));
            AppendLog("Saved folder ZIP: " + destinationPath);
        } catch (Exception ex) {
            SetFilesystemAccessStatusText("ZIP failed: " + TrimForDisplay(ex.Message, 120));
            AppendLog("Folder ZIP failed: " + TrimForDisplay(ex.Message, 180));
        } finally {
            try {
                if (File.Exists(tempZipPath))
                    File.Delete(tempZipPath);
            } catch {
            }
            if (actionButton != null)
                actionButton.IsEnabled = true;
        }
    }

