    private void UpdateHostTokenCostBreakdown() {
        if (HostTokenCostRateText == null)
            return;

        bool requiresPayment = HostRequiresPaymentCheckBox?.IsChecked.GetValueOrDefault(false) == true;
        string currency = FirstNonEmpty(_masterPricingCurrency, HostStripeCurrencyTextBox?.Text, "usd").ToUpperInvariant();

        HostTokenCostStatusText.Text = requiresPayment ? "Payment on" : "Preview";
        if (_masterTokenUsdPerToken <= 0) {
            HostTokenCostSmallText.Text = "25K -> loading";
            HostTokenCostMediumText.Text = "100K -> loading";
            HostTokenCostLargeText.Text = "500K -> loading";
            HostTokenCostRateText.Text = "Loading cost per token and service fee from the master-list pricing API.";
            _ = RefreshMasterPricingAsync(false);
            return;
        }

        double multiplier = GetHostCostFactor();
        double serviceFeeRate = Math.Max(0, _masterServiceFeePercent) / 100d;
        double serverCostPerToken = _masterTokenUsdPerToken * multiplier;
        double customerCostPerToken = serverCostPerToken * (1 + serviceFeeRate);

        HostTokenCostSmallText.Text = FormatTokenCostExample(25_000, customerCostPerToken);
        HostTokenCostMediumText.Text = FormatTokenCostExample(100_000, customerCostPerToken);
        HostTokenCostLargeText.Text = FormatTokenCostExample(500_000, customerCostPerToken);

        double feePerMillion = serverCostPerToken * 1_000_000 * serviceFeeRate;
        string paymentMode = requiresPayment
            ? "Renters spend SocketJack Tokens when master payments are configured."
            : "Free servers and owner access do not require tokens.";
        HostTokenCostRateText.Text = paymentMode + " Cost/token " +
            FormatUsd(serverCostPerToken) + " base, " +
            FormatUsd(customerCostPerToken) + " with fee. Per 1M tokens: " +
            FormatUsd(serverCostPerToken * 1_000_000) + " + " +
            FormatUsd(feePerMillion) + " fee (" +
            _masterServiceFeePercent.ToString("0.###", CultureInfo.InvariantCulture) + "% tax line), " +
            currency + " from " + _masterPricingSource + ".";
    }

    private static string FormatTokenCostExample(int tokens, double usdPerToken) {
        return FormatShortTokenCount(tokens) + " -> " + FormatUsd(tokens * usdPerToken);
    }

    private static string FormatShortTokenCount(int tokens) {
        if (tokens >= 1_000_000)
            return (tokens / 1_000_000.0).ToString("0.#", CultureInfo.InvariantCulture) + "M";
        if (tokens >= 1_000)
            return (tokens / 1_000.0).ToString("0.#", CultureInfo.InvariantCulture) + "K";
        return tokens.ToString(CultureInfo.InvariantCulture);
    }

    private static string FormatUsd(double value) {
        return "$" + value.ToString(value < 1 ? "0.0000" : "0.00", CultureInfo.InvariantCulture);
    }

    private double GetHostCostFactor() {
        if (HostCostFactorSlider != null)
            return ClampServerCostFactor(HostCostFactorSlider.Value);

        string text = (HostCostFactorText?.Text ?? "1").Trim().TrimEnd('x', 'X');
        return ClampServerCostFactor(ParseDouble(text, 1));
    }

