        try {
            _proxy.WebChatModelLoadApiEnabled = settings.WebChatModelLoadApiEnabled;
        } catch (Exception ex) {
            if (_uiReady && SettingsStatusText != null)
                SettingsStatusText.Text = "Model-load API setting failed: " + TrimForDisplay(ex.Message, 120);
        }
    }

    private long GetAdvertisedTokenRateForPolicy() {
        if (double.IsNaN(_tokenRatePerHour) || double.IsInfinity(_tokenRatePerHour))
            return 0;
        return Math.Max(0, (long)Math.Round(_tokenRatePerHour));
    }

    private void UpdateAdvertisedTokenRatePolicy() {
        try {
            long advertised = GetAdvertisedTokenRateForPolicy();
            DateTimeOffset now = DateTimeOffset.UtcNow;
            long delta = Math.Abs(advertised - _lastAdvertisedTokenRate);
            long threshold = Math.Max(1000, (long)Math.Round(Math.Max(1, _lastAdvertisedTokenRate) * 0.05));
            if ((now - _lastAdvertisedTokenRateSavedUtc) < TimeSpan.FromSeconds(15) && delta < threshold)
                return;

            _lastAdvertisedTokenRate = advertised;
            _lastAdvertisedTokenRateSavedUtc = now;
            _proxy.SetAdvertisedTokenRate(advertised);
        } catch { }
    }

    private void UpdateTokenRateRequestPolicyText() {
        if (TokenRateRequestPolicyText == null)
            return;

        bool enabled = TokenRateRequestsEnabledCheckBox?.IsChecked.GetValueOrDefault(false) == true;
        long min = Math.Max(0, ParseLong(TokenRateRequestMinTextBox?.Text ?? "1000", 1000));
        long max = Math.Max(min, ParseLong(TokenRateRequestMaxTextBox?.Text ?? "100000", 100000));
        TokenRateRequestPolicyText.Text = (enabled ? "Enabled" : "Disabled") +
                                          " | " + min.ToString("N0", CultureInfo.CurrentCulture) +
                                          " - " + max.ToString("N0", CultureInfo.CurrentCulture) +
                                          " tokens/hour";
    }

    private void ApplyServerBrowserProfileToProxy(JackLLMSettings settings) {
        try {
            _proxy.SocketJackAuthServerUrl = string.IsNullOrWhiteSpace(settings.MasterServerUrl)
                ? DefaultMasterServerUrl
                : settings.MasterServerUrl.TrimEnd('/');
            _proxy.UseSocketJackMasterAuth = true;
            _proxy.StoreLocalWebAuthAccounts = false;
            _proxy.ConfigureServerBrowserProfile(BuildServerProfileFromSettings(settings));
        } catch (Exception ex) {
            if (_uiReady && ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = "Server profile failed: " + TrimForDisplay(ex.Message, 120);
        }
    }

