            AvailableResources = settings.HostAvailableResources,
            AvailableModels = _detectedHostAvailableModels,
            ToolsAllowed = BuildHostToolsAllowedText(),
            AvailableVram = _detectedHostAvailableVram,
            MaxTokens = _detectedHostMaxTokens,
            ModelCapabilitiesJson = BuildModelCapabilitiesJson(),
            ModelBenchmarksJson = GetLatestModelBenchmarksJson(settings.HostModelBenchmarksJson),
            AdvertisedTokenRate = GetAdvertisedTokenRateForPolicy(),
            RequiresPayment = settings.HostRequiresPayment,
            StripePriceId = settings.HostStripePriceId,
            StripeAccount = settings.HostStripeAccount,
            StripeUnitAmountCents = settings.HostStripeUnitAmountCents,
            StripeCurrency = settings.HostStripeCurrency,
            StartedUtc = GetProxyStartedUtcText(),
