    private void ApplyDetectedGpuTdpToProxy() {
        try {
            GpuTdpDetectionSnapshot snapshot = _proxy.DetectAndApplyNvidiaGpuTdpWatts();
            if (snapshot.TdpWatts <= 0 && (IsWineSafeWpfMode() || IsWineEnvironment())) {
                AppendLog("NVIDIA GPU TDP was not visible from Wine; trying Linux nvidia-smi through bash.");
                snapshot = DetectAndApplyLinuxNvidiaGpuTdpViaShell();
            }
            if (snapshot.TdpWatts > 0) {
                string watts = snapshot.TdpWatts.ToString("0.#", CultureInfo.InvariantCulture);
                _gpuTdpText =  watts + "W | " + TrimForDisplay(snapshot.GpuName, 36);
                UpdateGpuTdpBillingText();
                AppendLog("Detected NVIDIA GPU TDP: " + snapshot.GpuName + " -> " + watts + "W (" + snapshot.Source + ").");
                return;
            }

            _gpuTdpText = "GPU TDP: no NVIDIA GPU detected";
            UpdateGpuTdpBillingText();
            AppendLog("No NVIDIA GPU TDP detected. Intel, AMD, and integrated graphics are ignored.");
        } catch (Exception ex) {
            _gpuTdpText = "detection failed";
            UpdateGpuTdpBillingText();
            AppendLog("NVIDIA GPU TDP detection failed: " + TrimForDisplay(ex.Message, 180));
        }
    }

    private void UpdateGpuTdpBillingText() {
        if (GpuTdpBillingText != null)
            GpuTdpBillingText.Text = _gpuTdpText;
    }

    private void UpdateCpuTdpBillingText() {
        if (CpuTdpBillingText == null)
            return;

        try {
            double watts = Math.Max(0, _proxy.ChatCpuTdpWatts);
            CpuTdpBillingText.Text = watts.ToString("0.#", CultureInfo.InvariantCulture) + "W";
            CpuTdpBillingText.ToolTip = "CPU TDP estimate used for billing: " + CpuTdpBillingText.Text;
        } catch (Exception ex) {
            CpuTdpBillingText.Text = "unavailable";
            CpuTdpBillingText.ToolTip = "CPU TDP estimate unavailable: " + TrimForDisplay(ex.Message, 120);
        }
    }

    private static string NormalizeStorageType(string storageType) {
        if (string.Equals(storageType, "SATA SSD", StringComparison.OrdinalIgnoreCase))
            return "SATA SSD";
        if (string.Equals(storageType, "SATA HDD", StringComparison.OrdinalIgnoreCase))
            return "SATA HDD";
        return "Nvme";
    }

    private static double ClampStorageCostFactor(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            return 1;
        return Math.Max(1, Math.Min(5, value));
    }

    private static double ClampServerCostFactor(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            return 1;
        return Math.Max(1, Math.Min(5, value));
    }

    private static long ClampHostStorageLimitMegabytes(long value) {
        if (value <= 0)
            return DefaultHostStorageLimitMegabytes;
        return Math.Max(MinHostStorageLimitMegabytes, Math.Min(MaxHostStorageLimitMegabytes, value));
    }

    private static int NormalizeHostThroughputTokensPerSecond(int tokensPerSecond) {
        if (tokensPerSecond <= 0)
            return 0;
        return Math.Max(1, Math.Min(MaxHostThroughputTokensPerSecond, tokensPerSecond));
    }

    private static int HostThroughputSliderValueToTokensPerSecond(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            return 0;

        int rounded = (int)Math.Round(value);
        if (rounded >= HostThroughputSliderUnlimitedValue)
            return 0;
        return NormalizeHostThroughputTokensPerSecond(rounded);
    }

    private static double HostThroughputTokensPerSecondToSliderValue(int tokensPerSecond) {
        tokensPerSecond = NormalizeHostThroughputTokensPerSecond(tokensPerSecond);
        return tokensPerSecond <= 0 ? HostThroughputSliderUnlimitedValue : tokensPerSecond;
    }

    private static string FormatHostThroughputTokensPerSecond(int tokensPerSecond) {
        tokensPerSecond = NormalizeHostThroughputTokensPerSecond(tokensPerSecond);
        return tokensPerSecond <= 0
            ? "Unlimited"
            : tokensPerSecond.ToString("N0", CultureInfo.CurrentCulture) + " Tok/sec";
    }

    private static string FormatStorageLimitMegabytes(long megabytes) {
        megabytes = ClampHostStorageLimitMegabytes(megabytes);
        if (megabytes >= 1024)
            return (megabytes / 1024.0).ToString("0.#", CultureInfo.InvariantCulture) + " GB";
        return megabytes.ToString("N0", CultureInfo.CurrentCulture) + " MB";
    }

    private async Task<JackLLMSettings> LoadSettingsAsync(CancellationToken cancellationToken) {
        try {
            (JackLLMSettings Settings, string Status) result = await Task.Run(LoadSettingsFromDisk, cancellationToken);
            SettingsStatusText.Text = result.Status;
            return result.Settings;
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            SettingsStatusText.Text = "Settings load failed: " + TrimForDisplay(ex.Message, 120);
            JackLLMSettings fallback = new JackLLMSettings();
            EnsureMasterServerOwnerToken(fallback);
            return fallback;
        }
    }

    private JackLLMSettings LoadSettings() {
        try {
            (JackLLMSettings Settings, string Status) result = LoadSettingsFromDisk();
            SettingsStatusText.Text = result.Status;
            return result.Settings;
        } catch (Exception ex) {
            SettingsStatusText.Text = "Settings load failed: " + TrimForDisplay(ex.Message, 120);
            JackLLMSettings fallback = new JackLLMSettings();
            EnsureMasterServerOwnerToken(fallback);
            return fallback;
        }
    }

    private (JackLLMSettings Settings, string Status) LoadSettingsFromDisk() {
        string settingsPath = ResolveExistingSettingsPath();
        if (string.IsNullOrWhiteSpace(settingsPath) || !System.IO.File.Exists(settingsPath)) {
            JackLLMSettings defaults = new JackLLMSettings();
            EnsureMasterServerOwnerToken(defaults);
            return (defaults, "Using defaults. Settings will save in user profile.");
        }

        string json = File.ReadAllText(settingsPath);
        JackLLMSettings? loaded = JsonSerializer.Deserialize<JackLLMSettings>(json);
        loaded ??= new JackLLMSettings();
        EnsureMasterServerOwnerToken(loaded);
        UpgradeLegacyDefaultSettings(loaded);
        string status = string.Equals(settingsPath, _settingsPath, StringComparison.OrdinalIgnoreCase)
            ? "Loaded settings from user profile."
            : "Loaded legacy settings. Future saves use user profile.";
        return (loaded, status);
    }

    private string ResolveExistingSettingsPath() {
        if (File.Exists(_settingsPath))
            return _settingsPath;

        string legacyPath = GetLegacySettingsPath();
        return File.Exists(legacyPath) ? legacyPath : "";
    }

    private static void EnsureMasterServerOwnerToken(JackLLMSettings settings) {
        if (settings == null)
            return;
        if (string.IsNullOrWhiteSpace(settings.MasterServerOwnerToken))
            settings.MasterServerOwnerToken = "lmvs_owner_" + Guid.NewGuid().ToString("N");
    }

    private static void UpgradeLegacyDefaultSettings(JackLLMSettings settings) {
        if (settings == null)
            return;
        if (settings.HostStorageLimitMegabytes == 500)
            settings.HostStorageLimitMegabytes = DefaultHostStorageLimitMegabytes;
        settings.ServicePropertyOverrides = settings.ServicePropertyOverrides == null
            ? new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
            : new Dictionary<string, string>(settings.ServicePropertyOverrides, StringComparer.OrdinalIgnoreCase);
        settings.ModelsLocation = NormalizeModelsLocationForSettings(settings.ModelsLocation);
    }

