    private void SelectModelRuntimeProvider(string provider) {
        provider = NormalizeModelRuntimeProvider(provider);
        _activeModelRuntimeProvider = provider;
        _settings.ModelRuntimeProvider = provider;
        if (ModelRuntimeProviderComboBox == null)
            return;

        foreach (object item in ModelRuntimeProviderComboBox.Items) {
            if (item is ComboBoxItem comboBoxItem &&
                string.Equals(comboBoxItem.Tag?.ToString(), provider, StringComparison.OrdinalIgnoreCase)) {
                ModelRuntimeProviderComboBox.SelectedItem = comboBoxItem;
                return;
            }
        }

        ModelRuntimeProviderComboBox.SelectedIndex = 0;
    }

    private string GetSelectedModelRuntimeProvider() {
        if (ModelRuntimeProviderComboBox?.SelectedItem is ComboBoxItem comboBoxItem)
            return NormalizeModelRuntimeProvider(comboBoxItem.Tag?.ToString());
        return NormalizeModelRuntimeProvider(_activeModelRuntimeProvider);
    }

    private static string NormalizeModelRuntimeProvider(string? provider) {
        provider = (provider ?? "").Trim().ToLowerInvariant().Replace(" ", "").Replace("-", "");
        return provider == RuntimeProviderLmStudio ? RuntimeProviderLmStudio : RuntimeProviderLlmRuntime;
    }

    private static string GetJackLlmContentRoot() {
        var candidates = new List<string?>();
        try { candidates.Add(Path.GetDirectoryName(Environment.ProcessPath ?? "")); } catch { }
        candidates.Add(AppContext.BaseDirectory);
        try { candidates.Add(Directory.GetCurrentDirectory()); } catch { }
        try {
            var baseDirectory = new DirectoryInfo(AppContext.BaseDirectory);
            if (string.Equals(baseDirectory.Name, "win-x64", StringComparison.OrdinalIgnoreCase))
                candidates.Add(baseDirectory.Parent?.FullName);
        } catch { }

        foreach (string? candidate in candidates) {
            if (string.IsNullOrWhiteSpace(candidate))
                continue;
            try {
                string fullPath = Path.GetFullPath(candidate);
                if (File.Exists(Path.Combine(fullPath, "JackLLM.exe")) ||
                    Directory.Exists(Path.Combine(fullPath, "CompleteModels")) ||
                    Directory.Exists(Path.Combine(fullPath, "Models")))
                    return fullPath;
            } catch { }
        }

        return AppContext.BaseDirectory;
    }

    private string GetEffectiveModelsLocation() {
        return GetEffectiveModelsLocation(_settings);
    }

    private static string GetEffectiveModelsLocation(JackLLMSettings? settings) {
        string configured = NormalizeModelsLocationForSettings(settings?.ModelsLocation);
        return !string.IsNullOrWhiteSpace(configured) ? configured : GetDefaultModelsLocation();
    }

    private static string GetDefaultModelsLocation() {
        string configured = FirstNonEmpty(
            Environment.GetEnvironmentVariable(ModelsLocationEnvironmentVariable),
            InferModelsLocationFromModelRoots(
                Environment.GetEnvironmentVariable(ModelRootEnvironmentVariable),
                Environment.GetEnvironmentVariable(CompleteModelRootEnvironmentVariable)));
        configured = NormalizeModelsLocationForSettings(configured);
        return !string.IsNullOrWhiteSpace(configured) ? configured : GetJackLlmContentRoot();
    }

    private static string InferModelsLocationFromModelRoots(string? modelRoot, string? completeModelRoot) {
        foreach (string? root in new[] { modelRoot, completeModelRoot }) {
            string normalized = NormalizeModelsLocationForSettings(root);
            if (string.IsNullOrWhiteSpace(normalized))
                continue;
            string leaf = GetDirectoryLeafName(normalized);
            if (leaf.Equals("Models", StringComparison.OrdinalIgnoreCase) ||
                leaf.Equals("CompleteModels", StringComparison.OrdinalIgnoreCase)) {
                string? parent = GetDirectoryParentPath(normalized);
                if (!string.IsNullOrWhiteSpace(parent))
                    return parent;
            }
        }

        return "";
    }

    private static string NormalizeModelsLocationForSettings(string? value) {
        value = Environment.ExpandEnvironmentVariables((value ?? "").Trim().Trim('"'));
        if (string.IsNullOrWhiteSpace(value))
            return "";

        value = ConvertWinePathToUnixPath(value);
        if (IsUnixAbsolutePath(value))
            return TrimUnixDirectory(value);

        try {
            return Path.GetFullPath(value).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
        } catch {
            return value.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
        }
    }

    private static string GetDirectoryLeafName(string path) {
        path = (path ?? "").TrimEnd('/', '\\');
        if (string.IsNullOrWhiteSpace(path))
            return "";
        int index = Math.Max(path.LastIndexOf('/'), path.LastIndexOf('\\'));
        return index >= 0 ? path[(index + 1)..] : path;
    }

    private static string? GetDirectoryParentPath(string path) {
        path = (path ?? "").TrimEnd('/', '\\');
        if (string.IsNullOrWhiteSpace(path))
            return null;
        if (IsUnixAbsolutePath(path)) {
            int index = path.LastIndexOf('/');
            if (index <= 0)
                return "/";
            return path[..index];
        }
        try {
            return Directory.GetParent(path)?.FullName;
        } catch {
            return null;
        }
    }

    private static bool IsUnixAbsolutePath(string path) {
        return !string.IsNullOrWhiteSpace(path) && path.StartsWith("/", StringComparison.Ordinal);
    }

    private static string TrimUnixDirectory(string path) {
        path = (path ?? "").Replace('\\', '/').Trim();
        if (path == "/")
            return path;
        return path.TrimEnd('/');
    }

    private static string ConvertWinePathToUnixPath(string path) {
        path = (path ?? "").Trim();
        if (path.Length >= 3 &&
            (path[0] == 'Z' || path[0] == 'z') &&
            path[1] == ':' &&
            (path[2] == '\\' || path[2] == '/')) {
            return "/" + path[3..].Replace('\\', '/').TrimStart('/');
        }
        return path;
    }

    private static string ConvertUnixPathToWinePath(string path) {
        path = TrimUnixDirectory(path);
        if (!IsUnixAbsolutePath(path))
            return path;
        return "Z:" + path.Replace('/', '\\');
    }

    private static string CombineModelsLocation(string modelsLocation, string childName) {
        modelsLocation = NormalizeModelsLocationForSettings(modelsLocation);
        if (IsUnixAbsolutePath(modelsLocation))
            return TrimUnixDirectory(modelsLocation) + "/" + childName;
        return Path.Combine(modelsLocation, childName);
    }

    private static string ToCurrentProcessPath(string path) {
        path = NormalizeModelsLocationForSettings(path);
        if ((IsWineSafeWpfMode() || IsWineEnvironment()) && IsUnixAbsolutePath(path))
            return ConvertUnixPathToWinePath(path);
        return path;
    }

    private (string ModelsDirectory, string CompleteModelsDirectory) GetModelStorageDirectoriesForCurrentProcess() {
        return GetModelStorageDirectoriesForCurrentProcess(_settings);
    }

    private static (string ModelsDirectory, string CompleteModelsDirectory) GetModelStorageDirectoriesForCurrentProcess(JackLLMSettings? settings) {
        string modelsLocation = GetEffectiveModelsLocation(settings);
        string models = CombineModelsLocation(modelsLocation, "Models");
        string completeModels = CombineModelsLocation(modelsLocation, "CompleteModels");
        return (ToCurrentProcessPath(models), ToCurrentProcessPath(completeModels));
    }

    private static (string ModelsDirectory, string CompleteModelsDirectory) GetModelStorageDirectoriesForNativeLinux(JackLLMSettings? settings) {
        string modelsLocation = GetEffectiveModelsLocation(settings);
        return (CombineModelsLocation(modelsLocation, "Models"), CombineModelsLocation(modelsLocation, "CompleteModels"));
    }

    private static JackOnnxOptions CreateJackOnnxOptions() {
        var storage = GetModelStorageDirectoriesForCurrentProcess(null);
        string contentRoot = GetJackLlmContentRoot();
        string modelRoot = Path.Combine(storage.ModelsDirectory, "JackONNX");
        string completeModelRoot = storage.CompleteModelsDirectory;
        var options = new JackOnnxOptions {
            ModelCachePath = modelRoot,
            ArtifactRoot = Path.Combine(contentRoot, "Artifacts", "JackONNX"),
            PreferredProvider = JackOnnxExecutionProvider.Cuda,
            DevicePolicy = JackOnnxDevicePolicy.RequirePreferredProvider,
            ImageGenerationPythonExecutable = JackOnnxPythonDiffusersImageRunner.DefaultPreferredImageGenerationPythonExecutable,
            AllowPythonBootstrap = true,
            AllowPythonPackageInstall = true
        };
        options.ModelManifestPaths.Add(modelRoot);
        options.ModelManifestPaths.Add(completeModelRoot);
        return options;
    }

    private static IEnumerable<IJackOnnxExecutionProvider> CreateJackOnnxProviders() {
        yield return new CudaExecutionProvider();
        yield return new DirectMlExecutionProvider();
        yield return new OnnxRuntimeCpuExecutionProvider();
    }

    private void ConfigureModelDownloaderControl() {
        if (ModelsManagerControl == null)
            return;

        ApplyModelsLocationToModelManagerControl();
        ModelsManagerControl.RuntimeBaseUrlProvider = () => {
            string externalRuntime = GetExternalModelManagerRuntimeBaseUrl();
            return !string.IsNullOrWhiteSpace(externalRuntime)
                ? externalRuntime
                : _embeddedLlmRuntime?.OpenAiBaseUrl ??
                  "http://127.0.0.1:" + LocalLmStudioProxyPort.ToString(CultureInfo.InvariantCulture);
        };
        ModelsManagerControl.EnsureRuntimeStartedAsync = async () => {
            if (!string.IsNullOrWhiteSpace(GetExternalModelManagerRuntimeBaseUrl())) {
                if (Dispatcher.CheckAccess()) {
                    SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                    ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                    SaveSettingsIfReady();
                } else {
                    await TryInvokeOnUiAsync(() => {
                        SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                        ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                        SaveSettingsIfReady();
                    }, "Model manager external runtime selection");
                }
                return;
            }

            if (Dispatcher.CheckAccess()) {
                SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                SaveSettingsIfReady();
                await EnsureSelectedEmbeddedLlmRuntimeStartedAsync("model-manager-embedded-runtime");
                return;
            }

            await TryInvokeOnUiAsync(() => {
                SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                SaveSettingsIfReady();
            }, "Model manager embedded runtime selection");
            await EnsureSelectedEmbeddedLlmRuntimeStartedAsync("model-manager-embedded-runtime");
        };
        ModelsManagerControl.ModelDownloaded += path => TryBeginOnUi(() => {
            AppendLog("Model downloaded: " + Path.GetFileName(path));
            SetStatus("Model downloaded: " + Path.GetFileName(path));
        }, "Model manager download completion");
        ModelsManagerControl.ModelBenchmarkRequestedWithMetadata += request => TryBeginOnUi(() => {
            if (request != null && !string.IsNullOrWhiteSpace(request.ModelId))
                _ = BenchmarkModelAsync(request.ModelId, request.SuggestedChatService, request.ModelType, request.Tags);
        }, "Model manager benchmark request");
        ModelsManagerControl.ModelBenchmarkRequested += model => TryBeginOnUi(() => {
            if (!string.IsNullOrWhiteSpace(model))
                _ = BenchmarkModelAsync(model);
        }, "Model manager benchmark request");
        ModelsManagerControl.BenchmarkAllModelsRequested += () => TryBeginOnUi(() => BenchmarkAllModelsButton_Click(ModelsManagerControl, new RoutedEventArgs()), "Model manager benchmark-all request");
        ModelsManagerControl.StatusChanged += status => TryBeginOnUi(() => {
            if (!string.IsNullOrWhiteSpace(status))
                SetStatus(status);
        }, "Model manager status update");
        ModelsManagerControl.ChatServiceSuggested += service => {
            if (string.IsNullOrWhiteSpace(service))
                return;

            TryBeginOnUi((Func<Task>)(async () => {
                if (!string.IsNullOrWhiteSpace(GetExternalModelManagerRuntimeBaseUrl())) {
                    SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                    ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                    await RefreshWpfChatServicesAsync();
                    SelectWpfChatService(service);
                    SaveSettingsIfReady();
                    SetStatus("Selected external LlmRuntime chat service: " + service.Replace("_", " "));
                    return;
                }

                SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                await EnsureSelectedEmbeddedLlmRuntimeStartedAsync("model-manager-chat-service");
                await RefreshWpfChatServicesAsync();
                SelectWpfChatService(service);
                SaveSettingsIfReady();
                SetStatus("Selected chat service: " + service.Replace("_", " "));
            }), "Model manager chat service suggestion");
        };
        SyncModelBenchmarksToModelsManager();
    }

    private void ApplyModelsLocationToModelManagerControl() {
        if (ModelsManagerControl == null)
            return;

        var storage = GetModelStorageDirectoriesForCurrentProcess();
        ModelsManagerControl.ModelsDirectory = storage.ModelsDirectory;
        ModelsManagerControl.CompleteModelsDirectory = storage.CompleteModelsDirectory;
    }

    private void ModelsLocationBrowseButton_Click(object sender, RoutedEventArgs e) {
        string currentLocation = NormalizeModelsLocationForSettings(ModelsLocationTextBox?.Text);
        if (string.IsNullOrWhiteSpace(currentLocation))
            currentLocation = GetEffectiveModelsLocation();

        using var dialog = new Forms.FolderBrowserDialog {
            Description = "Choose the base folder that contains Models and CompleteModels.",
            UseDescriptionForTitle = true,
            ShowNewFolderButton = true
        };
        string selectedPath = ToCurrentProcessPath(currentLocation);
        if (Directory.Exists(selectedPath))
            dialog.SelectedPath = selectedPath;

        if (dialog.ShowDialog() != Forms.DialogResult.OK)
            return;

        string selectedLocation = NormalizeModelsLocationForSettings(dialog.SelectedPath);
        if (string.IsNullOrWhiteSpace(selectedLocation))
            return;

        ModelsLocationTextBox.Text = selectedLocation;
        ApplyModelsLocationChange("models location changed");
        SaveSettingsIfReady();
        SetStatus("Models location set to " + selectedLocation + ".");
    }

    private async void ModelsLocationMoveButton_Click(object sender, RoutedEventArgs e) {
        string currentLocation = GetEffectiveModelsLocation();
        using var dialog = new Forms.FolderBrowserDialog {
            Description = "Choose the new base folder. Current Models and CompleteModels will be moved into it.",
            UseDescriptionForTitle = true,
            ShowNewFolderButton = true
        };
        string selectedPath = ToCurrentProcessPath(currentLocation);
        if (Directory.Exists(selectedPath))
            dialog.SelectedPath = selectedPath;
        if (dialog.ShowDialog() != Forms.DialogResult.OK)
            return;

        string newLocation = NormalizeModelsLocationForSettings(dialog.SelectedPath);
        if (string.IsNullOrWhiteSpace(newLocation) || AreSameModelStoragePath(currentLocation, newLocation)) {
            SetStatus("Models are already stored in that location.");
            return;
        }

        MessageBoxResult confirmation = System.Windows.MessageBox.Show(
            "Move Models and CompleteModels from:\n\n" + currentLocation + "\n\nto:\n\n" + newLocation +
            "\n\nFuture model downloads will also use the new location.",
            "Move JackLLM Models",
            MessageBoxButton.OKCancel,
            MessageBoxImage.Question);
        if (confirmation != MessageBoxResult.OK)
            return;

        ModelsLocationMoveButton.IsEnabled = false;
        SetStatus("Moving models to " + newLocation + "...");
        try {
            bool restartEmbeddedRuntime = _embeddedLlmRuntime != null &&
                                          string.Equals(GetSelectedModelRuntimeProvider(), RuntimeProviderLlmRuntime, StringComparison.OrdinalIgnoreCase) &&
                                          string.IsNullOrWhiteSpace(GetExternalModelManagerRuntimeBaseUrl()) &&
                                          (_proxy?.IsListening == true || _embeddedLlmRuntime.IsListening);
            if (_embeddedLlmRuntime != null)
                DisposeEmbeddedLlmRuntime();
            if (IsWineSafeWpfMode() || IsWineEnvironment())
                StopExternalLinuxNativeBackendProcesses();

            await Task.Run(() => MoveModelStorage(currentLocation, newLocation));

            ModelsLocationTextBox.Text = newLocation;
            ApplyModelsLocationChange("models moved");
            SaveSettingsIfReady();
            if (restartEmbeddedRuntime)
                StartSelectedEmbeddedLlmRuntimeInBackground("models-location-move");
            SetStatus("Models moved to " + newLocation + ". Future downloads will use this location.");
        } catch (Exception ex) {
            AppendLog("Models move failed: " + ex.Message);
            SetStatus("Models move failed: " + ex.Message);
            System.Windows.MessageBox.Show(
                "JackLLM could not move the models.\n\n" + ex.Message,
                "Move Models Failed",
                MessageBoxButton.OK,
                MessageBoxImage.Error);
        } finally {
            ModelsLocationMoveButton.IsEnabled = true;
        }
    }

    private static void MoveModelStorage(string sourceLocation, string destinationLocation) {
        string sourceBase = ToCurrentProcessPath(sourceLocation);
        string destinationBase = ToCurrentProcessPath(destinationLocation);
        foreach (string childName in new[] { "Models", "CompleteModels" })
            MoveModelDirectory(Path.Combine(sourceBase, childName), Path.Combine(destinationBase, childName));
    }

    private static void MoveModelDirectory(string sourceDirectory, string destinationDirectory) {
        if (!Directory.Exists(sourceDirectory)) {
            Directory.CreateDirectory(destinationDirectory);
            return;
        }

        string[] sourceFiles = Directory.GetFiles(sourceDirectory, "*", SearchOption.AllDirectories);
        foreach (string sourceFile in sourceFiles) {
            string relativePath = Path.GetRelativePath(sourceDirectory, sourceFile);
            string destinationFile = Path.Combine(destinationDirectory, relativePath);
            if (File.Exists(destinationFile))
                throw new IOException("The destination already contains " + relativePath + ". Choose an empty folder or remove the conflicting file.");
        }

        foreach (string sourceFile in sourceFiles) {
            string relativePath = Path.GetRelativePath(sourceDirectory, sourceFile);
            string destinationFile = Path.Combine(destinationDirectory, relativePath);
            Directory.CreateDirectory(Path.GetDirectoryName(destinationFile) ?? destinationDirectory);
            File.Copy(sourceFile, destinationFile, overwrite: false);
            File.Delete(sourceFile);
        }

        foreach (string directory in Directory.GetDirectories(sourceDirectory, "*", SearchOption.AllDirectories)
                     .OrderByDescending(path => path.Length)) {
            if (!Directory.EnumerateFileSystemEntries(directory).Any())
                Directory.Delete(directory);
        }
        if (!Directory.EnumerateFileSystemEntries(sourceDirectory).Any())
            Directory.Delete(sourceDirectory);
        Directory.CreateDirectory(destinationDirectory);
    }

    private void ApplyModelsLocationChange(string reason) {
        JackLLMSettings effectiveSettings = CaptureSettings();
        _settings.ModelsLocation = effectiveSettings.ModelsLocation;
        EnsureModelsLocationDirectories(effectiveSettings);
        ApplyModelsLocationEnvironment(effectiveSettings);
        ApplyModelsLocationToModelManagerControl();
        WriteModelsLocationEnvironmentHint(effectiveSettings);

        bool usingEmbeddedRuntime = _embeddedLlmRuntime != null &&
                                    string.Equals(GetSelectedModelRuntimeProvider(), RuntimeProviderLlmRuntime, StringComparison.OrdinalIgnoreCase) &&
                                    string.IsNullOrWhiteSpace(GetExternalModelManagerRuntimeBaseUrl());
        if (usingEmbeddedRuntime) {
            bool restart = _proxy?.IsListening == true || _embeddedLlmRuntime.IsListening;
            DisposeEmbeddedLlmRuntime();
            ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
            if (restart)
                StartSelectedEmbeddedLlmRuntimeInBackground("models-location-change");
        } else if (IsWineSafeWpfMode() || IsWineEnvironment()) {
            RestartLinuxNativeBackendForModelsLocationChange();
        }

        if (!string.IsNullOrWhiteSpace(reason))
            AppendLog("Models location applied: " + GetEffectiveModelsLocation(effectiveSettings));
    }

    private static void EnsureModelsLocationDirectories(JackLLMSettings settings) {
        var storage = GetModelStorageDirectoriesForCurrentProcess(settings);
        try { Directory.CreateDirectory(storage.ModelsDirectory); } catch { }
        try { Directory.CreateDirectory(storage.CompleteModelsDirectory); } catch { }
    }

    private static void ApplyModelsLocationEnvironment(JackLLMSettings settings) {
        string location = GetEffectiveModelsLocation(settings);
        var native = GetModelStorageDirectoriesForNativeLinux(settings);
        Environment.SetEnvironmentVariable(ModelsLocationEnvironmentVariable, location);
        Environment.SetEnvironmentVariable(ModelRootEnvironmentVariable, native.ModelsDirectory);
        Environment.SetEnvironmentVariable(CompleteModelRootEnvironmentVariable, native.CompleteModelsDirectory);
    }

    private static void WriteModelsLocationEnvironmentHint(JackLLMSettings settings) {
        if (!IsWineSafeWpfMode() && !IsWineEnvironment())
            return;

        string location = GetEffectiveModelsLocation(settings);
        if (!IsUnixAbsolutePath(location))
            return;

        var native = GetModelStorageDirectoriesForNativeLinux(settings);
        string text =
            "# Generated by JackLLM Workstation. Sourced by Linux launcher scripts.\n" +
            ModelsLocationEnvironmentVariable + "=" + ShellQuote(location) + "\n" +
            ModelRootEnvironmentVariable + "=" + ShellQuote(native.ModelsDirectory) + "\n" +
            CompleteModelRootEnvironmentVariable + "=" + ShellQuote(native.CompleteModelsDirectory) + "\n";

        foreach (string path in GetModelsLocationEnvironmentHintPaths()) {
            try {
                Directory.CreateDirectory(Path.GetDirectoryName(path) ?? GetJackLlmContentRoot());
                File.WriteAllText(path, text);
            } catch {
            }
        }
    }

    private static IEnumerable<string> GetModelsLocationEnvironmentHintPaths() {
        var paths = new List<string>();
        void Add(string path) {
            path = NormalizeModelsLocationForSettings(path);
            if (string.IsNullOrWhiteSpace(path))
                return;
            path = ToCurrentProcessPath(path);
            if (!paths.Contains(path, StringComparer.OrdinalIgnoreCase))
                paths.Add(path);
        }

        string configured = Environment.GetEnvironmentVariable("JACKLLM_MODELS_LOCATION_ENV_PATH") ?? "";
        if (!string.IsNullOrWhiteSpace(configured))
            Add(configured);

        string dataRoot = NormalizeModelsLocationForSettings(Environment.GetEnvironmentVariable("JACKLLM_DATA_ROOT"));
        if (string.IsNullOrWhiteSpace(dataRoot) && (IsWineSafeWpfMode() || IsWineEnvironment()))
            dataRoot = "/var/lib/jackllm";
        if (!string.IsNullOrWhiteSpace(dataRoot))
            Add(CombineModelsLocation(dataRoot, "jackllm-models-location.env"));

        string home = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
        if (!string.IsNullOrWhiteSpace(home))
            Add(Path.Combine(home, ".config", "jackllm", "jackllm-models-location.env"));

        Add(Path.Combine(GetJackLlmContentRoot(), "jackllm-models-location.env"));
        return paths;
    }

    private static string ShellQuote(string value) {
        return "'" + (value ?? "").Replace("'", "'\"'\"'") + "'";
    }

    private static string GetExternalModelManagerRuntimeBaseUrl() {
        string value = FirstNonEmpty(
            Environment.GetEnvironmentVariable("JACKLLM_MODELS_MANAGER_RUNTIME_URL"),
            Environment.GetEnvironmentVariable("JACKLLM_LLMRUNTIME_URL"),
            Environment.GetEnvironmentVariable("LLMRUNTIME_OPENAI_BASE_URL"));
        return NormalizeRuntimeBaseUrl(value, LocalLmStudioProxyPort);
    }

    private HttpLmVsProxyModelRuntime? GetExternalLlmRuntimeAdapter() {
        string baseUrl = GetExternalModelManagerRuntimeBaseUrl();
        if (string.IsNullOrWhiteSpace(baseUrl))
            return null;

        if (_externalLlmRuntime == null ||
            !string.Equals(_externalLlmRuntime.OpenAiBaseUrl.TrimEnd('/'), baseUrl.TrimEnd('/'), StringComparison.OrdinalIgnoreCase)) {
            _externalLlmRuntime = new HttpLmVsProxyModelRuntime("LlmRuntime", baseUrl, () => Task.CompletedTask);
        }

        return _externalLlmRuntime;
    }

    private static string NormalizeRuntimeBaseUrl(string? value, int defaultPort) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "";

        if (Uri.TryCreate(value, UriKind.Absolute, out Uri? uri) && !string.IsNullOrWhiteSpace(uri.Host)) {
            var builder = new UriBuilder(uri.Scheme, uri.Host, uri.Port > 0 ? uri.Port : defaultPort);
            return builder.Uri.ToString().TrimEnd('/');
        }

        if (!TryParseRemoteEndpoint(value, defaultPort, out string host, out int port))
            return "";

        if (host.Contains(':') && !host.StartsWith("[", StringComparison.Ordinal))
            host = "[" + host + "]";

        return "http://" + host + ":" + port.ToString(CultureInfo.InvariantCulture);
    }

    private void InitializeLinuxNativeBackendSupervisorIfNeeded() {
        if (!ShouldUseLinuxNativeBackendSupervisor())
            return;
        if (_linuxNativeBackendSupervisorTask != null && !_linuxNativeBackendSupervisorTask.IsCompleted)
            return;

        ConfigureLinuxNativeBackendEnvironment();
        RestartPrestartedLinuxNativeBackendIfModelsLocationRequiresIt();
        _linuxNativeBackendFailureCount = 0;
        _linuxNativeBackendSupervisorCancellation?.Dispose();
        _linuxNativeBackendSupervisorCancellation = new CancellationTokenSource();
        CancellationToken cancellationToken = _linuxNativeBackendSupervisorCancellation.Token;
        _linuxNativeBackendSupervisorTask = Task.Run(() => RunLinuxNativeBackendSupervisorAsync(cancellationToken), cancellationToken);
        AppendServiceEventLine("LlmRuntime", "Linux/Wine native backend supervisor enabled for http://127.0.0.1:" + LinuxNativeRuntimePort.ToString(CultureInfo.InvariantCulture) + ".");
    }

    private static bool ShouldUseLinuxNativeBackendSupervisor() {
        if (IsTruthyEnvironmentValue(Environment.GetEnvironmentVariable("JACKLLM_DISABLE_LINUX_NATIVE_BACKEND")))
            return false;

        string enabled = Environment.GetEnvironmentVariable("JACKLLM_ENABLE_LINUX_NATIVE_BACKEND") ?? "";
        if (IsTruthyEnvironmentValue(enabled))
            return true;
        if (IsFalsyEnvironmentValue(enabled))
            return false;

        return IsWineSafeWpfMode() || IsWineEnvironment();
    }

    private void RestartPrestartedLinuxNativeBackendIfModelsLocationRequiresIt() {
        if (_linuxNativeBackendStorageRestartAttempted)
            return;
        _linuxNativeBackendStorageRestartAttempted = true;

        string location = GetEffectiveModelsLocation(_settings);
        if (!IsUnixAbsolutePath(location))
            return;

        string defaultLocation = NormalizeModelsLocationForSettings(Environment.GetEnvironmentVariable("JACKLLM_DATA_ROOT"));
        if (string.IsNullOrWhiteSpace(defaultLocation))
            defaultLocation = "/var/lib/jackllm";
        if (AreSameModelStoragePath(location, defaultLocation))
            return;

        if (TryReadLinuxNativeBackendStorage(out string activeModelRoot, out string activeCompleteModelRoot) &&
            AreSameModelStoragePath(activeModelRoot, CombineModelsLocation(location, "Models")) &&
            AreSameModelStoragePath(activeCompleteModelRoot, CombineModelsLocation(location, "CompleteModels")))
            return;

        StopExternalLinuxNativeBackendProcesses();
        AppendServiceEventLine("LlmRuntime", "Restarted prestarted Linux backend so /Workstation model downloads use " + location + ".");
    }

    private static bool TryReadLinuxNativeBackendStorage(out string modelRoot, out string completeModelRoot) {
        modelRoot = "";
        completeModelRoot = "";
        try {
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(8));
            string body = client.GetStringAsync(
                    "http://127.0.0.1:" + LinuxNativeRuntimePort.ToString(CultureInfo.InvariantCulture) + "/api/v1/models")
                .GetAwaiter()
                .GetResult();
            modelRoot = FirstNonEmpty(TryReadJsonString(body, "modelsDirectory"), TryReadJsonString(body, "modelsRoot"));
            completeModelRoot = FirstNonEmpty(TryReadJsonString(body, "completeModelsDirectory"), TryReadJsonString(body, "completeModelsRoot"));
            return !string.IsNullOrWhiteSpace(modelRoot) || !string.IsNullOrWhiteSpace(completeModelRoot);
        } catch {
            return false;
        }
    }

    private static bool IsTruthyEnvironmentValue(string? value) {
        value = (value ?? "").Trim();
        return value.Equals("1", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("true", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("yes", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("on", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsFalsyEnvironmentValue(string? value) {
        value = (value ?? "").Trim();
        return value.Equals("0", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("false", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("no", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("off", StringComparison.OrdinalIgnoreCase);
    }

    private void ConfigureLinuxNativeBackendEnvironment() {
        string location = GetEffectiveModelsLocation(_settings);
        if (!IsUnixAbsolutePath(location))
            location = "/var/lib/jackllm";

        string modelRoot = CombineModelsLocation(location, "Models");
        string completeModelRoot = CombineModelsLocation(location, "CompleteModels");
        string runtimeUrl = "http://127.0.0.1:" + LinuxNativeRuntimePort.ToString(CultureInfo.InvariantCulture);
        string executablePath = ResolveLinuxNativeBackendExecutablePath();
        string logPath = FirstNonEmpty(
            Environment.GetEnvironmentVariable("JACKLLM_NATIVE_BACKEND_LOG"),
            "/var/log/jackllm/native-backend.log");

        _linuxNativeBackendExecutablePath = executablePath;
        _linuxNativeBackendLogPath = logPath;

        Environment.SetEnvironmentVariable(ModelsLocationEnvironmentVariable, location);
        Environment.SetEnvironmentVariable(ModelRootEnvironmentVariable, modelRoot);
        Environment.SetEnvironmentVariable(CompleteModelRootEnvironmentVariable, completeModelRoot);
        Environment.SetEnvironmentVariable("JACKLLM_MODELS_MANAGER_RUNTIME_URL", runtimeUrl);
        Environment.SetEnvironmentVariable("JACKLLM_LLMRUNTIME_URL", runtimeUrl);
        Environment.SetEnvironmentVariable("JACKLLM_NATIVE_BACKEND_PATH", executablePath);
        Environment.SetEnvironmentVariable("JACKLLM_NATIVE_BACKEND_LOG", logPath);
        WriteModelsLocationEnvironmentHint(new JackLLMSettings { ModelsLocation = location });
    }

    private static string ResolveLinuxNativeBackendExecutablePath() {
        string configured = ConvertWinePathToUnixPath(Environment.GetEnvironmentVariable("JACKLLM_NATIVE_BACKEND_PATH") ?? "");
        if (!string.IsNullOrWhiteSpace(configured))
            return configured;

        const string packagePath = "/opt/jackllm/workstation/native/JackLLM.Workstation";
        if (LinuxPathExistsForCurrentProcess(packagePath))
            return packagePath;

        string contentRoot = ConvertWinePathToUnixPath(GetJackLlmContentRoot());
        if (IsUnixAbsolutePath(contentRoot)) {
            string sibling = TrimUnixDirectory(GetDirectoryParentPath(contentRoot) ?? "") + "/native/JackLLM.Workstation";
            if (IsUnixAbsolutePath(sibling) && LinuxPathExistsForCurrentProcess(sibling))
                return sibling;
        }

        return packagePath;
    }

    private static bool LinuxPathExistsForCurrentProcess(string path) {
        if (string.IsNullOrWhiteSpace(path))
            return false;
        try {
            if (File.Exists(path))
                return true;
        } catch {
        }
        try {
            if (IsUnixAbsolutePath(path) && File.Exists(ConvertUnixPathToWinePath(path)))
                return true;
        } catch {
        }
        return false;
    }

    private async Task RunLinuxNativeBackendSupervisorAsync(CancellationToken cancellationToken) {
        while (!cancellationToken.IsCancellationRequested && !_shutdownCompleted) {
            try {
                if (await ProbeLinuxNativeBackendAsync(cancellationToken).ConfigureAwait(false)) {
                    ClearLinuxNativeBackendWarning();
                    await MonitorLinuxNativeBackendUntilFailureAsync(cancellationToken).ConfigureAwait(false);
                    continue;
                }

                StartLinuxNativeBackendProcess();
                if (await WaitForLinuxNativeBackendReadyAsync(TimeSpan.FromSeconds(35), cancellationToken).ConfigureAwait(false)) {
                    ClearLinuxNativeBackendWarning();
                    TryBeginOnUi(() => {
                        AppendServiceEventLine("LlmRuntime", "Linux native backend ready at http://127.0.0.1:" + LinuxNativeRuntimePort.ToString(CultureInfo.InvariantCulture) + ".");
                        SetStatus("Linux native LlmRuntime backend is ready.");
                    }, "Linux native backend ready");
                    await MonitorLinuxNativeBackendUntilFailureAsync(cancellationToken).ConfigureAwait(false);
                    continue;
                }

                RegisterLinuxNativeBackendFailure("Backend did not answer /api/v1/models after startup.");
                StopLinuxNativeBackendProcess(kill: true);
            } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
                break;
            } catch (Exception ex) {
                if (await WaitForLinuxNativeBackendReadyAsync(TimeSpan.FromSeconds(12), cancellationToken).ConfigureAwait(false)) {
                    ClearLinuxNativeBackendWarning();
                    TryBeginOnUi(() => {
                        AppendServiceEventLine("LlmRuntime", "Linux native backend became reachable after supervisor start reported: " + TrimForDisplay(ex.Message, 180));
                        SetStatus("Linux native LlmRuntime backend is ready.");
                    }, "Linux native backend recovered after start warning");
                    await MonitorLinuxNativeBackendUntilFailureAsync(cancellationToken).ConfigureAwait(false);
                    continue;
                }

                RegisterLinuxNativeBackendFailure(TrimForDisplay(ex.Message, 260));
                StopLinuxNativeBackendProcess(kill: true);
            }

            if (_linuxNativeBackendFailureCount >= 3 || cancellationToken.IsCancellationRequested)
                break;

            try {
                await Task.Delay(TimeSpan.FromSeconds(3), cancellationToken).ConfigureAwait(false);
            } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
                break;
            }
        }
    }

    private void StartLinuxNativeBackendProcess() {
        ConfigureLinuxNativeBackendEnvironment();
        string executablePath = _linuxNativeBackendExecutablePath;
        if (string.IsNullOrWhiteSpace(executablePath))
            throw new FileNotFoundException("Linux native backend path is empty.");

        StopLinuxNativeBackendProcess(kill: false);

        string modelRoot = Environment.GetEnvironmentVariable(ModelRootEnvironmentVariable) ?? "/var/lib/jackllm/Models";
        string completeModelRoot = Environment.GetEnvironmentVariable(CompleteModelRootEnvironmentVariable) ?? "/var/lib/jackllm/CompleteModels";
        string modelsLocation = Environment.GetEnvironmentVariable(ModelsLocationEnvironmentVariable) ?? "/var/lib/jackllm";
        string dataRoot = Environment.GetEnvironmentVariable("JACKLLM_DATA_ROOT") ?? "/var/lib/jackllm";
        if (!IsUnixAbsolutePath(dataRoot))
            dataRoot = "/var/lib/jackllm";
        string toolRoot = Environment.GetEnvironmentVariable("JACKLLM_TOOL_ROOT") ?? "";
        if (!IsUnixAbsolutePath(toolRoot))
            toolRoot = CombineModelsLocation(dataRoot, "Tools");
        string agentRoot = Environment.GetEnvironmentVariable("JACKLLM_AGENT_ROOT") ?? "";
        if (!IsUnixAbsolutePath(agentRoot))
            agentRoot = CombineModelsLocation(dataRoot, "Agents");
        string pythonHome = Environment.GetEnvironmentVariable("JACKONNX_PYTHON_HOME") ?? "";
        if (!IsUnixAbsolutePath(pythonHome))
            pythonHome = CombineModelsLocation(dataRoot, "Python");
        string pythonExecutable = Environment.GetEnvironmentVariable("JACKONNX_PYTHON") ?? "";
        if (!IsUnixAbsolutePath(pythonExecutable))
            pythonExecutable = CombineModelsLocation(pythonHome, "bin/python3");
        string logPath = _linuxNativeBackendLogPath;
        string nativeRoot = GetDirectoryParentPath(executablePath) ?? "/opt/jackllm/workstation/native";
        string wpfRoot = ConvertWinePathToUnixPath(GetJackLlmContentRoot());
        if (!IsUnixAbsolutePath(wpfRoot))
            wpfRoot = "/opt/jackllm/workstation/wpf";

        string script =
            "set -euo pipefail\n" +
            "EXE=" + ShellQuote(executablePath) + "\n" +
            "BASE=" + ShellQuote(nativeRoot) + "\n" +
            "WPF_ROOT=" + ShellQuote(wpfRoot) + "\n" +
            "LOG=" + ShellQuote(logPath) + "\n" +
            "MODEL_ROOT=" + ShellQuote(modelRoot) + "\n" +
            "COMPLETE_MODEL_ROOT=" + ShellQuote(completeModelRoot) + "\n" +
            "DATA_ROOT=" + ShellQuote(dataRoot) + "\n" +
            "TOOL_ROOT=" + ShellQuote(toolRoot) + "\n" +
            "AGENT_ROOT=" + ShellQuote(agentRoot) + "\n" +
            "PYTHON_HOME=" + ShellQuote(pythonHome) + "\n" +
            "PYTHON_EXE=" + ShellQuote(pythonExecutable) + "\n" +
            "mkdir -p \"$(dirname \"$LOG\")\" " + ShellQuote(modelsLocation) + " \"$MODEL_ROOT\" \"$COMPLETE_MODEL_ROOT\" \"$TOOL_ROOT\" \"$AGENT_ROOT\" \"$(dirname \"$PYTHON_HOME\")\"\n" +
            "touch \"$LOG\" 2>/dev/null || LOG=\"$HOME/.local/state/jackllm/native-backend.log\"\n" +
            "mkdir -p \"$(dirname \"$LOG\")\"\n" +
            "exec >>\"$LOG\" 2>&1\n" +
            "echo \"[$(date -Is)] starting JackLLM.Workstation native backend from WPF supervisor\"\n" +
            "CPU_BACKEND=noavx\n" +
            "if grep -qw avx512f /proc/cpuinfo 2>/dev/null && [ -f \"$BASE/runtimes/linux-x64/native/avx512/libggml-cpu.so\" ]; then CPU_BACKEND=avx512; " +
            "elif grep -qw avx2 /proc/cpuinfo 2>/dev/null && [ -f \"$BASE/runtimes/linux-x64/native/avx2/libggml-cpu.so\" ]; then CPU_BACKEND=avx2; " +
            "elif grep -qw avx /proc/cpuinfo 2>/dev/null && [ -f \"$BASE/runtimes/linux-x64/native/avx/libggml-cpu.so\" ]; then CPU_BACKEND=avx; fi\n" +
            "LLAMA_NATIVE_DIRS=\"$BASE/runtimes/linux-x64/native/cuda12:$BASE/runtimes/linux-x64/native/$CPU_BACKEND:$BASE/runtimes/linux-x64/native/noavx:$BASE/runtimes/linux-x64/native\"\n" +
            "CUDA_PY_DIRS=\"\"\n" +
            "for TORCH_SITE in \"$PYTHON_HOME\"/lib/python*/site-packages \"$PYTHON_HOME\"/lib64/python*/site-packages; do [ -d \"$TORCH_SITE\" ] || continue; CUDA_PY_DIRS=\"$CUDA_PY_DIRS:$TORCH_SITE/torch/lib:$TORCH_SITE/nvidia/cuda_runtime/lib:$TORCH_SITE/nvidia/cublas/lib:$TORCH_SITE/nvidia/cuda_nvrtc/lib:$TORCH_SITE/nvidia/cuda_cupti/lib:$TORCH_SITE/nvidia/cudnn/lib:$TORCH_SITE/nvidia/cufft/lib:$TORCH_SITE/nvidia/curand/lib:$TORCH_SITE/nvidia/cusolver/lib:$TORCH_SITE/nvidia/cusparse/lib:$TORCH_SITE/nvidia/nccl/lib:$TORCH_SITE/nvidia/nvjitlink/lib:$TORCH_SITE/nvidia/nvtx/lib\"; done\n" +
            "export JACKLLM_CONTENT_ROOT=\"$BASE\"\n" +
            "export JACKLLM_DATA_ROOT=\"$DATA_ROOT\"\n" +
            "export JACKLLM_MODELS_LOCATION=" + ShellQuote(modelsLocation) + "\n" +
            "export JACKLLM_MODEL_ROOT=\"$MODEL_ROOT\"\n" +
            "export JACKLLM_COMPLETE_MODEL_ROOT=\"$COMPLETE_MODEL_ROOT\"\n" +
            "export JACKLLM_TOOL_ROOT=\"$TOOL_ROOT\"\n" +
            "export JACKLLM_AGENT_ROOT=\"$AGENT_ROOT\"\n" +
            "export JACKONNX_PYTHON_HOME=\"$PYTHON_HOME\"\n" +
            "export JACKONNX_PYTHON=\"$PYTHON_EXE\"\n" +
            "export JACKONNX_AUTO_CUDA_TORCH=\"${JACKONNX_AUTO_CUDA_TORCH:-1}\"\n" +
            "if [ -z \"${JACKLLM_VLLM_PYTHON:-}\" ] && [ -x /opt/vllm/venv/bin/python ]; then export JACKLLM_VLLM_PYTHON=/opt/vllm/venv/bin/python; fi\n" +
            "export JACKLLM_VLLM_ARGS=\"${JACKLLM_VLLM_ARGS:---dtype auto --enforce-eager}\"\n" +
            "export HF_HOME=\"${HF_HOME:-$JACKLLM_MODELS_LOCATION/HuggingFace}\"\n" +
            "export HUGGINGFACE_HUB_CACHE=\"${HUGGINGFACE_HUB_CACHE:-$HF_HOME/hub}\"\n" +
            "export TRANSFORMERS_CACHE=\"${TRANSFORMERS_CACHE:-$HF_HOME/transformers}\"\n" +
            "export HF_XET_CACHE=\"${HF_XET_CACHE:-$HF_HOME/xet}\"\n" +
            "mkdir -p \"$HF_HOME\" \"$HUGGINGFACE_HUB_CACHE\" \"$TRANSFORMERS_CACHE\" \"$HF_XET_CACHE\"\n" +
            "export JACKLLM_RESTORE_LOADED_MODELS_ON_STARTUP=0\n" +
            "export NVIDIA_SMI_PATH=\"${NVIDIA_SMI_PATH:-/usr/bin/nvidia-smi}\"\n" +
            "export JACKLLM_NVIDIA_SMI=\"${JACKLLM_NVIDIA_SMI:-/usr/bin/nvidia-smi}\"\n" +
            "export LD_LIBRARY_PATH=\"$BASE:$LLAMA_NATIVE_DIRS:$CUDA_PY_DIRS:${LD_LIBRARY_PATH:-}\"\n" +
            "cd \"$BASE\"\n" +
            "exec \"$EXE\" --runtime llmruntime --proxy-port " + LinuxNativeProxyPort.ToString(CultureInfo.InvariantCulture) +
            " --copilot-duplicator-port " + LinuxNativeDuplicatorPort.ToString(CultureInfo.InvariantCulture) +
            " --chat-port " + LinuxNativeChatPort.ToString(CultureInfo.InvariantCulture) +
            " --runtime-port " + LinuxNativeRuntimePort.ToString(CultureInfo.InvariantCulture) +
            " --model-root \"$MODEL_ROOT\" --complete-model-root \"$COMPLETE_MODEL_ROOT\" --tool-root \"$TOOL_ROOT\" --agent-root \"$AGENT_ROOT\" --data-root \"$DATA_ROOT\" --sql-admin true --no-restore-loaded-models --verbose\n";

        var startInfo = new ProcessStartInfo {
            FileName = IsWineEnvironment() || IsWineSafeWpfMode() ? ConvertUnixPathToWinePath("/bin/bash") : "/bin/bash",
            UseShellExecute = false,
            CreateNoWindow = true
        };
        startInfo.ArgumentList.Add("-lc");
        startInfo.ArgumentList.Add(script);

        startInfo.Environment[ModelsLocationEnvironmentVariable] = modelsLocation;
        startInfo.Environment[ModelRootEnvironmentVariable] = modelRoot;
        startInfo.Environment[CompleteModelRootEnvironmentVariable] = completeModelRoot;
        startInfo.Environment["JACKLLM_DATA_ROOT"] = dataRoot;
        startInfo.Environment["JACKLLM_TOOL_ROOT"] = toolRoot;
        startInfo.Environment["JACKLLM_AGENT_ROOT"] = agentRoot;
        startInfo.Environment["JACKONNX_PYTHON_HOME"] = pythonHome;
        startInfo.Environment["JACKONNX_PYTHON"] = pythonExecutable;
        startInfo.Environment["JACKLLM_RESTORE_LOADED_MODELS_ON_STARTUP"] = "0";
        startInfo.Environment["JACKLLM_NATIVE_BACKEND_PATH"] = executablePath;
        startInfo.Environment["JACKLLM_NATIVE_BACKEND_LOG"] = logPath;

        _linuxNativeBackendProcess = Process.Start(startInfo) ?? throw new InvalidOperationException("Process.Start returned null for Linux native backend.");
        TryBeginOnUi(() => AppendServiceEventLine("LlmRuntime", "Started Linux native backend PID " + _linuxNativeBackendProcess.Id.ToString(CultureInfo.InvariantCulture) + "."), "Linux native backend start");
    }

    private async Task MonitorLinuxNativeBackendUntilFailureAsync(CancellationToken cancellationToken) {
        while (!cancellationToken.IsCancellationRequested && !_shutdownCompleted) {
            Process? process = _linuxNativeBackendProcess;
            if (process != null) {
                try {
                    if (process.HasExited) {
                        RegisterLinuxNativeBackendFailure("Backend process exited with code " + process.ExitCode.ToString(CultureInfo.InvariantCulture) + ".");
                        return;
                    }
                } catch {
                }
            }

            if (!await ProbeLinuxNativeBackendAsync(cancellationToken).ConfigureAwait(false)) {
                RegisterLinuxNativeBackendFailure("Backend model-list probe failed while running.");
                StopLinuxNativeBackendProcess(kill: true);
                return;
            }

            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken).ConfigureAwait(false);
        }
    }

    private async Task<bool> WaitForLinuxNativeBackendReadyAsync(TimeSpan timeout, CancellationToken cancellationToken) {
        Stopwatch stopwatch = Stopwatch.StartNew();
        while (stopwatch.Elapsed < timeout && !cancellationToken.IsCancellationRequested) {
            Process? process = _linuxNativeBackendProcess;
            if (process != null) {
                try {
                    if (process.HasExited)
                        return false;
                } catch {
                }
            }

            if (await ProbeLinuxNativeBackendAsync(cancellationToken).ConfigureAwait(false))
                return true;
            await Task.Delay(TimeSpan.FromMilliseconds(750), cancellationToken).ConfigureAwait(false);
        }

        return false;
    }

    private static async Task<bool> ProbeLinuxNativeBackendAsync(CancellationToken cancellationToken) {
        try {
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(4));
            using HttpResponseMessage response = await client.GetAsync(
                "http://127.0.0.1:" + LinuxNativeRuntimePort.ToString(CultureInfo.InvariantCulture) + "/api/v1/models",
                cancellationToken).ConfigureAwait(false);
            return response.IsSuccessStatusCode;
        } catch {
            return false;
        }
    }

    private void RegisterLinuxNativeBackendFailure(string detail) {
        _linuxNativeBackendFailureCount++;
        string attempt = _linuxNativeBackendFailureCount.ToString(CultureInfo.InvariantCulture) + "/3";
        string message = "Linux native backend failed (" + attempt + "): " + TrimForDisplay(detail, 220);
        TryBeginOnUi(() => {
            AppendServiceEventLine("LlmRuntime", message);
            SetStatus(message);
        }, "Linux native backend failure");

        if (_linuxNativeBackendFailureCount >= 3)
            SetLinuxNativeBackendWarning("The hidden Linux LlmRuntime backend failed 3 times. " + detail);
    }

    private void SetLinuxNativeBackendWarning(string detail) {
        _linuxNativeBackendWarningActive = true;
        _linuxNativeBackendWarningDetail = TrimForDisplay(detail, 320);
        TryBeginOnUi(RefreshModelReconfigurationSuggestions, "Linux native backend warning");
    }

    private void ClearLinuxNativeBackendWarning() {
        if (!_linuxNativeBackendWarningActive)
            return;
        _linuxNativeBackendWarningActive = false;
        _linuxNativeBackendWarningDetail = "";
        TryBeginOnUi(RefreshModelReconfigurationSuggestions, "Linux native backend warning cleared");
    }

    private void StopLinuxNativeBackendSupervisor() {
        try { _linuxNativeBackendSupervisorCancellation?.Cancel(); } catch { }
        _linuxNativeBackendSupervisorTask = null;
        StopLinuxNativeBackendProcess(kill: false);
    }

    private void StopLinuxNativeBackendProcess(bool kill) {
        Process? process = _linuxNativeBackendProcess;
        _linuxNativeBackendProcess = null;
        if (process == null)
            return;

        try {
            if (!process.HasExited)
                process.Kill(entireProcessTree: true);
        } catch {
        } finally {
            try { process.Dispose(); } catch { }
        }
    }

    private void RestartLinuxNativeBackendForModelsLocationChange() {
        StopLinuxNativeBackendSupervisor();
        StopExternalLinuxNativeBackendProcesses();
        _linuxNativeBackendFailureCount = 0;
        _linuxNativeBackendStorageRestartAttempted = true;
        ClearLinuxNativeBackendWarning();
        InitializeLinuxNativeBackendSupervisorIfNeeded();
        AppendLog("Models location updated for Linux/Wine. Restarted the native LlmRuntime bridge so /Workstation downloads use " + GetEffectiveModelsLocation() + ".");
        SetStatus("Restarting Linux native backend with updated models location.");
    }

    private void StopExternalLinuxNativeBackendProcesses() {
        if (!IsWineSafeWpfMode() && !IsWineEnvironment())
            return;

        try {
            string script =
                "pattern=\"[J]ackLLM[.]Workstation|[j]ackllm-workstation-native\"; " +
                "pkill -TERM -u \"$(id -u)\" -f \"$pattern\" >/dev/null 2>&1 || true; " +
                "sleep 1; " +
                "pkill -KILL -u \"$(id -u)\" -f \"$pattern\" >/dev/null 2>&1 || true";
            var startInfo = new ProcessStartInfo {
                FileName = IsWineEnvironment() || IsWineSafeWpfMode() ? ConvertUnixPathToWinePath("/bin/bash") : "/bin/bash",
                UseShellExecute = false,
                CreateNoWindow = true
            };
            startInfo.ArgumentList.Add("-lc");
            startInfo.ArgumentList.Add(script);
            using Process? process = Process.Start(startInfo);
            process?.WaitForExit(4000);
        } catch {
        }
    }

    private static bool AreSameModelStoragePath(string left, string right) {
        left = NormalizeModelsLocationForSettings(left);
        right = NormalizeModelsLocationForSettings(right);
        if (string.IsNullOrWhiteSpace(left) || string.IsNullOrWhiteSpace(right))
            return false;
        try {
            if (IsUnixAbsolutePath(left) || IsUnixAbsolutePath(right))
                return string.Equals(TrimUnixDirectory(left), TrimUnixDirectory(right), StringComparison.Ordinal);
            return string.Equals(
                Path.TrimEndingDirectorySeparator(Path.GetFullPath(left)),
                Path.TrimEndingDirectorySeparator(Path.GetFullPath(right)),
                StringComparison.OrdinalIgnoreCase);
        } catch {
            return string.Equals(left.TrimEnd('/', '\\'), right.TrimEnd('/', '\\'), StringComparison.OrdinalIgnoreCase);
        }
    }

    private void RestartLinuxNativeBackendFromWarning() {
        StopLinuxNativeBackendSupervisor();
        _linuxNativeBackendFailureCount = 0;
        ClearLinuxNativeBackendWarning();
        InitializeLinuxNativeBackendSupervisorIfNeeded();
        SetStatus("Restarting Linux native backend.");
    }

    private void OpenLinuxNativeBackendLog() {
        string path = FirstNonEmpty(_linuxNativeBackendLogPath, Environment.GetEnvironmentVariable("JACKLLM_NATIVE_BACKEND_LOG"), "/var/log/jackllm/native-backend.log");
        OpenPathOrUrl(ToCurrentProcessPath(path));
    }

    private void OpenModelsLocationFromWarning() {
        string location = Environment.GetEnvironmentVariable(ModelsLocationEnvironmentVariable) ?? GetEffectiveModelsLocation();
        OpenPathOrUrl(ToCurrentProcessPath(location));
    }

    private void OpenPathOrUrl(string pathOrUrl) {
        try {
            Process.Start(new ProcessStartInfo(pathOrUrl) { UseShellExecute = true });
        } catch (Exception ex) {
            AppendLog("Could not open " + TrimForDisplay(pathOrUrl, 120) + ": " + TrimForDisplay(ex.Message, 180));
        }
    }

    private async Task LoadDownloadedLlmRuntimeModelAsync(string modelPath) {
        try {
            string runtimeBaseUrl = GetExternalModelManagerRuntimeBaseUrl();
            if (string.IsNullOrWhiteSpace(runtimeBaseUrl)) {
                SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                SaveSettingsIfReady();
                await EnsureSelectedEmbeddedLlmRuntimeStartedAsync("downloaded-model-load");
                runtimeBaseUrl = _proxy.LocalModelRuntime.OpenAiBaseUrl;
            } else {
                SelectModelRuntimeProvider(RuntimeProviderLlmRuntime);
                ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                SaveSettingsIfReady();
            }

            string model = Path.GetFileName(modelPath);
            string endpoint = runtimeBaseUrl.TrimEnd('/') + "/api/v1/models/load";
            var payload = new {
                model,
                echo_load_config = true
            };

            using var client = CreateNetworkHttpClient(TimeSpan.FromMinutes(10));
            using var content = new System.Net.Http.StringContent(JsonSerializer.Serialize(payload), Encoding.UTF8, "application/json");
            using System.Net.Http.HttpResponseMessage response = await client.PostAsync(endpoint, content);
            string body = await response.Content.ReadAsStringAsync();
            string runtimeError = "";
            if (!response.IsSuccessStatusCode || TryReadLlmRuntimeError(body, out runtimeError)) {
                string detail = FirstNonEmpty(runtimeError, body);
                AppendLog("LlmRuntime model load failed: HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TrimForDisplay(detail, 260));
                SetStatus("Model downloaded, but load failed. Check diagnostics.");
                return;
            }

            AppendLog("Loaded LlmRuntime model: " + model);
            SetStatus("Loaded LlmRuntime model: " + model);
            string suggestedService = TryReadLlmRuntimeChatService(body);
            if (!string.IsNullOrWhiteSpace(suggestedService)) {
                await RefreshWpfChatServicesAsync();
                SelectWpfChatService(suggestedService);
                SaveSettingsIfReady();
                SetStatus("Loaded LlmRuntime model and selected chat service: " + suggestedService.Replace("_", " "));
            }
            await RefreshWpfChatModelsAsync(false);
        } catch (Exception ex) {
            AppendLog("LlmRuntime model load failed: " + TrimForDisplay(ex.Message, 260));
            SetStatus("Model downloaded, but load failed. Check diagnostics.");
        }
    }

    private static string TryReadLlmRuntimeChatService(string body) {
        if (string.IsNullOrWhiteSpace(body))
            return "";

        try {
            using JsonDocument document = JsonDocument.Parse(body);
            JsonElement root = document.RootElement;
            return FirstNonEmpty(
                GetJsonString(root, "chat_service", ""),
                GetJsonString(root, "chatService", ""),
                GetJsonString(root, "service", ""));
        } catch {
            return "";
        }
    }

    private static bool TryReadLlmRuntimeError(string body, out string error)
    {
        error = "";
        if (string.IsNullOrWhiteSpace(body))
            return false;

        try
        {
            using JsonDocument document = JsonDocument.Parse(body);
            JsonElement root = document.RootElement;
            if (!TryGetJsonProperty(root, "error", out JsonElement errorElement))
                return false;

            if (errorElement.ValueKind == JsonValueKind.String)
            {
                error = errorElement.GetString() ?? "";
                return !string.IsNullOrWhiteSpace(error);
            }

            if (errorElement.ValueKind == JsonValueKind.Object)
            {
                error = FirstNonEmpty(
                    GetJsonString(errorElement, "message", ""),
                    GetJsonString(errorElement, "code", ""),
                    errorElement.GetRawText());
                return !string.IsNullOrWhiteSpace(error);
            }
        }
        catch
        {
        }

        return false;
    }

    private void ApplyModelRuntimeProviderToProxy(string? provider, bool startEmbeddedRuntime) {
        string normalized = NormalizeModelRuntimeProvider(provider);
        _activeModelRuntimeProvider = normalized;
        _settings.ModelRuntimeProvider = normalized;
        if (normalized == RuntimeProviderLmStudio) {
            _proxy.LocalModelRuntime = _lmStudioRuntime;
            _proxy.EmergencyModelRuntimeFallbackEnabled = false;
            _proxy.EmergencyFallbackModelRuntime = null;
            ModelRuntimeProviderStatusText.Text = "LM Studio is the local provider. Embedded LlmRuntime is stopped.";
            _llmRuntimeCapabilityLine = "Embedded LlmRuntime stopped; JackONNX tools unavailable to chat runtime.";
            StopEmbeddedLlmRuntime();
            ScheduleWpfChatPromptReadyGlowRefresh();
            return;
        }

        HttpLmVsProxyModelRuntime? externalRuntime = GetExternalLlmRuntimeAdapter();
        if (externalRuntime != null) {
            _proxy.LocalModelRuntime = externalRuntime;
            _proxy.EmergencyModelRuntimeFallbackEnabled = false;
            _proxy.EmergencyFallbackModelRuntime = null;
            StopEmbeddedLlmRuntime();
            _llmRuntimeCapabilityLine = "External native LlmRuntime at " + externalRuntime.OpenAiBaseUrl + ".";
            ModelRuntimeProviderStatusText.Text = "External native LlmRuntime is the local provider at " + externalRuntime.OpenAiBaseUrl + ".";
            ScheduleWpfChatPromptReadyGlowRefresh();
            return;
        }

        IReadOnlyList<LlmToolDefinition> embeddedToolDefinitions = BuildEmbeddedLlmRuntimeToolDefinitions();
        if (_embeddedLlmRuntime == null) {
            string contentRoot = GetJackLlmContentRoot();
            var storage = GetModelStorageDirectoriesForCurrentProcess();
            _embeddedLlmRuntime = new LlmRuntimeModelRuntimeAdapter(
                new LlmRuntimeOptions {
                    ModelRoot = storage.ModelsDirectory,
                    CompleteModelRoot = storage.CompleteModelsDirectory,
                    IncludeLmStudioModels = true,
                    ToolRoot = Path.Combine(contentRoot, "Tools"),
                    AgentRoot = Path.Combine(contentRoot, "Agents"),
                    DefaultWorkspaceRoot = Environment.CurrentDirectory,
                    RuntimeConfigPath = Path.Combine(GetGuiUserDataRoot(), "LlmRuntime.config.json"),
                    CompatibilityConfigPath = Path.Combine(GetGuiUserDataRoot(), "LlmRuntime.compatibility.json"),
                    RestoreLoadedModelsOnStartup = false,
                    Port = LocalLmStudioProxyPort,
                    ServerName = "LlmRuntime"
                    ,RemoteVllmProfiles = _settings.RemoteVllmProfiles ?? []
                    ,SelectedRemoteVllmProfileId = _settings.SelectedRemoteVllmProfileId ?? ""
                },
                embeddedToolDefinitions,
                JackOnnxLlmRuntimeToolRegistration.CreateJackOnnxBuiltInTools(_jackOnnxRuntime, _jackOnnxToolOptions));
            _embeddedLlmRuntime.ServiceLog += OnEmbeddedLlmRuntimeServiceLog;
        }
        _proxy.LocalModelRuntime = _embeddedLlmRuntime;
        _proxy.EmergencyModelRuntimeFallbackEnabled = true;
        _proxy.EmergencyFallbackModelRuntime = _lmStudioRuntime;
        if (startEmbeddedRuntime)
            StartSelectedEmbeddedLlmRuntimeInBackground("provider-start");

        _llmRuntimeCapabilityLine = "JackONNX tools: " + _jackOnnxToolDefinitions.Count.ToString(CultureInfo.InvariantCulture) +
                                    " | SockJackDml tools: 7 | Total registered: " +
                                    embeddedToolDefinitions.Count.ToString(CultureInfo.InvariantCulture) + ".";
        ModelRuntimeProviderStatusText.Text = "Embedded LlmRuntime is the local provider at " + _embeddedLlmRuntime.OpenAiBaseUrl + ". " + _llmRuntimeCapabilityLine;
        ScheduleWpfChatPromptReadyGlowRefresh();
    }

    private void StartSelectedEmbeddedLlmRuntimeInBackground(string operation) {
        _ = EnsureSelectedEmbeddedLlmRuntimeStartedAsync(string.IsNullOrWhiteSpace(operation) ? "background" : operation);
    }

    private async Task EnsureSelectedEmbeddedLlmRuntimeStartedAsync(string operation, CancellationToken cancellationToken = default) {
        LlmRuntimeModelRuntimeAdapter? runtime = _embeddedLlmRuntime;
        if (runtime == null || !ReferenceEquals(_proxy.LocalModelRuntime, runtime))
            return;

        await TryInvokeOnUiAsync(() => {
            ModelRuntimeProviderStatusText.Text = "Starting embedded LlmRuntime at " + runtime.OpenAiBaseUrl + "...";
            _llmRuntimeCapabilityLine = string.IsNullOrWhiteSpace(_llmRuntimeCapabilityLine)
                ? "Starting embedded LlmRuntime."
                : _llmRuntimeCapabilityLine;
        }, "Embedded LlmRuntime startup status");

        try {
            await Task.Run(async () => await runtime.EnsureStartedAsync(cancellationToken).ConfigureAwait(false), cancellationToken).ConfigureAwait(false);
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            await TryInvokeOnUiAsync(() => AppendLog("LlmRuntime critical startup failure: " + TrimForDisplay(ex.Message, 220) + ". Checking LM Studio emergency fallback."), "Embedded LlmRuntime startup failure log");
            bool fallbackActivated = await _proxy.TryActivateEmergencyModelRuntimeFallbackAsync(operation, ex.Message, ex).ConfigureAwait(false);
            if (!fallbackActivated)
                throw;

            await TryInvokeOnUiAsync(() => {
                ModelRuntimeProviderStatusText.Text = "Embedded LlmRuntime critically failed; LM Studio emergency fallback is active. SocketJack.com was notified when possible.";
                _llmRuntimeCapabilityLine = "LlmRuntime failed; LM Studio emergency fallback active.";
                ScheduleWpfChatPromptReadyGlowRefresh();
            }, "Embedded LlmRuntime fallback status");
            return;
        }

        await TryInvokeOnUiAsync(() => {
            if (ReferenceEquals(_proxy.LocalModelRuntime, runtime))
                ModelRuntimeProviderStatusText.Text = "Embedded LlmRuntime is the local provider at " + runtime.OpenAiBaseUrl + ". " + _llmRuntimeCapabilityLine;
            ScheduleWpfChatPromptReadyGlowRefresh();
        }, "Embedded LlmRuntime started status");
    }

    private IReadOnlyList<LlmToolDefinition> BuildEmbeddedLlmRuntimeToolDefinitions() {
        var definitions = new List<LlmToolDefinition>();
        if (_jackOnnxToolDefinitions != null)
            definitions.AddRange(_jackOnnxToolDefinitions);

        foreach (LlmToolDefinition definition in BuildSockJackDmlLlmRuntimeToolDefinitions()) {
            if (!definitions.Any(existing => string.Equals(existing.Name, definition.Name, StringComparison.OrdinalIgnoreCase)))
                definitions.Add(definition);
        }

        return definitions;
    }

