                "Create or link a SockJackDml evidence packet to a plan, progress document, execution, or action result.",
                baseUrl + "/api/sockjackdml/tools/evidence/link",
                "{\"type\":\"object\",\"properties\":{\"evidencePacketId\":{\"type\":\"string\"},\"planId\":{\"type\":\"string\"},\"progressId\":{\"type\":\"string\"},\"executionId\":{\"type\":\"string\"},\"actionId\":{\"type\":\"string\"},\"title\":{\"type\":\"string\"},\"summary\":{\"type\":\"string\"},\"sourceKind\":{\"type\":\"string\"},\"sourceRef\":{\"type\":\"string\"},\"classification\":{\"type\":\"string\"},\"contentType\":{\"type\":\"string\"}},\"additionalProperties\":false}",
                LlmToolApprovalMode.AskOnDestructiveOperations,
                LlmToolPermissions.NetworkAccess | LlmToolPermissions.FileSystemWrite,
                600)
        };
    }

    private static LlmToolDefinition CreateSockJackDmlHttpToolDefinition(
        string id,
        string name,
        string description,
        string source,
        string inputSchema,
        LlmToolApprovalMode approvalMode,
        LlmToolPermissions permissions,
        int timeoutSeconds) {
        return new LlmToolDefinition {
            Id = id,
            Name = name,
            Description = description,
            Visibility = LlmToolVisibility.Proprietary,
            SourceType = LlmToolSourceType.Http,
            Source = source,
            Version = "0.1.0",
            Vendor = "JackOfFates",
            Tags = new List<string> { "sockjackdml", "workflow", "planning", "execution" },
            InputSchema = ParseSockJackDmlToolSchema(inputSchema),
            ApprovalMode = approvalMode,
            Permissions = permissions,
            TimeoutSeconds = timeoutSeconds
        };
    }

    private static JsonElement ParseSockJackDmlToolSchema(string schema) {
        using JsonDocument document = JsonDocument.Parse(schema);
        return document.RootElement.Clone();
    }

