    private void RefreshDetectedHostResourceFields(JackLLMSettings settings, LmStudioHostProbeResult? lmStudioProbe) {
        if (HostGpuNameTextBox == null)
            return;

        string gpuName = "";
        string gpuAvailability = "Waiting for LM Studio model metadata";
        if (TryQueryNvidiaGpu(out string detectedGpuName, out _, out _)) {
            gpuName = detectedGpuName;
        }

        if (lmStudioProbe != null) {
            _detectedHostAvailableModels = lmStudioProbe.AvailableModels;
            _detectedHostMaxTokens = lmStudioProbe.MaxTokens;
            _detectedHostModelCapabilitiesJson = lmStudioProbe.ModelCapabilities.Count == 0 ? "" : JsonSerializer.Serialize(lmStudioProbe.ModelCapabilities);
            RefreshModelBenchmarkItems(lmStudioProbe.ModelIds, lmStudioProbe.ModelCapabilities);
            if (!string.IsNullOrWhiteSpace(lmStudioProbe.GpuAvailable)) {
                gpuAvailability = lmStudioProbe.GpuAvailable;
                _detectedHostAvailableVram = lmStudioProbe.GpuAvailable;
            } else {
                gpuAvailability = "LM Studio model metadata unavailable";
                _detectedHostAvailableVram = "";
            }
        }

        if (string.IsNullOrWhiteSpace(_detectedHostToolsAllowed))
            _detectedHostToolsAllowed = BuildHostToolsAllowedText();

        HostGpuNameTextBox.Text = FirstNonEmpty(gpuName, settings.HostGpuName, "GPU not detected");
        HostGpuAvailableTextBox.Text = gpuAvailability;
        HostCpuNameTextBox.Text = FirstNonEmpty(GetCpuName(), settings.HostCpuName, Environment.ProcessorCount.ToString(CultureInfo.InvariantCulture) + " logical CPUs");
        HostCpuAvailableTextBox.Text = Environment.ProcessorCount.ToString(CultureInfo.InvariantCulture) + " logical processors";
        HostRamAvailableTextBox.Text = FirstNonEmpty(GetRamAvailableText(), settings.HostRamAvailable, "RAM unavailable");
        HostStorageAvailableTextBox.Text = FirstNonEmpty(GetStorageAvailableText(), settings.HostStorageAvailable, "Storage unavailable");
        HostAvailableResourcesTextBox.Text = BuildDetectedHostAvailableResourcesText(lmStudioProbe, settings);
        if (lmStudioProbe == null && _modelBenchmarkItems.Count == 0)
            LoadModelBenchmarksFromJson(settings.HostModelBenchmarksJson);

        PublishCurrentHostProfile(false);
    }

    private string BuildDetectedHostAvailableResourcesText(LmStudioHostProbeResult? lmStudioProbe, JackLLMSettings settings) {
        var lines = new List<string>();
        string models = FirstNonEmpty(lmStudioProbe?.AvailableModels, _detectedHostAvailableModels, "");
        if (!string.IsNullOrWhiteSpace(models))
            lines.Add("Available Models: " + models);
        else
            lines.Add("Available Models: LM Studio /v1/models not available");

        lines.Add("Tools Allowed: " + BuildHostToolsAllowedText());
        lines.Add("Available RAM: " + FirstNonEmpty(GetRamAvailableText(), settings.HostRamAvailable, "unavailable"));
        lines.Add("Available VRAM: " + FirstNonEmpty(lmStudioProbe?.GpuAvailable, _detectedHostAvailableVram, HostGpuAvailableTextBox?.Text, "unavailable"));
        lines.Add("GPU Model: " + FirstNonEmpty(HostGpuNameTextBox?.Text, settings.HostGpuName, "unavailable"));
        lines.Add("CPU Model: " + FirstNonEmpty(HostCpuNameTextBox?.Text, settings.HostCpuName, "unavailable"));

        long maxTokens = lmStudioProbe?.MaxTokens > 0 ? lmStudioProbe.MaxTokens : _detectedHostMaxTokens;
        lines.Add("Max Tokens: " + (maxTokens > 0 ? maxTokens.ToString(CultureInfo.InvariantCulture) : "LM Studio did not expose context/max token metadata"));
        lines.Add("Cost Factor: " + GetHostCostFactor().ToString("0.###", CultureInfo.InvariantCulture));
        lines.Add("Throughput: " + FormatHostThroughputTokensPerSecond(GetHostThroughputTokensPerSecond()));
        lines.Add("Session Storage Limit: " + FormatStorageLimitMegabytes(GetHostStorageLimitMegabytes()));

        if (lmStudioProbe?.MissingParameters.Count > 0)
            lines.Add("Needs LM Studio metadata: " + string.Join(", ", lmStudioProbe.MissingParameters));

        return string.Join(Environment.NewLine, lines);
    }

    private void PublishCurrentHostProfile(bool saveSettings) {
        if (!_uiReady || _isApplyingSettings)
            return;

        try {
            LmVsProxyServerProfile profile = BuildHostProfileFromUi();
            _proxy.ConfigureServerBrowserProfile(profile);
            if (!_suppressAutomaticLocalServerEntry && IsMyListingPublished())
                AddOrUpdateServerBrowserEntry(BuildLocalServerBrowserEntry(profile), false);
            if (saveSettings)
                SaveSettingsIfReady();
        } catch (Exception ex) {
            if (ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = "Host profile refresh failed: " + TrimForDisplay(ex.Message, 140);
        }
    }

    private void LoadServerBrowserItems(IEnumerable<ServerBrowserEntry>? entries) {
        _serverBrowserItems.Clear();
        if (entries != null && IsMyListingPublished()) {
            foreach (ServerBrowserEntry entry in entries) {
                if (entry == null)
                    continue;
                entry.Normalize();
                if (!entry.IsLocalHost)
                    continue;
                AddOrUpdateServerBrowserEntry(entry, false);
            }
        }

        if (_serverBrowserItems.Count == 0 && !_suppressAutomaticLocalServerEntry && IsMyListingPublished())
            AddOrUpdateServerBrowserEntry(BuildLocalServerBrowserEntry(), false);

        if (_serverBrowserItems.Count > 0 && ServerBrowserListBox.SelectedItem == null)
            ServerBrowserListBox.SelectedIndex = 0;
        RefreshMyListingsItems();
    }

