    private async Task LoadAutoPublishPreferenceAsync(bool interactive) {
        if (_autoPublishRefreshInProgress || !HasSocketJackAuthentication())
            return;

        _autoPublishRefreshInProgress = true;
        try {
            Uri uri = BuildSocketJackAuthUri("/api/lmvsproxy/auto-publish");
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, uri);
            AddSocketJackAuthHeaders(request);
            using System.Net.Http.HttpResponseMessage response = await client.SendAsync(request);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 160));

            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            bool autoPublish = GetJsonBool(document.RootElement, "autoPublish", true);
            SetAutoPublishCheckBoxSilently(autoPublish);
            SaveSettingsIfReady();
            if (autoPublish)
                await RunAutoPublishIfReadyAsync("auto-publish preference");
        } catch (Exception ex) {
            if (interactive && MasterServerStatusText != null)
                MasterServerStatusText.Text = "Auto-publish preference load failed: " + TrimForDisplay(ex.Message, 160);
        } finally {
            _autoPublishRefreshInProgress = false;
        }
    }

    private async Task SaveAutoPublishPreferenceAsync(bool enabled) {
        if (!HasSocketJackAuthentication())
            return;

        try {
            Uri uri = BuildSocketJackAuthUri("/api/lmvsproxy/auto-publish");
            string json = JsonSerializer.Serialize(new { autoPublish = enabled });
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, uri) {
                Content = content
            };
            AddSocketJackAuthHeaders(request);
            using System.Net.Http.HttpResponseMessage response = await client.SendAsync(request);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 160));
        } catch (Exception ex) {
            if (MasterServerStatusText != null)
                MasterServerStatusText.Text = "Auto-publish preference save failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

