    private void PulseElement(FrameworkElement element, Color color) {
        if (element == null)
            return;

        if (element.RenderTransform is not ScaleTransform scale) {
            scale = new ScaleTransform(1, 1);
            element.RenderTransform = scale;
            element.RenderTransformOrigin = new System.Windows.Point(0.5, 0.5);
        }

        var scaleAnimation = new DoubleAnimation(1.0, 1.045, TimeSpan.FromMilliseconds(520)) {
            AutoReverse = true,
            RepeatBehavior = new RepeatBehavior(4),
            EasingFunction = new SineEase { EasingMode = EasingMode.EaseInOut }
        };
        scale.BeginAnimation(ScaleTransform.ScaleXProperty, scaleAnimation);
        scale.BeginAnimation(ScaleTransform.ScaleYProperty, scaleAnimation);

        if (element.Effect is not DropShadowEffect glow) {
            glow = new DropShadowEffect {
                Color = color,
                BlurRadius = 20,
                ShadowDepth = 0,
                Opacity = 0
            };
            element.Effect = glow;
        }
        glow.Color = color;
        var glowAnimation = new DoubleAnimation(0.2, 0.95, TimeSpan.FromMilliseconds(520)) {
            AutoReverse = true,
            RepeatBehavior = new RepeatBehavior(4),
            EasingFunction = new SineEase { EasingMode = EasingMode.EaseInOut }
        };
        glow.BeginAnimation(DropShadowEffect.OpacityProperty, glowAnimation);
    }

    private void ShowElementToolTip(FrameworkElement target, string text, TimeSpan duration) {
        if (target == null)
            return;

        var tip = new System.Windows.Controls.ToolTip {
            Content = text,
            PlacementTarget = target,
            Placement = PlacementMode.Bottom,
            StaysOpen = true,
            IsOpen = true
        };
        var timer = new DispatcherTimer { Interval = duration <= TimeSpan.Zero ? TimeSpan.FromSeconds(4) : duration };
        timer.Tick += (_, _) => {
            timer.Stop();
            tip.IsOpen = false;
        };
        timer.Start();
    }

