    private void StartCoachmarkSequenceIfNeeded() {
        if (_settings.CoachmarkShowCount >= 3 || CoachmarkCanvas == null)
            return;

        _settings.CoachmarkShowCount++;
        SaveSettingsIfReady();
        _coachmarkIndex = -1;
        ShowNextCoachmark();
        _coachmarkTimer.Start();
    }

    private void ShowNextCoachmark() {
        if (WelcomeSplashOverlay?.Visibility == Visibility.Visible)
            return;

        var steps = new[] {
            new CoachmarkStep(StartStopButton, "Start JACK", "Starts the local HTTP, chat, FTP, and SocketJack surfaces."),
            new CoachmarkStep(SocketJackUserTextBox, "Sign in once", "Uploads, listings, storage, and paid usage are tied to this SocketJack.com username."),
            new CoachmarkStep(ModelsTabItem, "Models tab", "Browse, download, enable, and load local models here. If no models are installed yet, this is where you can download more."),
            new CoachmarkStep(OpenChatButton, "Web UI", "Opens the local web interface for shared sessions, uploads, downloads, and agent tools."),
            new CoachmarkStep(WpfChatAttachFileButton, "Attach session files", "Files are uploaded only after sign-in and count against the user's storage cap."),
            new CoachmarkStep(PublishedToggleButton, "Publish when ready", "Controls whether this PC appears on the master list for other users.")
        };

        for (int attempt = 0; attempt < steps.Length; attempt++) {
            _coachmarkIndex++;
            if (_coachmarkIndex >= steps.Length) {
                HideCoachmark();
                return;
            }

            CoachmarkStep step = steps[_coachmarkIndex];
            if (step.Target?.IsVisible != true || step.Target.ActualWidth <= 0 || step.Target.ActualHeight <= 0)
                continue;

            ShowCoachmark(step);
            return;
        }

        HideCoachmark();
    }

    private void ShowCoachmark(CoachmarkStep step) {
        if (CoachmarkCanvas == null || CoachmarkArrow == null || CoachmarkBubble == null)
            return;

        CoachmarkTitleText.Text = step.Title;
        CoachmarkBodyText.Text = step.Body;
        CoachmarkCanvas.Visibility = Visibility.Visible;
        PulseElement(step.Target, Color.FromRgb(64, 201, 162));

        System.Windows.Point center = step.Target.TranslatePoint(new System.Windows.Point(step.Target.ActualWidth, step.Target.ActualHeight / 2), CoachmarkCanvas);
        double canvasWidth = Math.Max(1, CoachmarkCanvas.ActualWidth);
        double bubbleWidth = CoachmarkBubble.Width > 0 ? CoachmarkBubble.Width : 280;
        double bubbleLeft = center.X + 46;
        if (bubbleLeft + bubbleWidth > canvasWidth - 16)
            bubbleLeft = Math.Max(16, center.X - bubbleWidth - 46);
        double bubbleTop = Math.Max(16, center.Y - 34);

        Canvas.SetLeft(CoachmarkArrow, Math.Max(8, center.X + 8));
        Canvas.SetTop(CoachmarkArrow, Math.Max(8, center.Y - 12));
        Canvas.SetLeft(CoachmarkBubble, bubbleLeft);
        Canvas.SetTop(CoachmarkBubble, bubbleTop);

        CoachmarkBubble.ToolTip = step.Body;
        CoachmarkArrowTransform.BeginAnimation(TranslateTransform.XProperty, new DoubleAnimation(-5, 5, TimeSpan.FromMilliseconds(620)) {
            AutoReverse = true,
            RepeatBehavior = RepeatBehavior.Forever,
            EasingFunction = new SineEase { EasingMode = EasingMode.EaseInOut }
        });
    }

    private void HideCoachmark() {
        _coachmarkTimer.Stop();
        if (CoachmarkArrowTransform != null)
            CoachmarkArrowTransform.BeginAnimation(TranslateTransform.XProperty, null);
        if (CoachmarkCanvas != null)
            CoachmarkCanvas.Visibility = Visibility.Collapsed;
    }

    private void MainWindow_PreviewKeyDown(object sender, System.Windows.Input.KeyEventArgs e) {
        if (e.Key == Key.Escape && WelcomeSplashOverlay?.Visibility == Visibility.Visible) {
            WelcomeSplashCloseButton_Click(sender, new RoutedEventArgs());
            e.Handled = true;
            return;
        }

        if (e.Key == Key.F5) {
            RefreshCurrentViewFromHotkey();
            e.Handled = true;
            return;
        }

        if (e.Key == Key.L && Keyboard.Modifiers.HasFlag(ModifierKeys.Control) && SocketJackUserTextBox != null) {
            SocketJackUserTextBox.Focus();
            SocketJackUserTextBox.SelectAll();
            e.Handled = true;
        }
    }

