    private void RefreshShellConfigurationPreview() {
        if (ShellPublishedTitleTextBox == null || ShellProxyUrlPreviewTextBox == null || ShellLocalApiTextBox == null)
            return;

        string title = FirstNonEmpty(HostServerNameTextBox?.Text, Environment.MachineName + " JACK");
        ShellPublishedTitleTextBox.Text = title;
        ShellProxyUrlPreviewTextBox.Text = BuildShellProxyPreviewUrl(title);
        ShellLocalApiTextBox.Text = "127.0.0.1:" + ChatServerPort.ToString(CultureInfo.InvariantCulture);
    }

    private string BuildShellProxyPreviewUrl(string title) {
        string baseUrl = BuildShellProxyPreviewBaseUrl();
        return baseUrl.TrimEnd('/') + "/proxy/" + Uri.EscapeDataString(NormalizeShellRouteTitle(title));
    }

    private string BuildShellProxyPreviewBaseUrl() {
        string value = ShellMasterServerTextBox?.Text ?? MasterServerTextBox?.Text ?? DefaultMasterServerUrl;
        if (string.IsNullOrWhiteSpace(value))
            value = DefaultMasterServerUrl;
        value = value.Trim();
        if (!value.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !value.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            value = IsLoopbackEndpoint(value) ? "http://" + value : "https://" + value;
        if (!Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
            return "https://socketjack.com";

        uri = UpgradePublicHttpUri(uri);

        if (string.Equals(uri.Host, "socketjack.com", StringComparison.OrdinalIgnoreCase))
            return "https://socketjack.com";

        string authority = uri.GetLeftPart(UriPartial.Authority);
        return authority;
    }

    private static string NormalizeShellRouteTitle(string value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "JACK";

        var builder = new StringBuilder(value.Length);
        bool lastWasSpace = false;
        foreach (char c in value) {
            if (char.IsLetterOrDigit(c) || c == '-' || c == '_' || c == '.') {
                builder.Append(c);
                lastWasSpace = false;
            } else if (char.IsWhiteSpace(c)) {
                if (!lastWasSpace && builder.Length > 0)
                    builder.Append(' ');
                lastWasSpace = true;
            }
        }

        string result = builder.ToString().Trim();
        return string.IsNullOrWhiteSpace(result) ? "JACK" : result;
    }

    private async Task<List<ShellRelayItem>> RefreshShellInstancesAsync() {
        try {
            Uri uri = BuildShellInstancesUri();
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(8));
            using System.Net.Http.HttpResponseMessage response = await client.GetAsync(uri);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + TrimForDisplay(body, 140));

            using JsonDocument document = JsonDocument.Parse(body);
            var items = new List<ShellRelayItem>();
            if (TryGetJsonProperty(document.RootElement, "instances", out JsonElement instances) && instances.ValueKind == JsonValueKind.Array) {
                foreach (JsonElement element in instances.EnumerateArray())
                    items.Add(ShellRelayItem.FromJson(element));
            }

            string selectedId = (ShellInstancesListBox.SelectedItem as ShellRelayItem)?.Id ?? "";
            _shellRelayItems.Clear();
            foreach (ShellRelayItem item in items)
                _shellRelayItems.Add(item);
            ShellInstancesListBox.SelectedItem = _shellRelayItems.FirstOrDefault(item => string.Equals(item.Id, selectedId, StringComparison.OrdinalIgnoreCase)) ??
                                                 _shellRelayItems.FirstOrDefault();
            ShellStatusText.Text = "Loaded " + _shellRelayItems.Count.ToString(CultureInfo.InvariantCulture) + " JACK shell route(s).";
            UpdateSelectedShellDebugText();
            return _shellRelayItems.ToList();
        } catch (Exception ex) {
            ShellStatusText.Text = "Shell refresh failed: " + TrimForDisplay(ex.Message, 180);
            AppendLog("Shell refresh failed: " + ex.Message);
            return _shellRelayItems.ToList();
        }
    }

    private Uri BuildShellInstancesUri() {
        return BuildShellApiUri("/api/shell/instances");
    }

    private Uri BuildShellProxyRequestUri() {
        return BuildShellApiUri("/api/shell/proxies");
    }

    private Uri BuildShellApiUri(string path) {
        string value = ShellMasterServerTextBox.Text;
        if (string.IsNullOrWhiteSpace(value))
            value = MasterServerTextBox.Text;
        if (string.IsNullOrWhiteSpace(value))
            value = DefaultMasterServerUrl;
        value = value.Trim();
        if (!value.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !value.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            value = IsLoopbackEndpoint(value) ? "http://" + value : "https://" + value;
        Uri uri = UpgradePublicHttpUri(new Uri(value.TrimEnd('/')));
        return new Uri(uri.GetLeftPart(UriPartial.Authority).TrimEnd('/') + path);
    }

    private string ResolveShellMasterHost() {
        Uri uri = BuildShellInstancesUri();
        return string.IsNullOrWhiteSpace(uri.Host) ? "127.0.0.1" : uri.Host;
    }

    private void ShellRelayClient_Log(object? sender, ReverseTcpRelayLogEventArgs e) {
        TryBeginOnUi(() => {
            ShellRelayItem? item = _shellRelayItems.FirstOrDefault(candidate => string.Equals(candidate.Id, e.InstanceId, StringComparison.OrdinalIgnoreCase));
            if (item != null) {
                item.AppendDebug(e.TimestampUtc.ToLocalTime().ToString("HH:mm:ss", CultureInfo.CurrentCulture) + " " + e.Message);
                item.ClientStatus = "Running";
            }
            UpdateSelectedShellDebugText();
        }, "Shell relay log update");
    }

