    private async Task DeleteServerBrowserItemAsync(ServerBrowserItem item) {
        if (item == null)
            return;

        ServerBrowserEntry entry = item.ToEntry();
        bool deletingCurrentLocal = IsCurrentLocalServerEntry(entry);
        bool shouldDeleteFromMaster = !string.IsNullOrWhiteSpace(entry.Endpoint) || !string.IsNullOrWhiteSpace(entry.ConnectHost) || !string.IsNullOrWhiteSpace(entry.Id);
        try {
            if (shouldDeleteFromMaster) {
                entry.PublishEnabled = false;
                entry.IsOnline = false;
                entry.LastStatus = "Deleted";
                entry.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
                Uri listUri = BuildMasterServerListUri(MasterServerTextBox.Text);
                using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
                await PostServerBrowserEntryToMasterServerAsync(client, listUri, entry, false, "delete");
            }
        } catch (Exception ex) {
            if (MasterServerStatusText != null)
                MasterServerStatusText.Text = "Master delete failed for " + entry.DisplayName + ": " + TrimForDisplay(ex.Message, 160);
            if (ex.Message.IndexOf("owner", StringComparison.OrdinalIgnoreCase) >= 0)
                return;
        }

        bool wasSelected = ReferenceEquals(ServerBrowserListBox?.SelectedItem, item);
        _serverBrowserItems.Remove(item);
        RefreshMyListingsItems();
        if (_uiReady)
            RefreshServerPickerItems();
        if (deletingCurrentLocal)
            _suppressAutomaticLocalServerEntry = true;
        SaveSettingsIfReady();
        if (ServerBrowserListBox != null && _serverBrowserItems.Count > 0) {
            if (wasSelected)
                ServerBrowserListBox.SelectedIndex = 0;
        } else if (ServerBrowserListBox != null) {
            ServerBrowserListBox.SelectedItem = null;
        }
        if (ServerBrowserStatusText != null)
            ServerBrowserStatusText.Text = "Deleted " + entry.DisplayName + " from My Listing.";
    }

    private bool IsCurrentLocalServerEntry(ServerBrowserEntry entry) {
        if (entry == null || !entry.IsLocalHost)
            return false;

        return string.Equals(
            BuildServerBrowserEntryKey(entry),
            BuildServerBrowserEntryKey(BuildLocalServerBrowserEntry()),
            StringComparison.OrdinalIgnoreCase);
    }

    private async Task CheckoutServerAsync(ServerBrowserItem item) {
        try {
            Uri checkoutUri = BuildServerBrowserCheckoutUri(item.ToEntry());
            var payload = new {
                clientReferenceId = "jackllm-" + Guid.NewGuid().ToString("N")
            };
            string json = JsonSerializer.Serialize(payload);
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(20));
            using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
            using System.Net.Http.HttpResponseMessage response = await client.PostAsync(checkoutUri, content);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("Checkout failed: HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + " " + TrimForDisplay(body, 160));

            using JsonDocument document = JsonDocument.Parse(body);
            JsonElement root = document.RootElement;
            string url = "";
            if (TryGetJsonProperty(root, "checkout", out JsonElement checkout))
                url = GetJsonString(checkout, "url", "");

            if (string.IsNullOrWhiteSpace(url))
                throw new InvalidOperationException("Checkout response did not include a URL.");

            Process.Start(new ProcessStartInfo(url) { UseShellExecute = true });
            ServerBrowserStatusText.Text = "Opened Stripe Checkout for " + item.DisplayName + ".";
        } catch (Exception ex) {
            ServerBrowserStatusText.Text = "Checkout failed: " + TrimForDisplay(ex.Message, 180);
        }
    }

