    private async void ServerBrowserPublishEnabled_Changed(object sender, RoutedEventArgs e) {
        if (sender is CheckBox checkBox && checkBox.DataContext is ServerBrowserItem item) {
            item.PublishEnabled = checkBox.IsChecked.GetValueOrDefault(false);
            bool requestedPublish = item.PublishEnabled;
            SaveSettingsIfReady();
            if (_uiReady && !_isApplyingSettings) {
                try {
                    await SetMasterServerWebsiteVisibilityAsync(item, requestedPublish);
                } catch (Exception ex) {
                    item.PublishEnabled = !requestedPublish;
                    SaveSettingsIfReady();
                    if (MasterServerStatusText != null)
                        MasterServerStatusText.Text = "Master visibility update failed: " + TrimForDisplay(ex.Message, 160);
                }
            }
            if (ServerBrowserStatusText != null) {
                ServerBrowserStatusText.Text = item.DisplayName + (item.PublishEnabled
                    ? " will be published when JACK runs."
                    : " was removed from the public master-list website.");
            }
            if (!requestedPublish) {
                if (item.IsLocalHost && PublishedToggleButton != null) {
                    _isApplyingSettings = true;
                    try {
                        PublishedToggleButton.IsChecked = false;
                        UpdatePublishedToggleContent();
                    } finally {
                        _isApplyingSettings = false;
                    }
                }
                _serverBrowserItems.Remove(item);
                SaveSettingsIfReady();
            }
        }
    }

    private async Task SetMasterServerWebsiteVisibilityAsync(ServerBrowserItem item, bool visible) {
        if (item == null || MasterServerTextBox == null)
            return;

        ServerBrowserEntry entry = item.ToEntry();
        bool hostingOnline = IsLocalHostingOnline() || entry.IsOnline;
        entry.PublishEnabled = visible;
        entry.IsOnline = visible && hostingOnline;
        entry.LastStatus = visible ? (hostingOnline ? "Hosting" : "Configured") : "Hidden from website";
        entry.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");

        Uri listUri = BuildMasterServerListUri(ShellMasterServerTextBox.Text);
        using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
        await PostServerBrowserEntryToMasterServerAsync(client, listUri, entry, visible, visible ? "online" : "unpublish");
        if (MasterServerStatusText != null)
            MasterServerStatusText.Text = visible
                ? "Published " + entry.DisplayName + " to the master-list website."
                : "Removed " + entry.DisplayName + " from the master-list website only.";
    }

