    private void BeginAutoFillPublicHostIfNeeded() {
        if (_publicIpResolveStarted || HostPublicHostTextBox == null)
            return;
        if (!string.IsNullOrWhiteSpace(HostPublicHostTextBox.Text))
            return;

        _publicIpResolveStarted = true;
        _ = ResolveExternalPublicHostAsync(overwriteExisting: false);
    }

    private async Task ResolveExternalPublicHostAsync(bool overwriteExisting) {
        if (HostPublicHostTextBox == null)
            return;

        string existing = (HostPublicHostTextBox.Text ?? "").Trim();
        if (!overwriteExisting && !string.IsNullOrWhiteSpace(existing))
            return;

        try {
            if (DetectPublicIpButton != null)
                DetectPublicIpButton.IsEnabled = false;
            if (HostPublicIpStatusText != null)
                HostPublicIpStatusText.Text = "Detecting external IP...";

            string address = await PublicIpResolver.GetExternalIpStringAsync();
            if (overwriteExisting || string.IsNullOrWhiteSpace(HostPublicHostTextBox.Text)) {
                HostPublicHostTextBox.Text = address;
                SaveSettingsIfReady();
                if (_uiReady && IsMyListingPublished()) {
                    LmVsProxyServerProfile profile = BuildHostProfileFromUi();
                    _proxy.ConfigureServerBrowserProfile(profile);
                    AddOrUpdateServerBrowserEntry(BuildLocalServerBrowserEntry(profile), false);
                }
                if (HostPublicIpStatusText != null)
                    HostPublicIpStatusText.Text = "External IP detected: " + address + ".";
            } else if (HostPublicIpStatusText != null) {
                HostPublicIpStatusText.Text = "External IP detected: " + address + ". Existing public host kept.";
            }
        } catch (Exception ex) {
            if (HostPublicIpStatusText != null)
                HostPublicIpStatusText.Text = "External IP detection failed: " + TrimForDisplay(ex.Message, 140);
        } finally {
            if (DetectPublicIpButton != null)
                DetectPublicIpButton.IsEnabled = true;
        }
    }

    private async Task RefreshMasterServerListIfDueAsync(bool force) {
        if (!_uiReady || MasterServerTextBox == null)
            return;
        if (!force && !IsServerListTabSelected())
            return;
        if (!force && DateTimeOffset.UtcNow - _lastMasterServerRefreshUtc < MasterServerRefreshInterval)
            return;

        await LoadMasterServerListAsync(force);
    }

    private async Task LoadMasterServerListAsync(bool force) {
        if (_masterServerRefreshInProgress)
            return;

        _masterServerRefreshInProgress = true;
        try {
            Uri listUri = BuildMasterServerListUri(MasterServerTextBox.Text);
            await RefreshMasterPricingAsync(force);
            if (MasterServerStatusText != null)
                MasterServerStatusText.Text = "Loading master list from " + listUri + "...";

            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(15));
            using System.Net.Http.HttpResponseMessage response = await client.GetAsync(listUri);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 160));

            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "[]" : body);
            int count = AddMasterServerEntriesFromJson(document.RootElement, listUri);
            _lastMasterServerRefreshUtc = DateTimeOffset.UtcNow;
            SaveSettingsIfReady();
            if (MasterServerStatusText != null)
                MasterServerStatusText.Text = "Loaded " + count + " server" + (count == 1 ? "" : "s") + " from the master list.";
            if (ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = "Master list refreshed.";
        } catch (Exception ex) {
            if (MasterServerStatusText != null)
                MasterServerStatusText.Text = "Master list load failed: " + TrimForDisplay(ex.Message, 180);
        } finally {
            _masterServerRefreshInProgress = false;
        }
    }

    private async Task RefreshMasterPricingAsync(bool force) {
        if (!_uiReady || MasterServerTextBox == null || _masterPricingRefreshInProgress)
            return;
        if (!force && _masterTokenUsdPerToken > 0 && DateTimeOffset.UtcNow - _lastMasterPricingRefreshUtc < TimeSpan.FromMinutes(5))
            return;

        _masterPricingRefreshInProgress = true;
        try {
            Uri uri = BuildMasterServerApiUri(MasterServerTextBox.Text, "/api/lmvsproxy/pricing");
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(8));
            using System.Net.Http.HttpResponseMessage response = await client.GetAsync(uri);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 160));

            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            JsonElement root = document.RootElement;
            _masterTokenUsdPerToken = Math.Max(0, GetJsonDouble(root, "tokenUsdPerToken", GetJsonDouble(root, "costPerTokenUsd", 0)));
            _masterServiceFeePercent = Math.Max(0, GetJsonDouble(root, "serviceFeePercent", GetJsonDouble(root, "feePercent", 0)));
            _masterPricingCurrency = FirstNonEmpty(GetJsonString(root, "currency", ""), "usd");
            _masterPricingSource = FirstNonEmpty(GetJsonString(root, "source", ""), "master-list pricing API");
            _lastMasterPricingRefreshUtc = DateTimeOffset.UtcNow;
            UpdateHostTokenCostBreakdown();
        } catch (Exception ex) {
            HostTokenCostRateText.Text = "Pricing API unavailable: " + TrimForDisplay(ex.Message, 140);
        } finally {
            _masterPricingRefreshInProgress = false;
        }
    }

