    private async Task AuthenticateSocketJackAccountAsync(bool register) {
        string username = SocketJackUserTextBox?.Text?.Trim() ?? "";
        string password = SocketJackPasswordBox?.Password ?? "";
        if (string.IsNullOrWhiteSpace(username)) {
            SetSocketJackAuthStatus("bad", "Enter your SocketJack.com username.");
            UpdateSocketJackAuthUi();
            return;
        }
        if (string.IsNullOrWhiteSpace(password)) {
            SetSocketJackAuthStatus("bad", "Enter your SocketJack.com password.");
            UpdateSocketJackAuthUi();
            return;
        }

        try {
            SetSocketJackAuthStatus("warn", register ? "Registering with SocketJack.com..." : "Signing in to SocketJack.com...");
            UpdateSocketJackAuthUi();
            Uri uri = BuildSocketJackAuthUri(register ? "/api/web-auth/register" : "/api/web-auth/login");
            var payload = new {
                username,
                password,
                remember = true
            };
            string json = JsonSerializer.Serialize(payload);
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(15));
            using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
            using System.Net.Http.HttpResponseMessage response = await client.PostAsync(uri, content);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 180));

            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            JsonElement root = document.RootElement;
            string token = GetJsonString(root, "accessToken", "");
            string returnedUserName = FirstNonEmpty(GetJsonString(root, "username", ""), username);
            if (string.IsNullOrWhiteSpace(token) || !GetJsonBool(root, "authenticated", true))
                throw new InvalidOperationException("SocketJack.com did not return an authenticated session token.");

            StoreSocketJackAuthSession(root, returnedUserName, token);
            _proxy.RememberChatSessionEncryptionSecret("webauth:" + returnedUserName.Trim().ToLowerInvariant(), password);
            _lastSocketJackAuthValidatedUtc = DateTimeOffset.UtcNow;
            SetSocketJackAuthStatus("good", "Session active. Published servers use this username.");
            UpdateSocketJackAuthUi();
            SaveSettingsIfReady();
            await LoadAutoPublishPreferenceAsync(false);
            PublishCurrentHostProfile(true);
            if (IsMyListingPublished() && IsLocalHostingOnline())
                await PublishEnabledHostsToMasterServerAsync(true, register ? "SocketJack registration" : "SocketJack login");
        } catch (Exception ex) {
            SetSocketJackAuthStatus("bad", "SocketJack login failed: " + TrimForDisplay(ex.Message, 180));
            UpdateSocketJackAuthUi();
        }
    }

    private Uri BuildSocketJackAuthUri(string path) {
        string endpoint = FirstNonEmpty(MasterServerTextBox?.Text, _settings?.MasterServerUrl, DefaultMasterServerUrl);
        return BuildMasterServerApiUri(endpoint, path);
    }

    private async Task LogoutSocketJackAccountAsync() {
        try {
            Uri uri = BuildSocketJackAuthUri("/api/web-auth/logout");
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, uri);
            AddSocketJackAuthHeaders(request);
            await client.SendAsync(request);
        } catch (Exception ex) {
            AppendLog("SocketJack logout request failed: " + TrimForDisplay(ex.Message, 160));
        } finally {
            _settings.SocketJackUserName = "";
            _settings.SocketJackAuthToken = "";
            _settings.SocketJackAuthExpiresUtc = "";
            _lastSocketJackAuthValidatedUtc = DateTimeOffset.MinValue;
            if (SocketJackUserTextBox != null)
                SocketJackUserTextBox.Text = "";
            if (SocketJackPasswordBox != null)
                SocketJackPasswordBox.Password = "";
            SetSocketJackAuthStatus("bad", "Signed out.");
            UpdateSocketJackAuthUi();
            SaveSettingsIfReady();
            PublishCurrentHostProfile(true);
        }
    }

    private async Task<bool> RefreshSocketJackSessionAsync(bool interactive) {
        if (_socketJackAuthRefreshInProgress)
            return HasSocketJackAuthentication();

        string username = GetSocketJackUserName();
        string token = GetSocketJackAuthToken();
        if (string.IsNullOrWhiteSpace(username) && string.IsNullOrWhiteSpace(token)) {
            SetSocketJackAuthStatus("bad", "Sign in to SocketJack.com before publishing this PC.");
            UpdateSocketJackAuthUi();
            return false;
        }

        try {
            _socketJackAuthRefreshInProgress = true;
            if (interactive) {
                SetSocketJackAuthStatus("warn", "Checking SocketJack.com session...");
                UpdateSocketJackAuthUi();
            }

            Uri uri = BuildSocketJackAuthUri("/api/web-auth/session");
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(12));
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, uri);
            AddSocketJackAuthHeaders(request);
            using System.Net.Http.HttpResponseMessage response = await client.SendAsync(request);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 180));

            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
            JsonElement root = document.RootElement;
            if (!GetJsonBool(root, "authenticated", false)) {
                _settings.SocketJackAuthToken = "";
                _settings.SocketJackAuthExpiresUtc = "";
                if (!string.IsNullOrWhiteSpace(username))
                    _settings.SocketJackUserName = username;
                SetSocketJackAuthStatus("bad", "Saved SocketJack session is no longer valid. Sign in again.");
                UpdateSocketJackAuthUi();
                SaveSettingsIfReady();
                return false;
            }

            if (!StoreSocketJackAuthSession(root, username, token))
                throw new InvalidOperationException("SocketJack.com session did not include a usable token.");

            _lastSocketJackAuthValidatedUtc = DateTimeOffset.UtcNow;
            bool restoredByKnownIp = GetJsonBool(root, "refreshedByKnownIp", false);
            SetSocketJackAuthStatus(
                "good",
                restoredByKnownIp
                    ? "Session restored from a known SocketJack.com IP."
                    : "Session active. Published servers use this username.");
            UpdateSocketJackAuthUi();
            SaveSettingsIfReady();
            await LoadAutoPublishPreferenceAsync(false);
            PublishCurrentHostProfile(true);
            return true;
        } catch (Exception ex) {
            bool hasSavedSession = HasSocketJackAuthentication();
            SetSocketJackAuthStatus(
                hasSavedSession ? "warn" : "bad",
                hasSavedSession
                    ? "Saved SocketJack session loaded; refresh failed: " + TrimForDisplay(ex.Message, 140)
                    : "SocketJack session refresh failed: " + TrimForDisplay(ex.Message, 140));
            UpdateSocketJackAuthUi();
            return hasSavedSession;
        } finally {
            _socketJackAuthRefreshInProgress = false;
        }
    }

    private bool StoreSocketJackAuthSession(JsonElement root, string fallbackUserName, string fallbackToken) {
        string returnedUserName = FirstNonEmpty(GetJsonString(root, "username", ""), fallbackUserName);
        string token = FirstNonEmpty(GetJsonString(root, "accessToken", ""), GetJsonString(root, "access_token", ""), fallbackToken);
        if (string.IsNullOrWhiteSpace(returnedUserName) || string.IsNullOrWhiteSpace(token))
            return false;

        _settings.SocketJackUserName = returnedUserName;
        _settings.SocketJackAuthToken = token;
        _settings.SocketJackAuthExpiresUtc = GetJsonString(root, "expiresUtc", _settings.SocketJackAuthExpiresUtc ?? "");
        if (SocketJackUserTextBox != null)
            SocketJackUserTextBox.Text = returnedUserName;
        if (SocketJackPasswordBox != null)
            SocketJackPasswordBox.Password = "";
        return true;
    }

    private void UpdateSocketJackAuthUi() {
        if (SocketJackAuthStatusText == null)
            return;

        bool signedIn = HasSocketJackAuthentication();
        string userName = FirstNonEmpty(GetSocketJackUserName(), "SocketJack user");
        string statusKind = _socketJackAuthStatusKind;
        string statusDetail = FirstNonEmpty(_socketJackAuthStatusDetail, signedIn ? "Session active." : "Sign in to SocketJack.com before publishing this PC.");
        if (signedIn && _lastSocketJackAuthValidatedUtc == DateTimeOffset.MinValue && statusKind.Equals("bad", StringComparison.OrdinalIgnoreCase)) {
            statusKind = "warn";
            statusDetail = "Saved session loaded; checking SocketJack.com...";
        }
        if (signedIn && IsSocketJackAuthExpired()) {
            statusKind = "warn";
            statusDetail = "Saved session needs refresh before publishing.";
        }

        if (SocketJackLoginFormPanel != null)
            SocketJackLoginFormPanel.Visibility = signedIn ? Visibility.Collapsed : Visibility.Visible;
        if (SocketJackSignedInPanel != null)
            SocketJackSignedInPanel.Visibility = signedIn ? Visibility.Visible : Visibility.Collapsed;
        if (SocketJackSignedInUserText != null)
            SocketJackSignedInUserText.Text = userName;
        if (SocketJackSignedInDetailText != null)
            SocketJackSignedInDetailText.Text = statusDetail;
        if (SocketJackAuthStatusDot != null)
            SocketJackAuthStatusDot.Background = BrushForSocketJackAuthStatus(statusKind);
        SocketJackAuthStatusText.Text = signedIn
            ? statusDetail
            : FirstNonEmpty(statusDetail, "Sign in to SocketJack.com before publishing this PC.");
        if (SocketJackLogoutButton != null)
            SocketJackLogoutButton.IsEnabled = signedIn;
        RefreshMyListingsItems();
    }

    private void SetSocketJackAuthStatus(string kind, string detail) {
        _socketJackAuthStatusKind = string.IsNullOrWhiteSpace(kind) ? "bad" : kind.Trim().ToLowerInvariant();
        _socketJackAuthStatusDetail = detail ?? "";
    }

    private static Brush BrushForSocketJackAuthStatus(string kind) {
        return kind.Equals("good", StringComparison.OrdinalIgnoreCase)
            ? new SolidColorBrush(Color.FromRgb(64, 224, 176))
            : kind.Equals("warn", StringComparison.OrdinalIgnoreCase)
                ? new SolidColorBrush(Color.FromRgb(250, 204, 21))
                : new SolidColorBrush(Color.FromRgb(248, 113, 113));
    }

    private bool HasSocketJackAuthentication() {
        return !string.IsNullOrWhiteSpace(GetSocketJackUserName()) &&
               !string.IsNullOrWhiteSpace(GetSocketJackAuthToken());
    }

    private string GetSocketJackUserName() {
        return FirstNonEmpty(_settings?.SocketJackUserName, SocketJackUserTextBox?.Text);
    }

    private string GetSocketJackAuthToken() {
        return _settings?.SocketJackAuthToken?.Trim() ?? "";
    }

    private bool IsSocketJackAuthExpired() {
        return TryGetSocketJackAuthExpiresUtc(out DateTimeOffset expires) && expires <= DateTimeOffset.UtcNow;
    }

    private bool ShouldRefreshSocketJackSession() {
        if (!HasSocketJackAuthentication())
            return true;
        if (_lastSocketJackAuthValidatedUtc == DateTimeOffset.MinValue ||
            DateTimeOffset.UtcNow - _lastSocketJackAuthValidatedUtc > TimeSpan.FromMinutes(5))
            return true;
        if (!TryGetSocketJackAuthExpiresUtc(out DateTimeOffset expires))
            return true;
        return expires <= DateTimeOffset.UtcNow.AddDays(7);
    }

    private bool TryGetSocketJackAuthExpiresUtc(out DateTimeOffset expires) {
        string value = _settings?.SocketJackAuthExpiresUtc ?? "";
        return DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out expires);
    }

    private async Task EnsureSocketJackAuthenticatedForPublishAsync() {
        if (ShouldRefreshSocketJackSession())
            await RefreshSocketJackSessionAsync(false);
        if (!HasSocketJackAuthentication())
            throw new InvalidOperationException("Sign in to SocketJack.com before publishing this PC.");
    }

    private void AddSocketJackAuthHeaders(System.Net.Http.HttpRequestMessage request) {
        string username = GetSocketJackUserName();
        if (!string.IsNullOrWhiteSpace(username)) {
            request.Headers.TryAddWithoutValidation("X-SocketJack-User", username);
            request.Headers.TryAddWithoutValidation("X-LmVsProxy-User", username);
        }

        string token = GetSocketJackAuthToken();
        if (string.IsNullOrWhiteSpace(token))
            return;

        request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", token);
        request.Headers.TryAddWithoutValidation("X-SocketJack-Auth", token);
        request.Headers.TryAddWithoutValidation("X-LmVsProxy-Auth", token);
    }

    private async Task ReportModelRuntimeFallbackToSocketJackAsync(LmVsProxyModelRuntimeFallbackReport report) {
        if (report == null)
            return;

        try {
            report.ReportedByUserName = FirstNonEmpty(report.ReportedByUserName, GetSocketJackUserName());
            report.SelectedProvider = GetSelectedModelRuntimeProvider();
            report.ClientName = "JackLLM Workstation";

            Uri uri = BuildShellApiUri("/api/socketjack/runtime-reports");
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(8));
            string json = JsonSerializer.Serialize(report);
            using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, uri) {
                Content = content
            };
            AddSocketJackAuthHeaders(request);
            using System.Net.Http.HttpResponseMessage response = await client.SendAsync(request);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode) {
                AppendLog("SocketJack.com runtime fallback report failed: HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TrimForDisplay(body, 220));
                return;
            }

            AppendLog("SocketJack.com runtime fallback report sent.");
        } catch (Exception ex) {
            AppendLog("SocketJack.com runtime fallback report failed: " + TrimForDisplay(ex.Message, 220));
        }
    }

    private async Task PublishEnabledHostsToMasterServerAsync(bool online, string reason) {
        try {
            bool shouldPublish = IsMyListingPublished();
            if (online && !shouldPublish) {
                PublishCurrentHostProfile(true);
                if (IsShellPublishingEnabled())
                    await StartShellModeAsync();
                if (MasterServerStatusText != null)
                    MasterServerStatusText.Text = _shellModeRunning
                        ? "My listing is unlisted; shell relay is online."
                        : "My listing is unlisted.";
                if (ServerBrowserStatusText != null)
                    ServerBrowserStatusText.Text = _shellModeRunning
                        ? _shellModeStatusText
                        : "My listing is unlisted. Enable Published to list it on the master server.";
                return;
            }

            if (online) {
                await EnsureSocketJackAuthenticatedForPublishAsync();
                PublishCurrentHostProfile(true);
                if (_shellModeRunning && _shellRelays.Count > 0) {
                    int poolSize = NormalizeShellAgentPoolSize(ParseInt(ShellAgentPoolTextBox?.Text ?? "8", 8));
                    ShellProxyRequestResult refreshed = await RequestShellProxyAsync(poolSize);
                    if (MasterServerStatusText != null)
                        MasterServerStatusText.Text = "Updated my shell listing with " + refreshed.Endpoint + " (" + reason + ").";
                    if (ServerBrowserStatusText != null)
                        ServerBrowserStatusText.Text = "Shell listing refresh complete (" + reason + ").";
                    return;
                }

                await StartShellModeAsync();
                if (!_shellModeRunning)
                    return;
                if (MasterServerStatusText != null)
                    MasterServerStatusText.Text = "Published my shell listing with " + BuildShellProxyRequestUri() + ".";
                if (ServerBrowserStatusText != null)
                    ServerBrowserStatusText.Text = "Shell listing publish complete (" + reason + ").";
                return;
            }

            await DeleteCurrentPublishedServerFromMasterServerAsync(reason);
            StopShellMode(updateCheckbox: false);
            RemoveCurrentLocalServerBrowserEntry();
            SaveSettingsIfReady();
            if (MasterServerStatusText != null)
                MasterServerStatusText.Text = "Removed my listing from the master list.";
            if (ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = "My listing was removed from the master list (" + reason + ").";
            return;
        } catch (Exception ex) {
            if (MasterServerStatusText != null)
                MasterServerStatusText.Text = "Master registration failed: " + TrimForDisplay(ex.Message, 180);
        }
    }

    private async Task DeleteCurrentPublishedServerFromMasterServerAsync(string reason) {
        if (!HasSocketJackAuthentication())
            return;

        var entries = new List<ServerBrowserEntry>();
        foreach (ServerBrowserItem item in _serverBrowserItems.Where(item => item.IsLocalHost).ToList())
            entries.Add(item.ToEntry());

        LmVsProxyServerProfile profile = BuildHostProfileFromUi();
        entries.Add(BuildLocalServerBrowserEntry(profile));
        entries.Add(BuildLocalServerBrowserEntry(profile, applyShellProxyEndpoint: false));

        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        List<ServerBrowserEntry> cleanupEntries = entries
            .Where(entry => entry != null)
            .Select(entry => {
                entry.Normalize();
                entry.OwnerUserName = GetSocketJackUserName();
                entry.PublishEnabled = false;
                entry.IsOnline = false;
                entry.LastStatus = "JACK stopped";
                entry.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
                return entry;
            })
            .Where(entry => seen.Add(BuildServerBrowserEntryKey(entry)))
            .ToList();

        if (cleanupEntries.Count == 0)
            return;

        Uri listUri = BuildMasterServerListUri(FirstNonEmpty(MasterServerTextBox?.Text, ShellMasterServerTextBox?.Text, DefaultMasterServerUrl));
        using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
        foreach (ServerBrowserEntry entry in cleanupEntries) {
            try {
                await PostServerBrowserEntryToMasterServerAsync(client, listUri, entry, false, "delete");
            } catch (Exception ex) when (ex.Message.IndexOf("not found", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                         ex.Message.IndexOf("404", StringComparison.OrdinalIgnoreCase) >= 0) {
                AppendLog("Master-list delete skipped (" + reason + "): " + TrimForDisplay(ex.Message, 120));
            }
        }
    }

    private static string BuildMyListingMasterPublishStatus(bool online, int published, Uri listUri, IReadOnlyCollection<string> errors, string delayedText) {
        string action = online ? "publish" : "mark offline";
        if (published > 0 && errors.Count == 0)
            return (online ? "Published my listing with " : "Marked my listing offline with ") + listUri + "." + delayedText;

        string prefix = published > 0
            ? (online ? "Published my listing with " : "Marked my listing offline with ") + listUri + "."
            : "Could not " + action + " my listing with " + listUri + ".";
        return prefix + (errors.Count == 0 ? "" : " Failed: " + string.Join("; ", errors.Take(3))) + delayedText;
    }

    private async Task FetchServerProfileAsync(string endpoint, bool select) {
        try {
            Uri profileUri = BuildServerBrowserProfileUri(endpoint);
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            using System.Net.Http.HttpResponseMessage response = await client.GetAsync(profileUri);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 160));

            using JsonDocument document = JsonDocument.Parse(body);
            ServerBrowserEntry entry = BuildServerBrowserEntryFromProfile(document.RootElement, profileUri);
            AddOrUpdateServerBrowserEntry(entry, select);
            SaveSettingsIfReady();
            ServerBrowserStatusText.Text = "Fetched " + entry.DisplayName + " from " + entry.Endpoint + ".";
        } catch (Exception ex) {
            ServerBrowserStatusText.Text = "Fetch failed: " + TrimForDisplay(ex.Message, 180);
        }
    }

    private void ApplySelectedServerToShellFields() {
        if (ServerBrowserListBox?.SelectedItem is not ServerBrowserItem item)
            return;

        ServerBrowserEntry entry = item.ToEntry();
        string target = string.IsNullOrWhiteSpace(entry.Endpoint)
            ? BuildServerBrowserEndpoint(entry.ConnectHost, entry.ChatPort <= 0 ? ChatServerPort : entry.ChatPort)
            : entry.Endpoint;
        BrowseServerEndpointTextBox.Text = target;
        ServerBrowserStatusText.Text = item.DisplayName + " selected.";
    }

