    private ServerBrowserEntry BuildLocalServerBrowserEntry() {
        return BuildLocalServerBrowserEntry(BuildHostProfileFromUi());
    }

    private ServerBrowserEntry BuildLocalServerBrowserEntry(LmVsProxyServerProfile profile) {
        return BuildLocalServerBrowserEntry(profile, applyShellProxyEndpoint: true);
    }

    private ServerBrowserEntry BuildLocalServerBrowserEntry(LmVsProxyServerProfile profile, bool applyShellProxyEndpoint) {
        string host = NormalizeServerBrowserHost(profile.PublicHost);
        if (string.IsNullOrWhiteSpace(host))
            host = "localhost";

        bool hostingOnline = IsLocalHostingOnline();
        var entry = new ServerBrowserEntry {
            Id = string.IsNullOrWhiteSpace(profile.ServerId) ? BuildShellProxyServerId(profile.ServerName) : profile.ServerId,
            OwnerUserName = profile.OwnerUserName,
            DisplayName = profile.ServerName,
            Endpoint = BuildServerBrowserEndpoint(host, ChatServerPort),
            ConnectHost = host,
            ProxyPort = ServerPort,
            ChatPort = ChatServerPort,
            LmStudioPort = LocalLmStudioProxyPort,
            FtpPort = FtpServerPort,
            CostFactor = profile.CostFactor,
            GpuName = profile.GpuName,
            GpuAvailable = profile.GpuAvailable,
            CpuName = profile.CpuName,
            CpuAvailable = profile.CpuAvailable,
            RamAvailable = profile.RamAvailable,
            StorageAvailable = profile.StorageAvailable,
            StorageLimitMegabytes = profile.StorageLimitMegabytes,
            AvailableResources = profile.AvailableResources,
            AvailableModels = profile.AvailableModels,
            ToolsAllowed = profile.ToolsAllowed,
            AvailableVram = profile.AvailableVram,
            MaxTokens = profile.MaxTokens,
            ModelCapabilitiesJson = profile.ModelCapabilitiesJson,
            ModelBenchmarksJson = profile.ModelBenchmarksJson,
            RequiresPayment = profile.RequiresPayment,
            StripePriceId = profile.StripePriceId,
            StripeAccount = profile.StripeAccount,
            StripeUnitAmountCents = profile.StripeUnitAmountCents,
            StripeCurrency = profile.StripeCurrency,
            StartedUtc = profile.StartedUtc,
            UptimeSeconds = profile.UptimeSeconds,
            UpdatedUtc = profile.UpdatedUtc,
            LastStatus = FirstNonEmpty(profile.StatusText, hostingOnline ? "Hosting" : "Configured"),
            PublishEnabled = IsMyListingPublished(),
            IsOnline = profile.IsOnline || hostingOnline,
            IsLocalHost = true
        };
        if (applyShellProxyEndpoint)
            ApplyShellProxyEndpointIfActive(entry);
        return entry;
    }

    private bool IsLocalHostingOnline() {
        return _proxy.IsListening ||
               (_proxy.IsChatServerCreated && _proxy.ChatServer != null && _proxy.ChatServer.IsListening) ||
               _shellModeRunning;
    }

    private string GetProxyStartedUtcText() {
        return _startedAt.HasValue ? _startedAt.Value.ToUniversalTime().ToString("O") : "";
    }

    private long GetProxyUptimeSeconds() {
        if (!_startedAt.HasValue)
            return 0;

        return Math.Max(0, (long)Math.Floor((DateTimeOffset.UtcNow - _startedAt.Value.ToUniversalTime()).TotalSeconds));
    }

    private string GetLocalHostingStatusText() {
        if (_shellModeRunning)
            return "JACK shell online";
        if (IsLocalHostingOnline())
            return "Hosting";
        return IsMyListingPublished() ? "Ready to publish" : "Configured";
    }

    private void ApplyShellProxyEndpointIfActive(ServerBrowserEntry entry) {
        if (entry == null || ShellEnabledCheckBox == null || !ShellEnabledCheckBox.IsChecked.GetValueOrDefault(false))
            return;

        string endpoint = FirstNonEmpty(
            ShellProxyUrlPreviewTextBox?.Text,
            _shellRelayItems.FirstOrDefault(item => item.Enabled && !string.IsNullOrWhiteSpace(item.Endpoint))?.Endpoint);
        if (string.IsNullOrWhiteSpace(endpoint))
            return;

        entry.Endpoint = endpoint;
        entry.ConnectHost = NormalizeServerBrowserHost(endpoint);
        int publicPort = TryReadPort(endpoint, ChatServerPort);
        entry.ChatPort = publicPort;
        entry.ProxyPort = publicPort;
        entry.LmStudioPort = publicPort;
        entry.LastStatus = _shellModeRunning ? "JACK shell online" : entry.LastStatus;
        entry.IsOnline = _shellModeRunning || entry.IsOnline;
    }

    private ServerBrowserEntry BuildServerBrowserEntryFromProfile(JsonElement root, Uri profileUri, bool fromMasterList = false) {
        JsonElement payload = root;
        JsonElement container = root;
        if (TryGetJsonProperty(payload, "profile", out JsonElement profile) && profile.ValueKind == JsonValueKind.Object)
            container = profile;

        JsonElement ports = default;
        JsonElement payment = default;
        JsonElement monitoring = default;
        JsonElement trust = default;
        JsonElement lease = default;
        if (TryGetJsonProperty(payload, "ports", out JsonElement rootPorts))
            ports = rootPorts;
        if (TryGetJsonProperty(payload, "payment", out JsonElement rootPayment))
            payment = rootPayment;
        if (TryGetJsonProperty(payload, "monitoring", out JsonElement rootMonitoring))
            monitoring = rootMonitoring;
        if (TryGetJsonProperty(payload, "trust", out JsonElement rootTrust))
            trust = rootTrust;
        if (TryGetJsonProperty(payload, "lease", out JsonElement rootLease))
            lease = rootLease;

        string endpoint = GetJsonString(container, "endpoint", GetJsonString(payload, "endpoint", ""));
        string connectHost = GetJsonString(container, "connectHost", GetJsonString(payload, "connectHost", ""));
        if (string.IsNullOrWhiteSpace(connectHost))
            connectHost = GetJsonString(container, "publicHost", GetJsonString(payload, "publicHost", ""));
        if (string.IsNullOrWhiteSpace(connectHost))
            connectHost = GetJsonString(container, "host", GetJsonString(payload, "host", ""));
        if (string.IsNullOrWhiteSpace(connectHost))
            connectHost = NormalizeServerBrowserHost(endpoint);
        if (string.IsNullOrWhiteSpace(connectHost))
            connectHost = profileUri.Host;

        int chatPort = (int)GetJsonLong(ports, "chat", GetJsonLong(container, "chatPort", GetJsonLong(payload, "chatPort", profileUri.Port > 0 ? profileUri.Port : ChatServerPort)));
        bool online = GetJsonBool(payload, "online", GetJsonBool(container, "online", !GetJsonBool(payload, "offline", GetJsonBool(container, "offline", false))));
        string status = FirstNonEmpty(
            GetJsonString(payload, "lastStatus", ""),
            GetJsonString(container, "lastStatus", ""),
            GetJsonString(payload, "statusText", ""),
            GetJsonString(container, "statusText", ""),
            GetJsonString(payload, "status", ""),
            GetJsonString(container, "status", ""),
            GetJsonString(payload, "state", ""),
            GetJsonString(container, "state", ""),
            online ? "Online" : "Offline");
        long storageLimitMegabytes = ReadStorageLimitMegabytes(container, payload);
        string id = FirstNonEmpty(
            GetJsonString(container, "serverId", ""),
            GetJsonString(payload, "serverId", ""),
            GetJsonString(container, "id", ""),
            GetJsonString(payload, "id", ""));
        string ownerUserName = FirstNonEmpty(
            GetJsonString(container, "ownerUserName", ""),
            GetJsonString(container, "ownerUsername", ""),
            GetJsonString(container, "serverOwnerUserName", ""),
            GetJsonString(container, "serverOwnerUsername", ""),
            GetJsonString(payload, "ownerUserName", ""),
            GetJsonString(payload, "ownerUsername", ""),
            GetJsonString(payload, "serverOwnerUserName", ""),
            GetJsonString(payload, "serverOwnerUsername", ""));
        string displayName = FirstNonEmpty(
            GetJsonString(container, "serverName", ""),
            GetJsonString(container, "displayName", ""),
            GetJsonString(container, "title", ""),
            GetJsonString(container, "name", ""),
            GetJsonString(payload, "serverName", ""),
            GetJsonString(payload, "displayName", ""),
            GetJsonString(payload, "title", ""),
            GetJsonString(payload, "name", ""),
            profileUri.Host);
        return new ServerBrowserEntry {
            Id = id,
            OwnerUserName = ownerUserName,
            DisplayName = displayName,
            Endpoint = string.IsNullOrWhiteSpace(endpoint) ? BuildServerBrowserEndpoint(connectHost, chatPort) : endpoint,
            ConnectHost = connectHost,
            ProxyPort = (int)GetJsonLong(ports, "vsProxy", GetJsonLong(container, "proxyPort", GetJsonLong(payload, "proxyPort", ServerPort))),
            ChatPort = chatPort,
            LmStudioPort = (int)GetJsonLong(ports, "lmStudio", GetJsonLong(container, "lmStudioPort", GetJsonLong(payload, "lmStudioPort", LocalLmStudioProxyPort))),
            FtpPort = (int)GetJsonLong(ports, "ftp", GetJsonLong(container, "ftpPort", GetJsonLong(payload, "ftpPort", FtpServerPort))),
            CostFactor = GetJsonDouble(container, "costFactor", 1),
            GpuName = GetJsonString(container, "gpuName", ""),
            GpuAvailable = GetJsonString(container, "gpuAvailable", ""),
            CpuName = GetJsonString(container, "cpuName", ""),
            CpuAvailable = GetJsonString(container, "cpuAvailable", ""),
            RamAvailable = GetJsonString(container, "ramAvailable", ""),
            StorageAvailable = GetJsonString(container, "storageAvailable", ""),
            StorageLimitMegabytes = storageLimitMegabytes,
            AvailableResources = GetJsonString(container, "availableResources", ""),
            AvailableModels = GetJsonString(container, "availableModels", GetJsonString(payload, "availableModels", "")),
            ToolsAllowed = GetJsonString(container, "toolsAllowed", GetJsonString(payload, "toolsAllowed", "")),
            AvailableVram = GetJsonString(container, "availableVram", GetJsonString(payload, "availableVram", "")),
            MaxTokens = GetJsonLong(container, "maxTokens", GetJsonLong(payload, "maxTokens", 0)),
            ModelCapabilitiesJson = FirstNonEmpty(GetJsonString(container, "modelCapabilitiesJson", ""), GetJsonString(payload, "modelCapabilitiesJson", ""), GetRawJsonProperty(container, "modelCapabilities"), GetRawJsonProperty(payload, "modelCapabilities")),
            ModelBenchmarksJson = FirstNonEmpty(GetJsonString(container, "modelBenchmarksJson", ""), GetJsonString(payload, "modelBenchmarksJson", ""), GetRawJsonProperty(container, "modelBenchmarks"), GetRawJsonProperty(payload, "modelBenchmarks")),
            RequiresPayment = GetJsonBool(container, "requiresPayment", GetJsonBool(payment, "requiresPayment", false)),
            StripePriceId = GetJsonString(payment, "stripePriceId", GetJsonString(container, "stripePriceId", "")),
            StripeAccount = GetJsonString(payment, "stripeAccount", GetJsonString(container, "stripeAccount", "")),
            StripeUnitAmountCents = GetJsonLong(payment, "unitAmountCents", GetJsonLong(container, "stripeUnitAmountCents", 0)),
            StripeCurrency = GetJsonString(payment, "currency", GetJsonString(container, "stripeCurrency", "usd")),
            PaymentStatus = FirstNonEmpty(GetJsonString(payment, "status", ""), GetJsonString(container, "paymentStatus", ""), GetJsonString(payload, "paymentStatus", "")),
            LeaseStatus = FirstNonEmpty(GetJsonString(lease, "status", ""), GetJsonString(container, "leaseStatus", ""), GetJsonString(payload, "leaseStatus", "")),
            LeaseId = FirstNonEmpty(GetJsonString(lease, "id", ""), GetJsonString(lease, "leaseId", ""), GetJsonString(container, "leaseId", ""), GetJsonString(payload, "leaseId", "")),
            LeaseExpiresUtc = FirstNonEmpty(GetJsonString(lease, "expiresUtc", ""), GetJsonString(container, "leaseExpiresUtc", ""), GetJsonString(payload, "leaseExpiresUtc", "")),
            HealthScore = GetJsonDouble(monitoring, "healthScore", GetJsonDouble(payload, "healthScore", GetJsonDouble(container, "healthScore", 0))),
            HealthTier = FirstNonEmpty(GetJsonString(monitoring, "healthTier", ""), GetJsonString(payload, "healthTier", ""), GetJsonString(container, "healthTier", "")),
            TrustTier = FirstNonEmpty(GetJsonString(trust, "riskTier", ""), GetJsonString(payload, "trustTier", ""), GetJsonString(container, "trustTier", "")),
            HostSuspended = GetJsonBool(trust, "hostSuspended", GetJsonBool(monitoring, "hostSuspended", GetJsonBool(payload, "hostSuspended", false))),
            StartedUtc = FirstNonEmpty(GetJsonString(payload, "startedUtc", ""), GetJsonString(container, "startedUtc", "")),
            UptimeSeconds = GetJsonLong(payload, "uptimeSeconds", GetJsonLong(container, "uptimeSeconds", 0)),
            UpdatedUtc = GetJsonString(container, "updatedUtc", DateTimeOffset.UtcNow.ToString("O")),
            LastStatus = status,
            PublishEnabled = !fromMasterList,
            IsOnline = online && !IsServerBrowserOfflineStatus(status),
            FromMasterList = fromMasterList
        };
    }

    private void AddOrUpdateServerBrowserEntry(ServerBrowserEntry entry, bool select) {
        if (entry == null)
            return;
        entry.Normalize();

        ServerBrowserItem? existing = entry.IsLocalHost
            ? _serverBrowserItems.FirstOrDefault(item => item.IsLocalHost) ??
              _serverBrowserItems.FirstOrDefault(item => item.Matches(entry))
            : _serverBrowserItems.FirstOrDefault(item => item.Matches(entry));

        if (existing != null && ShouldKeepCurrentLocalServerBrowserEntry(existing.ToEntry(), entry)) {
            RemoveDuplicateServerBrowserEntries(existing);
            if (select)
                ServerBrowserListBox.SelectedItem = existing;
            RefreshMyListingsItems();
            if (_uiReady)
                RefreshServerPickerItems();
            return;
        }

        ServerBrowserItem item;
        if (existing == null) {
            item = new ServerBrowserItem(entry);
            _serverBrowserItems.Add(item);
        } else {
            existing.UpdateFrom(entry);
            item = existing;
        }

        if (select)
            ServerBrowserListBox.SelectedItem = item;

        if (entry.IsLocalHost)
            RemoveDuplicateLocalServerBrowserEntries(item);
        RemoveDuplicateServerBrowserEntries(item);
        RefreshMyListingsItems();
        if (_uiReady)
            RefreshServerPickerItems();
    }

    private static bool ShouldKeepCurrentLocalServerBrowserEntry(ServerBrowserEntry current, ServerBrowserEntry incoming) {
        if (current == null || incoming == null || !current.IsLocalHost || !incoming.FromMasterList)
            return false;

        current.Normalize();
        incoming.Normalize();
        return IsSocketJackProxyServerBrowserEntry(current) &&
               !IsSocketJackProxyServerBrowserEntry(incoming);
    }

    private static bool IsSocketJackProxyServerBrowserEntry(ServerBrowserEntry entry) {
        return entry != null &&
               (TryCreateSocketJackProxyUri(entry.Endpoint) != null ||
                TryCreateSocketJackProxyUri(entry.ConnectHost) != null);
    }

    private void RemoveDuplicateServerBrowserEntries(ServerBrowserItem keep) {
        if (keep == null)
            return;

        string keepKey = BuildServerBrowserEntryKey(keep.ToEntry());
        if (string.IsNullOrWhiteSpace(keepKey))
            return;

        foreach (ServerBrowserItem duplicate in _serverBrowserItems
                     .Where(item => !ReferenceEquals(item, keep) &&
                                    string.Equals(BuildServerBrowserEntryKey(item.ToEntry()), keepKey, StringComparison.OrdinalIgnoreCase))
                     .ToList()) {
            _serverBrowserItems.Remove(duplicate);
        }
    }

    private void RemoveDuplicateLocalServerBrowserEntries(ServerBrowserItem keep) {
        foreach (ServerBrowserItem duplicate in _serverBrowserItems
                     .Where(item => !ReferenceEquals(item, keep) && item.IsLocalHost)
                     .ToList()) {
            _serverBrowserItems.Remove(duplicate);
        }
    }

    private int AddMasterServerEntriesFromJson(JsonElement root, Uri sourceUri) {
        List<ServerBrowserEntry> entries = ExtractMasterServerEntriesFromJson(root, sourceUri);
        return ApplyMasterServerEntries(entries);
    }

    private List<ServerBrowserEntry> ExtractMasterServerEntriesFromJson(JsonElement root, Uri sourceUri) {
        var entries = new List<ServerBrowserEntry>();
        if (root.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement element in root.EnumerateArray())
                entries.Add(BuildServerBrowserEntryFromProfile(element, sourceUri, true));
            return entries;
        }

        if (root.ValueKind == JsonValueKind.Object) {
            foreach (string propertyName in new[] { "servers", "items", "hosts", "data" }) {
                if (TryGetJsonProperty(root, propertyName, out JsonElement array) && array.ValueKind == JsonValueKind.Array) {
                    foreach (JsonElement element in array.EnumerateArray())
                        entries.Add(BuildServerBrowserEntryFromProfile(element, sourceUri, true));
                    return entries;
                }
            }

            if (TryGetJsonProperty(root, "profile", out _) ||
                TryGetJsonProperty(root, "serverName", out _) ||
                TryGetJsonProperty(root, "endpoint", out _)) {
                entries.Add(BuildServerBrowserEntryFromProfile(root, sourceUri, true));
            }
        }

        return entries;
    }

    private int ApplyMasterServerEntries(IReadOnlyCollection<ServerBrowserEntry> entries) {
        var onlineKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        var offlineKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

        foreach (ServerBrowserEntry entry in entries) {
            entry.FromMasterList = true;
            entry.Normalize();
            string key = BuildServerBrowserEntryKey(entry);
            if (string.IsNullOrWhiteSpace(key))
                continue;

            if (IsServerBrowserEntryOffline(entry)) {
                offlineKeys.Add(key);
                continue;
            }

            onlineKeys.Add(key);
            AddOrUpdateServerBrowserEntry(entry, false);
        }

        foreach (ServerBrowserItem item in _serverBrowserItems.ToList()) {
            ServerBrowserEntry entry = item.ToEntry();
            string key = BuildServerBrowserEntryKey(entry);
            if (!entry.FromMasterList || entry.IsLocalHost)
                continue;
            if (string.IsNullOrWhiteSpace(key) || offlineKeys.Contains(key) || !onlineKeys.Contains(key))
                _serverBrowserItems.Remove(item);
        }

        RefreshMyListingsItems();
        if (_serverBrowserItems.Count > 0 && ServerBrowserListBox.SelectedItem == null)
            ServerBrowserListBox.SelectedIndex = 0;

        if (_uiReady)
            RefreshServerPickerItems();
        return onlineKeys.Count;
    }

    private List<ServerBrowserEntry> GetEnabledMasterPublishEntries(bool online, List<string>? delayedEntries = null) {
        var entries = new List<ServerBrowserEntry>();
        DateTimeOffset now = DateTimeOffset.UtcNow;

        if (_suppressAutomaticLocalServerEntry)
            return entries;

        bool effectiveOnline = online || IsLocalHostingOnline();
        ServerBrowserEntry entry = BuildLocalServerBrowserEntry();
        entry.PublishEnabled = IsMyListingPublished() && effectiveOnline;
        entry.IsOnline = effectiveOnline;
        entry.LastStatus = effectiveOnline ? GetLocalHostingStatusText() : "Offline";
        entry.StartedUtc = GetProxyStartedUtcText();
        entry.UptimeSeconds = GetProxyUptimeSeconds();
        entry.UpdatedUtc = now.ToString("O");
        AddOrUpdateServerBrowserEntry(entry, false);

        if (effectiveOnline && entry.RequiresPayment && !HasCompletedModelBenchmark(entry.ModelBenchmarksJson)) {
            entry.IsOnline = false;
            entry.LastStatus = "Waiting for model benchmark";
            entry.UpdatedUtc = now.ToString("O");
            AddOrUpdateServerBrowserEntry(entry, false);
            delayedEntries?.Add(entry.DisplayName);
            return entries;
        }

        entries.Add(entry);
        return entries;
    }

    private void RemoveCurrentLocalServerBrowserEntry() {
        foreach (ServerBrowserItem item in _serverBrowserItems
                     .Where(item => item.IsLocalHost)
                     .ToList()) {
            _serverBrowserItems.Remove(item);
        }

        if (ServerBrowserListBox != null) {
            if (_serverBrowserItems.Count > 0)
                ServerBrowserListBox.SelectedIndex = 0;
            else
                ServerBrowserListBox.SelectedItem = null;
        }
        RefreshMyListingsItems();
        if (_uiReady)
            RefreshServerPickerItems();
    }

    private async Task<string> PostServerBrowserEntryToMasterServerAsync(System.Net.Http.HttpClient client, Uri listUri, ServerBrowserEntry entry, bool online, string? action = null) {
        if (online || HasSocketJackAuthentication())
            await EnsureSocketJackAuthenticatedForPublishAsync();
        LmVsProxyServerProfile profile = BuildServerProfileFromEntry(entry);
        int internetLatencyMs = online ? await MeasureMasterServerInternetLatencyMsAsync(client, listUri) : 0;
        var payload = new {
            action = string.IsNullOrWhiteSpace(action) ? (online ? "online" : "delete") : action,
            id = entry.Id,
            serverId = entry.Id,
            ownerUserName = FirstNonEmpty(entry.OwnerUserName, GetSocketJackUserName()),
            serverName = entry.DisplayName,
            displayName = entry.DisplayName,
            title = entry.DisplayName,
            name = entry.DisplayName,
            online,
            offline = !online,
            publishEnabled = online,
            visibleOnWebsite = online,
            profile,
            endpoint = entry.Endpoint,
            connectHost = entry.ConnectHost,
            status = entry.LastStatus,
            lastStatus = entry.LastStatus,
            internetLatencyMs,
            latencyMs = internetLatencyMs,
            startedUtc = entry.StartedUtc,
            uptimeSeconds = entry.UptimeSeconds,
            toolsAllowed = entry.ToolsAllowed,
            supportsTools = online,
            vsTools = online,
            modelCapabilitiesJson = entry.ModelCapabilitiesJson,
            modelCapabilities = ParseJsonArrayOrNull(entry.ModelCapabilitiesJson),
            modelBenchmarksJson = entry.ModelBenchmarksJson,
            modelBenchmarks = ParseJsonArrayOrNull(entry.ModelBenchmarksJson),
            benchmarkedModelCount = CountJsonArrayItems(entry.ModelBenchmarksJson),
            ports = new {
                vsProxy = entry.ProxyPort,
                chat = entry.ChatPort,
                lmStudio = entry.LmStudioPort,
                ftp = entry.FtpPort
            },
            payment = new {
                requiresPayment = entry.RequiresPayment,
                stripePriceId = entry.StripePriceId,
                stripeAccount = entry.StripeAccount,
                unitAmountCents = entry.StripeUnitAmountCents,
                currency = entry.StripeCurrency
            },
            registeredUtc = DateTimeOffset.UtcNow.ToString("O")
        };
        string json = JsonSerializer.Serialize(payload);
        using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
        using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, listUri) {
            Content = content
        };
        AddSocketJackAuthHeaders(request);
        request.Headers.TryAddWithoutValidation("X-LmVsProxy-Server-Owner", GetMasterServerOwnerToken());
        using System.Net.Http.HttpResponseMessage response = await client.SendAsync(request);
        string body = await response.Content.ReadAsStringAsync();
        if (!response.IsSuccessStatusCode)
            throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 160));

        return body;
    }

    private string GetMasterServerOwnerToken() {
        EnsureMasterServerOwnerToken(_settings);
        return _settings.MasterServerOwnerToken;
    }

    private static string HashMasterServerOwnerToken(string token) {
        token = (token ?? "").Trim();
        if (string.IsNullOrWhiteSpace(token))
            return "";
        return Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(token))).ToLowerInvariant();
    }

    private static LmVsProxyServerProfile BuildServerProfileFromEntry(ServerBrowserEntry entry) {
        var profile = new LmVsProxyServerProfile {
            ServerId = entry.Id,
            OwnerUserName = entry.OwnerUserName,
            ServerName = entry.DisplayName,
            PublicHost = entry.ConnectHost,
            CostFactor = entry.CostFactor,
            GpuName = entry.GpuName,
            GpuAvailable = entry.GpuAvailable,
            CpuName = entry.CpuName,
            CpuAvailable = entry.CpuAvailable,
            RamAvailable = entry.RamAvailable,
            StorageAvailable = entry.StorageAvailable,
            StorageLimitMegabytes = entry.StorageLimitMegabytes,
            AvailableResources = entry.AvailableResources,
            AvailableModels = entry.AvailableModels,
            ToolsAllowed = entry.ToolsAllowed,
            AvailableVram = entry.AvailableVram,
            MaxTokens = entry.MaxTokens,
            ModelCapabilitiesJson = entry.ModelCapabilitiesJson,
            ModelBenchmarksJson = entry.ModelBenchmarksJson,
            RequiresPayment = entry.RequiresPayment,
            StripePriceId = entry.StripePriceId,
            StripeAccount = entry.StripeAccount,
            StripeUnitAmountCents = entry.StripeUnitAmountCents,
            StripeCurrency = entry.StripeCurrency,
            StartedUtc = entry.StartedUtc,
            UptimeSeconds = entry.UptimeSeconds,
            IsOnline = entry.IsOnline,
            StatusText = entry.LastStatus,
            UpdatedUtc = entry.UpdatedUtc
        };
        profile.Normalize(entry.DisplayName);
        return profile;
    }

    private static string BuildServerBrowserEntryKey(ServerBrowserEntry entry) {
        if (entry == null)
            return "";

        ServerBrowserEntry normalized = entry.Clone();
        normalized.Normalize();
        if (!string.IsNullOrWhiteSpace(normalized.Id))
            return "id|" + normalized.Id.Trim().ToLowerInvariant();
        if (TryBuildSocketJackProxyServerBrowserKey(normalized, out string socketJackKey))
            return socketJackKey;

        string host = NormalizeServerBrowserHost(normalized.Endpoint);
        int port = normalized.ChatPort;
        if (Uri.TryCreate(normalized.Endpoint, UriKind.Absolute, out Uri? uri)) {
            if (!string.IsNullOrWhiteSpace(uri.Host))
                host = uri.Host;
            if (uri.Port > 0)
                port = uri.Port;
        }
        if (string.IsNullOrWhiteSpace(host))
            host = NormalizeServerBrowserHost(normalized.ConnectHost);
        if (string.IsNullOrWhiteSpace(host))
            return normalized.DisplayName ?? "";

        return host.ToLowerInvariant() + "|" + port.ToString(CultureInfo.InvariantCulture);
    }

    private static bool TryBuildSocketJackProxyServerBrowserKey(ServerBrowserEntry entry, out string key) {
        key = "";
        if (entry == null)
            return false;

        Uri? proxyUri = TryCreateSocketJackProxyUri(entry.Endpoint);
        if (proxyUri == null)
            proxyUri = TryCreateSocketJackProxyUri(entry.ConnectHost);
        if (proxyUri == null)
            return false;

        string route = NormalizeSocketJackProxyRoute(proxyUri);
        string owner = NormalizeServerBrowserKeyComponent(entry.OwnerUserName);
        string title = NormalizeServerBrowserKeyComponent(entry.DisplayName);
        string host = NormalizeServerBrowserKeyComponent(proxyUri.Host);
        string identity = FirstNonEmpty(route, title, NormalizeServerBrowserKeyComponent(entry.Id));
        if (string.IsNullOrWhiteSpace(host) || string.IsNullOrWhiteSpace(identity))
            return false;

        key = "socketjack-proxy|" + host + "|" + identity + "|owner:" + owner;
        return true;
    }

    private static Uri? TryCreateSocketJackProxyUri(string value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return null;
        if (!Uri.TryCreate(value, UriKind.Absolute, out Uri? uri) || string.IsNullOrWhiteSpace(uri.Host))
            return null;
        return IsSocketJackProxyUri(uri) ? uri : null;
    }

    private static bool IsSocketJackProxyUri(Uri uri) {
        string path = uri.AbsolutePath ?? "";
        if (path.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase))
            return true;
        return uri.Host.IndexOf("socketjack", StringComparison.OrdinalIgnoreCase) >= 0 &&
               path.IndexOf("/proxy/", StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static string NormalizeSocketJackProxyRoute(Uri uri) {
        string path = uri.AbsolutePath ?? "";
        int proxy = path.IndexOf("/proxy/", StringComparison.OrdinalIgnoreCase);
        if (proxy >= 0)
            path = path.Substring(proxy);
        path = Uri.UnescapeDataString(path).Trim().Trim('/');
        return NormalizeServerBrowserKeyComponent(path);
    }

    private static string NormalizeServerBrowserKeyComponent(string value) {
        return (value ?? "").Trim().ToLowerInvariant();
    }

    private static bool IsServerBrowserEntryOffline(ServerBrowserEntry entry) {
        if (entry == null)
            return true;
        return !entry.IsOnline || IsServerBrowserOfflineStatus(entry.LastStatus);
    }

    private static bool IsServerBrowserOfflineStatus(string status) {
        status = (status ?? "").Trim();
        if (status.Length == 0)
            return false;

        return status.IndexOf("offline", StringComparison.OrdinalIgnoreCase) >= 0 ||
               status.IndexOf("stopped", StringComparison.OrdinalIgnoreCase) >= 0 ||
               status.IndexOf("unavailable", StringComparison.OrdinalIgnoreCase) >= 0 ||
               status.IndexOf("failed", StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static Uri BuildMasterServerListUri(string endpoint) {
        endpoint = (endpoint ?? "").Trim();
        if (string.IsNullOrWhiteSpace(endpoint))
            endpoint = DefaultMasterServerUrl;
        if (!endpoint.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !endpoint.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            endpoint = IsLoopbackEndpoint(endpoint) ? "http://" + endpoint : "https://" + endpoint;
        if (!Uri.TryCreate(endpoint, UriKind.Absolute, out Uri? uri))
            throw new InvalidOperationException("Invalid master server endpoint.");
        uri = UpgradePublicHttpUri(uri);

        string path = uri.AbsolutePath ?? "";
        if (string.IsNullOrWhiteSpace(path) || path == "/") {
            string baseText = uri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
            return new Uri(baseText + "/api/lmvsproxy/servers");
        }

        return uri;
    }

    private static Uri BuildMasterServerApiUri(string endpoint, string path) {
        Uri listUri = BuildMasterServerListUri(endpoint);
        string authority = listUri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
        path = string.IsNullOrWhiteSpace(path) ? "/" : path.Trim();
        if (!path.StartsWith("/", StringComparison.Ordinal))
            path = "/" + path;
        return new Uri(authority + path);
    }

    private static async Task<int> MeasureMasterServerInternetLatencyMsAsync(System.Net.Http.HttpClient client, Uri endpoint) {
        if (client == null || endpoint == null)
            return 0;
        try {
            Uri healthUri = new(endpoint.GetLeftPart(UriPartial.Authority).TrimEnd('/') + "/healthz");
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, healthUri);
            request.Headers.TryAddWithoutValidation("Cache-Control", "no-store");
            Stopwatch stopwatch = Stopwatch.StartNew();
            using System.Net.Http.HttpResponseMessage response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
            stopwatch.Stop();
            return ClampLatencyMilliseconds(stopwatch.Elapsed);
        } catch {
            return 0;
        }
    }

    private static int ClampLatencyMilliseconds(TimeSpan elapsed) {
        if (elapsed <= TimeSpan.Zero)
            return 1;
        return (int)Math.Min(int.MaxValue, Math.Max(1, Math.Round(elapsed.TotalMilliseconds)));
    }

    private static Uri BuildServerBrowserProfileUri(string endpoint) {
        endpoint = (endpoint ?? "").Trim();
        if (string.IsNullOrWhiteSpace(endpoint))
            endpoint = "127.0.0.1:" + ChatServerPort;

        if (!endpoint.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !endpoint.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            endpoint = IsLoopbackEndpoint(endpoint) ? "http://" + endpoint : "https://" + endpoint;

        if (!Uri.TryCreate(endpoint, UriKind.Absolute, out Uri? uri))
            throw new InvalidOperationException("Invalid server endpoint.");
        uri = UpgradePublicHttpUri(uri);

        string path = uri.AbsolutePath ?? "";
        if (!path.EndsWith("/api/server-browser/profile", StringComparison.OrdinalIgnoreCase)) {
            string baseText = uri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
            uri = new Uri(baseText + "/api/server-browser/profile");
        }

        return uri;
    }

    private static Uri BuildServerBrowserCheckoutUri(ServerBrowserEntry entry) {
        string endpoint = entry?.Endpoint ?? "";
        Uri profileUri = BuildServerBrowserProfileUri(endpoint);
        string baseText = profileUri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
        return new Uri(baseText + "/api/server-browser/checkout");
    }

    private static string BuildServerBrowserEndpoint(string host, int port) {
        host = string.IsNullOrWhiteSpace(host) ? "localhost" : host.Trim();
        string bracketedHost = host.Contains(":") && !host.StartsWith("[", StringComparison.Ordinal)
            ? "[" + host + "]"
            : host;
        int safePort = port > 0 && port <= 65535 ? port : ChatServerPort;
        string portPart = safePort == 80 || safePort == 443 ? "" : ":" + safePort.ToString(CultureInfo.InvariantCulture);
        return "https://" + bracketedHost + portPart;
    }

    private static bool IsLoopbackEndpoint(string endpoint) {
        string host = NormalizeServerBrowserHost(endpoint);
        return IsLoopbackHost(host);
    }

    private static bool IsLoopbackHost(string host) {
        host = (host ?? "").Trim();
        return string.Equals(host, "localhost", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(host, "127.0.0.1", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(host, "::1", StringComparison.OrdinalIgnoreCase) ||
               host.StartsWith("127.", StringComparison.OrdinalIgnoreCase);
    }

    private static System.Net.Http.HttpClient CreateNetworkHttpClient(TimeSpan timeout) {
        var handler = new SocketsHttpHandler {
            AutomaticDecompression = DecompressionMethods.GZip | DecompressionMethods.Deflate | DecompressionMethods.Brotli,
            PooledConnectionLifetime = TimeSpan.FromMinutes(5)
        };
        handler.SslOptions.EnabledSslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13;

        return new System.Net.Http.HttpClient(handler) {
            Timeout = timeout <= TimeSpan.Zero ? TimeSpan.FromSeconds(30) : timeout
        };
    }

    private async Task ProbeCompanionStatusAsync(bool force = false) {
        if (_companionProbeInFlight)
            return;
        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (!force && now - _lastCompanionProbeUtc < TimeSpan.FromSeconds(6))
            return;

        _companionProbeInFlight = true;
        _lastCompanionProbeUtc = now;
        try {
            string endpoint = await ResolveCompanionEndpointAsync();
            _companionStatusText = string.IsNullOrWhiteSpace(endpoint) ? "Not running" : "Running";
            _companionEndpointText = string.IsNullOrWhiteSpace(endpoint)
                ? "Workspace: :80 or :8091"
                : endpoint.TrimEnd('/') + "/Workspace";
            RefreshServicesPanel();
        } finally {
            _companionProbeInFlight = false;
        }
    }

    private static async Task<string> ResolveCompanionEndpointAsync() {
        foreach (string endpoint in CompanionCandidateEndpoints()) {
            try {
                using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(2));
                using HttpResponseMessage response = await client.GetAsync(endpoint.TrimEnd('/') + "/api/workspace");
                if (response.IsSuccessStatusCode)
                    return endpoint.TrimEnd('/');
            } catch {
            }
        }

        return "";
    }

    private static IEnumerable<string> CompanionCandidateEndpoints() {
        yield return "http://localhost";
        yield return "http://localhost:" + CompanionFallbackPort.ToString(CultureInfo.InvariantCulture);
    }

    private static string? FindCompanionExecutablePath() {
        string baseDir = AppContext.BaseDirectory;
        string[] candidates = {
            Path.Combine(baseDir, "Companion", "JackLLMCompanion.exe"),
            Path.Combine(baseDir, "JackLLMCompanion.exe"),
            Path.GetFullPath(Path.Combine(baseDir, "..", "..", "..", "..", "JackLLMCompanion", "bin", "Debug", "net8.0-windows7.0", "JackLLMCompanion.exe")),
            Path.GetFullPath(Path.Combine(baseDir, "..", "..", "..", "..", "JackLLMCompanion", "bin", "Release", "net8.0-windows7.0", "JackLLMCompanion.exe"))
        };

        return candidates.FirstOrDefault(File.Exists);
    }

    private static Uri UpgradePublicHttpUri(Uri uri) {
        if (uri == null)
            throw new ArgumentNullException(nameof(uri));
        if (!string.Equals(uri.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) || IsLoopbackHost(uri.Host))
            return uri;
        if (!uri.IsDefaultPort && uri.Port != 80)
            return uri;

        var builder = new UriBuilder(uri) { Scheme = Uri.UriSchemeHttps };
        if (builder.Port == 80)
            builder.Port = -1;
        return builder.Uri;
    }

    private static string NormalizeServerBrowserHost(string value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "";

        if (Uri.TryCreate(value, UriKind.Absolute, out Uri? uri) && !string.IsNullOrWhiteSpace(uri.Host))
            return uri.Host;

        if (value.StartsWith("[", StringComparison.Ordinal)) {
            int close = value.IndexOf(']');
            if (close > 1)
                return value.Substring(1, close - 1).Trim();
        }

        int slash = value.IndexOf('/');
        if (slash >= 0)
            value = value.Substring(0, slash);

        int colon = value.LastIndexOf(':');
        if (colon > 0 && value.IndexOf(':') == colon)
            value = value.Substring(0, colon);

        return value.Trim();
    }

    private static bool TryGetJsonProperty(JsonElement element, string name, out JsonElement value) {
        value = default;
        if (element.ValueKind != JsonValueKind.Object)
            return false;

        if (element.TryGetProperty(name, out value))
            return true;

        foreach (JsonProperty property in element.EnumerateObject()) {
            if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase)) {
                value = property.Value;
                return true;
            }
        }

        return false;
    }

    private static string GetJsonString(JsonElement element, string name, string fallback) {
        if (!TryGetJsonProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.String)
            return value.GetString() ?? fallback;
        if (value.ValueKind == JsonValueKind.Number || value.ValueKind == JsonValueKind.True || value.ValueKind == JsonValueKind.False)
            return value.ToString();
        return fallback;
    }

    private static long ReadStorageLimitMegabytes(JsonElement container, JsonElement payload) {
        long megabytes = GetJsonLong(container, "storageLimitMegabytes", GetJsonLong(payload, "storageLimitMegabytes", 0));
        if (megabytes > 0)
            return ClampHostStorageLimitMegabytes(megabytes);

        long bytes = GetJsonLong(container, "storageLimitBytes", GetJsonLong(payload, "storageLimitBytes", 0));
        if (bytes > 0)
            return ClampHostStorageLimitMegabytes((long)Math.Ceiling(bytes / (1024.0 * 1024.0)));

        return DefaultHostStorageLimitMegabytes;
    }

    private static string GetRawJsonProperty(JsonElement element, string name) {
        if (!TryGetJsonProperty(element, name, out JsonElement value))
            return "";
        return value.ValueKind == JsonValueKind.Undefined || value.ValueKind == JsonValueKind.Null
            ? ""
            : value.GetRawText();
    }

    private static JsonElement? ParseJsonArrayOrNull(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return null;
        try {
            using JsonDocument document = JsonDocument.Parse(json);
            return document.RootElement.ValueKind == JsonValueKind.Array ? document.RootElement.Clone() : null;
        } catch {
            return null;
        }
    }

    private static int CountJsonArrayItems(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return 0;
        try {
            using JsonDocument document = JsonDocument.Parse(json);
            return document.RootElement.ValueKind == JsonValueKind.Array ? document.RootElement.GetArrayLength() : 0;
        } catch {
            return 0;
        }
    }

    private static double GetJsonDouble(JsonElement element, string name, double fallback) {
        if (!TryGetJsonProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetDouble(out double number))
            return number;
        if (value.ValueKind == JsonValueKind.String && double.TryParse(value.GetString(), NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed))
            return parsed;
        return fallback;
    }

    private static long GetJsonLong(JsonElement element, string name, long fallback) {
        if (!TryGetJsonProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetInt64(out long number))
            return number;
        if (value.ValueKind == JsonValueKind.String && long.TryParse(value.GetString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out long parsed))
            return parsed;
        return fallback;
    }

    private static int GetJsonInt(JsonElement element, string name, int fallback) {
        long value = GetJsonLong(element, name, fallback);
        if (value < int.MinValue)
            return int.MinValue;
        if (value > int.MaxValue)
            return int.MaxValue;
        return (int)value;
    }

    private static bool GetJsonBool(JsonElement element, string name, bool fallback) {
        if (!TryGetJsonProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.True)
            return true;
        if (value.ValueKind == JsonValueKind.False)
            return false;
        if (value.ValueKind == JsonValueKind.String && bool.TryParse(value.GetString(), out bool parsed))
            return parsed;
        return fallback;
    }

    private void ApplyWindowSettings(JackLLMSettings settings) {
        Rect workArea = SystemParameters.WorkArea;
        double maxWidth = Math.Max(MinWidth, workArea.Width - 32);
        double maxHeight = Math.Max(MinHeight, workArea.Height - 32);
        double targetWidth = settings.WindowWidth >= MinWidth ? settings.WindowWidth : Width;
        double targetHeight = settings.WindowHeight >= MinHeight ? settings.WindowHeight : Height;

        Width = Math.Min(Math.Max(MinWidth, targetWidth), maxWidth);
        Height = Math.Min(Math.Max(MinHeight, targetHeight), maxHeight);

        if (settings.WindowLeft.HasValue && settings.WindowTop.HasValue) {
            WindowStartupLocation = WindowStartupLocation.Manual;
            Left = Math.Min(Math.Max(workArea.Left + 8, settings.WindowLeft.Value), Math.Max(workArea.Left + 8, workArea.Right - Width - 8));
            Top = Math.Min(Math.Max(workArea.Top + 8, settings.WindowTop.Value), Math.Max(workArea.Top + 8, workArea.Bottom - Height - 8));
        } else {
            WindowStartupLocation = WindowStartupLocation.Manual;
            Left = workArea.Left + Math.Max(8, (workArea.Width - Width) / 2);
            Top = workArea.Top + Math.Max(8, (workArea.Height - Height) / 2);
        }
        if (settings.WindowMaximized)
            WindowState = WindowState.Maximized;
    }

    private void SaveSettingsIfReady() {
        if (!_uiReady || _isApplyingSettings)
            return;

        SaveSettings();
    }

    private void SaveSettings() {
        try {
            _settings = CaptureSettings();
            PersistSettingsToDisk(_settings, applyToServices: true);
            if (_uiReady && SettingsStatusText != null)
                SettingsStatusText.Text = "Saved settings to user profile.";
        } catch (Exception ex) {
            if (_uiReady && SettingsStatusText != null)
                SettingsStatusText.Text = "Settings save failed: " + TrimForDisplay(ex.Message, 120);
        }
    }

    private void PersistSettingsToDisk(JackLLMSettings settings, bool applyToServices) {
        Directory.CreateDirectory(Path.GetDirectoryName(_settingsPath) ?? AppContext.BaseDirectory);
        var options = new JsonSerializerOptions { WriteIndented = true };
        File.WriteAllText(_settingsPath, JsonSerializer.Serialize(settings, options));
        if (!applyToServices)
            return;

        ApplyWindowsStartupRegistration(settings);
        ApplyModelsLocationEnvironment(settings);
        WriteModelsLocationEnvironmentHint(settings);
        ApplyStorageSettingsToProxy(settings);
        ApplyOpenRegistrationSettingToProxy(settings);
        ApplyTokenRateRequestPolicyToProxy(settings);
        ApplyChatThroughputSettingToProxy(settings);
        ApplyWebChatModelLoadApiSettingToProxy(settings);
        ApplyServerBrowserProfileToProxy(settings);
    }

