    private void ApplyWindowsStartupRegistration(JackLLMSettings settings) {
        using RegistryKey? runKey = Registry.CurrentUser.OpenSubKey(WindowsStartupRegistryPath, writable: true);
        if (runKey == null)
            return;

        if (settings.WindowsStartupEnabled) {
            string executablePath = Environment.ProcessPath ?? "";
            if (string.IsNullOrWhiteSpace(executablePath)) {
                try {
                    executablePath = Process.GetCurrentProcess().MainModule?.FileName ?? "";
                } catch {
                    executablePath = "";
                }
            }

            if (string.IsNullOrWhiteSpace(executablePath))
                return;

            string command = "\"" + executablePath + "\"";
            if (settings.HideToTrayOnStartup)
                command += " --tray";
            runKey.SetValue(WindowsStartupValueName, command, RegistryValueKind.String);
            runKey.DeleteValue(LegacyWindowsStartupValueName, throwOnMissingValue: false);
        } else {
            runKey.DeleteValue(WindowsStartupValueName, throwOnMissingValue: false);
            runKey.DeleteValue(LegacyWindowsStartupValueName, throwOnMissingValue: false);
        }
    }

    private bool EnsureTrayIcon() {
        if (_trayIcon != null)
            return true;

        Forms.ContextMenuStrip? menu = TryCreateTrayContextMenu();

        try {
            string? executablePath = Environment.ProcessPath;
            _trayIconImage = !string.IsNullOrWhiteSpace(executablePath)
                ? System.Drawing.Icon.ExtractAssociatedIcon(executablePath)
                : null;
            _trayIcon = new Forms.NotifyIcon {
                Text = BuildTrayIconText(),
                Icon = _trayIconImage ?? System.Drawing.SystemIcons.Application,
                ContextMenuStrip = menu,
                Visible = true
            };
        } catch (Exception ex) when (IsTrayPlatformException(ex)) {
            AppendLog("Tray icon unavailable: " + TrimForDisplay(ex.GetBaseException().Message, 180));
            _trayMenu?.Dispose();
            _trayMenu = null;
            _trayIconImage?.Dispose();
            _trayIconImage = null;
            return false;
        }

        _trayIcon.DoubleClick += (_, _) => TryBeginOnUi(ShowFromTray, "Tray double-click");
        _trayIcon.MouseMove += (_, _) => TryBeginOnUi(ScheduleTrayStatusTooltip, "Tray tooltip scheduling");
        _trayIcon.MouseClick += (_, e) => TryBeginOnUi(() => {
            HideTrayStatusTooltip();
            if (_trayMenu == null && e.Button == Forms.MouseButtons.Right)
                ShowWpfTrayContextMenu();
        }, "Tray mouse click");
        return true;
    }

    private Forms.ContextMenuStrip? TryCreateTrayContextMenu() {
        if (!CanUseWinFormsTrayContextMenu()) {
            LogTrayContextMenuUnavailable("WinForms tray context menu unavailable in this environment.");
            return null;
        }

        Forms.ContextMenuStrip? menu = null;
        try {
            menu = new Forms.ContextMenuStrip {
                ForeColor = System.Drawing.Color.Black,
                ShowItemToolTips = true
            };
            menu.Opening += (_, _) => TryBeginOnUi(() => {
                HideTrayStatusTooltip();
                RebuildTrayContextMenu(menu);
            }, "Tray context opening");
            menu.Closed += (_, _) => TryBeginOnUi(HideTrayStatusTooltip, "Tray context closed");
            RebuildTrayContextMenu(menu);
            _trayMenu = menu;
            return menu;
        } catch (Exception ex) when (IsTrayPlatformException(ex)) {
            menu?.Dispose();
            if (ReferenceEquals(_trayMenu, menu))
                _trayMenu = null;
            LogTrayContextMenuUnavailable("Tray context menu fallback enabled: " + TrimForDisplay(ex.GetBaseException().Message, 180));
            return null;
        }
    }

    private void LogTrayContextMenuUnavailable(string message) {
        if (_trayContextMenuAvailabilityLogged)
            return;

        _trayContextMenuAvailabilityLogged = true;
        AppendLog(message);
    }

    private static bool CanUseWinFormsTrayContextMenu() {
        if (!OperatingSystem.IsWindows())
            return false;

        try {
            UserPreferenceChangingEventHandler handler = (_, _) => { };
            SystemEvents.UserPreferenceChanging += handler;
            SystemEvents.UserPreferenceChanging -= handler;
            using var menu = new Forms.ContextMenuStrip();
            return true;
        } catch (Exception ex) when (IsTrayPlatformException(ex)) {
            return false;
        }
    }

    private static bool IsTrayPlatformException(Exception ex) {
        return ex is PlatformNotSupportedException
            || ex is TypeInitializationException { InnerException: PlatformNotSupportedException }
            || ex.GetBaseException() is PlatformNotSupportedException;
    }

    private void ShowWpfTrayContextMenu() {
        _wpfTrayMenu?.Items.Clear();
        _wpfTrayMenu = new System.Windows.Controls.ContextMenu {
            Placement = System.Windows.Controls.Primitives.PlacementMode.MousePoint
        };
        _wpfTrayMenu.Closed += (_, _) => _wpfTrayMenu = null;
        RebuildWpfTrayContextMenu(_wpfTrayMenu);
        _wpfTrayMenu.IsOpen = true;
    }

    private void RebuildWpfTrayContextMenu(System.Windows.Controls.ContextMenu menu) {
        UpdateTrayIconStatusText();

        menu.Items.Add(CreateWpfTrayInfoItem("JackLLM Workstation"));
        menu.Items.Add(CreateWpfTrayInfoItem(BuildTrayPrimaryStatusLine()));
        menu.Items.Add(CreateWpfTrayInfoItem(BuildTrayPublishStatusText()));
        menu.Items.Add(new System.Windows.Controls.Separator());
        menu.Items.Add(CreateWpfTrayMenuItem("Show Dashboard", ShowFromTray));
        menu.Items.Add(CreateWpfTrayMenuItem("Open Web UI", () => OpenChatButton_Click(this, new RoutedEventArgs()), _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening));
        menu.Items.Add(CreateWpfTrayMenuItem("Chat", OpenSocketChatWindow, _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening));
        menu.Items.Add(CreateWpfTrayMenuItem(_proxy.IsListening ? "Stop JACK" : "Start JACK", () => {
            if (_proxy.IsListening)
                _ = StopProxyAsync();
            else
                _ = StartProxyAsync();
        }));
        menu.Items.Add(CreateWpfTrayMenuItem("Refresh Master List", () => _ = RefreshMasterServerListIfDueAsync(true)));
        menu.Items.Add(CreateWpfTrayMenuItem("Check for Updates", CheckUpdaterNow));
        menu.Items.Add(CreateWpfTrayMenuItem("Force JackLLM Workstation Update", ForceUpdaterApply));
        menu.Items.Add(new Separator());
        menu.Items.Add(CreateWpfTrayMenuItem("Exit", ExitFromTray));
    }

    private static System.Windows.Controls.MenuItem CreateWpfTrayMenuItem(string text, Action? action = null, bool enabled = true) {
        var item = new System.Windows.Controls.MenuItem {
            Header = text ?? "",
            IsEnabled = enabled
        };
        if (action != null)
            item.Click += (_, _) => action();
        return item;
    }

    private static System.Windows.Controls.MenuItem CreateWpfTrayInfoItem(string text) {
        return new System.Windows.Controls.MenuItem {
            Header = text ?? "",
            IsEnabled = false
        };
    }

    private void RebuildTrayContextMenu(Forms.ContextMenuStrip menu) {
        menu.Items.Clear();
        UpdateTrayIconStatusText();

        menu.Items.Add(CreateTrayInfoItem("JackLLM Workstation"));
        menu.Items.Add(CreateTrayInfoItem(BuildTrayPrimaryStatusLine()));
        menu.Items.Add(CreateTrayInfoItem(BuildTrayPublishStatusText()));
        menu.Items.Add(new Forms.ToolStripSeparator());

        var performanceMenu = CreateTrayMenuItem("Performance Metrics");
        PopulateTrayPerformanceMenu(performanceMenu);
        menu.Items.Add(performanceMenu);

        var serverMenu = CreateTrayMenuItem("Server Status");
        PopulateTrayServerStatusMenu(serverMenu);
        menu.Items.Add(serverMenu);

        var approvalsMenu = CreateTrayMenuItem("Pending Approvals (" + (_terminalPermissionRequests.Count + _filesystemPermissionRequests.Count + _registrationRequestItems.Count + _tokenRateRequestItems.Count) + ")");
        PopulateTrayApprovalsMenu(approvalsMenu);
        menu.Items.Add(approvalsMenu);

        menu.Items.Add(new Forms.ToolStripSeparator());
        var showItem = CreateTrayMenuItem("Show Dashboard", ShowFromTray);
        menu.Items.Add(showItem);
        var openChatItem = CreateTrayMenuItem("Open Web UI", () => OpenChatButton_Click(this, new RoutedEventArgs()));
        openChatItem.Enabled = _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening;
        menu.Items.Add(openChatItem);
        var socketChatItem = CreateTrayMenuItem("Chat", OpenSocketChatWindow);
        socketChatItem.Enabled = _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening;
        menu.Items.Add(socketChatItem);
        var startStopItem = CreateTrayMenuItem(_proxy.IsListening ? "Stop JACK" : "Start JACK", () => {
            if (_proxy.IsListening)
                _ = StopProxyAsync();
            else
                _ = StartProxyAsync();
        });
        menu.Items.Add(startStopItem);
        menu.Items.Add(CreateTrayMenuItem("Refresh Master List", () => _ = RefreshMasterServerListIfDueAsync(true)));
        menu.Items.Add(CreateTrayMenuItem("Check for Updates", CheckUpdaterNow));
        var forceUpdateItem = CreateTrayMenuItem("Force JackLLM Workstation Update", ForceUpdaterApply);
        forceUpdateItem.ToolTipText = "Downloads any missing or SHA-256-mismatched GUI files from SocketJack.com.";
        menu.Items.Add(forceUpdateItem);
        menu.Items.Add(new Forms.ToolStripSeparator());
        menu.Items.Add(CreateTrayMenuItem("Exit", ExitFromTray));
    }

