    private void PopulateTrayApprovalsMenu(Forms.ToolStripMenuItem parent) {
        if (_terminalPermissionRequests.Count == 0 && _filesystemPermissionRequests.Count == 0 && _registrationRequestItems.Count == 0 && _tokenRateRequestItems.Count == 0) {
            parent.DropDownItems.Add(CreateTrayInfoItem("No pending approvals"));
            return;
        }

        AddTrayApprovalSummary(parent, "Terminal approvals", _terminalPermissionRequests.Count);
        AddTrayApprovalSummary(parent, "Filesystem approvals", _filesystemPermissionRequests.Count);
        AddTrayApprovalSummary(parent, "Registration approvals", _registrationRequestItems.Count);
        AddTrayApprovalSummary(parent, "Token-rate approvals", _tokenRateRequestItems.Count);
        parent.DropDownItems.Add(new Forms.ToolStripSeparator());
        parent.DropDownItems.Add(CreateTrayMenuItem("Open Dashboard", ShowFromTray));
    }

    private static void AddTrayApprovalSummary(Forms.ToolStripMenuItem parent, string label, int count) {
        if (count <= 0)
            return;
        parent.DropDownItems.Add(CreateTrayInfoItem(label + ": " + count.ToString(CultureInfo.InvariantCulture)));
    }

    private void SelectTraySession(string sessionId) {
        ShowFromTray();
        ChatSessionListItem? item = _sessionItems.FirstOrDefault(candidate => string.Equals(candidate.Id, sessionId, StringComparison.Ordinal));
        if (item == null)
            return;

        SessionsListBox.SelectedItem = item;
        _selectedSessionId = item.Id;
        _selectedOwnerKey = item.OwnerKey;
        RefreshAccessibleDirectories(true);
        RefreshWorkspaceExplorer(true);
    }

    private static Forms.ToolStripMenuItem CreateTrayMenuItem(string text, Action? action = null) {
        var item = new Forms.ToolStripMenuItem(text ?? "");
        if (action != null)
            item.Click += (_, _) => action();
        return item;
    }

    private static Forms.ToolStripMenuItem CreateTrayInfoItem(string text) {
        return new Forms.ToolStripMenuItem(text ?? "") {
            Enabled = false
        };
    }

    private void UpdateTrayIconStatusText() {
        if (_trayIcon != null)
            _trayIcon.Text = BuildTrayIconText();
    }

    private string BuildTrayIconText() {
        string updates = IsUpdateAvailableVisible() ? " | update available" : "";
        return TrimNotifyIconText("JackLLM Workstation | " + BuildTrayPrimaryStatusLine() + updates);
    }

    private string BuildTrayPrimaryStatusLine() {
        string proxy = _proxy.IsListening ? "JACK running" : "JACK stopped";
        return proxy + " | " + GetTrayWebClientCountText();
    }

    private string BuildTrayPublishStatusText() {
        if (_suppressAutomaticLocalServerEntry)
            return "My listing: disabled";

        ServerBrowserEntry entry = BuildLocalServerBrowserEntry();
        return "My listing: " + (entry.IsOnline ? "online" : "configured");
    }

    private string BuildTrayPortForwardingText() {
        if (!_portForwardingEnabled)
            return "disabled";
        if (_portForwardingSucceeded)
            return "forwarded TCP " + FormatForwardedPorts();
        if (_portForwardingAttempted)
            return "attempted TCP " + FormatForwardedPorts();
        return "waiting for TCP " + FormatForwardedPorts();
    }

    private string GetTrayWebClientCountText() {
        if (!_proxy.IsChatServerCreated)
            return "web clients -";

        try {
            return "web clients " + _proxy.ChatServer.Clients.Count.ToString(CultureInfo.InvariantCulture);
        } catch {
            return "web clients ?";
        }
    }

    private string BuildTrayTooltipText() {
        var builder = new StringBuilder();
        builder.AppendLine("JackLLM Workstation");
        builder.AppendLine(BuildTrayPrimaryStatusLine());
        builder.AppendLine(BuildTrayPublishStatusText());
        builder.AppendLine("Updates: " + BuildUpdaterTrayStatusText());
        builder.AppendLine("Server: " + TrimForDisplay(StatusBarText?.Text ?? "-", 92));
        builder.AppendLine(GetModelRuntimeServiceName() + ": " + _lmStatusText + " | " + _lmLatencyText);
        builder.AppendLine("JackONNX: " + _jackOnnxCapabilityStatus + " | " + _jackOnnxCapabilityCountLine);
        builder.AppendLine(GetChatServerClientText() + " | " + GetChatServerByteText());
        builder.AppendLine("Network: up " + FormatKbps(_networkUpSnapshot.LiveKbps) + " / down " + FormatKbps(_networkDownSnapshot.LiveKbps));
        builder.AppendLine("Port forwarding: " + BuildTrayPortForwardingText());
        builder.AppendLine("CPU " + FormatPercent(_cpuUsagePercent) + " | RAM " + FormatPercent(_ramUsagePercent) + " | GPU " + _gpuUtilizationHealthText + " | VRAM " + _vramUsageHealthText);
        builder.AppendLine("I/O: read " + FormatBytesPerSecond(_ioReadBytesPerSecond) + " / write " + FormatBytesPerSecond(_ioWriteBytesPerSecond));

        return builder.ToString().TrimEnd();
    }

    private bool IsUpdateAvailableVisible() {
        return UpdateNowButton?.Visibility == Visibility.Visible;
    }

    private string BuildUpdaterTrayStatusText() {
        string text = UpdateStatusText?.Text ?? "updates: checking";
        return text.Replace("updates: ", "", StringComparison.OrdinalIgnoreCase);
    }

    private static string TrimNotifyIconText(string text) {
        text = (text ?? "").Trim();
        return text.Length <= 63 ? text : text.Substring(0, 60) + "...";
    }

    private void ScheduleTrayStatusTooltip() {
        if (_trayMenu?.Visible == true)
            return;

        _lastTrayMousePosition = Forms.Control.MousePosition;
        _lastTrayTooltipHoverUtc = DateTimeOffset.UtcNow;
        if (_trayStatusTooltipWindow?.IsVisible == true) {
            UpdateTrayStatusTooltipContent();
            PositionTrayStatusTooltip();
            EnsureTrayTooltipHoverMonitor();
            return;
        }

        if (!_trayTooltipDelayTimer.IsEnabled)
            _trayTooltipDelayTimer.Start();
    }

    private void ShowTrayStatusTooltip() {
        if (_trayMenu?.Visible == true)
            return;

        if (_trayStatusTooltipWindow == null)
            CreateTrayStatusTooltipWindow();
        UpdateTrayStatusTooltipContent();

        _trayStatusTooltipWindow!.Show();
        PositionTrayStatusTooltip();
        _lastTrayTooltipHoverUtc = DateTimeOffset.UtcNow;
        EnsureTrayTooltipHoverMonitor();
    }

    private void EnsureTrayTooltipHoverMonitor() {
        if (!_trayTooltipHideTimer.IsEnabled)
            _trayTooltipHideTimer.Start();
    }

    private void CheckTrayStatusTooltipHover() {
        if (_trayStatusTooltipWindow?.IsVisible != true) {
            _trayTooltipHideTimer.Stop();
            return;
        }

        if (_trayMenu?.Visible == true) {
            HideTrayStatusTooltip();
            return;
        }

        if (IsCursorNearTrayStatusTooltip()) {
            _lastTrayTooltipHoverUtc = DateTimeOffset.UtcNow;
            return;
        }

        if (DateTimeOffset.UtcNow - _lastTrayTooltipHoverUtc >= TimeSpan.FromMilliseconds(500))
            HideTrayStatusTooltip();
    }

    private bool IsCursorNearTrayStatusTooltip() {
        System.Drawing.Point cursor = Forms.Control.MousePosition;
        const double trayIconHoverRadius = 64;
        double dx = cursor.X - _lastTrayMousePosition.X;
        double dy = cursor.Y - _lastTrayMousePosition.Y;
        if ((dx * dx) + (dy * dy) <= trayIconHoverRadius * trayIconHoverRadius)
            return true;

        if (_trayStatusTooltipWindow?.IsVisible != true)
            return false;

        const double tooltipMargin = 18;
        double left = _trayStatusTooltipWindow.Left - tooltipMargin;
        double top = _trayStatusTooltipWindow.Top - tooltipMargin;
        double right = _trayStatusTooltipWindow.Left + Math.Max(1, _trayStatusTooltipWindow.ActualWidth) + tooltipMargin;
        double bottom = _trayStatusTooltipWindow.Top + Math.Max(1, _trayStatusTooltipWindow.ActualHeight) + tooltipMargin;
        return cursor.X >= left && cursor.X <= right && cursor.Y >= top && cursor.Y <= bottom;
    }

    private void CreateTrayStatusTooltipWindow() {
        _trayStatusTooltipTextBlock = new TextBlock {
            Foreground = Brushes.White,
            FontSize = 12,
            FontFamily = new System.Windows.Media.FontFamily("Consolas"),
            TextWrapping = TextWrapping.Wrap,
            MaxWidth = 430,
            LineHeight = 16
        };

        var border = new Border {
            Background = new SolidColorBrush(Color.FromRgb(18, 24, 32)),
            BorderBrush = new SolidColorBrush(Color.FromRgb(88, 116, 138)),
            BorderThickness = new Thickness(1),
            CornerRadius = new CornerRadius(7),
            Padding = new Thickness(10),
            Child = _trayStatusTooltipTextBlock
        };

        _trayStatusTooltipWindow = new Window {
            WindowStyle = WindowStyle.None,
            AllowsTransparency = true,
            Background = Brushes.Transparent,
            Content = border,
            SizeToContent = SizeToContent.WidthAndHeight,
            ResizeMode = ResizeMode.NoResize,
            Topmost = true,
            ShowInTaskbar = false,
            ShowActivated = false,
            Focusable = false,
            IsHitTestVisible = false
        };
    }

    private void UpdateTrayStatusTooltipContent() {
        UpdateTrayIconStatusText();
        if (_trayStatusTooltipTextBlock != null)
            _trayStatusTooltipTextBlock.Text = BuildTrayTooltipText();
    }

    private void PositionTrayStatusTooltip() {
        if (_trayStatusTooltipWindow == null)
            return;

        _trayStatusTooltipWindow.UpdateLayout();
        System.Drawing.Rectangle area = Forms.Screen.FromPoint(_lastTrayMousePosition).WorkingArea;
        double width = Math.Max(260, _trayStatusTooltipWindow.ActualWidth);
        double height = Math.Max(120, _trayStatusTooltipWindow.ActualHeight);
        double left = Math.Min(Math.Max(area.Left + 8, _lastTrayMousePosition.X - width + 24), area.Right - width - 8);
        double top = _lastTrayMousePosition.Y - height - 18;
        if (top < area.Top + 8)
            top = _lastTrayMousePosition.Y + 18;
        top = Math.Min(Math.Max(area.Top + 8, top), area.Bottom - height - 8);

        _trayStatusTooltipWindow.Left = left;
        _trayStatusTooltipWindow.Top = top;
    }

    private void HideTrayStatusTooltip() {
        _trayTooltipDelayTimer.Stop();
        _trayTooltipHideTimer.Stop();
        _lastTrayTooltipHoverUtc = DateTimeOffset.MinValue;
        if (_trayStatusTooltipWindow?.IsVisible == true)
            _trayStatusTooltipWindow.Hide();
    }

    private void HideToTray() {
        if (!EnsureTrayIcon()) {
            WindowState = WindowState.Minimized;
            ShowInTaskbar = true;
            return;
        }

        Hide();
        ShowInTaskbar = false;
    }

    private void ShowFromTray() {
        ShowInTaskbar = true;
        Show();
        if (WindowState == WindowState.Minimized)
            WindowState = WindowState.Normal;
        Activate();
    }

    private void ExitFromTray() {
        ExitApplication();
    }

    private void ExitApplication() {
        _allowExit = true;
        Close();
    }

    private void DisposeTrayIcon() {
        HideTrayStatusTooltip();
        if (_trayStatusTooltipWindow != null) {
            try { _trayStatusTooltipWindow.Close(); } catch { }
            _trayStatusTooltipWindow = null;
            _trayStatusTooltipTextBlock = null;
        }

        if (_wpfTrayMenu != null) {
            _wpfTrayMenu.IsOpen = false;
            _wpfTrayMenu = null;
        }

        if (_trayIcon == null)
            return;

        _trayIcon.Visible = false;
        _trayIcon.Dispose();
        _trayIcon = null;
        _trayIconImage?.Dispose();
        _trayIconImage = null;
        _trayMenu?.Dispose();
        _trayMenu = null;
    }

    private async Task StartProxyAsync(IProgress<StartupLoadingProgress>? startupProgress = null, CancellationToken cancellationToken = default) {
        StartStopButton.IsEnabled = false;
        StartStopButton.Content = "Starting...";
        SetStatus("Starting JACK.");
        ResetChatBandwidthMetrics();

        try {
            cancellationToken.ThrowIfCancellationRequested();
            ReportStartup(startupProgress, 97.2, "Starting JACK", "Applying the selected model runtime provider.");
            string selectedProvider = GetSelectedModelRuntimeProvider();
            ApplyModelRuntimeProviderToProxy(selectedProvider, startEmbeddedRuntime: false);
            if (string.Equals(NormalizeModelRuntimeProvider(selectedProvider), RuntimeProviderLlmRuntime, StringComparison.OrdinalIgnoreCase))
                await EnsureSelectedEmbeddedLlmRuntimeStartedAsync("gui-start", cancellationToken);
            cancellationToken.ThrowIfCancellationRequested();
            ReportStartup(startupProgress, 97.5, "Starting JACK", "Opening remote LM Studio support if enabled.");
            StartRemoteLmStudioProxyIfEnabled();

            cancellationToken.ThrowIfCancellationRequested();
            ReportStartup(startupProgress, 97.8, "Starting JACK", "Binding local JACK endpoints.");
            bool proxyStarted = _proxy.Start();
            if (!proxyStarted) {
                ReportStartup(startupProgress, 98.0, "JACK already running", "Existing local JACK endpoints are active; verifying shell publishing.");
                AppendLog("JACK was already running. Verifying chat UI and shell publishing.");
            }

            ReportStartup(startupProgress, 98.1, "Starting chat UI", "Binding the local web chat endpoint.");
            if (!_proxy.ChatServer.IsListening)
                _proxy.ChatServer.Listen();
            ApplyServicePropertyOverridesToKnownTargets("service start");

            _startedAt ??= DateTimeOffset.UtcNow;
            AppendLog("VS Copilot endpoint: http://localhost:" + ServerPort + "/v1/responses");
            AppendLog("VS chat-completions endpoint: http://localhost:" + ServerPort + "/v1/chat/completions");
            AppendLog("Model runtime provider: " + _proxy.LocalModelRuntime.DisplayName + " at " + _proxy.LocalModelRuntime.OpenAiBaseUrl);
            AppendLog("Chat UI: " + _proxy.ChatServerUrl);
            SetStatus(proxyStarted ? "JACK is running." : "JACK is already running.");
            if (IsAutoPublishEnabled() && !IsMyListingPublished())
                SetPublishedToggleSilently(true);
            cancellationToken.ThrowIfCancellationRequested();
            if (IsMyListingPublished()) {
                ReportStartup(startupProgress, 98.4, "Publishing host listing", "Syncing JACK with the master server.");
                await PublishEnabledHostsToMasterServerAsync(true, "proxy start");
            }
            if (IsShellPublishingEnabled()) {
                ReportStartup(startupProgress, 98.4, "Starting SocketJack shell mode", "Preparing shell publishing for JACK.");
                await StartShellModeAsync();
            }
            cancellationToken.ThrowIfCancellationRequested();
            ReportStartup(startupProgress, 98.8, "Probing model runtime", "Checking the selected local model endpoint.");
            await ProbeLmStudioAsync();
            _ = CheckPersonaPlexVoiceInstallNoticeAsync();
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            throw;
        } catch (Exception ex) {
            StopRemoteLmStudioProxy();
            AppendLog("Start error: " + ex.Message);
            SetStatus("Start failed: " + ex.Message);
        } finally {
            StartStopButton.IsEnabled = true;
            RefreshMetrics();
        }
    }

    private void BeginPortForwardingIfEnabled(string reason) {
        if (!_portForwardingEnabled)
            return;

        RegisterPortForwardingEvents();

        if (_portForwardingSucceeded) {
            UpdatePortForwardStatus("Succeeded: " + FormatForwardedPorts() + ". Failed: none.", Brushes.LimeGreen);
            return;
        }

        if (!NIC.InterfaceDiscovered || NIC.NAT == null) {
            UpdatePortForwardStatus("Enabled. Waiting for NAT discovery to forward TCP " + FormatForwardedPorts() + ".", Brushes.Orange);
            if (!_portForwardingDiscoveryStarted) {
                AppendLog("Port forwarding enabled for remote web/FTP access (" + reason + "). Waiting for NAT discovery. Targets: " + FormatForwardedPorts() + ". Skipped: " + ServerPort + ", " + LocalLmStudioProxyPort + ".");
                _ = MarkPortForwardingTimeoutAsync();
            }
            _portForwardingDiscoveryStarted = true;
            NIC.DiscoverNAT();
            return;
        }

        _ = ForwardWebPortAsync(reason);
    }

    private void RegisterPortForwardingEvents() {
        if (_portForwardingEventsRegistered)
            return;

        NIC.OnInterfaceDiscovered += OnNicInterfaceDiscovered;
        NIC.OnError += OnNicError;
        _portForwardingEventsRegistered = true;
    }

    private void UnregisterPortForwardingEvents() {
        if (!_portForwardingEventsRegistered)
            return;

        NIC.OnInterfaceDiscovered -= OnNicInterfaceDiscovered;
        NIC.OnError -= OnNicError;
        _portForwardingEventsRegistered = false;
    }

    private void OnNicInterfaceDiscovered(int mtu, IPAddress localIp) {
        TryBeginOnUi(() => {
            AppendLog("NAT interface discovered for port forwarding: " + localIp + " MTU " + mtu + ". Forwarding TCP " + FormatForwardedPorts() + ".");
            _ = ForwardWebPortAsync("NAT discovery");
        }, "NAT interface discovery");
    }

    private void OnNicError(Exception ex) {
        TryBeginOnUi(() => {
            if (!_portForwardingEnabled || _portForwardingSucceeded || _portForwardingInProgress)
                return;

            UpdatePortForwardStatus("Succeeded: none. Failed: " + FormatForwardedPorts() + ".", Brushes.IndianRed);
            AppendLog("Port forwarding failed. Succeeded: none. Failed: " + FormatForwardedPorts() + " (" + ex.Message + "). Skipped: " + ServerPort + ", " + LocalLmStudioProxyPort + ".");
        }, "NAT forwarding error");
    }

    private async Task ForwardWebPortAsync(string reason) {
        if (!_portForwardingEnabled || _portForwardingInProgress)
            return;

        _portForwardingInProgress = true;
        _portForwardingAttempted = true;
        UpdatePortForwardStatus("Forwarding TCP " + FormatForwardedPorts() + "...", Brushes.Orange);

        try {
            List<int> succeeded = new();
            List<string> failed = new();
            foreach (int port in ForwardedTcpPorts) {
                try {
                    bool forwarded = await NIC.ForwardPort(port);
                    if (forwarded)
                        succeeded.Add(port);
                    else
                        failed.Add(port.ToString(CultureInfo.InvariantCulture));
                } catch (Exception ex) {
                    failed.Add(port.ToString(CultureInfo.InvariantCulture) + " (" + ex.Message + ")");
                }
            }

            if (!_portForwardingEnabled)
                return;

            _portForwardingSucceeded = failed.Count == 0 && succeeded.Count == ForwardedTcpPorts.Length;

            string succeededText = succeeded.Count == 0 ? "none" : string.Join(", ", succeeded);
            string failedText = failed.Count == 0 ? "none" : string.Join(", ", failed);
            Brush statusBrush = failed.Count == 0 ? Brushes.LimeGreen : succeeded.Count == 0 ? Brushes.IndianRed : Brushes.Orange;

            if (failed.Count == 0) {
                UpdatePortForwardStatus("Succeeded: " + succeededText + ". Failed: none.", statusBrush);
                AppendLog("Port forwarding succeeded (" + reason + "). Succeeded: " + succeededText + ". Failed: none. Skipped: " + ServerPort + ", " + LocalLmStudioProxyPort + ".");
            } else {
                UpdatePortForwardStatus("Succeeded: " + succeededText + ". Failed: " + failedText + ".", statusBrush);
                AppendLog("Port forwarding failed (" + reason + "). Succeeded: " + succeededText + ". Failed: " + failedText + ". Skipped: " + ServerPort + ", " + LocalLmStudioProxyPort + ".");
            }
        } catch (Exception ex) {
            if (!_portForwardingEnabled)
                return;

            _portForwardingSucceeded = false;
            UpdatePortForwardStatus("Succeeded: none. Failed: " + FormatForwardedPorts() + ".", Brushes.IndianRed);
            AppendLog("Port forwarding failed (" + reason + "). Succeeded: none. Failed: " + FormatForwardedPorts() + " (" + ex.Message + "). Skipped: " + ServerPort + ", " + LocalLmStudioProxyPort + ".");
        } finally {
            _portForwardingInProgress = false;
            RefreshRentMyPcForwardingValidation();
        }
    }

    private async Task MarkPortForwardingTimeoutAsync() {
        await Task.Delay(TimeSpan.FromSeconds(12));
        if (!_portForwardingEnabled || _portForwardingAttempted || _portForwardingSucceeded || NIC.InterfaceDiscovered)
            return;

        UpdatePortForwardStatus("Succeeded: none. Failed: " + FormatForwardedPorts() + " (NAT discovery timed out).", Brushes.IndianRed);
        AppendLog("Port forwarding failed. Succeeded: none. Failed: " + FormatForwardedPorts() + " (NAT discovery timed out). Skipped: " + ServerPort + ", " + LocalLmStudioProxyPort + ".");
    }

    private void UpdatePortForwardStatus(string text, Brush brush) {
        PortForwardStatusText.Text = text;
        PortForwardStatusText.Foreground = brush;
        RefreshRentMyPcForwardingValidation(text);
    }

    private void RefreshRentMyPcForwardingValidation(string? statusText = null) {
        if (ShellForwardValidationText == null ||
            ShellForwardValidationDetailText == null ||
            ShellSuggestionText == null)
            return;

        ShellForwardValidationText.Text = "SocketJack Shell";
        ShellForwardValidationText.Foreground = Brushes.LimeGreen;
        ShellForwardValidationDetailText.Text = "Published listings use SocketJack Shell automatically. Direct router forwarding is disabled for this flow.";
        ShellSuggestionText.Text = HasSocketJackAuthentication()
            ? "When JACK starts, this PC publishes through your SocketJack.com username and is removed when JACK stops."
            : "Sign in to SocketJack.com before publishing so the master list can attach this PC to your username.";
        SetShellPromptAnimation(false);
    }

    private void SetShellPromptAnimation(bool enabled) {
        if (ShellEnablePromptBorder == null)
            return;

        if (ShellEnablePromptBorder.RenderTransform is not ScaleTransform scale) {
            scale = new ScaleTransform(1, 1);
            ShellEnablePromptBorder.RenderTransform = scale;
        }

        if (enabled) {
            ShellEnablePromptBorder.BorderBrush = Brushes.LimeGreen;
            var scaleAnimation = new DoubleAnimation(1.0, 1.045, TimeSpan.FromMilliseconds(720)) {
                AutoReverse = true,
                RepeatBehavior = RepeatBehavior.Forever,
                EasingFunction = new SineEase { EasingMode = EasingMode.EaseInOut }
            };
            scale.BeginAnimation(ScaleTransform.ScaleXProperty, scaleAnimation);
            scale.BeginAnimation(ScaleTransform.ScaleYProperty, scaleAnimation);

            if (ShellEnablePromptBorder.Effect is not DropShadowEffect glow) {
                glow = new DropShadowEffect {
                    Color = Color.FromRgb(93, 255, 155),
                    BlurRadius = 18,
                    ShadowDepth = 0,
                    Opacity = 0
                };
                ShellEnablePromptBorder.Effect = glow;
            }

            var glowAnimation = new DoubleAnimation(0.15, 0.88, TimeSpan.FromMilliseconds(720)) {
                AutoReverse = true,
                RepeatBehavior = RepeatBehavior.Forever,
                EasingFunction = new SineEase { EasingMode = EasingMode.EaseInOut }
            };
            glow.BeginAnimation(DropShadowEffect.OpacityProperty, glowAnimation);
        } else {
            scale.BeginAnimation(ScaleTransform.ScaleXProperty, null);
            scale.BeginAnimation(ScaleTransform.ScaleYProperty, null);
            scale.ScaleX = 1;
            scale.ScaleY = 1;
            ShellEnablePromptBorder.BorderBrush = new SolidColorBrush(Color.FromArgb(0x66, 0x8E, 0xE6, 0xC9));
            if (ShellEnablePromptBorder.Effect is DropShadowEffect glow) {
                glow.BeginAnimation(DropShadowEffect.OpacityProperty, null);
                glow.Opacity = 0;
            }
        }
    }

    private static string FormatForwardedPorts() {
        return string.Join(", ", ForwardedTcpPorts);
    }

    private async Task StopProxyAsync() {
        StartStopButton.IsEnabled = false;
        StartStopButton.Content = "Stopping...";
        SetStatus("Stopping JACK.");

        try {
            if (_proxy.IsListening || (_proxy.IsChatServerCreated && _proxy.ChatServer.IsListening))
                await PublishEnabledHostsToMasterServerAsync(false, "proxy stop");
            if (_proxy.IsListening || (_proxy.IsChatServerCreated && _proxy.ChatServer.IsListening))
                _proxy.Stop();
            StopRemoteLmStudioProxy();
            StopEmbeddedLlmRuntime();
            _startedAt = null;
            ResetChatBandwidthMetrics();
            SetStatus("JACK stopped.");
        } catch (Exception ex) {
            AppendLog("Stop error: " + ex.Message);
            SetStatus("Stop failed: " + ex.Message);
        } finally {
            StartStopButton.IsEnabled = true;
            RefreshMetrics();
        }
    }

    private async Task StartShellModeAsync(bool forceRestart = false) {
        if (_shellModeStarting)
            return;
        if (!forceRestart && _shellModeRunning && _shellRelays.Count > 0) {
            AppendLog("Shell mode already running; keeping the existing relay client.");
            return;
        }
        _shellModeStarting = true;
        StopShellMode(updateCheckbox: false);
        try {
            _startedAt ??= DateTimeOffset.UtcNow;
            EnsureChatServerListeningForShell();
            int poolSize = NormalizeShellAgentPoolSize(ParseInt(ShellAgentPoolTextBox.Text, 8));
            ShellProxyRequestResult proxy = await RequestShellProxyAsync(poolSize);
            string masterHost = ResolveShellMasterHost();
            var started = new List<ShellRelay>();
            string shellWebSocketTunnelUrl = ResolveShellWebSocketTunnelUrl(proxy.Instance);
            bool webSocketTunnelEnabled = IsShellWebSocketTunnelEnabled() &&
                                          !string.IsNullOrWhiteSpace(shellWebSocketTunnelUrl) &&
                                          (proxy.Instance.SupportsWebSocketTunnel ||
                                           proxy.Instance.TransportMode.Equals("websocketPreferred", StringComparison.OrdinalIgnoreCase));
            if (webSocketTunnelEnabled)
                StartShellWebSocketTunnel(started, proxy.Instance, masterHost, poolSize);
            else
                StartShellRelay(started, proxy.Instance, masterHost, poolSize);

            if (started.Count == 0)
                throw new InvalidOperationException("The master server did not return an enabled JACK shell.");

            _shellRelays.AddRange(started);
            _shellModeRunning = true;
            _startedAt ??= DateTimeOffset.UtcNow;
            _shellModeStatusText = webSocketTunnelEnabled
                ? "Shell enabled with WebSocket tunnel. JACK session available at " + proxy.Endpoint + "."
                : "Shell enabled. JACK session available at " + proxy.Endpoint + ".";
            SetShellEnabledCheckBox(true);
            ShellStatusText.Text = _shellModeStatusText;
            if (ShellModeStatusText != null)
                ShellModeStatusText.Text = _shellModeStatusText;
            if (ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = _shellModeStatusText;
            SetStatus(_shellModeStatusText);
            AppendLog(_shellModeStatusText);
            RefreshMetrics();
        } catch (Exception ex) {
            StopShellMode(updateCheckbox: false);
            SetShellEnabledCheckBox(false);
            ShellStatusText.Text = "Shell start failed: " + TrimForDisplay(ex.Message, 180);
            AppendLog("Shell start failed: " + ex.Message);
        } finally {
            _shellModeStarting = false;
        }
    }

    private async Task CleanupPublishedLocalListingBeforeShellStartAsync() {
        if (!IsMyListingPublished())
            return;

        var entries = new List<ServerBrowserEntry>();
        foreach (ServerBrowserItem item in _serverBrowserItems.Where(item => item.IsLocalHost).ToList())
            entries.Add(item.ToEntry());

        LmVsProxyServerProfile profile = BuildHostProfileFromUi();
        entries.Add(BuildLocalServerBrowserEntry(profile, applyShellProxyEndpoint: false));

        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        List<ServerBrowserEntry> cleanupEntries = entries
            .Where(entry => entry != null)
            .Select(entry => {
                entry.Normalize();
                return entry;
            })
            .Where(entry => seen.Add(BuildServerBrowserEntryKey(entry)))
            .ToList();
        if (cleanupEntries.Count == 0)
            return;

        Uri listUri = BuildMasterServerListUri(FirstNonEmpty(MasterServerTextBox?.Text, ShellMasterServerTextBox?.Text, DefaultMasterServerUrl));
        using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
        foreach (ServerBrowserEntry entry in cleanupEntries) {
            entry.PublishEnabled = false;
            entry.IsOnline = false;
            entry.LastStatus = "Shell route replaced";
            entry.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
            try {
                await PostServerBrowserEntryToMasterServerAsync(client, listUri, entry, false, "delete");
            } catch (Exception ex) when (ex.Message.IndexOf("not found", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                         ex.Message.IndexOf("404", StringComparison.OrdinalIgnoreCase) >= 0) {
                AppendLog("Old master-list entry already removed: " + TrimForDisplay(ex.Message, 120));
            }
        }

        RemoveCurrentLocalServerBrowserEntry();
        AppendLog("Removed old master-list entry before enabling Shell.");
    }

    private ShellRelayItem? ResolveShellInstance(IReadOnlyList<ShellRelayItem> instances) {
        ShellRelayItem? selected = ShellInstancesListBox?.SelectedItem as ShellRelayItem;
        if (selected != null && selected.Enabled)
            return selected;
        return instances.FirstOrDefault(item => item.Enabled);
    }

    private async Task<ShellProxyRequestResult> RequestShellProxyAsync(int poolSize) {
        await EnsureSocketJackAuthenticatedForPublishAsync();
        LmVsProxyServerProfile profile = BuildHostProfileFromUi();
        _proxy.ConfigureServerBrowserProfile(profile);
        ServerBrowserEntry entry = BuildLocalServerBrowserEntry(profile);
        entry.Normalize();
        if (string.IsNullOrWhiteSpace(entry.Id))
            entry.Id = BuildShellProxyServerId(profile.ServerName);

        Uri uri = BuildShellProxyRequestUri();
        using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
        int internetLatencyMs = await MeasureMasterServerInternetLatencyMsAsync(client, uri);
        var payload = new {
            id = entry.Id,
            serverId = entry.Id,
            ownerUserName = FirstNonEmpty(entry.OwnerUserName, GetSocketJackUserName()),
            serverName = entry.DisplayName,
            displayName = entry.DisplayName,
            requestedPath = entry.DisplayName,
            profile,
            endpoint = entry.Endpoint,
            connectHost = entry.ConnectHost,
            publishEnabled = IsMyListingPublished(),
            visibleOnWebsite = IsMyListingPublished(),
            online = true,
            status = "JACK shell online",
            lastStatus = "JACK shell online",
            transportMode = IsShellWebSocketTunnelEnabled() ? "websocketPreferred" : "tcp",
            fallbackTcpEnabled = true,
            ownerTokenHash = HashMasterServerOwnerToken(GetMasterServerOwnerToken()),
            internetLatencyMs,
            latencyMs = internetLatencyMs,
            startedUtc = entry.StartedUtc,
            uptimeSeconds = entry.UptimeSeconds,
            toolsAllowed = entry.ToolsAllowed,
            supportsTools = true,
            vsTools = true,
            modelCapabilitiesJson = entry.ModelCapabilitiesJson,
            modelCapabilities = ParseJsonArrayOrNull(entry.ModelCapabilitiesJson),
            modelBenchmarksJson = entry.ModelBenchmarksJson,
            modelBenchmarks = ParseJsonArrayOrNull(entry.ModelBenchmarksJson),
            benchmarkedModelCount = CountJsonArrayItems(entry.ModelBenchmarksJson),
            localTarget = new {
                host = "127.0.0.1",
                port = ChatServerPort
            },
            agentPoolSize = poolSize,
            ports = new {
                vsProxy = entry.ProxyPort,
                chat = entry.ChatPort,
                lmStudio = entry.LmStudioPort,
                ftp = entry.FtpPort
            },
            payment = new {
                requiresPayment = entry.RequiresPayment,
                stripePriceId = entry.StripePriceId,
                stripeAccount = entry.StripeAccount,
                unitAmountCents = entry.StripeUnitAmountCents,
                currency = entry.StripeCurrency
            },
            requestedUtc = DateTimeOffset.UtcNow.ToString("O")
        };
        string json = JsonSerializer.Serialize(payload);
        using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
        using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, uri) {
            Content = content
        };
        AddSocketJackAuthHeaders(request);
        request.Headers.TryAddWithoutValidation("X-LmVsProxy-Server-Owner", GetMasterServerOwnerToken());
        System.Net.Http.HttpResponseMessage response;
        try {
            response = await client.SendAsync(request);
        } catch (Exception ex) when (IsRecoverableShellProxyRegistrationException(ex)) {
            ShellProxyRequestResult? recovered = await TryRecoverExistingShellProxyRouteAsync(entry, uri, ex.Message);
            if (recovered != null)
                return recovered;
            throw new InvalidOperationException("JACK shell registration timed out and no reusable master route was found: " + ex.Message, ex);
        }

        using (response) {
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode) {
                ShellProxyRequestResult? recovered = await TryRecoverExistingShellProxyRouteAsync(entry, uri, "HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase);
                if (recovered != null)
                    return recovered;
                throw new InvalidOperationException("HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ": " + TrimForDisplay(body, 180));
            }

            using JsonDocument document = JsonDocument.Parse(body);
            JsonElement root = document.RootElement;
            if (!TryGetJsonProperty(root, "instance", out JsonElement instanceElement) || instanceElement.ValueKind != JsonValueKind.Object)
                throw new InvalidOperationException("Master server did not return a JACK shell instance.");

            ShellRelayItem instance = ShellRelayItem.FromJson(instanceElement);
            instance.Endpoint = GetJsonString(root, "endpoint", instance.Endpoint);
            instance.ProxyPath = GetJsonString(root, "proxyPath", instance.ProxyPath);
            string topLevelTunnelUrl = GetJsonString(root, "webSocketTunnelUrl", "");
            if (!string.IsNullOrWhiteSpace(topLevelTunnelUrl))
                instance.WebSocketTunnelUrl = topLevelTunnelUrl;
            if (GetJsonBool(root, "supportsWebSocketTunnel", instance.SupportsWebSocketTunnel) ||
                !string.IsNullOrWhiteSpace(instance.WebSocketTunnelUrl))
                instance.SupportsWebSocketTunnel = true;
            instance.TransportMode = FirstNonEmpty(GetJsonString(root, "transportMode", ""), instance.TransportMode, "websocketPreferred");
            ApplyShellRelayItem(instance, true);

            string endpoint = FirstNonEmpty(
                GetJsonString(root, "endpoint", instance.Endpoint),
                string.IsNullOrWhiteSpace(instance.ProxyPath) ? "" : uri.GetLeftPart(UriPartial.Authority).TrimEnd('/') + instance.ProxyPath);
            ApplyRecoveredShellRouteToLocalEntry(entry, instance, endpoint, uri);

            return new ShellProxyRequestResult(instance, endpoint);
        }
    }

    private static bool IsRecoverableShellProxyRegistrationException(Exception ex) {
        return ex is TaskCanceledException ||
               ex is TimeoutException ||
               ex is System.Net.Http.HttpRequestException ||
               ex is IOException ||
               ex is WebException;
    }

    private async Task<ShellProxyRequestResult?> TryRecoverExistingShellProxyRouteAsync(ServerBrowserEntry entry, Uri registrationUri, string reason) {
        try {
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, BuildShellInstancesUri());
            AddSocketJackAuthHeaders(request);
            request.Headers.TryAddWithoutValidation("X-LmVsProxy-Server-Owner", GetMasterServerOwnerToken());
            using System.Net.Http.HttpResponseMessage response = await client.SendAsync(request);
            string body = await response.Content.ReadAsStringAsync();
            if (!response.IsSuccessStatusCode)
                return null;

            using JsonDocument document = JsonDocument.Parse(body);
            JsonElement root = document.RootElement;
            JsonElement instancesElement;
            if (!TryGetJsonProperty(root, "instances", out instancesElement) || instancesElement.ValueKind != JsonValueKind.Array) {
                if (!TryGetJsonProperty(root, "proxies", out instancesElement) || instancesElement.ValueKind != JsonValueKind.Array)
                    return null;
            }

            List<ShellRelayItem> matches = new();
            foreach (JsonElement element in instancesElement.EnumerateArray()) {
                if (element.ValueKind != JsonValueKind.Object)
                    continue;
                ShellRelayItem item = ShellRelayItem.FromJson(element);
                if (item.Enabled && ShellRelayMatchesLocalEntry(item, entry))
                    matches.Add(item);
            }

            ShellRelayItem? selected = matches
                .OrderByDescending(item => string.Equals(item.ServerId, entry.Id, StringComparison.OrdinalIgnoreCase))
                .ThenByDescending(item => item.SupportsWebSocketTunnel && !string.IsNullOrWhiteSpace(ResolveShellWebSocketTunnelUrl(item)))
                .ThenByDescending(item => item.WebSocketTunnelConnected)
                .FirstOrDefault();
            if (selected == null)
                return null;

            string endpoint = FirstNonEmpty(
                selected.Endpoint,
                string.IsNullOrWhiteSpace(selected.ProxyPath) ? "" : registrationUri.GetLeftPart(UriPartial.Authority).TrimEnd('/') + selected.ProxyPath);
            if (string.IsNullOrWhiteSpace(endpoint))
                endpoint = BuildShellProxyPreviewBaseUrl().TrimEnd('/') + "/proxy/" + Uri.EscapeDataString(NormalizeShellRouteTitle(FirstNonEmpty(selected.RouteName, selected.Name, entry.DisplayName)));

            selected.AppendDebug(DateTimeOffset.Now.ToString("HH:mm:ss", CultureInfo.CurrentCulture) + " Reused existing master route after registration failed: " + TrimForDisplay(reason, 120));
            ApplyShellRelayItem(selected, true);
            ApplyRecoveredShellRouteToLocalEntry(entry, selected, endpoint, registrationUri);
            AppendLog("Shell registration did not complete (" + TrimForDisplay(reason, 160) + "); reusing existing master route " + selected.Id + ".");
            return new ShellProxyRequestResult(selected, endpoint);
        } catch (Exception ex) {
            AppendLog("Existing shell route recovery failed: " + TrimForDisplay(ex.Message, 180));
            return null;
        }
    }

    private bool ShellRelayMatchesLocalEntry(ShellRelayItem item, ServerBrowserEntry entry) {
        string desiredId = entry.Id ?? "";
        string desiredName = FirstNonEmpty(entry.DisplayName, HostServerNameTextBox?.Text, "TitanX");
        string desiredRoute = NormalizeShellRouteTitle(desiredName);
        return (!string.IsNullOrWhiteSpace(desiredId) && string.Equals(item.ServerId, desiredId, StringComparison.OrdinalIgnoreCase)) ||
               (!string.IsNullOrWhiteSpace(desiredRoute) && string.Equals(NormalizeShellRouteTitle(item.RouteName), desiredRoute, StringComparison.OrdinalIgnoreCase)) ||
               (!string.IsNullOrWhiteSpace(desiredRoute) && string.Equals(NormalizeShellRouteTitle(item.Name), desiredRoute, StringComparison.OrdinalIgnoreCase));
    }

    private void ApplyRecoveredShellRouteToLocalEntry(ServerBrowserEntry entry, ShellRelayItem instance, string endpoint, Uri registrationUri) {
        if (!string.IsNullOrWhiteSpace(endpoint) && ShellProxyUrlPreviewTextBox != null)
            ShellProxyUrlPreviewTextBox.Text = endpoint;
        entry.Endpoint = endpoint;
        entry.ConnectHost = string.IsNullOrWhiteSpace(endpoint) ? registrationUri.Host : NormalizeServerBrowserHost(endpoint);
        int publicPort = TryReadPort(endpoint, registrationUri.Port);
        entry.ChatPort = publicPort;
        entry.ProxyPort = publicPort;
        entry.LmStudioPort = publicPort;
        entry.FtpPort = FtpServerPort;
        entry.LastStatus = IsMyListingPublished() ? "JACK shell online" : "JACK shell ready (unlisted)";
        entry.StartedUtc = GetProxyStartedUtcText();
        entry.UptimeSeconds = GetProxyUptimeSeconds();
        entry.IsOnline = true;
        entry.PublishEnabled = IsMyListingPublished();
        AddOrUpdateServerBrowserEntry(entry, true);
    }

    private void ApplyShellRelayItem(ShellRelayItem item, bool select) {
        ShellRelayItem? existing = _shellRelayItems.FirstOrDefault(candidate => string.Equals(candidate.Id, item.Id, StringComparison.OrdinalIgnoreCase));
        if (existing != null)
            _shellRelayItems.Remove(existing);
        _shellRelayItems.Add(item);
        if (select)
            ShellInstancesListBox.SelectedItem = item;
        UpdateSelectedShellDebugText();
    }

    private string BuildShellProxyServerId(string serverName) {
        string seed = Environment.MachineName + "|" + FirstNonEmpty(GetSocketJackUserName(), GetMasterServerOwnerToken());
        byte[] hash = SHA256.HashData(Encoding.UTF8.GetBytes(seed.Trim().ToLowerInvariant()));
        return "lmvs-shell-" + Convert.ToHexString(hash, 0, 8).ToLowerInvariant();
    }

    private static int TryReadPort(string endpoint, int fallback) {
        if (Uri.TryCreate(endpoint, UriKind.Absolute, out Uri? uri) && uri.Port > 0)
            return uri.Port;
        return fallback > 0 && fallback <= 65535 ? fallback : ChatServerPort;
    }

    private void StartShellRelay(List<ShellRelay> started, ShellRelayItem item, string masterHost, int poolSize) {
        const string localShellHost = "127.0.0.1";
        const int localShellPort = ChatServerPort;
        var client = new ReverseTcpRelayClient(
            item.Id,
            item.Name,
            masterHost,
            item.AgentPort,
            localShellHost,
            localShellPort,
            poolSize);
        client.Log += ShellRelayClient_Log;
        client.Start();
        item.ClientStatus = "Connected";
        item.AppendDebug("Routing master public " + item.PublicPort.ToString(CultureInfo.InvariantCulture) + " to local JACK " + localShellHost + ":" + localShellPort.ToString(CultureInfo.InvariantCulture) + ".");
        started.Add(new ShellRelay(item.Id, item.Name, masterHost, item.PublicPort, item.AgentPort, localShellHost, localShellPort, poolSize, client, null, ShellRelayClient_Log));
    }

    private void StartShellWebSocketTunnel(List<ShellRelay> started, ShellRelayItem item, string masterHost, int poolSize) {
        const string localShellHost = "127.0.0.1";
        const int localShellPort = ChatServerPort;
        string tunnelUrl = ResolveShellWebSocketTunnelUrl(item);
        if (string.IsNullOrWhiteSpace(tunnelUrl)) {
            StartShellRelay(started, item, masterHost, poolSize);
            return;
        }

        string ownerToken = GetMasterServerOwnerToken();
        string[] tunnelRoles = GetShellWebSocketTunnelRoles();
        var clients = new List<ShellWebSocketTunnelClient>();
        foreach (string role in tunnelRoles) {
            var client = new ShellWebSocketTunnelClient(
                item.Id,
                string.IsNullOrWhiteSpace(role) ? item.Name : item.Name + " " + role,
                tunnelUrl,
                localShellHost,
                localShellPort,
                ownerToken,
                role);
            clients.Add(client);
        }

        var tunnelStates = new ConcurrentDictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
        var relay = new ShellRelay(item.Id, item.Name, masterHost, item.PublicPort, item.AgentPort, localShellHost, localShellPort, poolSize, null, clients.FirstOrDefault(), ShellRelayClient_Log);
        foreach (ShellWebSocketTunnelClient extraClient in clients.Skip(1))
            relay.AddAdditionalWebSocketTunnel(extraClient);

        foreach (ShellWebSocketTunnelClient client in clients) {
            string role = client.ChannelRole;
            tunnelStates[role] = false;
            client.StatusChanged += (_, args) => TryBeginOnUi(() => {
                tunnelStates[role] = args.Connected;
                int connectedTunnels = tunnelStates.Count(pair => pair.Value);
                string rolePrefix = string.IsNullOrWhiteSpace(role) ? "[WebSocket]" : "[WebSocket " + role + "]";
                item.AppendDebug(args.TimestampUtc.ToLocalTime().ToString("HH:mm:ss", CultureInfo.CurrentCulture) + " " + rolePrefix + " " + args.Message);
                item.ClientStatus = connectedTunnels > 0
                    ? "WebSocket " + connectedTunnels.ToString(CultureInfo.InvariantCulture)
                    : "WebSocket reconnecting";
                UpdateSelectedShellDebugText();
                if (connectedTunnels > 0)
                    relay.StopTcpFallback();
                else if (args.FallbackRecommended)
                    relay.EnsureTcpFallbackStarted();
            }, "Shell WebSocket status update");
        }

        foreach (ShellWebSocketTunnelClient client in clients)
            client.Start();

        item.ClientStatus = "WebSocket connecting";
        item.AppendDebug("Routing public JACK access through WebSocket tunnel " + tunnelUrl + " -> local JACK " + localShellHost + ":" + localShellPort.ToString(CultureInfo.InvariantCulture) + ".");
        started.Add(relay);
    }

    private static string[] GetShellWebSocketTunnelRoles() {
        return new[] { "api", "chat", "browser" };
    }

    private string ResolveShellWebSocketTunnelUrl(ShellRelayItem item) {
        if (!string.IsNullOrWhiteSpace(item.WebSocketTunnelUrl))
            return item.WebSocketTunnelUrl.Trim();

        if (string.IsNullOrWhiteSpace(item.Id))
            return "";
        Uri baseUri = BuildShellApiUri("/");
        string scheme = baseUri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase) ? "wss" : "ws";
        return scheme + "://" + baseUri.Authority.TrimEnd('/') + "/api/shell/proxies/" + Uri.EscapeDataString(item.Id) + "/tunnel";
    }

    private void SetShellEnabledCheckBox(bool enabled) {
        if (ShellEnabledCheckBox == null)
            return;

        _suppressShellToggleEvents = true;
        try {
            ShellEnabledCheckBox.Content = "Shell publishing";
            ShellEnabledCheckBox.IsChecked = enabled;
        } finally {
            _suppressShellToggleEvents = false;
        }
    }

    private void StopShellMode() {
        StopShellMode(updateCheckbox: true);
    }

    private void StopShellMode(bool updateCheckbox) {
        if (_shellRelays.Count == 0 && !_shellModeRunning) {
            if (updateCheckbox)
                SetShellEnabledCheckBox(false);
            return;
        }

        foreach (ShellRelay relay in _shellRelays.ToList()) {
            try {
                relay.Dispose();
            } catch (Exception ex) {
                AppendLog("Shell relay stop error (" + relay.Name + "): " + ex.Message);
            }
        }

        _shellRelays.Clear();
        _shellModeRunning = false;
        _startedAt = null;
        _shellModeStatusText = "Shell mode disabled.";
        if (ShellModeStatusText != null)
            ShellModeStatusText.Text = _shellModeStatusText;
        if (ShellStatusText != null)
            ShellStatusText.Text = _shellModeStatusText;
        if (updateCheckbox)
            SetShellEnabledCheckBox(false);
        foreach (ShellRelayItem item in _shellRelayItems)
            item.ClientStatus = "Idle";
        if (ServerBrowserStatusText != null)
            ServerBrowserStatusText.Text = "Shell mode is disabled.";
        RefreshRentMyPcForwardingValidation();
        SetStatus("Shell mode disabled.");
        RefreshMetrics();
    }

    private string FormatShellRelayPorts() {
        if (_shellRelays.Count == 0)
            return "-";

        return string.Join(", ", _shellRelays.Select(relay => relay.PublicPort.ToString(CultureInfo.InvariantCulture)));
    }

    private string GetShellTargetText() {
        if (ServerBrowserListBox?.SelectedItem is ServerBrowserItem selected) {
            ServerBrowserEntry entry = selected.ToEntry();
            if (!string.IsNullOrWhiteSpace(entry.Endpoint))
                return entry.Endpoint;
            if (!string.IsNullOrWhiteSpace(entry.ConnectHost))
                return BuildServerBrowserEndpoint(entry.ConnectHost, entry.ChatPort <= 0 ? ChatServerPort : entry.ChatPort);
        }

        return BrowseServerEndpointTextBox?.Text ?? "";
    }

    private ServerBrowserEntry ResolveShellTargetEntry() {
        if (ServerBrowserListBox?.SelectedItem is ServerBrowserItem selected) {
            ServerBrowserEntry entry = selected.ToEntry();
            return entry;
        }

        string text = GetShellTargetText();
        if (!TryParseRemoteEndpoint(text, ChatServerPort, out string host, out int chatPort))
            throw new InvalidOperationException("Shell target must be a host, host:port, or http(s) URL.");

        return new ServerBrowserEntry {
            DisplayName = host,
            Endpoint = BuildServerBrowserEndpoint(host, chatPort),
            ConnectHost = host,
            ProxyPort = ServerPort,
            ChatPort = chatPort,
            LmStudioPort = LocalLmStudioProxyPort,
            FtpPort = FtpServerPort,
            CostFactor = 1,
            UpdatedUtc = DateTimeOffset.UtcNow.ToString("O")
        };
    }

    private async Task EnsureLmStudioForPromptAsync() {
        if (GetSelectedModelRuntimeProvider() == RuntimeProviderLlmRuntime) {
            if (Dispatcher.CheckAccess()) {
                ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
            } else {
                await TryInvokeOnUiAsync(() => ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false), "Prompt LlmRuntime provider selection");
            }

            await EnsureSelectedEmbeddedLlmRuntimeStartedAsync("prompt");
            return;
        }

        if (Dispatcher.CheckAccess()) {
            await ProbeLmStudioAsync(allowLaunch: true);
            return;
        }

        if (!await TryInvokeOnUiAsync(() => ProbeLmStudioAsync(allowLaunch: true), "Prompt LM Studio probe"))
            throw new InvalidOperationException("Could not schedule LM Studio probe on the WPF dispatcher.");
    }

    private async Task EnsureLmStudioProviderForPromptAsync() {
        if (Dispatcher.CheckAccess()) {
            await ProbeLmStudioProviderAsync(allowLaunch: true);
            return;
        }

        if (!await TryInvokeOnUiAsync(() => ProbeLmStudioProviderAsync(allowLaunch: true), "Prompt LM Studio provider probe"))
            throw new InvalidOperationException("Could not schedule LM Studio provider probe on the WPF dispatcher.");
    }

    private async Task ProbeLmStudioAsync(bool allowLaunch = false) {
        if (GetSelectedModelRuntimeProvider() == RuntimeProviderLlmRuntime) {
            await ProbeEmbeddedLlmRuntimeAsync(allowLaunch || _proxy.IsListening);
            return;
        }

        await ProbeLmStudioProviderAsync(allowLaunch);
    }

    private async Task ProbeLmStudioProviderAsync(bool allowLaunch = false) {

        if (_isProbing && !allowLaunch)
            return;
        if (_isProbing) {
            for (int attempt = 0; attempt < 20 && _isProbing; attempt++)
                await Task.Delay(250);
            if (_isProbing)
                return;
        }

        _isProbing = true;
        ProbeButton.IsEnabled = false;
        _lmStatusText = "Checking process...";
        _lmStatusBrush = Brushes.Orange;
        _lmLatencyText = "Process: checking";

        try {
            int? runningProcessId = FindLmStudioProcessId();
            if (runningProcessId.HasValue) {
                SetLmStudioRunningStatus(runningProcessId.Value);
                await ProbeLmStudioHostingParametersAsync();
                return;
            }

            string executablePath = ResolveLmStudioExecutablePath();
            if (string.IsNullOrWhiteSpace(executablePath)) {
                _lmStatusText = "Not running";
                _lmLatencyText = "App not found";
                _lmStatusBrush = Brushes.IndianRed;
                AppendLog("LM Studio is not running and " + LmStudioExecutableName + " was not found under " + GetLocalProgramsLmStudioPath() + ".");
                return;
            }

            if (!allowLaunch) {
                _lmStatusText = "Not running";
                _lmLatencyText = "Launch deferred until prompt";
                _lmStatusBrush = Brushes.Gray;
                return;
            }

            _lmStatusText = "Starting";
            _lmLatencyText = "Process: launch requested";
            _lmStatusBrush = Brushes.Orange;
            RefreshMetrics();
            AppendLog("LM Studio is not running; starting for the prompt: " + executablePath);

            if (TryStartLmStudio(executablePath, out string error)) {
                await Task.Delay(TimeSpan.FromMilliseconds(1200));
                runningProcessId = FindLmStudioProcessId();
                if (runningProcessId.HasValue) {
                    SetLmStudioRunningStatus(runningProcessId.Value);
                    await ProbeLmStudioHostingParametersAsync();
                } else {
                    _lmStatusText = "Starting";
                    _lmLatencyText = "Process: launch requested";
                    _lmStatusBrush = Brushes.Orange;
                }
            } else {
                _lmStatusText = "Start failed";
                _lmLatencyText = TrimForDisplay(error, 90);
                _lmStatusBrush = Brushes.IndianRed;
                AppendLog("LM Studio start failed: " + error);
            }
        } finally {
            _lmStudioEventCount++;
            PulseService("LM Studio");
            AppendServiceEventLine("LM Studio", "Runtime probe completed with status " + TrimForDisplay(_lmStatusText, 110));
            _isProbing = false;
            ProbeButton.IsEnabled = true;
            RefreshMetrics();
        }
    }

    private void EnsureChatServerListeningForShell() {
        if (_proxy.ChatServer.IsListening)
            return;

        _proxy.ChatServer.Listen();
        AppendLog("Shell publishing started the local Chat UI listener at " + _proxy.ChatServerUrl + ".");
    }

    private async Task ProbeEmbeddedLlmRuntimeAsync(bool startRuntime) {
        if (_isProbing && !startRuntime)
            return;

        string externalRuntime = GetExternalModelManagerRuntimeBaseUrl();
        bool useExternalRuntime = !string.IsNullOrWhiteSpace(externalRuntime);
        _isProbing = true;
        ProbeButton.IsEnabled = false;
        _lmStatusText = useExternalRuntime ? "External runtime" : startRuntime ? "Starting runtime" : "Embedded runtime";
        _lmStatusBrush = Brushes.Orange;
        _lmLatencyText = useExternalRuntime ? "Provider: external LlmRuntime" : "Provider: LlmRuntime";
        try {
            if (startRuntime || useExternalRuntime) {
                ApplyModelRuntimeProviderToProxy(RuntimeProviderLlmRuntime, startEmbeddedRuntime: false);
                if (startRuntime && !useExternalRuntime)
                    await EnsureSelectedEmbeddedLlmRuntimeStartedAsync("runtime-probe");
            }

            string endpoint = _proxy.LocalModelRuntime.OpenAiBaseUrl.TrimEnd('/') + "/api/v1/models";
            var stopwatch = Stopwatch.StartNew();
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(4));
            using System.Net.Http.HttpResponseMessage response = await client.GetAsync(endpoint);
            stopwatch.Stop();
            _lmStatusText = response.IsSuccessStatusCode ? "Connected" : "HTTP " + (int)response.StatusCode;
            _lmLatencyText = "LlmRuntime " + stopwatch.ElapsedMilliseconds.ToString(CultureInfo.InvariantCulture) + " ms";
            _lmStatusBrush = response.IsSuccessStatusCode ? Brushes.LimeGreen : Brushes.OrangeRed;
            if (!response.IsSuccessStatusCode)
                AppendLog("LlmRuntime probe returned HTTP " + (int)response.StatusCode + " from " + endpoint + ".");

            string body = await response.Content.ReadAsStringAsync();
            try {
                using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
                LmStudioHostProbeResult probe = ParseLmStudioHostProbe(document.RootElement, endpoint);
                RefreshDetectedHostResourceFields(_settings, probe);
                await RefreshPublishedListingAfterModelProbeAsync(probe, "LlmRuntime model inventory probe");
                if (string.IsNullOrWhiteSpace(probe.AvailableModels))
                    NotifyModelsUnavailable("No models were returned by " + (useExternalRuntime ? "external" : "embedded") + " LlmRuntime at " + endpoint + ". Load or download a local model before starting chat.");
            } catch {
                RefreshDetectedHostResourceFields(_settings, null);
                NotifyModelsUnavailable((useExternalRuntime ? "External" : "Embedded") + " LlmRuntime did not return a readable model list from " + endpoint + ".");
            }
        } catch (Exception ex) {
            _lmStatusText = startRuntime ? "Start failed" : "Unavailable";
            _lmLatencyText = TrimForDisplay(ex.Message, 90);
            _lmStatusBrush = Brushes.IndianRed;
            AppendLog("LlmRuntime probe failed: " + ex.Message);
            NotifyModelsUnavailable((useExternalRuntime ? "External" : "Embedded") + " LlmRuntime model discovery failed: " + ex.Message);
        } finally {
            _lmStudioEventCount++;
            PulseService("LlmRuntime");
            AppendServiceEventLine("LlmRuntime", (useExternalRuntime ? "External" : "Embedded") + " runtime probe completed with status " + TrimForDisplay(_lmStatusText, 110));
            _isProbing = false;
            ProbeButton.IsEnabled = true;
            RefreshMetrics();
        }
    }

    private async Task ProbeLmStudioHostingParametersAsync() {
        LmStudioHostProbeResult? probe = null;
        string lastError = "";

        foreach (string endpoint in new[] {
            "http://localhost:" + LocalLmStudioProxyPort + "/v1/models",
            "http://localhost:" + LocalLmStudioProxyPort + "/api/v0/models",
            "http://127.0.0.1:1234/v1/models",
            "http://127.0.0.1:1234/api/v0/models"
        }) {
            try {
                using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(4));
                using System.Net.Http.HttpResponseMessage response = await client.GetAsync(endpoint);
                string body = await response.Content.ReadAsStringAsync();
                if (!response.IsSuccessStatusCode) {
                    lastError = "HTTP " + (int)response.StatusCode + " from " + endpoint;
                    continue;
                }

                using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
                probe = ParseLmStudioHostProbe(document.RootElement, endpoint);
                break;
            } catch (Exception ex) {
                lastError = TrimForDisplay(ex.Message, 140);
            }
        }

        if (probe == null) {
            probe = new LmStudioHostProbeResult();
            probe.MissingParameters.Add("LM Studio /v1/models endpoint");
            if (!string.IsNullOrWhiteSpace(lastError))
                probe.MissingParameters.Add(lastError);
        }

        RefreshDetectedHostResourceFields(_settings, probe);
        SaveSettingsIfReady();
        await RefreshPublishedListingAfterModelProbeAsync(probe, "LM Studio model inventory probe");

        if (string.IsNullOrWhiteSpace(probe.AvailableModels)) {
            string source = string.IsNullOrWhiteSpace(probe.Source) ? "the model runtime" : probe.Source;
            NotifyModelsUnavailable("No models were returned by " + source + ". Load a model in LM Studio or use the embedded LlmRuntime model downloader.");
        }

        if (probe.MissingParameters.Count > 0) {
            string missing = string.Join(", ", probe.MissingParameters.Distinct(StringComparer.OrdinalIgnoreCase));
            AppendLog("LM Studio host parameter probe needs: " + missing);
            if (ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = "LM Studio host probe missing: " + TrimForDisplay(missing, 180);
            return;
        }

        if (ServerBrowserStatusText != null)
            ServerBrowserStatusText.Text = "LM Studio host parameters updated from " + probe.Source + ".";
    }

    private static LmStudioHostProbeResult ParseLmStudioHostProbe(JsonElement root, string source) {
        var result = new LmStudioHostProbeResult { Source = source };
        JsonElement data = root;
        if (TryGetJsonProperty(root, "data", out JsonElement dataProperty) && dataProperty.ValueKind == JsonValueKind.Array)
            data = dataProperty;
        else if (TryGetJsonProperty(root, "models", out JsonElement modelsProperty) && modelsProperty.ValueKind == JsonValueKind.Array)
            data = modelsProperty;

        var modelNames = new List<string>();
        var gpuDetails = new List<string>();
        long maxTokens = 0;

        if (data.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement model in data.EnumerateArray())
                ReadLmStudioModelMetadata(model, modelNames, gpuDetails, result.ModelCapabilities, ref maxTokens);
        } else if (data.ValueKind == JsonValueKind.Object) {
            ReadLmStudioModelMetadata(data, modelNames, gpuDetails, result.ModelCapabilities, ref maxTokens);
        }

        result.AvailableModels = string.Join(", ", modelNames.Where(name => !string.IsNullOrWhiteSpace(name)).Distinct(StringComparer.OrdinalIgnoreCase).Take(12));
        result.ModelIds.AddRange(modelNames.Where(name => !string.IsNullOrWhiteSpace(name)).Distinct(StringComparer.OrdinalIgnoreCase));
        result.GpuAvailable = string.Join("; ", gpuDetails.Where(text => !string.IsNullOrWhiteSpace(text)).Distinct(StringComparer.OrdinalIgnoreCase).Take(5));
        result.MaxTokens = maxTokens;

        if (string.IsNullOrWhiteSpace(result.AvailableModels))
            result.MissingParameters.Add("available model id/name from /v1/models data[]");
        if (result.MaxTokens <= 0)
            result.MissingParameters.Add("context_length/max_context_length/n_ctx/max_tokens");
        if (string.IsNullOrWhiteSpace(result.GpuAvailable))
            result.MissingParameters.Add("gpu_layers/n_gpu_layers/offload/estimated_vram/available_vram");

        return result;
    }

    private void CancelActiveModelBenchmarks() {
        _modelBenchmarkCancellationSource?.Cancel();
        SetBenchmarkStatus("Stopping benchmark run after the current request returns...");
    }

    private void ModelBenchmarkItems_CollectionChanged(object? sender, System.Collections.Specialized.NotifyCollectionChangedEventArgs e) {
        if (e.OldItems != null) {
            foreach (object oldItem in e.OldItems) {
                if (oldItem is ModelBenchmarkItem benchmark)
                    benchmark.PropertyChanged -= ModelBenchmarkItem_PropertyChanged;
            }
        }

        if (e.NewItems != null) {
            foreach (object newItem in e.NewItems) {
                if (newItem is ModelBenchmarkItem benchmark)
                    benchmark.PropertyChanged += ModelBenchmarkItem_PropertyChanged;
            }
        }

        SyncModelBenchmarksToModelsManager();
    }

    private void ModelBenchmarkItem_PropertyChanged(object? sender, PropertyChangedEventArgs e) {
        if (sender is ModelBenchmarkItem benchmark)
            SyncModelBenchmarkToModelsManager(benchmark);
    }

    private void SyncModelBenchmarksToModelsManager() {
        if (ModelsManagerControl == null)
            return;

        ModelsManagerControl.SetModelBenchmarks(
            _modelBenchmarkItems
                .Where(item => !string.IsNullOrWhiteSpace(item.ModelId))
                .Select(ToModelManagerBenchmarkInfo)
                .ToList(),
            !_modelBenchmarkInProgress);
    }

    private void SyncModelBenchmarkToModelsManager(ModelBenchmarkItem item) {
        if (ModelsManagerControl == null || item == null || string.IsNullOrWhiteSpace(item.ModelId))
            return;

        ModelsManagerControl.UpdateModelBenchmark(ToModelManagerBenchmarkInfo(item), !_modelBenchmarkInProgress);
    }

    private static ModelManagerBenchmarkInfo ToModelManagerBenchmarkInfo(ModelBenchmarkItem item) {
        return new ModelManagerBenchmarkInfo {
            ModelId = item.ModelId,
            Status = item.Status,
            TokensPerSecond = item.TokensPerSecond,
            TokensPerHour = item.TokensPerHour,
            Rating = item.Rating,
            BenchmarkedUtc = item.BenchmarkedUtc,
            BenchmarkKind = item.BenchmarkKind,
            BenchmarkPrompt = item.BenchmarkPrompt,
            IsRunning = item.IsRunning,
            CanBenchmark = item.CanBenchmark
        };
    }

    private void SetBenchmarkControlsBusy(bool busy, bool batchMode, string status = "") {
        if (BenchmarkAllModelsButton != null) {
            BenchmarkAllModelsButton.Content = batchMode ? "Stop" : "Run All Benchmarks";
            BenchmarkAllModelsButton.IsEnabled = !busy || batchMode;
            BenchmarkAllModelsButton.Background = batchMode
                ? new SolidColorBrush(Color.FromRgb(158, 49, 70))
                : new SolidColorBrush(Color.FromRgb(31, 122, 104));
            BenchmarkAllModelsButton.BorderBrush = batchMode
                ? new SolidColorBrush(Color.FromRgb(255, 92, 122))
                : new SolidColorBrush(Color.FromRgb(89, 214, 201));
        }

        foreach (ModelBenchmarkItem item in _modelBenchmarkItems)
            item.CanBenchmark = !busy;

        RefreshBenchmarkSelectionState();
        SyncModelBenchmarksToModelsManager();

        if (!string.IsNullOrWhiteSpace(status))
            SetBenchmarkStatus(status);
    }

    private void SetBenchmarkStatus(string text) {
        if (BenchmarkStatusText != null)
            BenchmarkStatusText.Text = string.IsNullOrWhiteSpace(text) ? "Ready to benchmark detected models." : text;
    }

    private void RefreshModelBenchmarkItems(IEnumerable<string> modelIds, IEnumerable<ModelCapabilityInfo>? capabilities = null) {
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        var capabilityMap = (capabilities ?? Array.Empty<ModelCapabilityInfo>())
            .Where(item => item != null && !string.IsNullOrWhiteSpace(item.ModelId))
            .GroupBy(item => item.ModelId, StringComparer.OrdinalIgnoreCase)
            .ToDictionary(
                group => group.Key,
                group => new ModelCapabilityInfo {
                    ModelId = group.Key,
                    SupportsImages = group.Any(item => item.SupportsImages),
                    SupportsTools = group.Any(item => item.SupportsTools),
                    SupportsImageGeneration = group.Any(item => item.SupportsImageGeneration),
                    SupportsAudioGeneration = group.Any(item => item.SupportsAudioGeneration),
                    SupportsVideoGeneration = group.Any(item => item.SupportsVideoGeneration)
                },
                StringComparer.OrdinalIgnoreCase);

        foreach (string modelId in modelIds ?? Array.Empty<string>()) {
            string normalized = (modelId ?? "").Trim();
            if (string.IsNullOrWhiteSpace(normalized) || !seen.Add(normalized))
                continue;
            ModelBenchmarkItem? existing = _modelBenchmarkItems.FirstOrDefault(item => string.Equals(item.ModelId, normalized, StringComparison.OrdinalIgnoreCase));
            if (existing == null) {
                existing = new ModelBenchmarkItem { ModelId = normalized, CanBenchmark = !_modelBenchmarkInProgress };
                _modelBenchmarkItems.Add(existing);
            }
            if (capabilityMap.TryGetValue(normalized, out ModelCapabilityInfo? capability))
                existing.ApplyCapabilities(capability);
            else
                existing.ApplyCapabilities(new ModelCapabilityInfo {
                    ModelId = normalized,
                    SupportsImages = ModelNameLikelySupportsImages(normalized),
                    SupportsTools = ModelNameLikelySupportsTools(normalized),
                    SupportsImageGeneration = ModelNameLikelySupportsImageGeneration(normalized),
                    SupportsAudioGeneration = ModelNameLikelySupportsAudioGeneration(normalized),
                    SupportsVideoGeneration = ModelNameLikelySupportsVideoGeneration(normalized)
                });
        }

        foreach (ModelCapabilityInfo capability in capabilityMap.Values) {
            if (seen.Contains(capability.ModelId))
                continue;
            ModelBenchmarkItem? existing = _modelBenchmarkItems.FirstOrDefault(item => string.Equals(item.ModelId, capability.ModelId, StringComparison.OrdinalIgnoreCase));
            if (existing == null) {
                existing = new ModelBenchmarkItem { ModelId = capability.ModelId, CanBenchmark = !_modelBenchmarkInProgress };
                _modelBenchmarkItems.Add(existing);
            }
            existing.ApplyCapabilities(capability);
        }

        EnsureModelBenchmarkSelection();
        SyncModelBenchmarksToModelsManager();
    }

    private void RefreshModelReconfigurationSuggestions() {
        var suggestions = BuildModelReconfigurationSuggestions();
        string signature = string.Join("|", suggestions.Select(item => item.Signature));
        if (string.Equals(signature, _modelReconfigurationSignature, StringComparison.Ordinal))
            return;

        _modelReconfigurationItems.Clear();
        foreach (ModelReconfigurationSuggestionItem item in suggestions)
            _modelReconfigurationItems.Add(item);
        _modelReconfigurationSignature = signature;
        UpdateUsageWarningsTabHeader();
    }

    private void UpdateUsageWarningsTabHeader() {
        if (UsageWarningsTabHeaderText == null)
            return;

        int count = _modelReconfigurationItems.Count(item => item.SeverityRank > SeverityRank("OK"));
        UsageWarningsTabHeaderText.Text = count.ToString(CultureInfo.InvariantCulture) + (count == 1 ? " Warning" : " Warnings");
    }

    private List<ModelReconfigurationSuggestionItem> BuildModelReconfigurationSuggestions() {
        var activeSessions = Array.Empty<ActivePromptSessionDiagnosticsSnapshot>();
        try {
            activeSessions = _proxy.GetActivePromptSessionDiagnostics()?.ToArray() ?? Array.Empty<ActivePromptSessionDiagnosticsSnapshot>();
        } catch {
        }

        List<string> activeModels = activeSessions
            .Select(session => NormalizeModelForAdvisory(session.Model))
            .Where(model => !string.IsNullOrWhiteSpace(model))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .ToList();
        if (activeModels.Count == 0 && HasRuntimePressure())
            activeModels.Add("LM Studio active model");

        var suggestions = new List<ModelReconfigurationSuggestionItem>();
        if (_linuxNativeBackendWarningActive)
            suggestions.Add(BuildLinuxNativeBackendWarningItem());
        if (_imageRuntimeCompatibilityWarningActive)
            suggestions.Add(BuildImageRuntimeCompatibilityWarningItem());
        if (_personaPlexWarningActive)
            suggestions.Add(BuildPersonaPlexWarningItem());

        foreach (string model in activeModels) {
            ModelBenchmarkItem? benchmark = FindModelBenchmark(model);
            ModelReconfigurationSuggestionItem? suggestion = BuildActiveModelReconfigurationSuggestion(model, benchmark, activeSessions);
            if (suggestion != null)
                suggestions.Add(suggestion);
        }

        foreach (ModelBenchmarkItem item in _modelBenchmarkItems) {
            if (string.IsNullOrWhiteSpace(item.ModelId))
                continue;
            if (suggestions.Any(existing => string.Equals(existing.ModelName, item.ModelId, StringComparison.OrdinalIgnoreCase)))
                continue;

            if (item.Status.StartsWith("Benchmark failed", StringComparison.OrdinalIgnoreCase)) {
                suggestions.Add(new ModelReconfigurationSuggestionItem(
                    item.ModelId,
                    "WARN",
                    "Benchmark could not complete for this model.",
                    "In LM Studio, reload the model, reduce context length, lower GPU offload, then run the benchmark again."));
            } else if (item.TokensPerSecond > 0 && item.Rating <= 20) {
                suggestions.Add(new ModelReconfigurationSuggestionItem(
                    item.ModelId,
                    "WARN",
                    "Benchmark score " + item.Rating.ToString(CultureInfo.InvariantCulture) + "/100 (" + item.TokensPerSecond.ToString("0.0", CultureInfo.InvariantCulture) + " tok/s).",
                    "Use a smaller quantization/model, reduce context length, and lower batch size before publishing this model."));
            }
        }

        if (suggestions.Count == 0) {
            suggestions.Add(new ModelReconfigurationSuggestionItem(
                "Model load",
                "OK",
                "No active overloaded model detected from current CPU, RAM, GPU, VRAM, and token-rate telemetry.",
                "Keep current LM Studio parameters; re-run benchmarks after changing model, context length, or GPU offload."));
        }

        var visibleSuggestions = suggestions
            .OrderByDescending(item => item.SeverityRank)
            .ThenBy(item => item.ModelName, StringComparer.OrdinalIgnoreCase)
            .Take(6)
            .ToList();
        foreach (ModelReconfigurationSuggestionItem item in _dismissedNotificationInfoItems.Take(4)) {
            if (!visibleSuggestions.Any(existing => string.Equals(existing.Signature, item.Signature, StringComparison.Ordinal)))
                visibleSuggestions.Add(item);
        }

        return visibleSuggestions;
    }

    private void RecordDismissedNotificationInfo(string title, string detail) {
        if (!Dispatcher.CheckAccess()) {
            TryBeginOnUi(() => RecordDismissedNotificationInfo(title, detail), "dismissed notification info");
            return;
        }

        string cleanTitle = FirstNonEmpty(title, "Dismissed notification");
        string cleanDetail = FirstNonEmpty(detail, "Notification dismissed.");
        string dismissedAt = DateTimeOffset.Now.ToString("g", CultureInfo.CurrentCulture);
        var item = new ModelReconfigurationSuggestionItem(
            cleanTitle,
            "INFO",
            "Dismissed " + dismissedAt + ".",
            cleanDetail);
        _dismissedNotificationInfoItems.RemoveAll(existing => string.Equals(existing.ModelName, item.ModelName, StringComparison.OrdinalIgnoreCase));
        _dismissedNotificationInfoItems.Insert(0, item);
        while (_dismissedNotificationInfoItems.Count > 8)
            _dismissedNotificationInfoItems.RemoveAt(_dismissedNotificationInfoItems.Count - 1);
        RefreshModelReconfigurationSuggestions();
    }

    private ModelReconfigurationSuggestionItem BuildLinuxNativeBackendWarningItem() {
        return new ModelReconfigurationSuggestionItem(
            "Linux native backend",
            "CRIT",
            FirstNonEmpty(_linuxNativeBackendWarningDetail, "Hidden native LlmRuntime backend is not available."),
            "Use the actions below to restart the backend, inspect logs, repair CUDA/PyTorch, or verify the model root.",
            new[] {
                new WarningActionItem("Restart Backend", RestartLinuxNativeBackendFromWarning),
                new WarningActionItem("Open Native Log", OpenLinuxNativeBackendLog),
                new WarningActionItem("Repair CUDA/PyTorch", () => _ = BeginRepairPytorchFromWarningAsync()),
                new WarningActionItem("Open Models Location", OpenModelsLocationFromWarning)
            });
    }

    private ModelReconfigurationSuggestionItem BuildImageRuntimeCompatibilityWarningItem() {
        var actions = new List<WarningActionItem>();
        if (_imageRuntimeCompatibilityCanRepair)
            actions.Add(new WarningActionItem("Repair PyTorch", () => _ = BeginRepairPytorchFromWarningAsync()));
        if (_imageRuntimeCompatibilityCanInstallCuda)
            actions.Add(new WarningActionItem("Install CUDA", OpenCudaInstallerPage));

        return new ModelReconfigurationSuggestionItem(
            "Local image generation",
            _imageRuntimeCompatibilityWarningSeverity,
            FirstNonEmpty(_imageRuntimeCompatibilityWarningSignal, "JackLLM's image-generation Python runtime is not ready."),
            FirstNonEmpty(_imageRuntimeCompatibilityWarningRecommendation, "Use Repair PyTorch from Workstation so image generation can use CUDA."),
            actions);
    }

    private ModelReconfigurationSuggestionItem BuildPersonaPlexWarningItem() {
        var actions = new List<WarningActionItem>();
        if (_personaPlexWarningNeedsToken)
            actions.Add(new WarningActionItem("Add Token", ShowPersonaPlexTokenDialog));
        if (_personaPlexWarningCanInstall)
            actions.Add(new WarningActionItem(_personaPlexWarningNeedsToken ? "Reinstall" : "Install", () => _ = InstallPersonaPlexVoiceModeFromWorkstationAsync()));
        actions.Add(new WarningActionItem("Model Page", OpenPersonaPlexModelPage));

        return new ModelReconfigurationSuggestionItem(
            "NVIDIA PersonaPlex Voice Mode",
            _personaPlexWarningSeverity,
            FirstNonEmpty(_personaPlexWarningSignal, "PersonaPlex is not ready on this workstation."),
            FirstNonEmpty(_personaPlexWarningRecommendation, "Install Voice Mode from Workstation or add the Hugging Face token after accepting NVIDIA's model license."),
            actions);
    }

    private void WarningActionButton_Click(object sender, RoutedEventArgs e) {
        if ((sender as FrameworkElement)?.Tag is not WarningActionItem action)
            return;

        try {
            action.Execute();
        } catch (Exception ex) {
            AppendLog("Warning action failed: " + TrimForDisplay(ex.Message, 220));
        }
    }

    private ModelReconfigurationSuggestionItem? BuildActiveModelReconfigurationSuggestion(string model, ModelBenchmarkItem? benchmark, IReadOnlyList<ActivePromptSessionDiagnosticsSnapshot> activeSessions) {
        var signals = new List<string>();
        var recommendations = new List<string>();
        string severity = "OK";

        if (_vramUsagePercent >= 95) {
            severity = "CRIT";
            signals.Add("VRAM " + FormatPercent(_vramUsagePercent));
            recommendations.Add("lower GPU offload by 10-25%");
            recommendations.Add("reduce context length/KV cache");
            recommendations.Add("switch to a smaller quantization");
        } else if (_vramUsagePercent >= 88) {
            severity = MaxSeverity(severity, "WARN");
            signals.Add("VRAM " + FormatPercent(_vramUsagePercent));
            recommendations.Add("lower GPU offload or context length");
        }

        if (_ramUsagePercent >= 92) {
            severity = "CRIT";
            signals.Add("RAM " + FormatPercent(_ramUsagePercent));
            recommendations.Add("reduce context length and max tokens");
            recommendations.Add("use a smaller model/quantization");
        } else if (_ramUsagePercent >= 86) {
            severity = MaxSeverity(severity, "WARN");
            signals.Add("RAM " + FormatPercent(_ramUsagePercent));
            recommendations.Add("reduce context length or parallel requests");
        }

        if (_cpuUsagePercent >= 94) {
            severity = MaxSeverity(severity, "WARN");
            signals.Add("CPU " + FormatPercent(_cpuUsagePercent));
            if (_gpuUtilizationPercent < 55 && _vramUsagePercent < 82)
                recommendations.Add("increase GPU offload if VRAM allows");
            recommendations.Add("lower CPU threads, batch size, or concurrent clients");
        }

        if (_gpuUtilizationPercent >= 98 && _tokenRatePerHour > 0) {
            severity = MaxSeverity(severity, "WARN");
            signals.Add("GPU " + FormatPercent(_gpuUtilizationPercent));
            recommendations.Add("lower batch size or cap concurrent clients");
        }

        if (benchmark != null && benchmark.TokensPerHour > 0 && _tokenRatePerHour > 0) {
            double ratio = _tokenRatePerHour / Math.Max(1, benchmark.TokensPerHour);
            if (ratio < 0.35) {
                severity = MaxSeverity(severity, ratio < 0.2 ? "CRIT" : "WARN");
                signals.Add("live rate " + FormatTokensPerHour(_tokenRatePerHour) + " vs benchmark " + FormatTokensPerHour(benchmark.TokensPerHour));
                recommendations.Add("reduce context length, batch size, and max tokens");
                recommendations.Add("benchmark again after changes");
            }
        } else if (activeSessions.Any(session => session.ElapsedSeconds >= 45) && _tokenRatePerHour <= 0) {
            severity = MaxSeverity(severity, "WARN");
            signals.Add("active session with no measured token output");
            recommendations.Add("reload the model and lower context length/GPU offload");
        }

        if (signals.Count == 0)
            return null;

        string signalLine = string.Join(" | ", signals.Distinct(StringComparer.OrdinalIgnoreCase));
        string recommendationLine = "Change: " + string.Join("; ", recommendations
            .Where(text => !string.IsNullOrWhiteSpace(text))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .Take(4)) + ".";
        return new ModelReconfigurationSuggestionItem(model, severity, signalLine, recommendationLine);
    }

    private bool HasRuntimePressure() {
        return _vramUsagePercent >= 88 ||
               _ramUsagePercent >= 86 ||
               _cpuUsagePercent >= 94 ||
               (_gpuUtilizationPercent >= 98 && _tokenRatePerHour > 0);
    }

    private ModelBenchmarkItem? FindModelBenchmark(string model) {
        model = NormalizeModelForAdvisory(model);
        if (string.IsNullOrWhiteSpace(model))
            return null;

        return _modelBenchmarkItems.FirstOrDefault(item => string.Equals(item.ModelId, model, StringComparison.OrdinalIgnoreCase))
               ?? _modelBenchmarkItems.FirstOrDefault(item =>
                   !string.IsNullOrWhiteSpace(item.ModelId) &&
                   (model.IndexOf(item.ModelId, StringComparison.OrdinalIgnoreCase) >= 0 ||
                    item.ModelId.IndexOf(model, StringComparison.OrdinalIgnoreCase) >= 0));
    }

    private static string NormalizeModelForAdvisory(string model) {
        model = (model ?? "").Trim();
        return model.Equals("lm-studio", StringComparison.OrdinalIgnoreCase) ? "LM Studio active model" : model;
    }

    private static void ApplyBenchmarkRequestHints(ModelBenchmarkItem item, string mediaServiceHint, string modelTypeHint, IReadOnlyList<string>? modelTags) {
        if (item == null)
            return;

        string mediaKind = ResolveBenchmarkMediaKind(item.ModelId, item, mediaServiceHint, modelTypeHint, modelTags);
        if (string.IsNullOrWhiteSpace(mediaKind))
            return;

        item.ApplyCapabilities(new ModelCapabilityInfo {
            ModelId = item.ModelId,
            SupportsImageGeneration = mediaKind == "image",
            SupportsAudioGeneration = mediaKind == "audio",
            SupportsVideoGeneration = mediaKind == "video"
        });
    }

    private static string ResolveBenchmarkMediaKind(string modelId, ModelBenchmarkItem? item, string mediaServiceHint = "", string modelTypeHint = "", IReadOnlyList<string>? modelTags = null) {
        string serviceKind = NormalizeBenchmarkMediaKind(mediaServiceHint);
        if (!string.IsNullOrWhiteSpace(serviceKind))
            return serviceKind;

        string typeKind = NormalizeBenchmarkMediaKind(modelTypeHint);
        if (!string.IsNullOrWhiteSpace(typeKind))
            return typeKind;

        foreach (string tag in modelTags ?? Array.Empty<string>()) {
            string tagKind = NormalizeBenchmarkMediaKind(tag);
            if (!string.IsNullOrWhiteSpace(tagKind))
                return tagKind;
        }

        if (item?.SupportsVideoGeneration == true || ModelNameLikelySupportsVideoGeneration(modelId))
            return "video";
        if (item?.SupportsAudioGeneration == true || ModelNameLikelySupportsAudioGeneration(modelId))
            return "audio";
        if (item?.SupportsImageGeneration == true || ModelNameLikelySupportsImageGeneration(modelId))
            return "image";
        return "";
    }

    private static string NormalizeBenchmarkMediaKind(string value) {
        value = (value ?? "").Trim().ToLowerInvariant().Replace("-", "_");
        if (string.IsNullOrWhiteSpace(value))
            return "";
        if (value.EndsWith("_generation", StringComparison.OrdinalIgnoreCase))
            value = value.Substring(0, value.Length - "_generation".Length);
        if (value.Contains("video", StringComparison.OrdinalIgnoreCase) ||
            value.Contains("text_to_video", StringComparison.OrdinalIgnoreCase) ||
            value.Contains("image_to_video", StringComparison.OrdinalIgnoreCase) ||
            value.Contains("video_to_video", StringComparison.OrdinalIgnoreCase))
            return "video";
        if (value.Contains("audio", StringComparison.OrdinalIgnoreCase) ||
            value.Contains("speech", StringComparison.OrdinalIgnoreCase) ||
            value.Contains("text_to_speech", StringComparison.OrdinalIgnoreCase))
            return "audio";
        if (value.Contains("image", StringComparison.OrdinalIgnoreCase) ||
            value.Contains("text_to_image", StringComparison.OrdinalIgnoreCase) ||
            value.Contains("image_to_image", StringComparison.OrdinalIgnoreCase))
            return "image";
        if (value == "image" || value == "audio" || value == "video")
            return value;
        return "";
    }

    private static string MaxSeverity(string current, string candidate) {
        return SeverityRank(candidate) > SeverityRank(current) ? candidate : current;
    }

    private static int SeverityRank(string severity) {
        return severity.Equals("CRIT", StringComparison.OrdinalIgnoreCase) ? 3 :
               severity.Equals("WARN", StringComparison.OrdinalIgnoreCase) ? 2 :
               severity.Equals("INFO", StringComparison.OrdinalIgnoreCase) ? 1 :
               severity.Equals("OK", StringComparison.OrdinalIgnoreCase) ? 1 : 0;
    }

    private async Task BenchmarkModelAsync(string modelId, string mediaServiceHint = "", string modelTypeHint = "", IReadOnlyList<string>? modelTags = null) {
        modelId = (modelId ?? "").Trim();
        if (string.IsNullOrWhiteSpace(modelId) || _modelBenchmarkInProgress)
            return;

        _modelBenchmarkInProgress = true;
        _modelBenchmarkCancellationSource = new CancellationTokenSource();
        SetBenchmarkControlsBusy(true, false, "Benchmarking " + modelId + "...");
        try {
            await BenchmarkModelAsync(modelId, _modelBenchmarkCancellationSource.Token, false, 1, 1, mediaServiceHint, modelTypeHint, modelTags);
        } catch (OperationCanceledException) {
            SetBenchmarkStatus("Benchmark canceled.");
        } finally {
            _modelBenchmarkCancellationSource?.Dispose();
            _modelBenchmarkCancellationSource = null;
            _modelBenchmarkInProgress = false;
            SetBenchmarkControlsBusy(false, false);
        }
    }

    private async Task BenchmarkModelAsync(string modelId, CancellationToken cancellationToken, bool fromBatch, int index, int total, string mediaServiceHint = "", string modelTypeHint = "", IReadOnlyList<string>? modelTags = null) {
        modelId = (modelId ?? "").Trim();
        if (string.IsNullOrWhiteSpace(modelId))
            return;

        ModelBenchmarkItem item = _modelBenchmarkItems.FirstOrDefault(candidate => string.Equals(candidate.ModelId, modelId, StringComparison.OrdinalIgnoreCase))
                                  ?? new ModelBenchmarkItem { ModelId = modelId, CanBenchmark = !_modelBenchmarkInProgress };
        if (!_modelBenchmarkItems.Contains(item))
            _modelBenchmarkItems.Add(item);
        ApplyBenchmarkRequestHints(item, mediaServiceHint, modelTypeHint, modelTags);

        string progress = fromBatch
            ? " (" + index.ToString(CultureInfo.InvariantCulture) + "/" + total.ToString(CultureInfo.InvariantCulture) + ")"
            : "";
        item.BeginBenchmark("Running benchmark" + progress + "...");
        SetBenchmarkStatus("Benchmarking " + modelId + progress + "...");
        try {
            ModelBenchmarkResult result = await RunModelBenchmarkAsync(modelId, cancellationToken, status => {
                string progressStatus = status + progress;
                item.Status = progressStatus;
                SetBenchmarkStatus(progressStatus);
            }, mediaServiceHint, modelTypeHint, modelTags);
            item.Apply(result);
            CacheLatestModelBenchmarksJson(BuildModelBenchmarksJson());
            if (!fromBatch) {
                PublishCurrentHostProfile(true);
                await PublishEnabledHostsToMasterServerAsync(true, "model benchmark");
            }
            string completed = FormatModelBenchmarkCompletion(modelId, result);
            SetBenchmarkStatus(completed);
            if (ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = completed;
        } catch (OperationCanceledException) {
            item.CancelBenchmark();
            throw;
        } catch (Exception ex) {
            item.FailBenchmark("Benchmark failed: " + TrimForDisplay(ex.Message, 120));
            if (ServerBrowserStatusText != null)
                ServerBrowserStatusText.Text = item.Status;
            SetBenchmarkStatus(item.Status);
        }
    }

    private async Task<ModelBenchmarkResult> RunModelBenchmarkAsync(string modelId, CancellationToken cancellationToken, Action<string>? reportProgress = null, string mediaServiceHint = "", string modelTypeHint = "", IReadOnlyList<string>? modelTags = null) {
        ModelBenchmarkItem? benchmarkItem = FindModelBenchmark(modelId);
        string mediaKind = ResolveBenchmarkMediaKind(modelId, benchmarkItem, mediaServiceHint, modelTypeHint, modelTags);
        if (!string.IsNullOrWhiteSpace(mediaKind))
            return await RunMediaModelBenchmarkAsync(modelId, mediaKind, cancellationToken, reportProgress).ConfigureAwait(true);

        string runtimeName = GetSelectedModelRuntimeProvider() == RuntimeProviderLlmRuntime ? "LlmRuntime" : "LM Studio";
        string[] endpoints = await GetModelBenchmarkCompletionEndpointsAsync(cancellationToken);
        string lastError = "";
        foreach (string endpoint in endpoints) {
            try {
                var payload = new {
                    model = modelId,
                    messages = new[] {
                        new { role = "user", content = "Write exactly one compact technical paragraph about measuring language model token throughput. Use plain text only." }
                    },
                    temperature = 0,
                    max_tokens = 128,
                    stream = false
                };
                reportProgress?.Invoke("Loading " + modelId + " in " + runtimeName + " before measured benchmark; timer starts after load...");
                using (var warmupClient = CreateNetworkHttpClient(TimeSpan.FromMinutes(10))) {
                    await WarmModelForBenchmarkAsync(warmupClient, endpoint, modelId, cancellationToken);
                }

                reportProgress?.Invoke("Measuring " + modelId + " generation throughput with " + runtimeName + "...");
                string json = JsonSerializer.Serialize(payload);
                using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(90));
                using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
                Stopwatch sw = Stopwatch.StartNew();
                using System.Net.Http.HttpResponseMessage response = await client.PostAsync(endpoint, content, cancellationToken);
                string body = await response.Content.ReadAsStringAsync(cancellationToken);
                sw.Stop();
                if (!response.IsSuccessStatusCode) {
                    lastError = "HTTP " + (int)response.StatusCode + " from " + endpoint + ": " + TrimForDisplay(body, 120);
                    continue;
                }

                int outputTokens = ExtractCompletionTokens(body);
                if (outputTokens <= 0)
                    outputTokens = EstimateBenchmarkTokens(body);
                double requestSeconds = Math.Max(0.001, sw.Elapsed.TotalSeconds);
                double tokensPerSecond = ExtractBenchmarkTokensPerSecond(body);
                double seconds = ExtractBenchmarkDurationSeconds(body) ??
                                 (tokensPerSecond > 0 && outputTokens > 0 ? outputTokens / tokensPerSecond : requestSeconds);
                seconds = Math.Max(0.001, seconds);
                if (tokensPerSecond <= 0)
                    tokensPerSecond = outputTokens / seconds;
                int rating = ComputeModelBenchmarkRating(tokensPerSecond);
                return new ModelBenchmarkResult {
                    ModelId = modelId,
                    SupportsImages = ModelNameLikelySupportsImages(modelId),
                    SupportsTools = ModelNameLikelySupportsTools(modelId),
                    SupportsImageGeneration = ModelNameLikelySupportsImageGeneration(modelId),
                    SupportsAudioGeneration = ModelNameLikelySupportsAudioGeneration(modelId),
                    SupportsVideoGeneration = ModelNameLikelySupportsVideoGeneration(modelId),
                    TokensPerSecond = tokensPerSecond,
                    TokensPerHour = tokensPerSecond * 3600d,
                    OutputTokens = outputTokens,
                    DurationMs = sw.Elapsed.TotalMilliseconds,
                    Rating = rating,
                    BenchmarkedUtc = DateTimeOffset.UtcNow.ToString("O"),
                    BenchmarkKind = "text"
                };
            } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
                throw;
            } catch (Exception ex) {
                lastError = TrimForDisplay(ex.Message, 140);
            }
        }

        throw new InvalidOperationException(string.IsNullOrWhiteSpace(lastError) ? runtimeName + " benchmark endpoint unavailable." : lastError);
    }

    private async Task<ModelBenchmarkResult> RunMediaModelBenchmarkAsync(string modelId, string mediaKind, CancellationToken cancellationToken, Action<string>? reportProgress = null) {
        mediaKind = NormalizeBenchmarkMediaKind(mediaKind);
        if (string.IsNullOrWhiteSpace(mediaKind))
            throw new InvalidOperationException("Media benchmark requires image, audio, or video model metadata.");

        string[] endpoints = await GetModelBenchmarkMediaToolEndpointsAsync(cancellationToken);
        string toolName = GetBenchmarkMediaToolName(mediaKind);
        string lastError = "";
        foreach (string endpoint in endpoints) {
            try {
                reportProgress?.Invoke("Measuring " + modelId + " " + mediaKind + " generation with prompt \"" + MediaBenchmarkPrompt + "\"...");
                string json = BuildMediaBenchmarkToolPayload(toolName, mediaKind, modelId);
                using var client = CreateNetworkHttpClient(TimeSpan.FromMinutes(30));
                using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
                Stopwatch sw = Stopwatch.StartNew();
                using System.Net.Http.HttpResponseMessage response = await client.PostAsync(endpoint, content, cancellationToken);
                string body = await response.Content.ReadAsStringAsync(cancellationToken);
                sw.Stop();
                if (!response.IsSuccessStatusCode) {
                    lastError = "HTTP " + (int)response.StatusCode + " from " + endpoint + ": " + TrimForDisplay(body, 160);
                    continue;
                }

                if (!TryReadMediaBenchmarkSuccess(body, out int outputUnits, out string mediaError)) {
                    lastError = string.IsNullOrWhiteSpace(mediaError) ? mediaKind + " generation benchmark failed." : mediaError;
                    continue;
                }

                double seconds = Math.Max(0.001, sw.Elapsed.TotalSeconds);
                outputUnits = Math.Max(1, outputUnits);
                double unitsPerSecond = outputUnits / seconds;
                return new ModelBenchmarkResult {
                    ModelId = modelId,
                    SupportsImages = ModelNameLikelySupportsImages(modelId),
                    SupportsTools = ModelNameLikelySupportsTools(modelId),
                    SupportsImageGeneration = mediaKind == "image" || ModelNameLikelySupportsImageGeneration(modelId),
                    SupportsAudioGeneration = mediaKind == "audio" || ModelNameLikelySupportsAudioGeneration(modelId),
                    SupportsVideoGeneration = mediaKind == "video" || ModelNameLikelySupportsVideoGeneration(modelId),
                    TokensPerSecond = unitsPerSecond,
                    TokensPerHour = unitsPerSecond * 3600d,
                    OutputTokens = outputUnits,
                    DurationMs = sw.Elapsed.TotalMilliseconds,
                    Rating = ComputeMediaModelBenchmarkRating(mediaKind, seconds),
                    BenchmarkedUtc = DateTimeOffset.UtcNow.ToString("O"),
                    BenchmarkKind = mediaKind,
                    BenchmarkPrompt = MediaBenchmarkPrompt
                };
            } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
                throw;
            } catch (Exception ex) {
                lastError = TrimForDisplay(ex.Message, 160);
            }
        }

        throw new InvalidOperationException(string.IsNullOrWhiteSpace(lastError) ? "LlmRuntime media benchmark endpoint unavailable." : lastError);
    }

