    private static string BuildMediaBenchmarkToolPayload(string toolName, string mediaKind, string modelId) {
        var arguments = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase) {
            ["modelId"] = modelId
        };
        if (mediaKind == "audio")
            arguments["text"] = MediaBenchmarkPrompt;
        else
            arguments["prompt"] = MediaBenchmarkPrompt;

        return JsonSerializer.Serialize(new {
            approved = true,
            tool_calls = new[] {
                new {
                    id = "call_media_bench_" + Guid.NewGuid().ToString("N").Substring(0, 12),
                    name = toolName,
                    arguments
                }
            }
        });
    }

    private static bool TryReadMediaBenchmarkSuccess(string json, out int outputUnits, out string error) {
        outputUnits = 0;
        error = "";
        try {
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
            JsonElement root = document.RootElement;
            if (TryGetJsonProperty(root, "error", out JsonElement rootError)) {
                error = JsonElementToDisplayText(rootError);
                return false;
            }

            if (!TryGetJsonProperty(root, "results", out JsonElement results) || results.ValueKind != JsonValueKind.Array) {
                if (GetJsonBool(root, "success", false)) {
                    outputUnits = CountMediaBenchmarkArtifacts(root);
                    return true;
                }

                error = FirstNonEmpty(GetJsonString(root, "message", ""), JsonElementToDisplayText(root));
                return false;
            }

            foreach (JsonElement result in results.EnumerateArray()) {
                bool success = GetJsonBool(result, "success", false);
                if (TryGetJsonProperty(result, "outputJson", out JsonElement outputJson)) {
                    bool outputSuccess = GetJsonBool(outputJson, "success", success);
                    if (success && outputSuccess) {
                        outputUnits = CountMediaBenchmarkArtifacts(outputJson);
                        return true;
                    }

                    error = FirstNonEmpty(GetJsonString(outputJson, "message", ""), error);
                }

                if (success) {
                    outputUnits = Math.Max(1, CountMediaBenchmarkArtifacts(result));
                    return true;
                }

                error = FirstNonEmpty(
                    GetJsonString(result, "error", ""),
                    GetJsonString(result, "content", ""),
                    error);
            }
        } catch (Exception ex) {
            error = ex.Message;
        }

        return false;
    }

    private static int CountMediaBenchmarkArtifacts(JsonElement element) {
        if (TryGetJsonProperty(element, "artifacts", out JsonElement artifacts) && artifacts.ValueKind == JsonValueKind.Array)
            return Math.Max(1, artifacts.GetArrayLength());
        return 1;
    }

    private static string JsonElementToDisplayText(JsonElement element) {
        if (element.ValueKind == JsonValueKind.String)
            return element.GetString() ?? "";
        if (element.ValueKind == JsonValueKind.Null || element.ValueKind == JsonValueKind.Undefined)
            return "";
        return TrimForDisplay(element.GetRawText(), 220);
    }

    private static string GetBenchmarkMediaToolName(string mediaKind) {
        return mediaKind == "image" ? "jackonnx_image_generate" :
               mediaKind == "audio" ? "jackonnx_audio_speech" :
               "jackonnx_video_generate";
    }

    private static int ComputeMediaModelBenchmarkRating(string mediaKind, double seconds) {
        if (double.IsNaN(seconds) || double.IsInfinity(seconds) || seconds <= 0)
            return 0;

        double targetSeconds = mediaKind == "video" ? 120d :
                               mediaKind == "audio" ? 15d :
                               45d;
        return (int)Math.Round(Math.Max(0, Math.Min(100, (targetSeconds / seconds) * 100d)));
    }

    private static string FormatModelBenchmarkCompletion(string modelId, ModelBenchmarkResult result) {
        string kind = (result.BenchmarkKind ?? "").Trim().ToLowerInvariant();
        string rate = FormatBenchmarkRate(kind, result.TokensPerSecond, result.TokensPerHour);
        return "Benchmarked " + modelId + ": " + rate + ", score " +
               result.Rating.ToString(CultureInfo.InvariantCulture) + "/100.";
    }

    private static string FormatBenchmarkRate(string benchmarkKind, double unitsPerSecond, double unitsPerHour) {
        benchmarkKind = (benchmarkKind ?? "").Trim().ToLowerInvariant();
        if (benchmarkKind == "image")
            return unitsPerSecond.ToString("0.000", CultureInfo.InvariantCulture) + " img/s";
        if (benchmarkKind == "audio")
            return unitsPerSecond.ToString("0.000", CultureInfo.InvariantCulture) + " audio/s";
        if (benchmarkKind == "video")
            return unitsPerSecond.ToString("0.000", CultureInfo.InvariantCulture) + " video/s";
        return unitsPerSecond.ToString("0.0", CultureInfo.InvariantCulture) + " tok/s";
    }

