    private static async Task WarmModelForBenchmarkAsync(System.Net.Http.HttpClient client, string endpoint, string modelId, CancellationToken cancellationToken) {
        var payload = new {
            model = modelId,
            messages = new[] {
                new { role = "user", content = "Reply with OK." }
            },
            temperature = 0,
            max_tokens = 1,
            stream = false
        };
        string json = JsonSerializer.Serialize(payload);
        using var content = new System.Net.Http.StringContent(json, Encoding.UTF8, "application/json");
        using System.Net.Http.HttpResponseMessage response = await client.PostAsync(endpoint, content, cancellationToken);
        string body = await response.Content.ReadAsStringAsync(cancellationToken);
        if (!response.IsSuccessStatusCode)
            throw new InvalidOperationException("Warm-up HTTP " + (int)response.StatusCode + " from " + endpoint + ": " + TrimForDisplay(body, 120));
    }

    private static int ExtractCompletionTokens(string json) {
        try {
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
            if (TryGetJsonProperty(document.RootElement, "usage", out JsonElement usage)) {
                long completion = GetJsonLong(usage, "completion_tokens", GetJsonLong(usage, "completionTokens", 0));
                if (completion > 0)
                    return (int)Math.Min(int.MaxValue, completion);
            }
        } catch {
        }

        return 0;
    }

    private static double ExtractBenchmarkTokensPerSecond(string json) {
        try {
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
            if (TryFindFirstJsonDoubleByExactKey(document.RootElement, out double value, out _,
                    "tokens_per_second",
                    "tokensPerSecond",
                    "completion_tokens_per_second",
                    "completionTokensPerSecond",
                    "predicted_per_second",
                    "predictedPerSecond",
                    "eval_tokens_per_second",
                    "evalTokensPerSecond",
                    "eval_rate",
                    "evalRate")) {
                return Math.Max(0, value);
            }
        } catch {
        }

        return 0;
    }

    private static double? ExtractBenchmarkDurationSeconds(string json) {
        try {
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
            JsonElement root = document.RootElement;
            if (TryFindFirstJsonDoubleByExactKey(root, out double explicitSeconds, out string explicitSecondsKey,
                    "elapsed_seconds",
                    "elapsedSeconds",
                    "generation_seconds",
                    "generationSeconds",
                    "completion_seconds",
                    "completionSeconds")) {
                return NormalizeBenchmarkDurationSeconds(explicitSeconds, explicitSecondsKey);
            }

            if (TryFindFirstJsonDoubleByExactKey(root, out double generationDuration, out string generationDurationKey,
                    "generation_duration",
                    "generationDuration",
                    "generation_time",
                    "generationTime",
                    "completion_duration",
                    "completionDuration",
                    "completion_time",
                    "completionTime")) {
                return NormalizeBenchmarkDurationSeconds(generationDuration, generationDurationKey);
            }

            if (TryFindFirstJsonDoubleByExactKey(root, out double totalDuration, out string totalDurationKey, "total_duration", "totalDuration") &&
                TryFindFirstJsonDoubleByExactKey(root, out double loadDuration, out _, "load_duration", "loadDuration") &&
                totalDuration > loadDuration) {
                return NormalizeBenchmarkDurationSeconds(totalDuration - loadDuration, totalDurationKey);
            }

            if (TryFindFirstJsonDoubleByExactKey(root, out double evalDuration, out string evalDurationKey, "eval_duration", "evalDuration"))
                return NormalizeBenchmarkDurationSeconds(evalDuration, evalDurationKey);
        } catch {
        }

        return null;
    }

    private static bool TryFindFirstJsonDoubleByExactKey(JsonElement element, out double value, out string key, params string[] names) {
        value = 0;
        key = "";
        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (JsonKeyEqualsAny(property.Name, names) && TryJsonElementToDouble(property.Value, out value) && value > 0) {
                    key = property.Name;
                    return true;
                }

                if (TryFindFirstJsonDoubleByExactKey(property.Value, out value, out key, names))
                    return true;
            }
        } else if (element.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement child in element.EnumerateArray()) {
                if (TryFindFirstJsonDoubleByExactKey(child, out value, out key, names))
                    return true;
            }
        }

        return false;
    }

    private static bool JsonKeyEqualsAny(string key, params string[] names) {
        string normalized = NormalizeJsonMetricKey(key);
        foreach (string name in names) {
            if (string.Equals(normalized, NormalizeJsonMetricKey(name), StringComparison.OrdinalIgnoreCase))
                return true;
        }

        return false;
    }

    private static bool TryJsonElementToDouble(JsonElement value, out double number) {
        if (value.ValueKind == JsonValueKind.Number && value.TryGetDouble(out number))
            return true;
        if (value.ValueKind == JsonValueKind.String && double.TryParse(value.GetString(), NumberStyles.Float, CultureInfo.InvariantCulture, out number))
            return true;

        number = 0;
        return false;
    }

    private static double? NormalizeBenchmarkDurationSeconds(double value, string key) {
        if (double.IsNaN(value) || double.IsInfinity(value) || value <= 0)
            return null;

        string normalized = NormalizeJsonMetricKey(key);
        if (normalized.Contains("millisecond", StringComparison.OrdinalIgnoreCase) || normalized.EndsWith("ms", StringComparison.OrdinalIgnoreCase))
            return value / 1000d;
        if (normalized.Contains("microsecond", StringComparison.OrdinalIgnoreCase))
            return value / 1_000_000d;
        if (normalized.Contains("nanosecond", StringComparison.OrdinalIgnoreCase))
            return value / 1_000_000_000d;
        if (normalized.Contains("second", StringComparison.OrdinalIgnoreCase))
            return value;

        if (value >= 1_000_000d)
            return value / 1_000_000_000d;
        if (value >= 1000d)
            return value / 1000d;
        return value;
    }

    private static int EstimateBenchmarkTokens(string json) {
        try {
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
            if (TryGetJsonProperty(document.RootElement, "choices", out JsonElement choices) && choices.ValueKind == JsonValueKind.Array) {
                string text = "";
                foreach (JsonElement choice in choices.EnumerateArray()) {
                    if (TryGetJsonProperty(choice, "message", out JsonElement message))
                        text += " " + GetJsonString(message, "content", "");
                    text += " " + GetJsonString(choice, "text", "");
                }
                return Math.Max(1, (int)Math.Ceiling(text.Split(new[] { ' ', '\t', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries).Length * 1.35));
            }
        } catch {
        }

        return 1;
    }

    private static int ComputeModelBenchmarkRating(double tokensPerSecond) {
        if (double.IsNaN(tokensPerSecond) || double.IsInfinity(tokensPerSecond) || tokensPerSecond <= 0)
            return 0;
        return (int)Math.Round(Math.Max(0, Math.Min(100, (tokensPerSecond / 120d) * 100d)));
    }

    private string BuildModelBenchmarksJson() {
        var results = _modelBenchmarkItems
            .Where(HasCompletedModelBenchmark)
            .Select(item => item.ToResult())
            .ToList();
        return results.Count == 0 ? "" : JsonSerializer.Serialize(results);
    }

    private string GetLatestModelBenchmarksJson(string fallback = "") {
        string current = BuildModelBenchmarksJson();
        if (HasCompletedModelBenchmark(current)) {
            _latestModelBenchmarksJson = current;
            return current;
        }

        if (HasCompletedModelBenchmark(_latestModelBenchmarksJson))
            return _latestModelBenchmarksJson;

        if (HasCompletedModelBenchmark(fallback)) {
            _latestModelBenchmarksJson = fallback;
            return fallback;
        }

        string saved = _settings?.HostModelBenchmarksJson ?? "";
        if (HasCompletedModelBenchmark(saved)) {
            _latestModelBenchmarksJson = saved;
            return saved;
        }

        return "";
    }

    private void CacheLatestModelBenchmarksJson(string json) {
        if (HasCompletedModelBenchmark(json))
            _latestModelBenchmarksJson = json;
    }

    private static bool HasCompletedModelBenchmark(ModelBenchmarkItem item) {
        return item != null &&
               (item.TokensPerSecond > 0 ||
                item.TokensPerHour > 0 ||
                item.OutputTokens > 0 ||
                item.DurationMs > 0 ||
                item.Rating > 0 ||
                !string.IsNullOrWhiteSpace(item.BenchmarkedUtc));
    }

    private string BuildModelCapabilitiesJson() {
        var capabilities = _modelBenchmarkItems
            .Where(item => !string.IsNullOrWhiteSpace(item.ModelId))
            .Select(item => new ModelCapabilityInfo {
                ModelId = item.ModelId,
                SupportsImages = item.SupportsImages || ModelNameLikelySupportsImages(item.ModelId),
                SupportsTools = item.SupportsTools || ModelNameLikelySupportsTools(item.ModelId),
                SupportsImageGeneration = item.SupportsImageGeneration || ModelNameLikelySupportsImageGeneration(item.ModelId),
                SupportsAudioGeneration = item.SupportsAudioGeneration || ModelNameLikelySupportsAudioGeneration(item.ModelId),
                SupportsVideoGeneration = item.SupportsVideoGeneration || ModelNameLikelySupportsVideoGeneration(item.ModelId),
                RequiresPayment = item.RequiresPayment,
                StripePriceId = item.StripePriceId,
                StripeAccount = item.StripeAccount,
                StripeUnitAmountCents = item.StripeUnitAmountCents,
                StripeCurrency = item.StripeCurrency,
                PaymentStatus = item.PaymentStatus,
                CheckoutConfigured = item.CheckoutConfigured
            })
            .ToList();
        foreach (ModelCapabilityInfo capability in capabilities)
            ApplyHostPaymentDefaults(capability);
        return capabilities.Count == 0 ? ApplyHostPaymentDefaultsToModelCapabilitiesJson(_detectedHostModelCapabilitiesJson) : JsonSerializer.Serialize(capabilities);
    }

    private static bool HasCompletedModelBenchmark(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return false;

        try {
            using JsonDocument document = JsonDocument.Parse(json);
            if (document.RootElement.ValueKind != JsonValueKind.Array)
                return false;

            foreach (JsonElement item in document.RootElement.EnumerateArray()) {
                double tokensPerSecond = GetJsonDouble(item, "tokensPerSecond", GetJsonDouble(item, "TokensPerSecond", 0));
                int rating = GetJsonInt(item, "rating", GetJsonInt(item, "Rating", GetJsonInt(item, "benchmarkRating", GetJsonInt(item, "BenchmarkRating", GetJsonInt(item, "score", GetJsonInt(item, "Score", 0))))));
                double tokensPerHour = GetJsonDouble(item, "tokensPerHour", GetJsonDouble(item, "TokensPerHour", 0));
                int outputTokens = GetJsonInt(item, "outputTokens", GetJsonInt(item, "OutputTokens", 0));
                double durationMs = GetJsonDouble(item, "durationMs", GetJsonDouble(item, "DurationMs", GetJsonDouble(item, "benchmarkDurationMs", GetJsonDouble(item, "BenchmarkDurationMs", 0))));
                string benchmarkedUtc = FirstNonEmpty(GetJsonString(item, "benchmarkedUtc", ""), GetJsonString(item, "BenchmarkedUtc", ""));
                if (tokensPerSecond > 0 || tokensPerHour > 0 || outputTokens > 0 || durationMs > 0 || rating > 0 || !string.IsNullOrWhiteSpace(benchmarkedUtc))
                    return true;
            }
        } catch { }

        return false;
    }

    private void LoadModelBenchmarksFromJson(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return;
        CacheLatestModelBenchmarksJson(json);
        try {
            List<ModelBenchmarkResult>? results = JsonSerializer.Deserialize<List<ModelBenchmarkResult>>(json);
            if (results == null)
                return;
            foreach (ModelBenchmarkResult result in results) {
                if (string.IsNullOrWhiteSpace(result.ModelId))
                    continue;
                ModelBenchmarkItem? item = _modelBenchmarkItems.FirstOrDefault(candidate => string.Equals(candidate.ModelId, result.ModelId, StringComparison.OrdinalIgnoreCase));
                if (item == null) {
                    item = new ModelBenchmarkItem { ModelId = result.ModelId };
                    _modelBenchmarkItems.Add(item);
                }
                    item.Apply(result);
            }
        } catch {
        }

        EnsureModelBenchmarkSelection();
        SyncModelBenchmarksToModelsManager();
    }

    private void RefreshBenchmarkSelectionState() {
        if (NoSelectedBenchmarkText == null || SelectedBenchmarkDetailsPanel == null || RunSelectedModelBenchmarkButton == null)
            return;

        ModelBenchmarkItem? selected = ModelBenchmarkComboBox?.SelectedItem as ModelBenchmarkItem;
        NoSelectedBenchmarkText.Visibility = selected == null ? Visibility.Visible : Visibility.Collapsed;
        SelectedBenchmarkDetailsPanel.Visibility = selected == null ? Visibility.Collapsed : Visibility.Visible;
        RunSelectedModelBenchmarkButton.IsEnabled = selected != null && !_modelBenchmarkInProgress && selected.CanBenchmark;
    }

    private void EnsureModelBenchmarkSelection() {
        if (ModelBenchmarkComboBox == null)
            return;

        ModelBenchmarkItem? selected = ModelBenchmarkComboBox.SelectedItem as ModelBenchmarkItem;
        if (selected != null && !_modelBenchmarkItems.Contains(selected))
            selected = null;
        if (selected == null && _modelBenchmarkItems.Count > 0)
            selected = _modelBenchmarkItems.FirstOrDefault();

        ModelBenchmarkComboBox.SelectedItem = selected;
        RefreshBenchmarkSelectionState();
    }

    private static void ReadLmStudioModelMetadata(JsonElement model, List<string> modelNames, List<string> gpuDetails, List<ModelCapabilityInfo> modelCapabilities, ref long maxTokens) {
        string modelName = FirstNonEmpty(
            GetJsonString(model, "id", ""),
            GetJsonString(model, "name", ""),
            GetJsonString(model, "path", ""));
        if (!string.IsNullOrWhiteSpace(modelName)) {
            ReadModelPaymentInfo(model, out bool requiresPayment, out string stripePriceId, out string stripeAccount, out long unitAmountCents, out string stripeCurrency, out string paymentStatus);
            modelNames.Add(modelName);
            AddOrUpdateModelCapability(modelCapabilities, new ModelCapabilityInfo {
                ModelId = modelName,
                SupportsImages = ModelNameLikelySupportsImages(modelName) || JsonElementIndicatesCapability(model, "vision", "image", "images", "multimodal", "vlm"),
                SupportsTools = ModelNameLikelySupportsTools(modelName) || JsonElementIndicatesCapability(model, "tool", "tools", "function", "function_calling", "tool_use"),
                SupportsImageGeneration = ModelNameLikelySupportsImageGeneration(modelName) || JsonElementIndicatesMediaGeneration(model, "image"),
                SupportsAudioGeneration = ModelNameLikelySupportsAudioGeneration(modelName) || JsonElementIndicatesMediaGeneration(model, "audio"),
                SupportsVideoGeneration = ModelNameLikelySupportsVideoGeneration(modelName) || JsonElementIndicatesMediaGeneration(model, "video"),
                RequiresPayment = requiresPayment,
                StripePriceId = stripePriceId,
                StripeAccount = stripeAccount,
                StripeUnitAmountCents = unitAmountCents,
                StripeCurrency = stripeCurrency,
                PaymentStatus = paymentStatus,
                CheckoutConfigured = !string.IsNullOrWhiteSpace(stripePriceId) || unitAmountCents > 0
            });
        }

        long detectedMaxTokens = FindLargestJsonLongByKey(model,
            "context_length",
            "max_context_length",
            "contextLength",
            "maxContextLength",
            "n_ctx",
            "ctx_size",
            "max_tokens",
            "maxTokens",
            "token_limit",
            "tokenLimit");
        if (detectedMaxTokens > maxTokens)
            maxTokens = detectedMaxTokens;

        CollectJsonMetricDetails(model, gpuDetails,
            "available_vram",
            "vram_available",
            "vram_free",
            "free_vram",
            "gpu_memory_available",
            "gpu_layers",
            "n_gpu_layers",
            "offload",
            "offloaded",
            "estimated_vram",
            "required_vram");
    }

    private static void AddOrUpdateModelCapability(List<ModelCapabilityInfo> modelCapabilities, ModelCapabilityInfo capability) {
        if (modelCapabilities == null || capability == null || string.IsNullOrWhiteSpace(capability.ModelId))
            return;
        NormalizeModelCapabilityPayment(capability);

        ModelCapabilityInfo? existing = modelCapabilities.FirstOrDefault(item => string.Equals(item.ModelId, capability.ModelId, StringComparison.OrdinalIgnoreCase));
        if (existing == null) {
            modelCapabilities.Add(capability);
            return;
        }

        existing.SupportsImages = existing.SupportsImages || capability.SupportsImages;
        existing.SupportsTools = existing.SupportsTools || capability.SupportsTools;
        existing.SupportsImageGeneration = existing.SupportsImageGeneration || capability.SupportsImageGeneration;
        existing.SupportsAudioGeneration = existing.SupportsAudioGeneration || capability.SupportsAudioGeneration;
        existing.SupportsVideoGeneration = existing.SupportsVideoGeneration || capability.SupportsVideoGeneration;
        existing.RequiresPayment = existing.RequiresPayment || capability.RequiresPayment;
        existing.StripePriceId = FirstNonEmpty(existing.StripePriceId, capability.StripePriceId);
        existing.StripeAccount = FirstNonEmpty(existing.StripeAccount, capability.StripeAccount);
        if (existing.StripeUnitAmountCents <= 0)
            existing.StripeUnitAmountCents = Math.Max(0L, capability.StripeUnitAmountCents);
        existing.StripeCurrency = FirstNonEmpty(existing.StripeCurrency, capability.StripeCurrency, "usd").ToLowerInvariant();
        existing.PaymentStatus = FirstNonEmpty(existing.PaymentStatus, capability.PaymentStatus);
        existing.CheckoutConfigured = existing.CheckoutConfigured || capability.CheckoutConfigured || !string.IsNullOrWhiteSpace(existing.StripePriceId) || existing.StripeUnitAmountCents > 0;
    }

    private static void NormalizeModelCapabilityPayment(ModelCapabilityInfo capability) {
        if (capability == null)
            return;
        capability.StripeCurrency = FirstNonEmpty(capability.StripeCurrency, "usd").ToLowerInvariant();
        capability.StripeUnitAmountCents = Math.Max(0L, capability.StripeUnitAmountCents);
        capability.CheckoutConfigured = capability.CheckoutConfigured || !string.IsNullOrWhiteSpace(capability.StripePriceId) || capability.StripeUnitAmountCents > 0;
        capability.RequiresPayment = capability.RequiresPayment || capability.CheckoutConfigured;
        capability.PaymentStatus = FirstNonEmpty(capability.PaymentStatus, capability.RequiresPayment ? "payment-required" : "");
    }

    private void ApplyHostPaymentDefaults(ModelCapabilityInfo capability) {
        if (capability == null)
            return;

        bool hostRequiresPayment = HostRequiresPaymentCheckBox?.IsChecked.GetValueOrDefault(false) == true;
        string hostPriceId = HostStripePriceIdTextBox?.Text ?? "";
        string hostAccount = HostStripeAccountTextBox?.Text ?? "";
        long hostUnitAmountCents = Math.Max(0L, ParseLong(HostStripeUnitAmountTextBox?.Text ?? "", 0));
        string hostCurrency = FirstNonEmpty(HostStripeCurrencyTextBox?.Text, "usd").ToLowerInvariant();
        if (!hostRequiresPayment && string.IsNullOrWhiteSpace(hostPriceId) && string.IsNullOrWhiteSpace(hostAccount) && hostUnitAmountCents <= 0) {
            NormalizeModelCapabilityPayment(capability);
            return;
        }

        capability.RequiresPayment = capability.RequiresPayment || hostRequiresPayment;
        capability.StripePriceId = FirstNonEmpty(capability.StripePriceId, hostPriceId);
        capability.StripeAccount = FirstNonEmpty(capability.StripeAccount, hostAccount);
        if (capability.StripeUnitAmountCents <= 0)
            capability.StripeUnitAmountCents = hostUnitAmountCents;
        capability.StripeCurrency = FirstNonEmpty(capability.StripeCurrency, hostCurrency, "usd").ToLowerInvariant();
        capability.PaymentStatus = FirstNonEmpty(capability.PaymentStatus, capability.RequiresPayment ? "payment-required" : "");
        capability.CheckoutConfigured = capability.CheckoutConfigured || !string.IsNullOrWhiteSpace(capability.StripePriceId) || capability.StripeUnitAmountCents > 0;
        NormalizeModelCapabilityPayment(capability);
    }

    private string ApplyHostPaymentDefaultsToModelCapabilitiesJson(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return json ?? "";
        bool hasHostPaymentDefaults =
            HostRequiresPaymentCheckBox?.IsChecked.GetValueOrDefault(false) == true ||
            !string.IsNullOrWhiteSpace(HostStripePriceIdTextBox?.Text) ||
            !string.IsNullOrWhiteSpace(HostStripeAccountTextBox?.Text) ||
            ParseLong(HostStripeUnitAmountTextBox?.Text ?? "", 0) > 0;
        if (!hasHostPaymentDefaults)
            return json;

        try {
            List<ModelCapabilityInfo>? capabilities = JsonSerializer.Deserialize<List<ModelCapabilityInfo>>(json);
            if (capabilities == null || capabilities.Count == 0)
                return json;
            foreach (ModelCapabilityInfo capability in capabilities)
                ApplyHostPaymentDefaults(capability);
            return JsonSerializer.Serialize(capabilities);
        } catch {
            return json;
        }
    }

    private static void ReadModelPaymentInfo(
        JsonElement element,
        out bool requiresPayment,
        out string stripePriceId,
        out string stripeAccount,
        out long unitAmountCents,
        out string stripeCurrency,
        out string paymentStatus) {
        JsonElement payment = element;
        if (TryGetJsonProperty(element, "payment", out JsonElement paymentElement) &&
            paymentElement.ValueKind == JsonValueKind.Object)
            payment = paymentElement;

        requiresPayment =
            GetJsonBool(payment, "requiresPayment", GetJsonBool(payment, "paymentRequired", false)) ||
            GetJsonBool(element, "requiresPayment", GetJsonBool(element, "paymentRequired", false));
        stripePriceId = FirstNonEmpty(
            GetJsonString(payment, "stripePriceId", ""),
            GetJsonString(payment, "priceId", ""),
            GetJsonString(element, "stripePriceId", ""),
            GetJsonString(element, "priceId", ""));
        stripeAccount = FirstNonEmpty(
            GetJsonString(payment, "stripeAccount", ""),
            GetJsonString(payment, "connectedAccount", ""),
            GetJsonString(payment, "account", ""),
            GetJsonString(element, "stripeAccount", ""),
            GetJsonString(element, "connectedAccount", ""),
            GetJsonString(element, "account", ""));
        unitAmountCents = Math.Max(0L, Math.Max(
            GetJsonLong(payment, "stripeUnitAmountCents", GetJsonLong(payment, "unitAmountCents", GetJsonLong(payment, "amountCents", 0))),
            GetJsonLong(element, "stripeUnitAmountCents", GetJsonLong(element, "unitAmountCents", GetJsonLong(element, "amountCents", 0)))));
        stripeCurrency = FirstNonEmpty(
            GetJsonString(payment, "stripeCurrency", ""),
            GetJsonString(payment, "currency", ""),
            GetJsonString(element, "stripeCurrency", ""),
            GetJsonString(element, "currency", ""),
            "usd").ToLowerInvariant();
        paymentStatus = FirstNonEmpty(
            GetJsonString(payment, "paymentStatus", ""),
            GetJsonString(payment, "status", ""),
            GetJsonString(element, "paymentStatus", ""));
    }

