    private static bool JsonElementIndicatesMediaGeneration(JsonElement element, string mediaKind) {
        if (element.ValueKind != JsonValueKind.Object || string.IsNullOrWhiteSpace(mediaKind))
            return false;

        string normalizedKind = mediaKind.Trim().ToLowerInvariant();
        string serviceId = normalizedKind + "_generation";
        string service = FirstNonEmpty(
            GetJsonString(element, "chat_service", ""),
            GetJsonString(element, "chatService", ""),
            GetJsonString(element, "service", ""));
        if (string.Equals(service, serviceId, StringComparison.OrdinalIgnoreCase) ||
            string.Equals(service, serviceId.Replace("_", "-"), StringComparison.OrdinalIgnoreCase))
            return true;

        string type = GetJsonString(element, "type", "");
        if (string.Equals(type, normalizedKind, StringComparison.OrdinalIgnoreCase))
            return true;

        string pascalKind = char.ToUpperInvariant(normalizedKind[0]) + normalizedKind.Substring(1);
        return JsonElementIndicatesCapability(
            element,
            serviceId,
            serviceId.Replace("_", "-"),
            serviceId.Replace("_", ""),
            "generates" + pascalKind,
            "jackonnx_" + normalizedKind,
            normalizedKind + "_generate",
            normalizedKind + ".generate");
    }

    private static bool JsonElementIndicatesCapability(JsonElement element, params string[] tokens) {
        if (tokens == null || tokens.Length == 0)
            return false;

        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                bool propertyMatches = TextContainsAnyToken(property.Name, tokens);
                JsonElement value = property.Value;
                if (propertyMatches && JsonElementIsTruthy(value))
                    return true;
                if (JsonElementIndicatesCapability(value, tokens))
                    return true;
            }
        } else if (element.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement child in element.EnumerateArray()) {
                if (JsonElementIndicatesCapability(child, tokens))
                    return true;
            }
        } else if (element.ValueKind == JsonValueKind.String) {
            return TextContainsAnyToken(element.GetString(), tokens);
        }

        return false;
    }

    private static bool JsonElementIsTruthy(JsonElement value) {
        if (value.ValueKind == JsonValueKind.True)
            return true;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetInt64(out long number))
            return number != 0;
        if (value.ValueKind == JsonValueKind.String) {
            string text = value.GetString() ?? "";
            return !string.IsNullOrWhiteSpace(text) &&
                   !text.Equals("false", StringComparison.OrdinalIgnoreCase) &&
                   !text.Equals("none", StringComparison.OrdinalIgnoreCase) &&
                   !text.Equals("0", StringComparison.OrdinalIgnoreCase) &&
                   !text.Equals("unknown", StringComparison.OrdinalIgnoreCase) &&
                   !text.Equals("n/a", StringComparison.OrdinalIgnoreCase);
        }
        return value.ValueKind == JsonValueKind.Array || value.ValueKind == JsonValueKind.Object;
    }

    private static bool TextContainsAnyToken(string? text, params string[] tokens) {
        if (string.IsNullOrWhiteSpace(text))
            return false;

        string lower = text.ToLowerInvariant();
        foreach (string token in tokens) {
            if (!string.IsNullOrWhiteSpace(token) && lower.Contains(token.ToLowerInvariant()))
                return true;
        }
        return false;
    }

    private static long FindLargestJsonLongByKey(JsonElement element, params string[] names) {
        long best = 0;
        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (JsonKeyMatches(property.Name, names))
                    best = Math.Max(best, JsonElementToLong(property.Value));
                best = Math.Max(best, FindLargestJsonLongByKey(property.Value, names));
            }
        } else if (element.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement child in element.EnumerateArray())
                best = Math.Max(best, FindLargestJsonLongByKey(child, names));
        }

        return best;
    }

    private static void CollectJsonMetricDetails(JsonElement element, List<string> details, params string[] names) {
        if (details.Count >= 8)
            return;

        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (JsonKeyMatches(property.Name, names)) {
                    string formatted = FormatJsonMetric(property.Name, property.Value);
                    if (!string.IsNullOrWhiteSpace(formatted))
                        details.Add(formatted);
                }

                CollectJsonMetricDetails(property.Value, details, names);
                if (details.Count >= 8)
                    return;
            }
        } else if (element.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement child in element.EnumerateArray()) {
                CollectJsonMetricDetails(child, details, names);
                if (details.Count >= 8)
                    return;
            }
        }
    }

    private static bool JsonKeyMatches(string key, params string[] names) {
        string normalized = NormalizeJsonMetricKey(key);
        foreach (string name in names) {
            string candidate = NormalizeJsonMetricKey(name);
            if (string.Equals(normalized, candidate, StringComparison.OrdinalIgnoreCase) ||
                normalized.Contains(candidate, StringComparison.OrdinalIgnoreCase))
                return true;
        }

        return false;
    }

    private static string NormalizeJsonMetricKey(string value) {
        return new string((value ?? "").Where(char.IsLetterOrDigit).Select(char.ToLowerInvariant).ToArray());
    }

    private static long JsonElementToLong(JsonElement value) {
        if (value.ValueKind == JsonValueKind.Number && value.TryGetInt64(out long number))
            return number;
        if (value.ValueKind == JsonValueKind.String && long.TryParse(value.GetString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out long parsed))
            return parsed;
        return 0;
    }

    private static string FormatJsonMetric(string key, JsonElement value) {
        string label = SplitJsonMetricLabel(key);
        if (value.ValueKind == JsonValueKind.String)
            return label + ": " + (value.GetString() ?? "");
        if (value.ValueKind == JsonValueKind.True || value.ValueKind == JsonValueKind.False)
            return label + ": " + value.ToString().ToLowerInvariant();
        if (value.ValueKind != JsonValueKind.Number)
            return "";

        if (!value.TryGetDouble(out double number))
            return "";

        string normalized = NormalizeJsonMetricKey(key);
        if ((normalized.Contains("vram", StringComparison.OrdinalIgnoreCase) ||
             normalized.Contains("memory", StringComparison.OrdinalIgnoreCase)) &&
            !normalized.Contains("layers", StringComparison.OrdinalIgnoreCase)) {
            return label + ": " + FormatMegabytes(number);
        }

        return label + ": " + number.ToString("0.###", CultureInfo.InvariantCulture);
    }

    private static string SplitJsonMetricLabel(string key) {
        string text = (key ?? "").Replace("_", " ").Replace("-", " ").Trim();
        return string.IsNullOrWhiteSpace(text) ? "metric" : text;
    }

    private static int? FindLmStudioProcessId() {
        Process[] processes;
        try {
            processes = Process.GetProcessesByName(LmStudioProcessName);
        } catch {
            return null;
        }

        try {
            foreach (Process process in processes) {
                try {
                    if (!process.HasExited)
                        return process.Id;
                } catch {
                    // Ignore races where Windows exits the process while we enumerate it.
                }
            }
        } finally {
            foreach (Process process in processes)
                process.Dispose();
        }

        return null;
    }

