    private void OnJackOnnxGenerationRequested(JackOnnxJobSnapshot job, JackOnnxGenerationRequest request) {
        TryBeginOnUi(() => {
            if (!_jackOnnxLoggedGenerationJobIds.Add(job.Id))
                return;

            AppendServiceEventLine("JackONNX", BuildJackOnnxGenerationRequestLogLine(job, request));
            RefreshMetrics();
        }, "JackONNX generation request");
    }

    private void OnJackOnnxProgressReported(JackOnnxProgress progress) {
        TryBeginOnUi(() => {
            string bucket = progress.State is JackOnnxJobState.Completed or JackOnnxJobState.Failed or JackOnnxJobState.Cancelled
                ? "terminal"
                : (Math.Floor(Math.Clamp(progress.Percent, 0, 100) / 10d) * 10d).ToString("0", CultureInfo.InvariantCulture);
            string signature = progress.JobId + "|" + progress.State + "|" + bucket + "|" + TrimForDisplay(progress.Message ?? "", 140);
            if (_jackOnnxLastProgressSignatureByJobId.TryGetValue(progress.JobId, out string? previous) &&
                string.Equals(previous, signature, StringComparison.Ordinal))
                return;

            _jackOnnxLastProgressSignatureByJobId[progress.JobId] = signature;
            AppendServiceEventLine(
                "JackONNX",
                "Job " + TrimForDisplay(progress.JobId, 24) + " " + progress.State + " " +
                Math.Clamp(progress.Percent, 0, 100).ToString("0", CultureInfo.InvariantCulture) + "% - " +
                TrimForDisplay(progress.Message ?? "", 220));
            RefreshMetrics();
        }, "JackONNX progress");
    }

    private static string BuildJackOnnxGenerationRequestLogLine(JackOnnxJobSnapshot job, JackOnnxGenerationRequest request) {
        string prompt = request switch {
            SpeechGenerationRequest speech => speech.Text,
            _ => request.Prompt
        };
        var parts = new List<string> {
            job.Kind + " generation queued",
            "job=" + TrimForDisplay(job.Id, 24)
        };
        if (!string.IsNullOrWhiteSpace(request.ModelId))
            parts.Add("model=" + TrimForDisplay(request.ModelId, 80));
        if (!string.IsNullOrWhiteSpace(prompt))
            parts.Add("prompt=\"" + TrimForDisplay(prompt.Replace("\r", " ").Replace("\n", " "), 160) + "\"");
        if (request is ImageGenerationRequest image) {
            parts.Add(image.Width.ToString(CultureInfo.InvariantCulture) + "x" + image.Height.ToString(CultureInfo.InvariantCulture));
            parts.Add("steps=" + image.Steps.ToString(CultureInfo.InvariantCulture));
        } else if (request is VideoGenerationRequest video) {
            parts.Add(video.Width.ToString(CultureInfo.InvariantCulture) + "x" + video.Height.ToString(CultureInfo.InvariantCulture));
            parts.Add("seconds=" + video.Seconds.ToString("0.###", CultureInfo.InvariantCulture));
            parts.Add("fps=" + video.Fps.ToString(CultureInfo.InvariantCulture));
        } else if (request is SpeechGenerationRequest speech) {
            parts.Add("voice=" + TrimForDisplay(speech.Voice, 60));
            parts.Add("sampleRate=" + speech.SampleRate.ToString(CultureInfo.InvariantCulture));
        } else if (request is AudioGenerationRequest audio) {
            parts.Add("seconds=" + audio.Seconds.ToString("0.###", CultureInfo.InvariantCulture));
            parts.Add("sampleRate=" + audio.SampleRate.ToString(CultureInfo.InvariantCulture));
        }
        if (request.Seed.HasValue)
            parts.Add("seed=" + request.Seed.Value.ToString(CultureInfo.InvariantCulture));

        return string.Join(" | ", parts);
    }

