    private ChatClientPermissionSnapshot ReadSelectedUserPermissionsSnapshot(WebAuthUserItem? user) {
        string ownerKey = string.IsNullOrWhiteSpace(user?.OwnerKey) ? "global" : user.OwnerKey;
        ChatClientPermissionSnapshot snapshot = _selectedWebAuthUserPermissions != null &&
            string.Equals(_selectedWebAuthUserPermissions.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase)
                ? _selectedWebAuthUserPermissions
                : _proxy.GetChatClientPermissionsDiagnostics(ownerKey);

        snapshot.OwnerKey = ownerKey;
        snapshot.AgentAccess = UserPermAgentAccessCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.VsCopilotTools = UserPermVsToolsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.InternetSearch = UserPermInternetSearchCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.FileUploads = UserPermFileUploadsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.ImageUploads = UserPermImageUploadsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.FileDownloads = UserPermFileDownloadsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.FtpServer = UserPermFtpServerCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.SqlAdmin = UserPermSqlAdminCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.TerminalCommands = UserPermTerminalCommandsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.TerminalForeverApproved = UserPermTerminalTrustCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.PcAccess = UserPermPcAccessCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamAgentAccess = UserDreamAgentAccessCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamVsCopilotTools = UserDreamVsToolsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamInternetSearch = UserDreamInternetSearchCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamFileUploads = UserDreamFileUploadsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamImageUploads = UserDreamImageUploadsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamFileDownloads = UserDreamFileDownloadsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamFtpServer = UserDreamFtpServerCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamSqlAdmin = UserDreamSqlAdminCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamTerminalCommands = UserDreamTerminalCommandsCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        snapshot.DreamPcAccess = UserDreamPcAccessCheckBox?.IsChecked.GetValueOrDefault() ?? false;
        return snapshot;
    }

    private void LoadSelectedWebAuthUserPermissions() {
        WebAuthUserItem? user = GetSelectedWebAuthUser();
        string ownerKey = string.IsNullOrWhiteSpace(user?.OwnerKey) ? "global" : user.OwnerKey;

        try {
            ChatClientPermissionSnapshot snapshot = _proxy.GetChatClientPermissionsDiagnostics(ownerKey);
            ApplyUserPermissionsSnapshot(snapshot);
            if (UserPermissionsStatusText != null)
                UserPermissionsStatusText.Text = user == null
                    ? "Loaded global default permissions."
                    : "Loaded permissions for " + user.UserName + ".";
        } catch (Exception ex) {
            ClearSelectedUserPermissionsUi("Permission load failed: " + TrimForDisplay(ex.Message, 160));
            AppendLog("Server permission load failed: " + TrimForDisplay(ex.Message, 180));
        }
    }

    private void SaveSelectedWebAuthUserPermissions() {
        WebAuthUserItem? user = GetSelectedWebAuthUser();

        try {
            ChatClientPermissionSnapshot snapshot = ReadSelectedUserPermissionsSnapshot(user);
            ChatClientPermissionSnapshot updated = _proxy.SaveChatClientPermissionsDiagnostics(snapshot);
            ApplyUserPermissionsSnapshot(updated);
            RefreshSessionsPanel(true);
            RefreshAccessibleDirectories(true);
            RefreshWorkspaceExplorer(true);
            RefreshWebAuthUsersPanel(true, updated.OwnerKey, refreshPermissions: false);
            ApplyUserPermissionsSnapshot(updated);
            string target = user == null ? "global defaults" : user.UserName;
            AppendLog("Saved chat permissions for " + target + ".");
            if (ServerManagementStatusText != null)
                ServerManagementStatusText.Text = "Saved permissions for " + target + ".";
            if (UserPermissionsStatusText != null)
                UserPermissionsStatusText.Text = user == null
                    ? "Saved global default permissions."
                    : "Saved permissions for " + user.UserName + ".";
        } catch (Exception ex) {
            AppendLog("Server permission save failed: " + TrimForDisplay(ex.Message, 180));
            if (UserPermissionsStatusText != null)
                UserPermissionsStatusText.Text = "Permission save failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private int GetSelectedUserRestrictionMinutes() {
        if (UserRestrictionDurationComboBox?.SelectedItem is ComboBoxItem item &&
            int.TryParse(item.Tag?.ToString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out int minutes))
            return Math.Max(0, minutes);
        return 60;
    }

    private void ApplyWebAuthUserUpdate(Func<WebAuthUserItem, WebAuthUserDiagnosticsSnapshot> update, string actionText) {
        WebAuthUserItem? user = GetSelectedWebAuthUser();
        if (user == null) {
            if (ServerManagementStatusText != null)
                ServerManagementStatusText.Text = "Select a WebAuth user first.";
            return;
        }

        try {
            WebAuthUserDiagnosticsSnapshot snapshot = update(user);
            AddOrUpdateWebAuthUserItem(snapshot, true);
            RefreshSessionsPanel(true);
            RefreshMetrics();
            if (ServerManagementStatusText != null)
                ServerManagementStatusText.Text = actionText + " " + snapshot.UserName + ".";
        } catch (Exception ex) {
            AppendLog("WebAuth user update failed: " + TrimForDisplay(ex.Message, 180));
            if (ServerManagementStatusText != null)
                ServerManagementStatusText.Text = "User update failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private string SelectedDreamOwnerKey() => DreamOwnerComboBox?.SelectedValue as string ?? "global";

    private void PromptForDreamHardwareRecommendation() {
        if (_startHiddenRequested || _proxy == null)
            return;
        try {
            DreamHardwareRecommendationSnapshot recommendation = _proxy.GetDreamHardwareRecommendationDiagnostics();
            if (!recommendation.Pending)
                return;
            string title = recommendation.Reason == "hardware-changed" ? "Dream Mode hardware changed" : "Dream Mode recommended settings";
            string message = (recommendation.Reason == "hardware-changed"
                    ? "JackLLM detected a hardware change."
                    : "JackLLM can tune Dream Mode for this PC.") +
                "\n\n" + (string.IsNullOrWhiteSpace(recommendation.PreviousHardware) ? "" : "Previous: " + recommendation.PreviousHardware + "\n") +
                "Current: " + recommendation.CurrentHardware +
                "\n\nApply the recommended resource thresholds? Choose No to keep your current thresholds.";
            MessageBoxResult answer = MessageBox.Show(this, message, title, MessageBoxButton.YesNo, MessageBoxImage.Question, MessageBoxResult.Yes);
            _proxy.ResolveDreamHardwareRecommendationDiagnostics(answer == MessageBoxResult.Yes ? "apply" : "keep");
        } catch (Exception ex) {
            AppendLog("Dream hardware recommendation prompt failed: " + TrimForDisplay(ex.Message, 180));
        }
    }

    private void RefreshDreamManagement(bool refreshOwners) {
        if (_proxy == null || DreamManagementStatusText == null || _refreshingDreamManagement)
            return;
        try {
            _refreshingDreamManagement = true;
            string selectedOwner = SelectedDreamOwnerKey();
            if (refreshOwners || DreamOwnerComboBox.ItemsSource == null) {
                IReadOnlyList<DreamOwnerSnapshot> owners = _proxy.GetDreamOwnersDiagnostics();
                DreamOwnerComboBox.ItemsSource = owners;
                DreamOwnerComboBox.SelectedValue = owners.Any(item => item.OwnerKey == selectedOwner) ? selectedOwner : "global";
            }
            string owner = SelectedDreamOwnerKey();
            DreamSettingsSnapshot settings = _proxy.GetDreamSettingsDiagnostics(owner);
            DreamStatusSnapshot status = _proxy.GetDreamStatusDiagnostics(owner);
            DreamEnabledCheckBox.IsChecked = settings.Enabled;
            string preset = settings.Preset ?? "custom";
            DreamPresetComboBox.SelectedItem = DreamPresetComboBox.Items.OfType<ComboBoxItem>().FirstOrDefault(item => string.Equals(item.Tag as string, preset, StringComparison.OrdinalIgnoreCase));
            if (DreamPresetComboBox.SelectedItem == null) DreamPresetComboBox.SelectedIndex = 4;
            DreamJournalListBox.ItemsSource = _proxy.GetDreamJournalDiagnostics(owner);
            DreamMobileDevicesListBox.ItemsSource = _proxy.GetMobileDreamDevicesDiagnostics();
            DreamManagementStatusText.Text = status.Status + " | " + status.Phase +
                (string.IsNullOrWhiteSpace(status.LimitingResource) ? "" : " | limited by " + status.LimitingResource) +
                " | CPU " + status.Resources.CpuPercent.ToString("0", CultureInfo.InvariantCulture) + "%" +
                " | RAM " + status.Resources.RamPercent.ToString("0", CultureInfo.InvariantCulture) + "%" +
                " | GPU " + status.Resources.GpuPercent.ToString("0", CultureInfo.InvariantCulture) + "%" +
                " | " + status.ProcessedSessions + " sessions / " + status.ProcessedMessages + " messages" +
                (string.IsNullOrWhiteSpace(status.NextRunUtc) ? "" : " | next " + status.NextRunUtc);
        } catch (Exception ex) {
            DreamManagementStatusText.Text = "Dream management refresh failed: " + TrimForDisplay(ex.Message, 180);
        } finally {
            _refreshingDreamManagement = false;
        }
    }

    private void RefreshDreamManagementButton_Click(object sender, RoutedEventArgs e) => RefreshDreamManagement(true);
    private void DreamOwnerComboBox_SelectionChanged(object sender, SelectionChangedEventArgs e) { if (!_refreshingDreamManagement) RefreshDreamManagement(false); }

    private void SaveDreamManagementButton_Click(object sender, RoutedEventArgs e) {
        try {
            string owner = SelectedDreamOwnerKey();
            DreamSettingsSnapshot settings = _proxy.GetDreamSettingsDiagnostics(owner);
