        try {
            ChatClientPermissionSnapshot snapshot = update(user);
            if (_selectedWebAuthUserPermissions == null ||
                string.Equals(_selectedWebAuthUserPermissions.OwnerKey, snapshot.OwnerKey, StringComparison.OrdinalIgnoreCase))
                ApplyUserPermissionsSnapshot(snapshot);
            RefreshWebAuthUsersPanel(true, snapshot.OwnerKey, refreshPermissions: false);
            ApplyUserPermissionsSnapshot(snapshot);
            RefreshSessionsPanel(true);
            RefreshMetrics();
            if (ServerManagementStatusText != null)
                ServerManagementStatusText.Text = actionText + " " + user.UserName + ".";
        } catch (Exception ex) {
            AppendLog("Server user update failed: " + TrimForDisplay(ex.Message, 180));
            if (ServerManagementStatusText != null)
                ServerManagementStatusText.Text = "User update failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

