    private void RefreshTrustAbusePanel(bool force) {
        try {
            var items = _proxy.GetTrustAbuseCases()
                .Select(TrustAbuseCaseItem.FromSnapshot)
                .ToList();
            _trustAbuseCaseItems.Clear();
            foreach (TrustAbuseCaseItem item in items)
                _trustAbuseCaseItems.Add(item);

            TrustAbuseSummarySnapshot summary = _proxy.GetTrustAbuseSummary();
            if (TrustAbuseSummaryText != null)
                TrustAbuseSummaryText.Text = "Reputation " + summary.ReputationScore.ToString(CultureInfo.InvariantCulture) + "/100 (" + summary.ReputationTier + ")" +
                                             " | open " + summary.OpenCases.ToString(CultureInfo.InvariantCulture) +
                                             " | disputes " + summary.DisputeCount.ToString(CultureInfo.InvariantCulture) +
                                             " | host " + summary.HostVerificationStatus +
                                             " | renter identity " + summary.RenterIdentityStatus +
                                             " | commands " + (summary.CommandsBlocked ? "blocked" : "allowed");
            if (force && TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = _trustAbuseCaseItems.Count.ToString(CultureInfo.InvariantCulture) + " trust case(s) loaded.";
        } catch (Exception ex) {
            AppendLog("Trust and abuse refresh failed: " + TrimForDisplay(ex.Message, 180));
            if (force && TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = "Trust refresh failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private void CreateTrustCaseButton_Click(object sender, RoutedEventArgs e) {
        try {
            string category = ReadComboTag(TrustCategoryComboBox, "dispute");
            string severity = ReadComboTag(TrustSeverityComboBox, "medium");
            var snapshot = new TrustAbuseCaseSnapshot {
                Category = category,
                Severity = severity,
                Status = "open",
                OwnerKey = TrustOwnerKeyTextBox?.Text ?? "",
                UserName = TrustUserNameTextBox?.Text ?? "",
                ServerId = TrustServerIdTextBox?.Text ?? "",
                ExternalIp = TrustExternalIpTextBox?.Text ?? "",
                Summary = TrustSummaryTextBox?.Text ?? "",
                Detail = TrustDetailTextBox?.Text ?? "",
                ReporterUserName = "JackLLM Workstation"
            };
            TrustAbuseCaseSnapshot created = _proxy.CreateTrustAbuseCase(snapshot);
            _trustAbuseCaseItems.Insert(0, TrustAbuseCaseItem.FromSnapshot(created));
            RefreshTrustAbusePanel(false);
            if (TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = "Opened trust case " + created.Id + ".";
        } catch (Exception ex) {
            AppendLog("Trust case create failed: " + TrimForDisplay(ex.Message, 180));
            if (TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = "Open case failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private void ApplyTrustInterventionButton_Click(object sender, RoutedEventArgs e) {
        if (TrustAbuseCasesListBox?.SelectedItem is not TrustAbuseCaseItem item) {
            if (TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = "Select a trust case first.";
            return;
        }

        try {
            string intervention = ReadComboTag(TrustInterventionComboBox, "resolve");
            string note = TrustDetailTextBox?.Text ?? "";
            TrustAbuseCaseSnapshot updated = _proxy.ApplyTrustAbuseAdminIntervention(item.Id, intervention, "JackLLM Workstation", note);
            RefreshTrustAbusePanel(false);
            TrustAbuseCaseItem? refreshed = _trustAbuseCaseItems.FirstOrDefault(candidate => candidate.Id == updated.Id);
            if (refreshed != null && TrustAbuseCasesListBox != null)
                TrustAbuseCasesListBox.SelectedItem = refreshed;
            RefreshWebAuthUsersPanel(true);
            RefreshSessionsPanel(true);
            RefreshServerPickerItems();
            if (TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = "Applied " + intervention + " to " + updated.Id + ".";
        } catch (Exception ex) {
            AppendLog("Trust intervention failed: " + TrimForDisplay(ex.Message, 180));
            if (TrustAbuseStatusText != null)
                TrustAbuseStatusText.Text = "Intervention failed: " + TrimForDisplay(ex.Message, 160);
        }
    }

    private static string ReadComboTag(System.Windows.Controls.ComboBox? comboBox, string fallback) {
        if (comboBox?.SelectedItem is ComboBoxItem item)
            return item.Tag?.ToString() ?? fallback;
        return fallback;
    }

    private void LoadPendingTerminalPermissionRequests() {
        try {
            foreach (TerminalPermissionRequestSnapshot request in _proxy.GetPendingTerminalPermissionRequests()) {
                if (_terminalPermissionRequests.Any(item => item.Id == request.Id))
                    continue;

                var item = TerminalPermissionRequestItem.FromSnapshot(request);
                _terminalPermissionRequests.Insert(0, item);
                ShowTerminalPermissionToast(item);
            }
            RefreshSessionsPanel(true);
        } catch (Exception ex) {
            AppendLog("Terminal permission requests unavailable: " + TrimForDisplay(ex.Message, 180));
        }
    }

