    private void AppendLog(string? text) {
        if (string.IsNullOrEmpty(text))
            return;

        string safe = NormalizeLogText(text);
        if (!safe.EndsWith(Environment.NewLine, StringComparison.Ordinal))
            safe += Environment.NewLine;

        Debug.Write(safe);
        if (!_suppressAppendLogServiceRouting && _uiReady)
            RecordDiagnostics(safe);
    }

    private bool ShouldMirrorServiceLogToDebugger(string serviceName) {
        string normalized = NormalizeServiceName(serviceName);
        return !string.IsNullOrWhiteSpace(normalized) && _selectedServiceLogNames.Contains(normalized);
    }

    private void AppendServiceLogToDebugger(string serviceName, string line) {
        string safe = NormalizeLogText("[" + NormalizeServiceName(serviceName) + "] " + line);
        if (!safe.EndsWith(Environment.NewLine, StringComparison.Ordinal))
            safe += Environment.NewLine;

        Debug.Write(safe);
    }

    private bool IsShellPublishingEnabled() {
        return ShellEnabledCheckBox == null || ShellEnabledCheckBox.IsChecked.GetValueOrDefault(true);
    }

    private void AppendSyntaxLogLine(Paragraph paragraph, string line) {
        foreach (string token in SplitLogSyntaxTokens(line)) {
            var run = new Run(token) {
                Foreground = GetLogTokenBrush(token)
            };
            if (IsLogKeyword(token) || IsServiceToken(token))
                run.FontWeight = FontWeights.SemiBold;
            paragraph.Inlines.Add(run);
        }
    }

    private static IEnumerable<string> SplitLogSyntaxTokens(string line) {
        if (string.IsNullOrEmpty(line))
            yield break;

        var builder = new StringBuilder();
        char previousKind = '\0';
        for (int i = 0; i < line.Length; i++) {
            char ch = line[i];
            if (ch == '[') {
                int close = line.IndexOf(']', i + 1);
                if (close > i) {
                    if (builder.Length > 0) {
                        yield return builder.ToString();
                        builder.Clear();
                    }

                    yield return line.Substring(i, close - i + 1);
                    i = close;
                    previousKind = '\0';
                    continue;
                }
            }

            char kind = char.IsWhiteSpace(ch) ? 'w'
                : "{}[]():,=".IndexOf(ch) >= 0 ? 'p'
                : ch == '"' || ch == '\'' ? 'q'
                : 't';
            if (builder.Length > 0 && kind != previousKind) {
                yield return builder.ToString();
                builder.Clear();
            }
            builder.Append(ch);
            previousKind = kind;
        }
        if (builder.Length > 0)
            yield return builder.ToString();
    }

    private static Brush GetLogTokenBrush(string token) {
        string trimmed = token.Trim();
        if (trimmed.Length == 0)
            return new SolidColorBrush(Color.FromArgb(0xA8, 0xFF, 0xFF, 0xFF));

        string core = NormalizeLogToken(trimmed);
        if (IsLogErrorKeyword(core))
            return new SolidColorBrush(Color.FromRgb(0xFF, 0x5C, 0x7A));
        if (TryGetServiceLogColor(core, out Color serviceColor))
            return new SolidColorBrush(serviceColor);
        if (IsLogWarningKeyword(core))
            return new SolidColorBrush(Color.FromRgb(0xFF, 0xB0, 0x20));
        if (IsLogPositiveKeyword(core))
            return new SolidColorBrush(Color.FromRgb(0x7C, 0xFF, 0x9D));
        if (trimmed.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || trimmed.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            return new SolidColorBrush(Color.FromRgb(0x62, 0xB8, 0xFF));
        if (trimmed.Length == 1 && "{}[]():,=".Contains(trimmed, StringComparison.Ordinal))
            return new SolidColorBrush(Color.FromRgb(0xFB, 0x71, 0x85));
        if (trimmed.Length >= 2 && (trimmed[0] == '"' || trimmed[0] == '\''))
            return new SolidColorBrush(Color.FromRgb(0xA7, 0xF3, 0xD0));
        return new SolidColorBrush(Color.FromArgb(0xA8, 0xFF, 0xFF, 0xFF));
    }

    private static bool IsLogKeyword(string token) {
        string value = NormalizeLogToken(token);
        return IsLogErrorKeyword(value) ||
               IsLogWarningKeyword(value) ||
               IsLogPositiveKeyword(value) ||
               value.Equals("denied", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("stopped", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsServiceToken(string token) {
        return TryGetServiceLogColor(NormalizeLogToken(token), out _);
    }

    private static string NormalizeLogToken(string token) {
        string value = (token ?? "").Trim();
        if (value.Length >= 2 && value[0] == '[' && value[^1] == ']')
            value = value[1..^1];
        return value.Trim().TrimEnd(':', ',', '.', ';');
    }

    private static bool IsLogErrorKeyword(string value) {
        return value.Equals("error", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("failed", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("failure", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("exception", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("invalid", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("denied", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsLogWarningKeyword(string value) {
        return value.Equals("warning", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("warn", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsLogPositiveKeyword(string value) {
        return value.Equals("approved", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("running", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("loaded", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("started", StringComparison.OrdinalIgnoreCase) ||
               value.Equals("ready", StringComparison.OrdinalIgnoreCase);
    }

    private static bool TryGetServiceLogColor(string value, out Color color) {
        value = NormalizeServiceName(value);
        if (ServiceLogColors.TryGetValue(value, out color))
            return true;

        string compact = value.Replace("_", " ").Replace("-", " ");
        foreach (KeyValuePair<string, Color> entry in ServiceLogColors) {
            if (string.Equals(compact, entry.Key, StringComparison.OrdinalIgnoreCase)) {
                color = entry.Value;
                return true;
            }
        }

        color = default;
        return false;
    }

    private static string NormalizeServiceName(string? serviceName) {
        string value = (serviceName ?? "").Trim();
        if (value.Length >= 2 && value[0] == '[' && value[^1] == ']')
            value = value[1..^1].Trim();
        string compact = value.Replace("_", " ").Replace("-", " ").Trim();
        if (string.Equals(compact, "LmVsProxy", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(compact, "Lm Vs Proxy", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(compact, "Proxy", StringComparison.OrdinalIgnoreCase))
            return "Workstation";
        if (string.Equals(compact, "Web Client UI", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(compact, "Web UI Chat", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(compact, "Chat UI", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(compact, "WebAuth", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(compact, "Http", StringComparison.OrdinalIgnoreCase))
            return "HTTP";
        return value;
    }

    private static bool ServiceNameEquals(string? left, string right) {
        return string.Equals(NormalizeServiceName(left), NormalizeServiceName(right), StringComparison.OrdinalIgnoreCase);
    }

    private static string NormalizeLogText(string text) {
        var builder = new StringBuilder(text.Length);
        foreach (char ch in text) {
            if (ch == '\r' || ch == '\n' || ch == '\t' || ch >= ' ')
                builder.Append(ch <= '\u00FF' ? ch : "\\u" + ((int)ch).ToString("X4", CultureInfo.InvariantCulture));
            else
                builder.Append(' ');
        }
        return builder.ToString();
    }

    private void RecordDiagnostics(string? text) {
        if (string.IsNullOrWhiteSpace(text))
            return;

        string[] lines = text.Split(new[] { "\r\n", "\n", "\r" }, StringSplitOptions.RemoveEmptyEntries);
        _logLines += Math.Max(1, lines.Length);
        string eventSummary = NormalizeLogText(lines[^1]);
        string modelRuntimeName = GetModelRuntimeServiceName();
        string lower = text.ToLowerInvariant();
        var routedServices = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

        void Route(string serviceName, params string[] relatedServices) {
            string normalizedServiceName = NormalizeServiceName(serviceName);
            if (string.IsNullOrWhiteSpace(normalizedServiceName))
                return;

            var pulseNames = new List<string> { normalizedServiceName };
            if (relatedServices != null) {
                foreach (string relatedService in relatedServices) {
                    string normalizedRelatedService = NormalizeServiceName(relatedService);
                    if (!string.IsNullOrWhiteSpace(normalizedRelatedService) &&
                        !pulseNames.Contains(normalizedRelatedService, StringComparer.OrdinalIgnoreCase))
                        pulseNames.Add(normalizedRelatedService);
                }
            }

            PulseService(pulseNames.ToArray());
            if (routedServices.Add(normalizedServiceName))
                AppendServiceEventLine(normalizedServiceName, eventSummary);
        }

        Route("Workstation");
        if (TextContainsAnyToken(lower, "[request]", "[http]", "/v1/chat/completions", "/v1/responses"))
            _requestCount++;
        if (TextContainsAnyToken(lower, "[responses bridge]", "/v1/responses"))
            _responsesBridgeCount++;
        if (TextContainsAnyToken(lower, "tool call", "tool_calls", "[tool calls]", "[native tool calls]", "[conversation tool"))
            _toolCallCount++;
        if (lower.Contains("stream"))
            _streamCount++;
        if (TextContainsAnyToken(lower, "error", "failed", "exception", "invalid", "denied", "rejected", "timed out"))
            _errorLines++;

        if (TextContainsAnyToken(lower, "lm studio", "[lm studio]")) {
            _lmStudioEventCount++;
            Route("LM Studio", "Workstation");
        }
        if (TextContainsAnyToken(lower, "llmruntime", "embedded runtime", "[model runtime]", "/api/v1/models", "/api/models")) {
            _lmStudioEventCount++;
            Route("LlmRuntime", "Workstation", "JackONNX");
        }
        if (TextContainsAnyToken(lower,
                "[http]",
                "http ",
                "http/",
                "http:",
                "https:",
                "[chat ui]",
                "[chat storage]",
                "[webauth]",
                "[token rate]",
                "[llm client api]",
                "/api/chat",
                "/api/models",
                "/api/chat-services",
                "/api/health",
                "/api/server-hardware",
                "/api/ftp-config",
                "/sql",
                "/api/prompt-intellisense",
                "registration request",
                "token-rate request",
                "client admin",
                "chat client permissions")) {
            _chatUiEventCount += Math.Max(1, lines.Length);
            _activePipelineKind = "web-chat";
            Route("HTTP", "Workstation", modelRuntimeName);
        }
        if (TextContainsAnyToken(lower, "vs copilot", "/v1/responses", "[responses bridge]", "[http]", "[request]")) {
            _activePipelineKind = "vs-copilot";
            Route("VS Copilot", "Workstation", modelRuntimeName);
        }
        if (TextContainsAnyToken(lower,
                "agent",
                "tool call",
                "tool_calls",
                "[tool calls]",
                "[native tool calls]",
                "[conversation tool",
                "[proxy research]",
                "[vs agent tool]",
                "vs_read_file",
                "vs_write_file",
                "vs_replace_in_file",
                "get_file",
                "replace_string_in_file",
                "create_file")) {
            _agentServiceEventCount++;
            if (lower.Contains("[chat ui]"))
                _activePipelineKind = "agent";
            Route("Agent Tools", "Workstation", modelRuntimeName);
        }
        if (lower.Contains("companion")) {
            _activePipelineKind = "companion";
            Route("Companion", "HTTP", "Workstation");
        }
        if (TextContainsAnyToken(lower,
                "internet_search",
                "searchinternet",
                "[searchinternet service]",
                "[internet search]",
                "[proxy research]",
                "nuget_search",
                "github_code_search",
                "search service")) {
            _internetSearchEventCount++;
            _activePipelineKind = "internet-search";
            Route("Internet Search", "Agent Tools", "Workstation", modelRuntimeName);
        }
        if (TextContainsAnyToken(lower,
                "reflectionservice",
            "reflection service",
            "[reflection]",
            "/reflect")) {
            _reflectionServiceEventCount++;
            _activePipelineKind = "reflection";
            Route("Reflection", "Workstation", modelRuntimeName);
        }
        if (TextContainsAnyToken(lower, "prompt intellisense", "/api/prompt-intellisense", "prompt_intellisense")) {
            _promptIntellisenseEventCount++;
            _activePipelineKind = "prompt-intellisense";
            Route("Prompt Intellisense", "HTTP");
        }
        if (TextContainsAnyToken(lower,
                "[chat storage]",
                "[filesystem permission]",
                "file upload",
                "session file",
                "download_file",
                "sessionfiles",
                "filesystem access",
                "directory browser",
                "solution explorer",
                "file preview",
                "file download",
                "session zip")) {
            _sessionFileEventCount++;
            Route("Session Files", "Agent Tools");
        }
        if (TextContainsAnyToken(lower,
                "terminal service",
                "[terminal permission]",
                "run_command_in_terminal",
                "terminal approvals")) {
            _terminalServiceEventCount++;
            _activePipelineKind = "terminal";
            Route("Terminal", "Workstation", "Agent Tools", modelRuntimeName);
        }
        if (TextContainsAnyToken(lower, "[ftp]", "ftp config", "ftp server", "ftp permission", " ftp ", "ftp ")) {
            _ftpEventCount++;
            _activePipelineKind = "ftp";
            Route("FTP", "Session Files");
        }
        if (TextContainsAnyToken(lower, "port forwarding", "nat interface", "forwarding tcp")) {
            _portForwardingEventCount++;
            Route("Port Forwarding");
        }
        if (TextContainsAnyToken(lower, "jackonnx", "image_generation", "audio_generation", "video_generation", "image generation", "audio generation", "video generation", "media route")) {
            Route("JackONNX", "LlmRuntime");
        }

        _lastEventText = "Last event: " + TrimForDisplay(lines[^1], 180);
    }

    private void PulseService(params string[] names) {
        DateTimeOffset now = DateTimeOffset.UtcNow;
        foreach (string name in names) {
            string normalizedName = NormalizeServiceName(name);
            if (string.IsNullOrWhiteSpace(normalizedName))
                continue;

            _servicePulseUtc[normalizedName] = now;
        }
    }

    private bool WasServicePulsed(string name, DateTimeOffset now) {
        string normalizedName = NormalizeServiceName(name);
        return !string.IsNullOrWhiteSpace(normalizedName) &&
               _servicePulseUtc.TryGetValue(normalizedName, out DateTimeOffset lastPulse) &&
               now - lastPulse <= TimeSpan.FromMilliseconds(950);
    }

    private void RefreshMetrics() {
        bool proxyRunning = _proxy.IsListening;
        bool running = proxyRunning;
        StartStopButton.Content = proxyRunning ? "Stop JACK" : "Start JACK";
        StartStopButton.Background = running ? new SolidColorBrush(Color.FromRgb(137, 52, 66)) : new SolidColorBrush(Color.FromRgb(31, 122, 104));
        bool chatRunning = _proxy.IsChatServerCreated && _proxy.ChatServer.IsListening;
        OpenChatButton.IsEnabled = chatRunning;
        SocketChatButton.IsEnabled = chatRunning;
        if (WebUiReloadButton != null)
            WebUiReloadButton.IsEnabled = chatRunning;
        if (WebUiOpenExternalButton != null)
            WebUiOpenExternalButton.IsEnabled = chatRunning;
        if (!chatRunning && WebUiTabItem?.IsSelected == true)
            SetWebUiStatus("Start JACK to load the local Web UI.");
        if (chatRunning && string.IsNullOrWhiteSpace(_pendingWebUiUrl))
            SetWebUiStatus("Web UI: " + BuildWebUiDisplayUrl(BuildChatServerEndpoint("/")));
        if (OpenMagicWorkflowButton != null)
            OpenMagicWorkflowButton.IsEnabled = chatRunning;
        if (RefreshMagicWorkflowButton != null)
            RefreshMagicWorkflowButton.IsEnabled = chatRunning;
