    private void RefreshServerManagementLivePanelsIfDue() {
        if (!IsServerManagementTabSelected() && string.IsNullOrWhiteSpace(_selectedSessionId))
            return;

        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (IsServerManagementTabSelected() && now - _lastServerUserUsageRefreshUtc >= TimeSpan.FromSeconds(3)) {
            _lastServerUserUsageRefreshUtc = now;
            RefreshWebAuthUsersPanel(false, refreshPermissions: false);
        }

        if (!IsServerManagementTabSelected() &&
            SessionLogBrowserHost?.IsVisible == true &&
            now - _lastSessionLogRefreshUtc >= TimeSpan.FromSeconds(3)) {
            _lastSessionLogRefreshUtc = now;
            RefreshSessionLogPreview(false);
        }
    }

    private void RefreshShellRelayHealthIfDue() {
        if (!_uiReady || _isStopping || _shellModeRecoveryInProgress || !IsShellPublishingEnabled())
            return;
        if (!_proxy.IsListening && !_shellModeRunning)
            return;

        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (now - _lastShellRelayHealthCheckUtc < ShellRelayHealthCheckInterval)
            return;

        _lastShellRelayHealthCheckUtc = now;
        _ = RefreshShellRelayHealthAsync();
    }

    private async Task RefreshShellRelayHealthAsync() {
        if (_shellModeRecoveryInProgress)
            return;

        _shellModeRecoveryInProgress = true;
        try {
            if (!_shellModeRunning || _shellRelays.Count == 0) {
                await RestartShellModeForRecoveryAsync("Shell publishing is enabled, but no local relay client is running.");
                return;
            }

            List<ShellRelayItem> items = await RefreshShellInstancesAsync();
            DateTimeOffset now = DateTimeOffset.UtcNow;
            var localRelayIds = new HashSet<string>(_shellRelays.Select(relay => relay.Id), StringComparer.OrdinalIgnoreCase);
            List<ShellRelayItem> localItems = items
                .Where(item => localRelayIds.Contains(item.Id))
                .ToList();

            if (localItems.Count == 0) {
                await RestartShellModeForRecoveryAsync("The master server no longer reports the local shell relay.");
                return;
            }

            bool liveAgentAvailable = localItems.Any(item =>
                item.Enabled &&
                (item.WebSocketTunnelConnected ||
                 item.WaitingAgents > 0 ||
                 item.ActiveSessions > 0));
            if (liveAgentAvailable) {
                _shellRelayNoAgentSinceUtc = DateTimeOffset.MinValue;
                return;
            }

            bool recentlySeen = localItems.Any(item =>
                item.Enabled &&
                IsShellRelayRecentlySeen(item, now));
            if (recentlySeen && _shellRelayNoAgentSinceUtc == DateTimeOffset.MinValue) {
                _shellRelayNoAgentSinceUtc = now;
                return;
            }

            if (_shellRelayNoAgentSinceUtc == DateTimeOffset.MinValue) {
                _shellRelayNoAgentSinceUtc = now;
                return;
            }

            if (now - _shellRelayNoAgentSinceUtc >= ShellRelayRecoveryNoAgentDelay)
                await RestartShellModeForRecoveryAsync("The master server has not seen an available reverse agent for " + ShellRelayRecoveryNoAgentDelay.TotalSeconds.ToString("0", CultureInfo.InvariantCulture) + " seconds.");
        } catch (Exception ex) {
            AppendLog("Shell relay health check failed: " + TrimForDisplay(ex.Message, 180));
        } finally {
            _shellModeRecoveryInProgress = false;
        }
    }

    private async Task RestartShellModeForRecoveryAsync(string reason) {
        _shellRelayNoAgentSinceUtc = DateTimeOffset.MinValue;
        AppendLog("Shell relay recovery: " + reason);
        await StartShellModeAsync(forceRestart: true);
    }

    private static bool IsShellRelayRecentlySeen(ShellRelayItem item, DateTimeOffset now) {
        if (item == null || string.IsNullOrWhiteSpace(item.LastAgentSeenUtc))
            return false;
        if (!DateTimeOffset.TryParse(item.LastAgentSeenUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset lastSeen))
            return false;
        return now.ToUniversalTime() - lastSeen.ToUniversalTime() <= ShellRelayRecentAgentGrace;
    }

    private void RefreshImageRuntimeCompatibilityWarningIfDue() {
        if (_imageRuntimeCompatibilityRefreshInProgress || _shutdownCompleted || _isStopping)
            return;

        if (GetSelectedModelRuntimeProvider() == RuntimeProviderLmStudio) {
            ClearImageRuntimeCompatibilityWarning();
            return;
        }

        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (now - _lastImageRuntimeCompatibilityRefreshUtc < LocalRuntimeWarningRefreshInterval)
            return;

        string runtimeBaseUrl = GetExternalModelManagerRuntimeBaseUrl();
        if (string.IsNullOrWhiteSpace(runtimeBaseUrl))
            runtimeBaseUrl = _proxy?.LocalModelRuntime?.OpenAiBaseUrl ?? "";
        if (string.IsNullOrWhiteSpace(runtimeBaseUrl)) {
            ClearImageRuntimeCompatibilityWarning();
            return;
        }

        _lastImageRuntimeCompatibilityRefreshUtc = now;
        _imageRuntimeCompatibilityRefreshInProgress = true;
        _ = Task.Run(async () => {
            try {
                await RefreshImageRuntimeCompatibilityWarningAsync(runtimeBaseUrl.TrimEnd('/')).ConfigureAwait(false);
            } finally {
                _imageRuntimeCompatibilityRefreshInProgress = false;
            }
        });
    }

    private async Task RefreshImageRuntimeCompatibilityWarningAsync(string runtimeBaseUrl) {
        try {
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(12));
            using HttpResponseMessage response = await client.GetAsync(runtimeBaseUrl + "/api/v1/runtime/compatibility").ConfigureAwait(false);
            string json = await response.Content.ReadAsStringAsync().ConfigureAwait(false);
            if (!response.IsSuccessStatusCode || string.IsNullOrWhiteSpace(json))
                return;

            using JsonDocument document = JsonDocument.Parse(json);
            JsonElement root = document.RootElement;
            bool repairRequired = TryReadJsonBool(root, "requiresPytorchRepair");
            bool generationDisabled = TryReadJsonBool(root, "generationDisabled");
            bool gpuEnabled = TryReadJsonBool(root, "isGpuGenerationEnabled");
            string status = TryReadJsonString(root, "status");
            if (!repairRequired && !generationDisabled && (gpuEnabled || status.Equals("ok", StringComparison.OrdinalIgnoreCase))) {
                TryBeginOnUi(ClearImageRuntimeCompatibilityWarning, "clear image runtime warning");
                return;
            }

            string message = FirstNonEmpty(TryReadJsonString(root, "message"), "Local image generation is disabled.");
            string pythonPath = TryReadNestedJsonString(root, "diagnostics", "python", "executablePath");
            bool canRepair = HasCompatibilityAction(root, "repair_pytorch", requireEnabled: true) || repairRequired;
            bool canInstallCuda = HasCompatibilityAction(root, "install_cuda", requireEnabled: false);
            string signal = message;
            if (!string.IsNullOrWhiteSpace(pythonPath))
                signal += " Python: " + TrimForDisplay(pythonPath, 110) + ".";
            string recommendation = canRepair
                ? "Use Repair PyTorch from Workstation; CUDA can be installed while JackLLM's Python environment still lacks CUDA-enabled torch."
                : canInstallCuda
                    ? "Open the CUDA installer page, then run Repair PyTorch so JackLLM's image-generation Python can use CUDA."
                    : "Repair or configure PyTorch in JackLLM's image-generation Python environment.";
            string severity = repairRequired || generationDisabled ? "WARN" : "INFO";

            TryBeginOnUi(() => {
                _imageRuntimeCompatibilityWarningActive = true;
                _imageRuntimeCompatibilityWarningSeverity = severity;
                _imageRuntimeCompatibilityWarningSignal = TrimForDisplay(signal, 260);
                _imageRuntimeCompatibilityWarningRecommendation = recommendation;
                _imageRuntimeCompatibilityCanRepair = canRepair;
                _imageRuntimeCompatibilityCanInstallCuda = canInstallCuda;
                RefreshModelReconfigurationSuggestions();
            }, "image runtime warning update");
        } catch (Exception ex) {
            TryBeginOnUi(() => AppendLog("Image runtime compatibility warning refresh failed: " + TrimForDisplay(ex.Message, 160)), "image runtime warning failure");
        }
    }

    private void ClearImageRuntimeCompatibilityWarning() {
        if (!_imageRuntimeCompatibilityWarningActive &&
            string.IsNullOrWhiteSpace(_imageRuntimeCompatibilityWarningSignal))
            return;

        _imageRuntimeCompatibilityWarningActive = false;
        _imageRuntimeCompatibilityWarningSeverity = "WARN";
        _imageRuntimeCompatibilityWarningSignal = "";
        _imageRuntimeCompatibilityWarningRecommendation = "";
        _imageRuntimeCompatibilityCanRepair = false;
        _imageRuntimeCompatibilityCanInstallCuda = false;
        RefreshModelReconfigurationSuggestions();
    }

    private void RefreshPersonaPlexWarningIfDue() {
        if (_personaPlexStatusRefreshInProgress || _shutdownCompleted || _isStopping)
            return;

        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (now - _lastPersonaPlexStatusRefreshUtc < LocalRuntimeWarningRefreshInterval)
            return;

        string statusUrl = PersonaPlexApiUrl("/api/personaplex/status");
        string installToken = _proxy?.PersonaPlexInstallToken ?? "";
        if (string.IsNullOrWhiteSpace(statusUrl) || string.IsNullOrWhiteSpace(installToken))
            return;

        _lastPersonaPlexStatusRefreshUtc = now;
        _personaPlexStatusRefreshInProgress = true;
        _ = Task.Run(async () => {
            try {
                await RefreshPersonaPlexWarningAsync(statusUrl, installToken).ConfigureAwait(false);
            } finally {
                _personaPlexStatusRefreshInProgress = false;
            }
        });
    }

    private async Task RefreshPersonaPlexWarningAsync(string statusUrl, string installToken) {
        try {
            using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(10));
            using var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, statusUrl);
            request.Headers.TryAddWithoutValidation(PersonaPlexInstallHeaderName, installToken);
            using HttpResponseMessage response = await client.SendAsync(request).ConfigureAwait(false);
            string json = await response.Content.ReadAsStringAsync().ConfigureAwait(false);
            if (!response.IsSuccessStatusCode || string.IsNullOrWhiteSpace(json))
                return;

            using JsonDocument document = JsonDocument.Parse(json);
            JsonElement root = document.RootElement;
            if (!root.TryGetProperty("install", out JsonElement install) || install.ValueKind != JsonValueKind.Object) {
                TryBeginOnUi(ClearPersonaPlexWarning, "clear PersonaPlex warning");
                return;
            }

            bool canInstall = TryReadJsonBool(root, "canInstall");
            bool ready = TryReadJsonBool(root, "ready");
            bool localInstalled = TryReadJsonBool(install, "localInstalled");
            bool serverRunning = TryReadJsonBool(install, "serverRunning");
            bool hfTokenAvailable = TryReadJsonBool(install, "hfTokenAvailable");
            bool needsToken = TryReadJsonBool(install, "needsHuggingFaceToken");
            bool hfTokenRejected = TryReadJsonBool(install, "hfTokenRejected");
            bool installFootprintFound = TryReadJsonBool(install, "installFootprintFound");
            bool installIncomplete = TryReadJsonBool(install, "installIncomplete");
            string installStatus = TryReadJsonString(install, "status");
            string message = FirstNonEmpty(TryReadJsonString(install, "hfTokenError"), TryReadJsonString(install, "message"), TryReadJsonString(root, "error"));
            bool failed = installStatus.Equals("failed", StringComparison.OrdinalIgnoreCase);
            bool missingExpectedInstall = !localInstalled && (installIncomplete || installFootprintFound || hfTokenAvailable || failed || installStatus.Equals("missing", StringComparison.OrdinalIgnoreCase));
            bool installedButNeedsToken = localInstalled && needsToken;
            bool installedButStoppedAfterError = localInstalled && hfTokenAvailable && !ready && !serverRunning && !string.IsNullOrWhiteSpace(TryReadJsonString(root, "error"));

            if (!missingExpectedInstall && !installedButNeedsToken && !failed && !installedButStoppedAfterError) {
                TryBeginOnUi(ClearPersonaPlexWarning, "clear PersonaPlex warning");
                return;
            }

            string missing = JoinJsonStringArray(install, "missingComponents");
            string signal = failed
                ? hfTokenRejected
                    ? "PersonaPlex model access failed: " + FirstNonEmpty(message, "Hugging Face rejected the token") + "."
                    : "PersonaPlex install failed: " + FirstNonEmpty(message, "unknown error") + "."
                : missingExpectedInstall
                    ? "PersonaPlex was configured before, but the local Voice Mode install is missing or incomplete" + (string.IsNullOrWhiteSpace(missing) ? "." : ": " + missing + ".")
                    : installedButNeedsToken
                        ? "PersonaPlex is installed, but the NVIDIA Hugging Face model token is missing."
                        : "PersonaPlex is installed, but the local Voice Mode server is not ready: " + FirstNonEmpty(TryReadJsonString(root, "error"), message, "not running") + ".";
            string recommendation = hfTokenRejected
                ? "Accept the nvidia/personaplex-7b-v1 license on Hugging Face, then replace the token in Workstation."
                : missingExpectedInstall || failed
                ? "Reinstall Voice Mode from Workstation; use Model Page first if the NVIDIA license still needs acceptance."
                : installedButNeedsToken
                    ? "Accept the nvidia/personaplex-7b-v1 license on Hugging Face, then add the token in Workstation."
                    : "Start Voice Mode again from the web chat panel or reinstall it from Workstation if startup keeps failing.";

            TryBeginOnUi(() => {
                _personaPlexWarningActive = true;
                _personaPlexWarningSeverity = failed || missingExpectedInstall ? "WARN" : "INFO";
                _personaPlexWarningSignal = TrimForDisplay(signal, 280);
                _personaPlexWarningRecommendation = recommendation;
                _personaPlexWarningCanInstall = canInstall;
                _personaPlexWarningNeedsToken = installedButNeedsToken || hfTokenRejected;
                RefreshModelReconfigurationSuggestions();
            }, "PersonaPlex warning update");
        } catch (Exception ex) {
            TryBeginOnUi(() => AppendLog("PersonaPlex warning refresh failed: " + TrimForDisplay(ex.Message, 160)), "PersonaPlex warning failure");
        }
    }

    private void ClearPersonaPlexWarning() {
        if (!_personaPlexWarningActive &&
            string.IsNullOrWhiteSpace(_personaPlexWarningSignal))
            return;

        _personaPlexWarningActive = false;
        _personaPlexWarningSeverity = "WARN";
        _personaPlexWarningSignal = "";
        _personaPlexWarningRecommendation = "";
        _personaPlexWarningCanInstall = false;
        _personaPlexWarningNeedsToken = false;
        RefreshModelReconfigurationSuggestions();
    }

    private static bool HasCompatibilityAction(JsonElement root, string actionId, bool requireEnabled) {
        if (root.ValueKind != JsonValueKind.Object ||
            !root.TryGetProperty("actions", out JsonElement actions) ||
            actions.ValueKind != JsonValueKind.Array)
            return false;

        foreach (JsonElement action in actions.EnumerateArray()) {
            if (action.ValueKind != JsonValueKind.Object)
                continue;
            if (!string.Equals(TryReadJsonString(action, "id"), actionId, StringComparison.OrdinalIgnoreCase))
                continue;
            return !requireEnabled || TryReadJsonBool(action, "enabled");
        }

        return false;
    }

    private static string TryReadNestedJsonString(JsonElement root, params string[] path) {
        JsonElement current = root;
        foreach (string segment in path ?? Array.Empty<string>()) {
            if (current.ValueKind != JsonValueKind.Object ||
                !current.TryGetProperty(segment, out current))
                return "";
        }
        return current.ValueKind == JsonValueKind.String ? (current.GetString() ?? "") : current.ToString();
    }

    private static string JoinJsonStringArray(JsonElement root, string propertyName) {
        if (root.ValueKind != JsonValueKind.Object ||
            !root.TryGetProperty(propertyName, out JsonElement value) ||
            value.ValueKind != JsonValueKind.Array)
            return "";

        return string.Join(", ", value.EnumerateArray()
            .Select(item => item.ValueKind == JsonValueKind.String ? item.GetString() : item.ToString())
            .Where(item => !string.IsNullOrWhiteSpace(item)));
    }

    private void RefreshRuntimeCapabilityStatusIfDue() {
        UpdateLlmRuntimeCapabilityLine();
        RefreshImageRuntimeCompatibilityWarningIfDue();
        RefreshPersonaPlexWarningIfDue();

        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (_jackOnnxCapabilityRefreshInProgress ||
            now - _lastJackOnnxCapabilityRefreshUtc < TimeSpan.FromSeconds(15))
            return;

        _jackOnnxCapabilityRefreshInProgress = true;
        _lastJackOnnxCapabilityRefreshUtc = now;
        _ = Task.Run(async () => {
            var devices = await _jackOnnxRuntime.ListDevicesAsync().ConfigureAwait(false);
            var compatibility = await _jackOnnxRuntime.CheckProviderCompatibilityAsync().ConfigureAwait(false);
            var models = await _jackOnnxRuntime.ListModelsAsync().ConfigureAwait(false);
            var jobs = await _jackOnnxRuntime.ListJobsAsync().ConfigureAwait(false);
            return BuildJackOnnxCapabilitySnapshot(devices, compatibility, models, jobs);
        }).ContinueWith(task => {
            try {
                if (!TryBeginOnUi(() => {
                    try {
                        if (task.IsCompletedSuccessfully) {
                            JackOnnxCapabilitySnapshot snapshot = task.Result;
                            bool changed =
                                !string.Equals(_jackOnnxCapabilityStatus, snapshot.Status, StringComparison.OrdinalIgnoreCase) ||
                                !string.Equals(_jackOnnxCapabilityCountLine, snapshot.CountLine, StringComparison.OrdinalIgnoreCase) ||
                                !string.Equals(_jackOnnxCapabilityDetail, snapshot.Detail, StringComparison.OrdinalIgnoreCase);
                            _jackOnnxCapabilityStatus = snapshot.Status;
                            _jackOnnxCapabilityCountLine = snapshot.CountLine;
                            _jackOnnxCapabilityDetail = snapshot.Detail;
                            _jackOnnxProviderLine = snapshot.ProviderLine;
                            PulseService("JackONNX");
                            if (changed) {
                                AppendServiceEventLine(
                                    "JackONNX",
                                    "Capability refresh: " + snapshot.Status + " | " + snapshot.CountLine + " | " + snapshot.Detail);
                            }
                        } else {
                            string error = task.Exception?.GetBaseException().Message ?? "Capability probe failed.";
                            _jackOnnxCapabilityStatus = "Probe failed";
                            _jackOnnxCapabilityCountLine = "Tools: " + _jackOnnxToolDefinitions.Count.ToString(CultureInfo.InvariantCulture) + " | Models: - | Jobs: -";
                            _jackOnnxCapabilityDetail = TrimForDisplay(error, 120);
                            _jackOnnxProviderLine = "Providers: unavailable";
                            AppendServiceEventLine("JackONNX", "Capability refresh failed: " + _jackOnnxCapabilityDetail);
                        }
                    } finally {
                        _jackOnnxCapabilityRefreshInProgress = false;
                        RefreshServicesPanel();
                    }
                }, "JackONNX capability refresh"))
                    _jackOnnxCapabilityRefreshInProgress = false;
            } catch {
                _jackOnnxCapabilityRefreshInProgress = false;
            }
        });
    }

    private void UpdateLlmRuntimeCapabilityLine() {
        if (GetSelectedModelRuntimeProvider() == RuntimeProviderLmStudio) {
            _llmRuntimeCapabilityLine = "Embedded LlmRuntime stopped; JackONNX tools unavailable to chat runtime.";
            return;
        }

        string runtimeState = _embeddedLlmRuntime?.IsListening == true ? "running" : "starts on demand";
        string endpoint = _embeddedLlmRuntime?.OpenAiBaseUrl ?? "http://127.0.0.1:" + LocalLmStudioProxyPort.ToString(CultureInfo.InvariantCulture);
        _llmRuntimeCapabilityLine = "LlmRuntime " + runtimeState + " at " + endpoint +
                                    " | JackONNX tools: " + _jackOnnxToolDefinitions.Count.ToString(CultureInfo.InvariantCulture);
    }

    private JackOnnxCapabilitySnapshot BuildJackOnnxCapabilitySnapshot(
        IReadOnlyList<JackOnnxDeviceInfo> devices,
        IReadOnlyList<JackOnnxProviderCompatibility> compatibility,
        IReadOnlyList<JackOnnxModelManifest> models,
        IReadOnlyList<JackOnnxJobSnapshot> jobs) {
        var availableProviderNames = compatibility
            .Where(provider => provider.IsAvailable && provider.CanCreateSessionOptions)
            .Select(provider => provider.Provider.ToString())
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(name => name, StringComparer.OrdinalIgnoreCase)
            .ToList();

        bool hasGpuProvider = compatibility.Any(provider =>
            provider.IsAvailable &&
            provider.CanCreateSessionOptions &&
            provider.Provider is JackOnnxExecutionProvider.Cuda or JackOnnxExecutionProvider.DirectML);
        bool hasAnyProvider = availableProviderNames.Count > 0;
        bool nativeLinuxCudaReady = _linuxNativeCudaPytorchReady && (IsWineSafeWpfMode() || IsWineEnvironment());
        int availableDeviceCount = devices.Count(device => device.IsAvailable);
        int activeJobCount = jobs.Count(job => job.State is not JackOnnxJobState.Completed and not JackOnnxJobState.Cancelled and not JackOnnxJobState.Failed);
        string status = !hasAnyProvider
            ? "Unavailable"
            : hasGpuProvider
                ? "GPU ready"
                : nativeLinuxCudaReady ? "Native GPU ready"
                : models.Count == 0 ? "Providers ready" : "CPU ready";

        string providerLine = "Providers: " + (availableProviderNames.Count == 0 ? "none ready" : string.Join(", ", availableProviderNames));
        string nativeLinuxCudaLine = nativeLinuxCudaReady
            ? "Media CUDA: native LlmRuntime PyTorch ready" + (string.IsNullOrWhiteSpace(_linuxNativeCudaPytorchStatusLine) ? "" : " (" + TrimForDisplay(_linuxNativeCudaPytorchStatusLine, 90) + ")")
            : "";
        string unavailableGpuLine = nativeLinuxCudaReady ? "" : BuildJackOnnxUnavailableGpuLine(compatibility);
        string mediaLine = BuildJackOnnxMediaLine(models);
        string memoryLine = BuildJackOnnxMemoryLine(devices);
        string jobLine = activeJobCount.ToString(CultureInfo.InvariantCulture) + " active / " + jobs.Count.ToString(CultureInfo.InvariantCulture) + " total";
        string countLine = "Tools: " + _jackOnnxToolDefinitions.Count.ToString(CultureInfo.InvariantCulture) +
                           " | Models: " + models.Count.ToString(CultureInfo.InvariantCulture) +
                           " | Jobs: " + jobs.Count.ToString(CultureInfo.InvariantCulture);
        string detail = providerLine +
                        " | Devices: " + availableDeviceCount.ToString(CultureInfo.InvariantCulture) +
                        " | " + mediaLine +
                        " | Jobs: " + jobLine +
                        " | " + memoryLine +
                        (string.IsNullOrWhiteSpace(nativeLinuxCudaLine) ? "" : " | " + nativeLinuxCudaLine) +
                        (string.IsNullOrWhiteSpace(unavailableGpuLine) ? "" : " | " + unavailableGpuLine);

        return new JackOnnxCapabilitySnapshot(status, countLine, detail, providerLine);
    }

    private static string BuildJackOnnxUnavailableGpuLine(IReadOnlyList<JackOnnxProviderCompatibility> compatibility) {
        bool hasReadyGpuProvider = compatibility.Any(provider =>
            provider.IsAvailable &&
            provider.CanCreateSessionOptions &&
            provider.Provider is JackOnnxExecutionProvider.Cuda or JackOnnxExecutionProvider.DirectML);
        if (hasReadyGpuProvider)
            return "";

        var notes = compatibility
            .Where(provider => !provider.IsAvailable &&
                               provider.Provider is JackOnnxExecutionProvider.Cuda or JackOnnxExecutionProvider.DirectML)
            .Select(provider => provider.Provider.ToString() + ": " + TrimForDisplay(provider.Detail, 90))
            .Where(note => !string.IsNullOrWhiteSpace(note))
            .ToList();

        return notes.Count == 0 ? "" : "GPU notes: " + string.Join("; ", notes);
    }

    private static string BuildJackOnnxMediaLine(IReadOnlyList<JackOnnxModelManifest> models) {
        if (models.Count == 0)
            return "Media: no manifests in Models\\JackONNX";

        var kinds = models
            .Select(model => (model.Type ?? "").Split('.', StringSplitOptions.RemoveEmptyEntries).FirstOrDefault() ?? "")
            .Where(kind => !string.IsNullOrWhiteSpace(kind))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(kind => kind, StringComparer.OrdinalIgnoreCase)
            .ToList();

        return "Media: " + (kinds.Count == 0 ? "manifested models" : string.Join(", ", kinds));
    }

    private static string BuildJackOnnxMemoryLine(IReadOnlyList<JackOnnxDeviceInfo> devices) {
        long totalMemory = devices
            .Where(device => device.IsAvailable)
            .Select(device => device.DedicatedMemoryBytes ?? 0)
            .Where(bytes => bytes > 0)
            .Sum();

        return totalMemory > 0 ? "Device memory: " + FormatBytes(totalMemory) : "Device memory: unspecified";
    }

    private void RefreshSessionsPanel(bool force) {
        try {
            if (!force && !IsSessionsPanelVisible())
                return;

            DateTimeOffset now = DateTimeOffset.UtcNow;
            if (!force && now - _lastSessionsPanelRefreshUtc < TimeSpan.FromSeconds(4))
                return;
            _lastSessionsPanelRefreshUtc = now;

            IReadOnlyList<ActivePromptSessionDiagnosticsSnapshot> sessions = _proxy.GetActivePromptSessionDiagnostics();
            RefreshInternalsPanel(sessions);
            IReadOnlyList<ChatSessionDiagnosticsSnapshot> storedSessions = _proxy.GetChatSessionDiagnostics();
            IReadOnlyList<TerminalPermissionRequestSnapshot> terminalApprovals = _proxy.GetPendingTerminalPermissionRequests();
            var allItems = terminalApprovals.Select(ChatSessionListItem.FromTerminalPermissionSnapshot)
                .Concat(sessions.Select(ChatSessionListItem.FromPromptSnapshot))
                .Concat(storedSessions.Select(ChatSessionListItem.FromSnapshot))
                .ToList();
            var items = FilterSessionItems(allItems).ToList();
            string signature = string.Join("|", items.Select(item => item.Signature));
            if (force || !string.Equals(signature, _sessionListSignature, StringComparison.Ordinal)) {
                string selectedSessionId = _selectedSessionId;
                _sessionItems.Clear();
                foreach (ChatSessionListItem item in items)
                    _sessionItems.Add(item);
                _sessionListSignature = signature;

                ChatSessionListItem? selectedItem = null;
                if (!string.IsNullOrWhiteSpace(selectedSessionId))
                    selectedItem = _sessionItems.FirstOrDefault(item => string.Equals(item.Id, selectedSessionId, StringComparison.Ordinal));
                selectedItem ??= _sessionItems.FirstOrDefault();
                if (selectedItem != null || items.Count == 0 || string.IsNullOrWhiteSpace(_selectedOwnerKey))
                    ApplySelectedSession(selectedItem, syncLists: true, refreshNow: true);
            }

            string sessionSummary = sessions.Count == 1
                ? "1 current LLM prompt session"
                : sessions.Count + " current LLM prompt sessions";
            sessionSummary += storedSessions.Count == 1
                ? " | 1 stored session"
                : " | " + storedSessions.Count + " stored sessions";
            if (items.Count != allItems.Count)
                sessionSummary += " | " + items.Count + " matching";
            if (terminalApprovals.Count > 0)
            {
                sessionSummary += terminalApprovals.Count == 1
                    ? " | 1 pending terminal approval"
                    : " | " + terminalApprovals.Count + " pending terminal approvals";
            }
            SetSessionsSummaryText(sessionSummary);
            RefreshServerManagementSessions(items, allItems.Count, force);
            if (force || IsSessionLogPanelVisible())
                RefreshSessionLogPreview(false);
        } catch (Exception ex) {
            SetSessionsSummaryText("Sessions unavailable: " + TrimForDisplay(ex.Message, 120));
        }
    }

