    private void RefreshServerManagementSessions(IReadOnlyList<ChatSessionListItem> filteredItems, int unfilteredCount, bool force) {
        const string privateSessionSummary = "Session data is private and encrypted. Server Management cannot inspect transcripts, prompts, responses, or session files.";
        string signature = "private-server-management-sessions";
        if (force || !string.Equals(signature, _serverSessionListSignature, StringComparison.Ordinal)) {
            _serverSessionItems.Clear();
            _serverSessionListSignature = signature;
            if (ServerSessionsListBox != null && ServerSessionsListBox.SelectedItem != null)
                SyncSessionListSelections(null);
        }

        if (ServerSessionsSummaryText != null)
            ServerSessionsSummaryText.Text = privateSessionSummary;
        if (IsServerManagementTabSelected())
            RenderSessionLogPlaceholder(privateSessionSummary, force);
    }

    private void RefreshInternalsPanel(IReadOnlyList<ActivePromptSessionDiagnosticsSnapshot> sessions) {
        var activeById = sessions
            .Where(session => !string.IsNullOrWhiteSpace(session.Id))
            .ToDictionary(session => session.Id, session => session, StringComparer.Ordinal);

        for (int i = _promptInternalItems.Count - 1; i >= 0; i--) {
            PromptInternalItem item = _promptInternalItems[i];
            if (activeById.TryGetValue(item.Id, out ActivePromptSessionDiagnosticsSnapshot snapshot)) {
                item.Update(snapshot, true);
                activeById.Remove(item.Id);
            } else {
                item.IsRunning = false;
                item.CloseVisibility = Visibility.Visible;
                if (!item.IsExpanded && !_retainedInternalPromptIds.Contains(item.Id))
                    _promptInternalItems.RemoveAt(i);
            }
        }

        foreach (ActivePromptSessionDiagnosticsSnapshot snapshot in activeById.Values)
            _promptInternalItems.Insert(0, PromptInternalItem.FromSnapshot(snapshot, true));
    }

    private void InternalsPrompt_Expanded(object sender, RoutedEventArgs e) {
        if ((sender as FrameworkElement)?.Tag is PromptInternalItem item)
            _retainedInternalPromptIds.Add(item.Id);
    }

    private void InternalsPromptClose_Click(object sender, RoutedEventArgs e) {
        if ((sender as FrameworkElement)?.Tag is not PromptInternalItem item)
            return;

        _retainedInternalPromptIds.Remove(item.Id);
        _promptInternalItems.Remove(item);
    }

    private IEnumerable<ChatSessionListItem> FilterSessionItems(IEnumerable<ChatSessionListItem> items) {
        string query = _sessionSearchQuery.Trim();
        if (string.IsNullOrWhiteSpace(query)) {
            SessionRegexStatusText.Text = _sessionSearchRegexEnabled
                ? "Regex mode ready. Try locked|public, ^Copy, or \\btoken."
                : "Search title, owner, model, lock state, clone state, and prompt tokens.";
            return items;
        }

        if (_sessionSearchRegexEnabled) {
            try {
                var regex = new Regex(query.StartsWith("(?i)", StringComparison.Ordinal) ? query.Substring(4) : query, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
                SessionRegexStatusText.Text = "Regex matched session metadata.";
                return items.Where(item => regex.IsMatch(item.SearchText));
            } catch (Exception ex) {
                SessionRegexStatusText.Text = "Regex issue: " + TrimForDisplay(ex.Message, 110);
                return Enumerable.Empty<ChatSessionListItem>();
            }
        }

        string[] terms = query.Split(' ', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
        SessionRegexStatusText.Text = "Search matched title, owner, model, state, and prompt-token metadata.";
        return items.Where(item => terms.All(term => item.SearchText.Contains(term, StringComparison.OrdinalIgnoreCase)));
    }

    private void RefreshStoredSessionsMenuItems(bool force) {
        try {
            IReadOnlyList<ChatSessionDiagnosticsSnapshot> sessions = _proxy.GetChatSessionDiagnostics();
            var items = sessions.Select(ChatSessionListItem.FromSnapshot).ToList();
            string signature = string.Join("|", items.Select(item => item.Signature));
            if (!force && string.Equals(signature, _storedSessionListSignature, StringComparison.Ordinal))
                return;

            _storedSessionItems.Clear();
            foreach (ChatSessionListItem item in items)
                _storedSessionItems.Add(item);
            _storedSessionListSignature = signature;
        } catch {
            _storedSessionItems.Clear();
            _storedSessionListSignature = "";
        }
    }

    private void RefreshWorkspaceExplorer(bool force) {
        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (!force && now - _lastWorkspaceRefreshUtc < TimeSpan.FromSeconds(5))
            return;

        _lastWorkspaceRefreshUtc = now;

        try {
            List<AccessibleDirectoryListItem> directories = RefreshAccessibleDirectories(force);
            string ownerKey = ResolveActiveFilesystemOwnerKey();
            string signature = BuildExplorerSignature(ownerKey, directories);
            if (!force && string.Equals(signature, _workspaceTreeSignature, StringComparison.Ordinal))
                return;

            _workspaceTreeSignature = signature;
            _workspaceTreeItems.Clear();

            if (directories.Count == 0) {
                _workspaceTreeItems.Add(new FileTreeItem {
                    DisplayName = "No accessible directories",
                    Detail = "Add a directory above to make it available to the Web UI agent.",
                    Icon = "[dir]",
                    AccentBrush = Brushes.SlateGray,
                    FontWeight = FontWeights.SemiBold,
                    IsExpanded = true
                });
            } else {
                bool first = true;
                foreach (AccessibleDirectoryListItem directory in directories) {
                    FileTreeItem node = BuildDirectoryTree(
                        directory.Path,
                        GetDirectoryDisplayName(directory.Path),
                        3,
                        first,
                        true);
                    if (!directory.Exists)
                        node = new FileTreeItem {
                            DisplayName = GetDirectoryDisplayName(directory.Path),
                            Detail = TrimPathForDisplay(directory.Path, 84) + " (missing)",
                            Icon = "[dir]",
                            AccentBrush = Brushes.SlateGray,
                            FontWeight = FontWeights.SemiBold,
                            SourcePath = directory.Path,
                            CanRemove = true,
                            IsExpanded = first
                        };

                    _workspaceTreeItems.Add(node);
                    first = false;
                }
            }

            SetWorkspaceSummaryText("Explorer roots: " + directories.Count + " accessible director" + (directories.Count == 1 ? "y" : "ies"));
        } catch (Exception ex) {
            SetWorkspaceSummaryText("Explorer unavailable: " + TrimForDisplay(ex.Message, 120));
        }
    }

    private List<AccessibleDirectoryListItem> RefreshAccessibleDirectories(bool force) {
        string ownerKey = ResolveActiveFilesystemOwnerKey();
        try {
            IReadOnlyList<ChatFilesystemAccessSnapshot> snapshots =
                _proxy.GetChatFilesystemAccessDiagnostics(ownerKey);
            List<AccessibleDirectoryListItem> items = snapshots.Select(AccessibleDirectoryListItem.FromSnapshot).ToList();
            string signature = ownerKey + "\u001E" + string.Join("\u001F", items.Select(item => item.Signature));
            if (force || !string.Equals(signature, _accessibleDirectorySignature, StringComparison.Ordinal)) {
                _accessibleDirectoryItems.Clear();
                foreach (AccessibleDirectoryListItem item in items)
                    _accessibleDirectoryItems.Add(item);
                _accessibleDirectorySignature = signature;
            }

            SetFilesystemOwnerText("Owner: " + ownerKey);
            string currentStatus = FilesystemAccessStatusText?.Text ?? ServerFilesystemAccessStatusText?.Text ?? "";
            if (string.IsNullOrWhiteSpace(currentStatus) ||
                currentStatus.StartsWith("Loaded", StringComparison.OrdinalIgnoreCase) ||
                currentStatus.StartsWith("No", StringComparison.OrdinalIgnoreCase) ||
                currentStatus.StartsWith("Select", StringComparison.OrdinalIgnoreCase)) {
                SetFilesystemAccessStatusText(items.Count == 0
                    ? "No accessible directories defined."
                    : "Loaded " + items.Count + " accessible director" + (items.Count == 1 ? "y." : "ies."));
            }
            return items;
        } catch (Exception ex) {
            SetFilesystemOwnerText("Owner: " + ownerKey);
            SetFilesystemAccessStatusText("Access list unavailable: " + TrimForDisplay(ex.Message, 120));
            return _accessibleDirectoryItems.ToList();
        }
    }

    private string ResolveActiveFilesystemOwnerKey() {
        if (IsServerManagementTabSelected()) {
            string selectedUserOwnerKey = GetSelectedWebAuthOwnerKey();
            if (!string.IsNullOrWhiteSpace(selectedUserOwnerKey))
                return selectedUserOwnerKey;
        }

        if (!string.IsNullOrWhiteSpace(_selectedOwnerKey))
            return _selectedOwnerKey;

        ChatSessionListItem? selectedItem = SessionsListBox.SelectedItem as ChatSessionListItem;
        if (!string.IsNullOrWhiteSpace(selectedItem?.OwnerKey))
            return selectedItem.OwnerKey;

        string firstOwner = _sessionItems.FirstOrDefault(item => !string.IsNullOrWhiteSpace(item.OwnerKey))?.OwnerKey ?? "";
        return string.IsNullOrWhiteSpace(firstOwner) ? _proxy.GetDefaultLocalChatOwnerKey() : firstOwner;
    }

