    private void RefreshSessionLogPreview(bool force) {
        if (SessionLogBrowserHost == null)
            return;

        if (IsServerManagementTabSelected()) {
            RenderSessionLogPlaceholder("Session transcripts are private, encrypted, and unavailable to Server Management.", force);
            return;
        }

        ChatSessionListItem? item = SessionsListBox?.SelectedItem as ChatSessionListItem;
        if (item == null) {
            RenderSessionLogPlaceholder("Select a session to render its chat log.", force);
            return;
        }

        if (string.Equals(item.Kind, "terminal", StringComparison.OrdinalIgnoreCase)) {
            RenderSessionLogPlaceholder("Terminal approval items do not have a chat transcript.", force);
            return;
        }

        string renderId = string.IsNullOrWhiteSpace(item.SessionId) ? item.Id : item.SessionId;
        string ownerKey = ResolveSessionOwnerKey(item);
        try {
            ChatSessionRenderDiagnosticsSnapshot snapshot = _proxy.GetChatSessionRenderDiagnostics(renderId, ownerKey);
            string signature = BuildSessionLogSignature(snapshot);
            if (!force && string.Equals(signature, _sessionLogSignature, StringComparison.Ordinal))
                return;

            _sessionLogSignature = signature;
            if (ServerSessionLogTitleText != null)
                ServerSessionLogTitleText.Text = string.IsNullOrWhiteSpace(snapshot.Title) ? item.Title : snapshot.Title;
            if (ServerSessionLogMetaText != null)
                ServerSessionLogMetaText.Text = BuildSessionLogMetaLine(snapshot, item);
            if (SessionLogStatusText != null)
                SessionLogStatusText.Text = snapshot.Found
                    ? "Rendered " + snapshot.MessageCount.ToString("N0", CultureInfo.CurrentCulture) + " messages for " + snapshot.OwnerKey + "."
                    : "No stored transcript found for " + item.Title + ".";
            NavigateSessionLogHtml(BuildSessionLogHtml(snapshot, item));
        } catch (Exception ex) {
            if (SessionLogStatusText != null)
                SessionLogStatusText.Text = "Session log unavailable: " + TrimForDisplay(ex.Message, 160);
            NavigateSessionLogHtml(BuildSessionLogErrorHtml(item.Title, ex.Message));
        }
    }

    private void RenderSessionLogPlaceholder(string message, bool force = true) {
        string signature = "placeholder:" + message;
        if (!force && string.Equals(signature, _sessionLogSignature, StringComparison.Ordinal))
            return;

        _sessionLogSignature = signature;
        if (ServerSessionLogTitleText != null)
            ServerSessionLogTitleText.Text = "Session log";
        if (ServerSessionLogMetaText != null)
            ServerSessionLogMetaText.Text = message;
        if (SessionLogStatusText != null)
            SessionLogStatusText.Text = message;
        NavigateSessionLogHtml(BuildSessionLogShellHtml("Session log", "<div class=\"empty\">" + HtmlEncode(message) + "</div>"));
    }

    private void NavigateSessionLogHtml(string html) {
        _pendingSessionLogHtml = string.IsNullOrWhiteSpace(html)
            ? BuildSessionLogShellHtml("Session log", "<div class=\"empty\">Session log is empty.</div>")
            : html;

        if (_sessionLogUsesFallbackViewer) {
            NavigateSessionLogFallback(_pendingSessionLogHtml);
            return;
        }

        if (!_sessionLogBrowserReady || _sessionLogBrowser?.CoreWebView2 == null) {
            _ = EnsureSessionLogBrowserReadyAsync();
            return;
        }

        try {
            NavigateSessionLogBrowserCore(_pendingSessionLogHtml);
        } catch (Exception ex) {
            if (SessionLogStatusText != null)
                SessionLogStatusText.Text = "Session log browser failed: " + TrimForDisplay(ex.Message, 160);
            _sessionLogBrowserReady = false;
            _ = EnsureSessionLogBrowserReadyAsync();
        }
    }

    private async Task EnsureSessionLogBrowserReadyAsync() {
        if (_sessionLogUsesFallbackViewer || _sessionLogBrowser == null || _sessionLogBrowserReady || _sessionLogBrowserInitializing)
            return;

        if (!_sessionLogBrowser.IsLoaded) {
            _sessionLogBrowser.Loaded -= SessionLogBrowser_Loaded;
            _sessionLogBrowser.Loaded += SessionLogBrowser_Loaded;
            if (SessionLogStatusText != null)
                SessionLogStatusText.Text = "Session log browser is waiting for the tab to load...";
            return;
        }

        _sessionLogBrowserInitializing = true;
        try {
            if (SessionLogStatusText != null)
                SessionLogStatusText.Text = "Starting session log browser...";

            await _sessionLogBrowser.EnsureCoreWebView2Async().ConfigureAwait(true);
            if (_sessionLogBrowser.CoreWebView2 == null)
                throw new InvalidOperationException("WebView2 core was not created.");

            _sessionLogBrowserReady = true;
            _sessionLogBrowser.CoreWebView2.Settings.AreDefaultContextMenusEnabled = true;
            _sessionLogBrowser.CoreWebView2.Settings.AreDevToolsEnabled = false;
            if (!_sessionLogBrowserEventsAttached) {
                _sessionLogBrowser.CoreWebView2.NewWindowRequested += SessionLogBrowser_NewWindowRequested;
                _sessionLogBrowser.CoreWebView2.NavigationCompleted += SessionLogBrowser_NavigationCompleted;
                _sessionLogBrowserEventsAttached = true;
            }

            if (!string.IsNullOrWhiteSpace(_pendingSessionLogHtml))
                NavigateSessionLogBrowserCore(_pendingSessionLogHtml);
        } catch (Exception ex) {
            _sessionLogBrowserReady = false;
            if (SessionLogStatusText != null)
                SessionLogStatusText.Text = "Session log browser failed to start: " + TrimForDisplay(ex.Message, 160);
        } finally {
            _sessionLogBrowserInitializing = false;
        }
    }

    private void NavigateSessionLogBrowserCore(string html) {
        if (_sessionLogBrowser == null)
            return;

        try {
            string filePath = WriteSessionLogHtmlFile(html);
            string uri = new Uri(filePath).AbsoluteUri + "?v=" + (++_sessionLogBrowserNavigationVersion).ToString(CultureInfo.InvariantCulture);
            _sessionLogBrowser.CoreWebView2?.Navigate(uri);
            if (_sessionLogBrowser.CoreWebView2 == null)
                _sessionLogBrowser.Source = new Uri(filePath);
        } catch {
            _sessionLogBrowser.NavigateToString(html);
        }
    }

    private void NavigateSessionLogFallback(string html) {
        if (_sessionLogFallbackTextBox == null)
            return;

        _sessionLogFallbackTextBox.Text = ConvertSessionLogHtmlToPlainText(html);
        _sessionLogFallbackTextBox.ScrollToHome();
    }

    private static string ConvertSessionLogHtmlToPlainText(string html) {
        if (string.IsNullOrWhiteSpace(html))
            return "";

        string text = Regex.Replace(html, @"<(br|/div|/p|/h[1-6]|/li|/pre|/code)\b[^>]*>", "\n", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<style\b[^>]*>.*?</style>", "", RegexOptions.IgnoreCase | RegexOptions.Singleline);
        text = Regex.Replace(text, @"<script\b[^>]*>.*?</script>", "", RegexOptions.IgnoreCase | RegexOptions.Singleline);
        text = Regex.Replace(text, "<[^>]+>", "");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"[ \t]+\r?\n", "\n");
        text = Regex.Replace(text, @"(\r?\n){3,}", "\n\n");
        return text.Trim();
    }

    private static string WriteSessionLogHtmlFile(string html) {
        string basePath = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
        if (string.IsNullOrWhiteSpace(basePath))
            basePath = Path.GetTempPath();

        string directory = Path.Combine(basePath, "JackLLM", "SessionLogBrowser");
        Directory.CreateDirectory(directory);
        string filePath = Path.Combine(directory, "session-log.html");
        File.WriteAllText(filePath, html ?? "", Encoding.UTF8);
        return filePath;
    }

    private void SessionLogBrowser_Loaded(object sender, RoutedEventArgs e) {
        if (_sessionLogBrowser != null)
            _sessionLogBrowser.Loaded -= SessionLogBrowser_Loaded;
        _ = EnsureSessionLogBrowserReadyAsync();
    }

    private void SessionLogBrowser_NewWindowRequested(object? sender, CoreWebView2NewWindowRequestedEventArgs e) {
        e.Handled = true;
        try {
            string uri = e.Uri ?? "";
            if (!string.IsNullOrWhiteSpace(uri))
                Process.Start(new ProcessStartInfo(uri) { UseShellExecute = true });
        } catch {
        }
    }

    private void SessionLogBrowser_NavigationCompleted(object? sender, CoreWebView2NavigationCompletedEventArgs e) {
        if (SessionLogStatusText == null || e.IsSuccess)
            return;

        SessionLogStatusText.Text = "Session log browser navigation failed: " + e.WebErrorStatus;
    }

    private static string BuildSessionLogSignature(ChatSessionRenderDiagnosticsSnapshot snapshot) {
        snapshot ??= new ChatSessionRenderDiagnosticsSnapshot();
        string hashInput = (snapshot.MessagesJson ?? "") + "\u001F" + (snapshot.DraftPrompt ?? "") + "\u001F" + (snapshot.PromptText ?? "");
        return string.Join("\u001F",
            snapshot.Found,
            snapshot.IsActive,
            snapshot.Id,
            snapshot.OwnerKey,
            snapshot.UpdatedUtc,
            snapshot.CompletedUtc,
            snapshot.Model,
            snapshot.Runtime,
            snapshot.Status,
            snapshot.Phase,
            snapshot.ElapsedSeconds.ToString(CultureInfo.InvariantCulture),
            snapshot.PromptTokenCount.ToString(CultureInfo.InvariantCulture),
            snapshot.MessageCount.ToString(CultureInfo.InvariantCulture),
            snapshot.FileCount.ToString(CultureInfo.InvariantCulture),
            ComputeShortHash(hashInput));
    }

    private static string BuildSessionLogMetaLine(ChatSessionRenderDiagnosticsSnapshot snapshot, ChatSessionListItem item) {
        string model = FirstNonEmpty(snapshot.Model, "model unknown");
        string runtime = FirstNonEmpty(snapshot.Runtime, "runtime unknown");
        string status = FirstNonEmpty(snapshot.Status, snapshot.IsActive ? "Running" : "Stored");
        string phase = string.IsNullOrWhiteSpace(snapshot.Phase) ? "" : " | " + snapshot.Phase.Trim();
        string rate = snapshot.TokensPerSecond > 0
            ? " | " + snapshot.TokensPerSecond.ToString("0.##", CultureInfo.CurrentCulture) + " tok/sec"
            : "";
        string tokens = " | prompt " + FormatSessionLogLong(snapshot.PromptTokenCount) + " tokens";
        string owner = " | " + FirstNonEmpty(snapshot.OwnerKey, item.OwnerKey, "owner unknown");
        return model + " | " + runtime + " | " + status + phase + rate + tokens + owner;
    }

    private static string BuildSessionLogHtml(ChatSessionRenderDiagnosticsSnapshot snapshot, ChatSessionListItem item) {
        snapshot ??= new ChatSessionRenderDiagnosticsSnapshot();
        var body = new StringBuilder();
        body.Append("<section class=\"metrics\">");
        AppendSessionLogMetric(body, "Model", FirstNonEmpty(snapshot.Model, "unknown"));
        AppendSessionLogMetric(body, "Runtime", FirstNonEmpty(snapshot.Runtime, "unknown"));
        AppendSessionLogMetric(body, "Status", FirstNonEmpty(snapshot.Status, snapshot.IsActive ? "Running" : "Stored"));
        AppendSessionLogMetric(body, "Tok/sec", snapshot.TokensPerSecond > 0 ? snapshot.TokensPerSecond.ToString("0.##", CultureInfo.CurrentCulture) : "-");
        AppendSessionLogMetric(body, "Prompt tokens", FormatSessionLogLong(snapshot.PromptTokenCount));
        AppendSessionLogMetric(body, "Messages", snapshot.MessageCount.ToString("N0", CultureInfo.CurrentCulture));
        AppendSessionLogMetric(body, "Files", snapshot.FileCount.ToString("N0", CultureInfo.CurrentCulture));
        AppendSessionLogMetric(body, "GPU", FormatSessionLogKwh(snapshot.Usage.GpuKwh) + " @ " + FormatSessionLogKw(snapshot.Usage.GpuKw));
        AppendSessionLogMetric(body, "CPU", FormatSessionLogKwh(snapshot.Usage.CpuKwh) + " @ " + FormatSessionLogKw(snapshot.Usage.CpuKw));
        AppendSessionLogMetric(body, "Tokens used", FormatSessionLogLong(snapshot.Usage.TokensUsed));
        AppendSessionLogMetric(body, "Cost", FormatSessionLogUsd(snapshot.Usage.TotalCostUsd));
        body.Append("</section>");

        if (!snapshot.Found) {
            body.Append("<div class=\"empty\">No stored transcript was found for this session yet. Active prompt metadata will appear here as it updates.</div>");
        }

        string messagesHtml = BuildSessionMessagesHtml(snapshot);
        if (!string.IsNullOrWhiteSpace(messagesHtml))
            body.Append(messagesHtml);

        string filesHtml = BuildSessionFilesHtml(snapshot.FilesJson);
        if (!string.IsNullOrWhiteSpace(filesHtml))
            body.Append(filesHtml);

        string title = FirstNonEmpty(snapshot.Title, item.Title, "Session log");
        string subtitle = "Owner " + HtmlEncode(FirstNonEmpty(snapshot.OwnerKey, item.OwnerKey, "unknown")) +
                          " | Session " + HtmlEncode(FirstNonEmpty(snapshot.Id, item.SessionId, item.Id, "-")) +
                          (string.IsNullOrWhiteSpace(snapshot.UpdatedUtc) ? "" : " | Updated " + HtmlEncode(FormatManagementDate(snapshot.UpdatedUtc)));
        return BuildSessionLogShellHtml(title, "<div class=\"subtitle\">" + subtitle + "</div>" + body);
    }

    private static string BuildSessionMessagesHtml(ChatSessionRenderDiagnosticsSnapshot snapshot) {
        var body = new StringBuilder();
        bool renderedAny = false;

        try {
            using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(snapshot.MessagesJson) ? "[]" : snapshot.MessagesJson);
            if (document.RootElement.ValueKind == JsonValueKind.Array) {
                foreach (JsonElement message in document.RootElement.EnumerateArray()) {
                    renderedAny = true;
                    body.Append(RenderSessionMessageHtml(message));
                }
            }
        } catch (Exception ex) {
            body.Append("<div class=\"message system\"><div class=\"role\">Parser</div><div class=\"content\">Could not parse message JSON: " + HtmlEncode(ex.Message) + "</div></div>");
        }

        if (!renderedAny) {
            if (!string.IsNullOrWhiteSpace(snapshot.PromptText)) {
                body.Append("<div class=\"message user\"><div class=\"role\">Active prompt</div><div class=\"content\">");
                body.Append(RenderMarkdownishText(snapshot.PromptText));
                body.Append("</div></div>");
            }
            if (!string.IsNullOrWhiteSpace(snapshot.DraftPrompt)) {
                body.Append("<div class=\"message user\"><div class=\"role\">Draft prompt</div><div class=\"content\">");
                body.Append(RenderMarkdownishText(snapshot.DraftPrompt));
                body.Append("</div></div>");
            }
            if (!string.IsNullOrWhiteSpace(snapshot.ReferencesText)) {
                body.Append("<div class=\"message system\"><div class=\"role\">References</div><div class=\"content\">");
                body.Append(RenderMarkdownishText(snapshot.ReferencesText));
                body.Append("</div></div>");
            }
        }

        return body.ToString();
    }

    private static string RenderSessionMessageHtml(JsonElement message) {
        string role = TryGetJsonString(message, "role");
        if (string.IsNullOrWhiteSpace(role))
            role = "message";
        string safeRole = HtmlEncode(role.Trim());
        string cssRole = role.Trim().ToLowerInvariant();
        if (cssRole != "assistant" && cssRole != "user" && cssRole != "system" && cssRole != "tool")
            cssRole = "other";

        var body = new StringBuilder();
        body.Append("<div class=\"message ").Append(cssRole).Append("\">");
        body.Append("<div class=\"role\">").Append(safeRole);
        string name = TryGetJsonString(message, "name");
        if (!string.IsNullOrWhiteSpace(name))
            body.Append(" <span>").Append(HtmlEncode(name)).Append("</span>");
        body.Append("</div><div class=\"content\">");

        if (message.TryGetProperty("content", out JsonElement content))
            body.Append(RenderMessageContentHtml(content));
        else
            body.Append("<em>No content field.</em>");

        string reasoning = TryGetJsonString(message, "reasoning");
        if (!string.IsNullOrWhiteSpace(reasoning)) {
            body.Append("<details><summary>Reasoning</summary>");
            body.Append(RenderMarkdownishText(reasoning));
            body.Append("</details>");
        }

        if (message.TryGetProperty("tool_calls", out JsonElement toolCalls) &&
            toolCalls.ValueKind != JsonValueKind.Undefined &&
            toolCalls.ValueKind != JsonValueKind.Null) {
            body.Append("<details><summary>Tool calls</summary><pre>");
            body.Append(HtmlEncode(toolCalls.GetRawText()));
            body.Append("</pre></details>");
        }

        body.Append("</div></div>");
        return body.ToString();
    }

    private static string RenderMessageContentHtml(JsonElement content) {
        if (content.ValueKind == JsonValueKind.String)
            return RenderMarkdownishText(content.GetString() ?? "");

        if (content.ValueKind == JsonValueKind.Array) {
            var body = new StringBuilder();
            foreach (JsonElement part in content.EnumerateArray()) {
                if (part.ValueKind == JsonValueKind.String) {
                    body.Append(RenderMarkdownishText(part.GetString() ?? ""));
                    continue;
                }

                if (part.ValueKind == JsonValueKind.Object) {
                    string text = FirstNonEmpty(
                        TryGetJsonString(part, "text"),
                        TryGetJsonString(part, "content"),
                        TryGetJsonString(part, "input_text"),
                        TryGetJsonString(part, "output_text"));
                    if (!string.IsNullOrWhiteSpace(text)) {
                        body.Append(RenderMarkdownishText(text));
                        continue;
                    }

                    string imageUrl = TryGetJsonString(part, "image_url");
                    if (string.IsNullOrWhiteSpace(imageUrl) &&
                        part.TryGetProperty("image_url", out JsonElement imageObject) &&
                        imageObject.ValueKind == JsonValueKind.Object)
                        imageUrl = TryGetJsonString(imageObject, "url");
                    if (!string.IsNullOrWhiteSpace(imageUrl)) {
                        body.Append("<div class=\"attachment\">Image: ").Append(HtmlEncode(TrimForDisplay(imageUrl, 180))).Append("</div>");
                        continue;
                    }
                }

                body.Append("<pre>").Append(HtmlEncode(part.GetRawText())).Append("</pre>");
            }
            return body.ToString();
        }

        if (content.ValueKind == JsonValueKind.Null || content.ValueKind == JsonValueKind.Undefined)
            return "<em>No content.</em>";

        return "<pre>" + HtmlEncode(content.GetRawText()) + "</pre>";
    }

    private static string BuildSessionFilesHtml(string filesJson) {
        if (string.IsNullOrWhiteSpace(filesJson) || filesJson.Trim() == "[]")
            return "";

        var body = new StringBuilder("<section class=\"files\"><h2>Files</h2>");
        try {
            using JsonDocument document = JsonDocument.Parse(filesJson);
            if (document.RootElement.ValueKind == JsonValueKind.Array) {
                foreach (JsonElement file in document.RootElement.EnumerateArray()) {
                    string name = FirstNonEmpty(
                        TryGetJsonString(file, "name"),
                        TryGetJsonString(file, "fileName"),
                        TryGetJsonString(file, "path"),
                        TryGetJsonString(file, "relativePath"),
                        "file");
                    string detail = FirstNonEmpty(
                        TryGetJsonString(file, "path"),
                        TryGetJsonString(file, "relativePath"),
                        TryGetJsonString(file, "mimeType"),
                        TryGetJsonString(file, "kind"));
                    body.Append("<div class=\"file\"><strong>").Append(HtmlEncode(name)).Append("</strong>");
                    if (!string.IsNullOrWhiteSpace(detail))
                        body.Append("<span>").Append(HtmlEncode(detail)).Append("</span>");
                    body.Append("</div>");
                }
            }
        } catch (Exception ex) {
            body.Append("<div class=\"file\"><strong>Files unavailable</strong><span>").Append(HtmlEncode(ex.Message)).Append("</span></div>");
        }
        body.Append("</section>");
        return body.ToString();
    }

    private static string BuildSessionLogErrorHtml(string title, string message) {
        return BuildSessionLogShellHtml(
            string.IsNullOrWhiteSpace(title) ? "Session log" : title,
            "<div class=\"empty error\">" + HtmlEncode(message) + "</div>");
    }

