    private static void AppendSessionLogMetric(StringBuilder body, string label, string value) {
        body.Append("<div class=\"metric\"><span>")
            .Append(HtmlEncode(label))
            .Append("</span><strong>")
            .Append(HtmlEncode(string.IsNullOrWhiteSpace(value) ? "-" : value))
            .Append("</strong></div>");
    }

    private static string RenderMarkdownishText(string text) {
        if (string.IsNullOrEmpty(text))
            return "";

        string normalized = text.Replace("\r\n", "\n").Replace('\r', '\n');
        var body = new StringBuilder();
        string[] pieces = normalized.Split(new[] { "```" }, StringSplitOptions.None);
        for (int i = 0; i < pieces.Length; i++) {
            string piece = pieces[i];
            if (i % 2 == 1) {
                body.Append("<pre><code>").Append(HtmlEncode(piece.Trim('\n'))).Append("</code></pre>");
            } else {
                body.Append(HtmlEncode(piece).Replace("\n", "<br>"));
            }
        }

        return body.ToString();
    }

    private static string TryGetJsonString(JsonElement element, string propertyName) {
        if (element.ValueKind != JsonValueKind.Object ||
            !element.TryGetProperty(propertyName, out JsonElement property))
            return "";

        return property.ValueKind switch {
            JsonValueKind.String => property.GetString() ?? "",
            JsonValueKind.Number or JsonValueKind.True or JsonValueKind.False => property.ToString(),
            _ => ""
        };
    }

    private static string HtmlEncode(string value) {
        return WebUtility.HtmlEncode(value ?? "");
    }

    private static string ComputeShortHash(string value) {
        byte[] hash = SHA256.HashData(Encoding.UTF8.GetBytes(value ?? ""));
        return Convert.ToHexString(hash, 0, 8).ToLowerInvariant();
    }

    private static string FormatSessionLogLong(long value) {
        return Math.Max(0, value).ToString("N0", CultureInfo.CurrentCulture);
    }

    private static string FormatSessionLogKwh(double value) {
        return Math.Max(0, value).ToString("0.######", CultureInfo.CurrentCulture) + " kWh";
    }

    private static string FormatSessionLogKw(double value) {
        return Math.Max(0, value).ToString("0.###", CultureInfo.CurrentCulture) + " kW";
    }

    private static string FormatSessionLogUsd(double value) {
        return value <= 0 ? "$0.00" : value.ToString("C4", CultureInfo.CurrentCulture);
    }

    private string ResolveSelectedSessionFilesPath() {
        string sessionRoot = _proxy.ChatSessionFilesRoot;
        if (!string.IsNullOrWhiteSpace(_selectedSessionId))
            return Path.Combine(sessionRoot, SanitizePathSegment(_selectedSessionId));

        return sessionRoot;
    }

    private static string BuildExplorerSignature(string ownerKey, IEnumerable<AccessibleDirectoryListItem> directories) {
        return (ownerKey ?? "") + "|" + string.Join("|", directories.Select(item => item.Path + "|" + item.Exists + "|" + BuildDirectorySignature(item.Path)));
    }

    private static string BuildDirectorySignature(string path) {
        try {
            var info = new DirectoryInfo(path);
            if (!info.Exists)
                return path + "|missing";

            const int maxSignatureCount = 100;
            long fileCount = 0;
            long directoryCount = 0;
            try {
                fileCount = info.EnumerateFiles().Take(maxSignatureCount + 1).LongCount();
                directoryCount = info.EnumerateDirectories().Take(maxSignatureCount + 1).LongCount();
            } catch { }

            string fileCountText = fileCount > maxSignatureCount ? maxSignatureCount.ToString(CultureInfo.InvariantCulture) + "+" : fileCount.ToString(CultureInfo.InvariantCulture);
            string directoryCountText = directoryCount > maxSignatureCount ? maxSignatureCount.ToString(CultureInfo.InvariantCulture) + "+" : directoryCount.ToString(CultureInfo.InvariantCulture);
            return info.FullName + "|" + info.LastWriteTimeUtc.Ticks + "|" + fileCountText + "|" + directoryCountText;
        } catch {
            return path + "|unavailable";
        }
    }

    private FileTreeItem BuildDirectoryTree(string path, string displayName, int maxDepth, bool expanded, bool applyDefaultExclusions) {
        var info = new DirectoryInfo(path);
        if (!info.Exists) {
            return new FileTreeItem {
                DisplayName = displayName,
                Detail = TrimPathForDisplay(path, 84) + " (not created yet)",
                Icon = "[dir]",
                AccentBrush = Brushes.SlateGray,
                FontWeight = FontWeights.SemiBold,
                SourcePath = path,
                IsDirectory = true,
                CanRemove = true,
                IsExpanded = expanded
            };
        }

        var item = new FileTreeItem {
            DisplayName = displayName,
            Detail = TrimPathForDisplay(info.FullName, 84),
            Icon = "[dir]",
            AccentBrush = Brushes.DeepSkyBlue,
            FontWeight = FontWeights.SemiBold,
            SourcePath = info.FullName,
            IsDirectory = true,
            CanRemove = true,
            IsExpanded = expanded
        };

        AddDirectoryChildren(item, info, maxDepth, applyDefaultExclusions);
        return item;
    }

    private void AddDirectoryChildren(FileTreeItem parent, DirectoryInfo directory, int remainingDepth, bool applyDefaultExclusions) {
        if (remainingDepth <= 0)
            return;

        const int maxChildrenPerDirectory = 80;
        int added = 0;

        try {
            foreach (DirectoryInfo childDirectory in directory.EnumerateDirectories()
                         .Where(item => !applyDefaultExclusions || !IsDefaultExplorerExcluded(item.Name))
                         .Take(maxChildrenPerDirectory + 1)
                         .OrderBy(item => item.Name, StringComparer.CurrentCultureIgnoreCase)) {
                if (added >= maxChildrenPerDirectory)
                    break;

                var child = new FileTreeItem {
                    DisplayName = childDirectory.Name,
                    Detail = FormatDirectoryDetail(childDirectory),
                    Icon = "[dir]",
                    AccentBrush = Brushes.DeepSkyBlue,
                    FontWeight = FontWeights.Normal,
                    SourcePath = childDirectory.FullName,
                    IsDirectory = true,
                    IsExpanded = false
                };
                AddDirectoryChildren(child, childDirectory, remainingDepth - 1, applyDefaultExclusions);
                parent.Children.Add(child);
                added++;
            }

            foreach (FileInfo file in directory.EnumerateFiles()
                         .Take(maxChildrenPerDirectory + 1)
                         .OrderBy(item => item.Name, StringComparer.CurrentCultureIgnoreCase)) {
                if (added >= maxChildrenPerDirectory)
                    break;

                bool image = IsImageFile(file.Extension);
                parent.Children.Add(new FileTreeItem {
                    DisplayName = file.Name,
                    Detail = FormatBytes(file.Length) + " | " + file.LastWriteTime.ToString("M/d h:mm tt", CultureInfo.CurrentCulture),
                    Icon = image ? "[img]" : "[file]",
                    AccentBrush = image ? Brushes.MediumPurple : Brushes.LightSteelBlue,
                    FontWeight = FontWeights.Normal,
                    SourcePath = file.FullName,
                    IsExpanded = false
                });
                added++;
            }

            int remaining = CountRemainingChildren(directory, maxChildrenPerDirectory, applyDefaultExclusions);
            if (remaining > 0) {
                parent.Children.Add(new FileTreeItem {
                    DisplayName = "... " + remaining + " more",
                    Detail = "Use Refresh after narrowing the folder.",
                    Icon = "[...]",
                    AccentBrush = Brushes.SlateGray,
                    FontWeight = FontWeights.Normal,
                    IsExpanded = false
                });
            }
        } catch (Exception ex) {
            parent.Children.Add(new FileTreeItem {
                DisplayName = "Unavailable",
                Detail = TrimForDisplay(ex.Message, 90),
                Icon = "[!]",
                AccentBrush = Brushes.IndianRed,
                FontWeight = FontWeights.Normal,
                IsExpanded = false
            });
        }
    }

    private static int CountRemainingChildren(DirectoryInfo directory, int maxChildren, bool applyDefaultExclusions) {
        try {
            int directories = directory.EnumerateDirectories()
                .Where(item => !applyDefaultExclusions || !IsDefaultExplorerExcluded(item.Name))
                .Take(maxChildren + 1)
                .Count();
            int files = directory.EnumerateFiles()
                .Take(maxChildren + 1)
                .Count();
            return Math.Max(0, directories + files - maxChildren);
        } catch {
            return 0;
        }
    }

    private static bool IsDefaultExplorerExcluded(string name) {
        return name.Equals(".git", StringComparison.OrdinalIgnoreCase) ||
               name.Equals(".vs", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("bin", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("obj", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsImageFile(string extension) {
        return extension.Equals(".png", StringComparison.OrdinalIgnoreCase) ||
               extension.Equals(".jpg", StringComparison.OrdinalIgnoreCase) ||
               extension.Equals(".jpeg", StringComparison.OrdinalIgnoreCase) ||
               extension.Equals(".gif", StringComparison.OrdinalIgnoreCase) ||
               extension.Equals(".bmp", StringComparison.OrdinalIgnoreCase) ||
               extension.Equals(".webp", StringComparison.OrdinalIgnoreCase);
    }

    private static string FormatDirectoryDetail(DirectoryInfo directory) {
        try {
            int directoryCount = directory.EnumerateDirectories().Take(51).Count();
            int fileCount = directory.EnumerateFiles().Take(51).Count();
            string directoryText = directoryCount > 50 ? "50+ folders" : directoryCount + " folders";
            string fileText = fileCount > 50 ? "50+ files" : fileCount + " files";
            return directoryText + ", " + fileText;
        } catch {
            return "Contents unavailable";
        }
    }

    private static string SanitizePathSegment(string value) {
        if (string.IsNullOrWhiteSpace(value))
            return "_";

        string result = value.Trim();
        foreach (char ch in Path.GetInvalidFileNameChars())
            result = result.Replace(ch, '_');
        return string.IsNullOrWhiteSpace(result) ? "_" : result;
    }

    private static string GetDirectoryDisplayName(string path) {
        if (string.IsNullOrWhiteSpace(path))
            return "Directory";

        try {
            string trimmed = path.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
            string name = Path.GetFileName(trimmed);
            if (!string.IsNullOrWhiteSpace(name))
                return name;
            string root = Path.GetPathRoot(path) ?? "";
            return string.IsNullOrWhiteSpace(root) ? path : root;
        } catch {
            return path;
        }
    }

    private static string MakeSafeZipFileName(string name) {
        name = string.IsNullOrWhiteSpace(name) ? "folder" : name.Trim();
        foreach (char invalid in Path.GetInvalidFileNameChars())
            name = name.Replace(invalid, '_');
        name = name.Trim('.', ' ');
        if (string.IsNullOrWhiteSpace(name))
            name = "folder";
        return name.EndsWith(".zip", StringComparison.OrdinalIgnoreCase) ? name : name + ".zip";
    }

    private static string TrimPathForDisplay(string path, int maxLength) {
        if (string.IsNullOrWhiteSpace(path))
            return "-";

        string compact = path.Trim();
        if (compact.Length <= maxLength)
            return compact;

        int keep = Math.Max(12, maxLength - 3);
        return "..." + compact[^keep..];
    }

    private void RefreshServicesPanel() {
        _ = ProbeCompanionStatusAsync();
        string? previouslySelectedService = _selectedServiceMetric?.Name;
        var services = BuildServiceMetricItems();
        UpdateServiceMetricItems(services);

        var pipeline = BuildPipelineItems();
        string pipelineSignature = string.Join("|", pipeline.Select(item => item.Signature));
        if (!string.Equals(pipelineSignature, _pipelineSignature, StringComparison.Ordinal)) {
            _pipelineItems.Clear();
            foreach (PipelineNodeItem item in pipeline)
                _pipelineItems.Add(item);
            _pipelineSignature = pipelineSignature;
        }

        SyncServiceListSelection();
        ServiceMetricItem? nextService = GetSelectedServiceItems().FirstOrDefault(item =>
            !string.IsNullOrWhiteSpace(previouslySelectedService) &&
            string.Equals(item.Name, previouslySelectedService, StringComparison.OrdinalIgnoreCase))
            ?? GetSelectedServiceItems().FirstOrDefault()
            ?? (!string.IsNullOrWhiteSpace(previouslySelectedService)
                ? _serviceMetricItems.FirstOrDefault(item => string.Equals(item.Name, previouslySelectedService, StringComparison.OrdinalIgnoreCase))
                : null)
            ?? _serviceMetricItems.FirstOrDefault();

        UpdateServiceDetailsPanel(nextService);
        PipelineSummaryText.Text = BuildPipelineSummary();
    }

    private void UpdateServiceMetricItems(IReadOnlyList<ServiceMetricItem> services) {
        string namesSignature = string.Join("|", services.Select(item => NormalizeServiceName(item.Name)));
        bool rebuild = !string.Equals(namesSignature, _servicePanelSignature, StringComparison.Ordinal) ||
                       _serviceMetricItems.Count != services.Count;

        if (!rebuild) {
            for (int i = 0; i < services.Count; i++) {
                if (!ServiceNameEquals(_serviceMetricItems[i].Name, services[i].Name)) {
                    rebuild = true;
                    break;
                }
            }
        }

        if (rebuild) {
            _updatingServiceSelection = true;
            try {
                _serviceMetricItems.Clear();
                foreach (ServiceMetricItem item in services)
                    _serviceMetricItems.Add(item);
            } finally {
                _updatingServiceSelection = false;
            }

            _servicePanelSignature = namesSignature;
            _selectedServiceDetailsSignature = "";
            _selectedServiceLogSignature = "";
            return;
        }

        for (int i = 0; i < services.Count; i++)
            _serviceMetricItems[i].UpdateFrom(services[i]);
    }

    private void ServicesListBox_SelectionChanged(object sender, SelectionChangedEventArgs e) {
        if (!_updatingServiceSelection) {
            _selectedServiceLogNames.Clear();
            foreach (ServiceMetricItem item in GetSelectedServiceItems())
                _selectedServiceLogNames.Add(NormalizeServiceName(item.Name));
        }

        _selectedServiceMetric = e.AddedItems.OfType<ServiceMetricItem>().LastOrDefault()
            ?? GetSelectedServiceItems().FirstOrDefault();
        UpdateServiceDetailsPanel(_selectedServiceMetric);
    }

    private void ServicePropertySearchBox_TextChanged(object sender, TextChangedEventArgs e) {
        if (_renderingServiceOptions)
            return;
        if (_selectedServiceMetric != null)
            RenderServiceOptions(_selectedServiceMetric);
    }

    private void UpdateServiceDetailsPanel(ServiceMetricItem? service) {
        if (ServiceDetailsPanel == null)
            return;

        _selectedServiceMetric = service;
        if (service == null) {
            ServiceDetailsPanel.Visibility = Visibility.Collapsed;
            _selectedServiceDetailsSignature = "";
            _selectedServiceLogSignature = "";
            return;
        }

        ServiceDetailsPanel.Visibility = Visibility.Visible;
        var selectedNames = GetSelectedServiceNames().ToList();
        string selectedNamesSignature = string.Join("\u001F", selectedNames.Select(NormalizeServiceName));
        string detailsSignature = service.Signature + "\u001E" + selectedNamesSignature;
        if (!string.Equals(detailsSignature, _selectedServiceDetailsSignature, StringComparison.Ordinal)) {
            _selectedServiceDetailsSignature = detailsSignature;
            if (SelectedServiceNameText != null)
                SelectedServiceNameText.Text = selectedNames.Count > 1
                    ? service.Name + " +" + (selectedNames.Count - 1).ToString(CultureInfo.InvariantCulture)
                    : service.Name;
            if (SelectedServiceStatusText != null)
                SelectedServiceStatusText.Text = service.Status + " | " + service.CountLine;
            if (SelectedServiceDetailText != null)
                SelectedServiceDetailText.Text = selectedNames.Count > 1
                    ? service.Detail + Environment.NewLine + "Logging: " + string.Join(", ", selectedNames)
                    : service.Detail;
            RenderServiceOptions(service);
        }

        RenderSelectedServiceEventLog();
    }

    private IReadOnlyList<ServiceMetricItem> GetSelectedServiceItems() {
        if (ServicesListBox == null)
            return Array.Empty<ServiceMetricItem>();

        return ServicesListBox.SelectedItems
            .OfType<ServiceMetricItem>()
            .ToArray();
    }

    private IEnumerable<string> GetSelectedServiceNames() {
        foreach (string name in _selectedServiceLogNames.Select(NormalizeServiceName).Where(name => !string.IsNullOrWhiteSpace(name)).Distinct(StringComparer.OrdinalIgnoreCase).OrderBy(name => name, StringComparer.OrdinalIgnoreCase))
            yield return name;
    }

    private void SyncServiceListSelection() {
        if (ServicesListBox == null)
            return;

        var desiredNames = new HashSet<string>(
            _selectedServiceLogNames
                .Select(NormalizeServiceName)
                .Where(name => !string.IsNullOrWhiteSpace(name)),
            StringComparer.OrdinalIgnoreCase);
        var availableDesiredNames = new HashSet<string>(
            _serviceMetricItems
                .Select(item => NormalizeServiceName(item.Name))
                .Where(name => desiredNames.Contains(name)),
            StringComparer.OrdinalIgnoreCase);
        var currentNames = new HashSet<string>(
            ServicesListBox.SelectedItems
                .OfType<ServiceMetricItem>()
                .Select(item => NormalizeServiceName(item.Name))
                .Where(name => !string.IsNullOrWhiteSpace(name)),
            StringComparer.OrdinalIgnoreCase);
        if (currentNames.SetEquals(availableDesiredNames))
            return;

        _updatingServiceSelection = true;
        try {
            ServicesListBox.SelectedItems.Clear();
            foreach (ServiceMetricItem item in _serviceMetricItems) {
                if (availableDesiredNames.Contains(NormalizeServiceName(item.Name)))
                    ServicesListBox.SelectedItems.Add(item);
            }
        } finally {
            _updatingServiceSelection = false;
        }
    }

    private void RenderServiceOptions(ServiceMetricItem service) {
        if (ServiceOptionsPanel == null)
            return;

        _renderingServiceOptions = true;
        try {
            ServiceOptionsPanel.Children.Clear();
            AddServiceConfigSection("Snapshot");
            AddServiceConfigRow("Status", service.Status, BuildServiceStatusBrush(service.Status));
            AddServiceConfigRow("Summary", service.CountLine);
            AddServiceConfigRow("Detail", service.Detail);
            AddServiceActionRow(CreateServiceActionButton("Refresh services", RefreshServicesPanel));

            if (ServiceNameEquals(service.Name, "HTTP")) {
                RenderWebClientServiceOptions();
            } else if (ServiceNameEquals(service.Name, "Workstation")) {
                RenderLmVsProxyServiceOptions();
            } else if (string.Equals(service.Name, "LM Studio", StringComparison.OrdinalIgnoreCase) ||
                       string.Equals(service.Name, "LlmRuntime", StringComparison.OrdinalIgnoreCase)) {
                RenderModelRuntimeServiceOptions(service.Name);
            } else if (string.Equals(service.Name, "JackONNX", StringComparison.OrdinalIgnoreCase)) {
                RenderJackOnnxServiceOptions();
            } else if (string.Equals(service.Name, "VS Copilot", StringComparison.OrdinalIgnoreCase)) {
                RenderVsCopilotServiceOptions();
            } else if (string.Equals(service.Name, "Agent Tools", StringComparison.OrdinalIgnoreCase)) {
                RenderAgentToolsServiceOptions();
            } else if (string.Equals(service.Name, "Companion", StringComparison.OrdinalIgnoreCase)) {
                RenderCompanionServiceOptions();
            } else if (string.Equals(service.Name, "Internet Search", StringComparison.OrdinalIgnoreCase)) {
                RenderPermissionBackedServiceOptions("Internet Search", "SearchInternet/SearchService", snapshot => snapshot.InternetSearch);
            } else if (string.Equals(service.Name, "Reflection", StringComparison.OrdinalIgnoreCase)) {
                RenderPermissionBackedServiceOptions("Reflection", "ReflectionService and /reflect routes", _ => true);
            } else if (string.Equals(service.Name, "Prompt Intellisense", StringComparison.OrdinalIgnoreCase)) {
                RenderPromptIntellisenseServiceOptions();
            } else if (string.Equals(service.Name, "Session Files", StringComparison.OrdinalIgnoreCase)) {
                RenderSessionFilesServiceOptions();
            } else if (string.Equals(service.Name, "Terminal", StringComparison.OrdinalIgnoreCase)) {
                RenderTerminalServiceOptions();
            } else if (string.Equals(service.Name, "FTP", StringComparison.OrdinalIgnoreCase)) {
                RenderFtpServiceOptions();
            } else if (string.Equals(service.Name, "Port Forwarding", StringComparison.OrdinalIgnoreCase)) {
                RenderPortForwardingServiceOptions();
            } else {
                RenderGenericServiceOptions(service);
            }

            AddReflectedServiceProperties(service);
        } finally {
            _renderingServiceOptions = false;
        }
    }

