    private void RenderWebAuthSummaryRows() {
        try {
            IReadOnlyList<WebAuthUserDiagnosticsSnapshot> users = _proxy.GetWebAuthUserDiagnostics();
            int adminCount = users.Count(user => user.IsAdministrator);
            int enabledCount = users.Count(user => user.Enabled);
            AddServiceConfigRow("WebAuth users", users.Count.ToString(CultureInfo.InvariantCulture) + " total | " +
                                                 enabledCount.ToString(CultureInfo.InvariantCulture) + " enabled | " +
                                                 adminCount.ToString(CultureInfo.InvariantCulture) + " admin");
            foreach (WebAuthUserDiagnosticsSnapshot user in users.Take(3)) {
                string lastLogin = string.IsNullOrWhiteSpace(user.LastLoginUtc) ? "never logged in" : FormatManagementDate(user.LastLoginUtc);
                AddServiceConfigRow("User login", user.UserName + " | " + user.OwnerKey + " | " + lastLogin);
            }
        } catch (Exception ex) {
            AddServiceConfigRow("WebAuth users", "unavailable: " + TrimForDisplay(ex.Message, 120), Brushes.Orange);
        }
    }

    private void RenderCachedFtpConfigRows() {
        AddServiceConfigSection("FTP configuration");
        if (_ftpConfigPanelRows.Count == 0) {
            AddServiceConfigParagraph(_proxy.IsChatServerCreated && _proxy.ChatServer.IsListening
                ? "Loading saved FTP configuration."
                : "Start the Chat UI to load saved FTP configuration.");
            return;
        }

        foreach (ServiceConfigRowItem row in _ftpConfigPanelRows)
            AddServiceConfigRow(row.Label, row.Value, row.Label.IndexOf("error", StringComparison.OrdinalIgnoreCase) >= 0 ? Brushes.IndianRed : null);
    }

    private async Task RefreshFtpServiceConfigSnapshotAsync(bool force) {
        if (_ftpConfigPanelLoadInProgress)
            return;
        if (!force && DateTimeOffset.UtcNow - _lastFtpConfigPanelLoadUtc < TimeSpan.FromSeconds(8))
            return;

        _ftpConfigPanelLoadInProgress = true;
        _lastFtpConfigPanelLoadUtc = DateTimeOffset.UtcNow;
        try {
            var rows = new List<ServiceConfigRowItem>();
            if (!_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening) {
                rows.Add(new ServiceConfigRowItem("Status", "Chat UI is stopped; FTP API is unavailable."));
            } else {
                string endpoint = BuildChatServerEndpoint("/api/ftp-config");
                using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(8));
                using var request = new HttpRequestMessage(HttpMethod.Get, endpoint);
                AddSocketJackAuthHeaders(request);
                using HttpResponseMessage response = await client.SendAsync(request);
                string body = await response.Content.ReadAsStringAsync();
                if (!response.IsSuccessStatusCode) {
                    rows.Add(new ServiceConfigRowItem("Error", "HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TrimForDisplay(body, 180)));
                } else {
                    using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
                    rows.AddRange(BuildFtpConfigRows(document.RootElement));
                }
            }

            _ftpConfigPanelRows = rows;
            await TryInvokeOnUiAsync(() => {
                if (_selectedServiceMetric != null &&
                    string.Equals(_selectedServiceMetric.Name, "FTP", StringComparison.OrdinalIgnoreCase))
                    RenderServiceOptions(_selectedServiceMetric);
            }, "FTP config panel render");
        } catch (Exception ex) {
            _ftpConfigPanelRows = new[] { new ServiceConfigRowItem("Error", TrimForDisplay(ex.Message, 180)) };
            await TryInvokeOnUiAsync(() => {
                if (_selectedServiceMetric != null &&
                    string.Equals(_selectedServiceMetric.Name, "FTP", StringComparison.OrdinalIgnoreCase))
                    RenderServiceOptions(_selectedServiceMetric);
            }, "FTP config error render");
        } finally {
            _ftpConfigPanelLoadInProgress = false;
        }
    }

    private List<ServiceConfigRowItem> BuildFtpConfigRows(JsonElement root) {
        var rows = new List<ServiceConfigRowItem>();
        if (!GetJsonBool(root, "ok", false)) {
            rows.Add(new ServiceConfigRowItem("Error", GetJsonString(root, "error", "FTP config API returned ok=false.")));
            return rows;
        }

        rows.Add(new ServiceConfigRowItem("Owner", GetJsonString(root, "ownerKey", "-")));
        rows.Add(new ServiceConfigRowItem("Can edit", FormatEnabled(GetJsonBool(root, "canEdit", false))));
        rows.Add(new ServiceConfigRowItem("Permission", FormatEnabled(GetJsonBool(root, "permissionEnabled", false))));
        if (TryGetJsonProperty(root, "status", out JsonElement status)) {
            bool running = GetJsonBool(status, "running", false);
            int port = GetJsonInt(status, "port", 0);
            rows.Add(new ServiceConfigRowItem("Server status", running ? "running" : "stopped"));
            rows.Add(new ServiceConfigRowItem("Active endpoint", running && port > 0 ? "ftp://localhost:" + port.ToString(CultureInfo.InvariantCulture) + "/" : "-"));
            rows.Add(new ServiceConfigRowItem("Active owner", GetJsonString(status, "ownerKey", "-")));
            rows.Add(new ServiceConfigRowItem("Active root", TrimPathForDisplay(GetJsonString(status, "rootPath", "-"), 90)));
            rows.Add(new ServiceConfigRowItem("Active users", GetJsonInt(status, "userCount", 0).ToString(CultureInfo.InvariantCulture)));
        }

        if (TryGetJsonProperty(root, "config", out JsonElement config)) {
            rows.Add(new ServiceConfigRowItem("Saved port", GetJsonInt(config, "port", FtpServerPort).ToString(CultureInfo.InvariantCulture)));
            rows.Add(new ServiceConfigRowItem("Saved root", TrimPathForDisplay(GetJsonString(config, "rootPath", "-"), 90)));
            rows.Add(new ServiceConfigRowItem("Autostart", FormatEnabled(GetJsonBool(config, "autoStart", false))));
            rows.Add(new ServiceConfigRowItem("Primary login", FirstNonEmpty(GetJsonString(config, "userName", ""), "lmvsproxy") +
                                                      " | write " + FormatEnabled(GetJsonBool(config, "allowWrite", false))));
            rows.Add(new ServiceConfigRowItem("User logins", BuildFtpUsersLine(config)));
        }

        if (TryGetJsonProperty(root, "directories", out JsonElement directories))
            rows.Add(new ServiceConfigRowItem("Folder paths", BuildFtpDirectoriesLine(directories)));

        return rows;
    }

    private static string BuildFtpUsersLine(JsonElement config) {
        if (!TryGetJsonProperty(config, "users", out JsonElement users) || users.ValueKind != JsonValueKind.Array)
            return "-";

        var parts = new List<string>();
        foreach (JsonElement user in users.EnumerateArray()) {
            string userName = GetJsonString(user, "userName", "user");
            string rootPath = TrimPathForDisplay(GetJsonString(user, "rootPath", "-"), 48);
            string mode = GetJsonBool(user, "allowWrite", false) ? "write" : "read";
            parts.Add(userName + " -> " + rootPath + " (" + mode + ")");
        }

        if (parts.Count == 0)
            return "-";
        string suffix = parts.Count > 5 ? "; +" + (parts.Count - 5).ToString(CultureInfo.InvariantCulture) + " more" : "";
        return string.Join("; ", parts.Take(5)) + suffix;
    }

    private static string BuildFtpDirectoriesLine(JsonElement directories) {
        if (directories.ValueKind != JsonValueKind.Array)
            return "-";

        var parts = new List<string>();
        foreach (JsonElement directory in directories.EnumerateArray()) {
            string path = TrimPathForDisplay(GetJsonString(directory, "path", "-"), 56);
            bool exists = GetJsonBool(directory, "exists", false);
            parts.Add(path + (exists ? "" : " (missing)"));
        }

        if (parts.Count == 0)
            return "No accessible folders configured.";
        string suffix = parts.Count > 4 ? "; +" + (parts.Count - 4).ToString(CultureInfo.InvariantCulture) + " more" : "";
        return string.Join("; ", parts.Take(4)) + suffix;
    }

    private async Task ApplyFtpConfigActionAsync(string action) {
        if (!_proxy.IsChatServerCreated || !_proxy.ChatServer.IsListening)
            throw new InvalidOperationException("Chat UI is stopped; FTP API is unavailable.");

        string endpoint = BuildChatServerEndpoint("/api/ftp-config");
        using var client = CreateNetworkHttpClient(TimeSpan.FromSeconds(12));
        using var request = new HttpRequestMessage(HttpMethod.Post, endpoint);
        AddSocketJackAuthHeaders(request);
        request.Content = new StringContent(JsonSerializer.Serialize(new { action }), Encoding.UTF8, "application/json");
        using HttpResponseMessage response = await client.SendAsync(request);
        string body = await response.Content.ReadAsStringAsync();
        if (!response.IsSuccessStatusCode)
            throw new InvalidOperationException("FTP " + action + " failed: HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TrimForDisplay(body, 160));

        using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
        if (!GetJsonBool(document.RootElement, "ok", false))
            throw new InvalidOperationException("FTP " + action + " failed: " + GetJsonString(document.RootElement, "error", "unknown error"));

        AppendServiceEventLine("FTP", "FTP " + action + " applied.");
        _lastFtpConfigPanelLoadUtc = DateTimeOffset.MinValue;
        await RefreshFtpServiceConfigSnapshotAsync(force: true);
        RefreshMetrics();
    }

