    private string BuildChatServerEndpoint(string path) {
        string baseUrl = BuildLocalChatServerBaseUrl();

        string normalizedPath = (path ?? "").Trim();
        if (string.IsNullOrWhiteSpace(normalizedPath))
            return baseUrl;
        if (!normalizedPath.StartsWith("/", StringComparison.Ordinal))
            normalizedPath = "/" + normalizedPath;
        return baseUrl.TrimEnd('/') + normalizedPath;
    }

    private string BuildLocalChatServerBaseUrl() {
        string configured = (_proxy.ChatServerUrl ?? "").Trim();
        if (TryBuildLocalChatServerBaseUrl(configured, out string localBaseUrl))
            return localBaseUrl;

        return "http://127.0.0.1:" + ChatServerPort.ToString(CultureInfo.InvariantCulture) + "/";
    }

    private static bool TryBuildLocalChatServerBaseUrl(string candidate, out string baseUrl) {
        baseUrl = "";
        if (string.IsNullOrWhiteSpace(candidate))
            return false;

        if (!Uri.TryCreate(candidate, UriKind.Absolute, out Uri? uri))
            return false;

        if (!IsLoopbackHostAlias(uri.Host))
            return false;

        if (!string.Equals(uri.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) &&
            !string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
            return false;

        var builder = new UriBuilder(uri) {
            Path = "",
            Query = "",
            Fragment = ""
        };
        baseUrl = builder.Uri.ToString();
        return true;
    }

    private void OpenServiceUrl(string urlOrPath) {
        if (string.IsNullOrWhiteSpace(urlOrPath))
            return;

        try {
            Process.Start(new ProcessStartInfo(urlOrPath) { UseShellExecute = true });
        } catch (Exception ex) {
            AppendServiceEventLine(_selectedServiceMetric?.Name ?? "Services", "Open failed: " + TrimForDisplay(ex.Message, 160));
        }
    }

    private static Brush? BuildServiceStatusBrush(string value) {
        string lower = (value ?? "").ToLowerInvariant();
        if (lower.Contains("error") || lower.Contains("fail") || lower.Contains("unavailable") || lower.Contains("stopped") || lower.Contains("not running"))
            return Brushes.IndianRed;
        if (lower.Contains("running") || lower.Contains("listening") || lower.Contains("connected") || lower.Contains("online") || lower.Contains("ready"))
            return Brushes.LimeGreen;
        if (lower.Contains("waiting") || lower.Contains("starting") || lower.Contains("deferred") || lower.Contains("idle"))
            return Brushes.Orange;
        return null;
    }

    private static string FormatEnabled(bool enabled) {
        return enabled ? "enabled" : "disabled";
    }

    private static string FormatManagementDate(string value) {
        if (DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed))
            return parsed.ToLocalTime().ToString("M/d/yyyy h:mm:ss tt", CultureInfo.CurrentCulture);
        return string.IsNullOrWhiteSpace(value) ? "-" : value;
    }

