    private void AddReflectedServiceProperties(ServiceMetricItem service) {
        if (ServiceOptionsPanel == null)
            return;

        string query = GetServicePropertySearchText();
        var rows = new List<ReflectedServicePropertyRow>();
        foreach (ServicePropertySource source in BuildServicePropertySources(service)) {
            if (source.Target == null)
                continue;

            PropertyInfo[] properties;
            try {
                properties = source.Target.GetType().GetProperties(BindingFlags.Public | BindingFlags.Instance);
            } catch {
                continue;
            }

            foreach (PropertyInfo property in properties.OrderBy(property => property.Name, StringComparer.OrdinalIgnoreCase)) {
                if (!IsInspectableServiceProperty(property))
                    continue;
                if (source.Filter != null && !source.Filter(property))
                    continue;

                bool sensitive = IsSensitiveServiceProperty(property);
                object? value = null;
                string displayValue;
                try {
                    value = property.GetValue(source.Target);
                    displayValue = sensitive ? "[redacted]" : FormatServicePropertyValue(value);
                } catch (Exception ex) {
                    displayValue = "load failed: " + TrimForDisplay(ex.Message, 120);
                }

                bool canWrite = source.AllowWrites &&
                                !sensitive &&
                                property.CanWrite &&
                                property.SetMethod?.IsPublic == true &&
                                IsEditableServicePropertyType(property.PropertyType);
                string overrideKey = BuildServicePropertyOverrideKey(source.Category, property.Name);
                var row = new ReflectedServicePropertyRow(
                    NormalizeServiceName(service.Name),
                    source.Category,
                    overrideKey,
                    source.Target,
                    property,
                    value,
                    displayValue,
                    canWrite,
                    sensitive);

                if (ServicePropertyMatchesSearch(row, query))
                    rows.Add(row);
            }
        }

        AddServiceConfigSection("Properties");
        if (rows.Count == 0) {
            AddServiceConfigParagraph(string.IsNullOrWhiteSpace(query)
                ? "No reflected loadable properties were found for this service."
                : "No reflected properties match the current search.");
            return;
        }

        foreach (var group in rows.GroupBy(row => row.Category)) {
            AddServicePropertyGroup(group.Key, group.ToList());
        }
    }

    private string GetServicePropertySearchText() {
        return ServicePropertySearchBox?.Text?.Trim() ?? "";
    }

    private static string BuildServicePropertyOverrideKey(string category, string propertyName) {
        return (category ?? "").Trim() + "|" + (propertyName ?? "").Trim();
    }

    private IEnumerable<ServicePropertySource> BuildServicePropertySources(ServiceMetricItem service) {
        yield return new ServicePropertySource("Service card", service, false);

        string normalizedName = NormalizeServiceName(service.Name);
        if (ServiceNameEquals(normalizedName, "Workstation")) {
            yield return new ServicePropertySource("Workstation settings", _settings, true);
            yield return new ServicePropertySource("Workstation runtime", _proxy, true);
            yield break;
        }

        if (ServiceNameEquals(normalizedName, "HTTP")) {
            yield return new ServicePropertySource("HTTP settings", _settings, true, property => PropertyNameContainsAny(property, "WebChat", "WpfChat", "Chat", "OpenRegistration", "TokenRate"));
            object? chatServer = TryGetChatServerPropertyTarget();
            if (chatServer != null)
                yield return new ServicePropertySource("HTTP listener", chatServer, true);
            yield break;
        }

        if (string.Equals(normalizedName, "LlmRuntime", StringComparison.OrdinalIgnoreCase)) {
            yield return new ServicePropertySource("Runtime settings", _settings, true, property => PropertyNameContainsAny(property, "ModelRuntime", "RemoteLmStudio", "RemoteServer", "HostModel", "HostGpu", "HostThroughput"));
            if (_embeddedLlmRuntime != null)
                yield return new ServicePropertySource("Embedded runtime", _embeddedLlmRuntime, true);
            yield return new ServicePropertySource("JackONNX tool options", _jackOnnxToolOptions, true);
            yield break;
        }

        if (string.Equals(normalizedName, "LM Studio", StringComparison.OrdinalIgnoreCase)) {
            yield return new ServicePropertySource("LM Studio settings", _settings, true, property => PropertyNameContainsAny(property, "ModelRuntime", "RemoteLmStudio", "RemoteServer"));
            yield return new ServicePropertySource("LM Studio runtime", _lmStudioRuntime, true);
            yield break;
        }

        if (string.Equals(normalizedName, "JackONNX", StringComparison.OrdinalIgnoreCase)) {
            yield return new ServicePropertySource("JackONNX options", _jackOnnxRuntime.Options, true);
            yield return new ServicePropertySource("JackONNX tool options", _jackOnnxToolOptions, true);
            yield return new ServicePropertySource("JackONNX runtime", _jackOnnxRuntime, false);
            yield break;
        }

        if (string.Equals(normalizedName, "FTP", StringComparison.OrdinalIgnoreCase)) {
            yield return new ServicePropertySource("FTP settings", _settings, true, property => PropertyNameContainsAny(property, "Ftp", "Chat", "Storage"));
            yield return new ServicePropertySource("Workstation runtime", _proxy, false, property => PropertyNameContainsAny(property, "Ftp", "Chat", "Session"));
            yield break;
        }

        if (string.Equals(normalizedName, "Session Files", StringComparison.OrdinalIgnoreCase)) {
            yield return new ServicePropertySource("Session settings", _settings, true, property => PropertyNameContainsAny(property, "Storage", "Chat", "Host"));
            yield return new ServicePropertySource("Session runtime", _proxy, false, property => PropertyNameContainsAny(property, "Session", "Chat", "Storage"));
            yield break;
        }

        if (string.Equals(normalizedName, "Terminal", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(normalizedName, "Agent Tools", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(normalizedName, "VS Copilot", StringComparison.OrdinalIgnoreCase)) {
            yield return new ServicePropertySource(normalizedName + " settings", _settings, true, property => PropertyNameContainsAny(property, "TokenRate", "Storage", "Host", "WpfChat", "Model"));
            yield return new ServicePropertySource("Workstation runtime", _proxy, false);
            yield break;
        }

        if (string.Equals(normalizedName, "Port Forwarding", StringComparison.OrdinalIgnoreCase)) {
            yield return new ServicePropertySource("Forwarding settings", _settings, true, property => PropertyNameContainsAny(property, "Port", "Shell", "Host", "Publish"));
            yield break;
        }

        yield return new ServicePropertySource(normalizedName + " settings", _settings, true, property => PropertyNameContainsAny(property, normalizedName.Replace(" ", "")));
    }

    private IEnumerable<ServicePropertySource> BuildKnownServicePropertySources() {
        string[] serviceNames = {
            "Workstation",
            "HTTP",
            "LlmRuntime",
            "LM Studio",
            "JackONNX",
            "VS Copilot",
            "Agent Tools",
            "Companion",
            "Internet Search",
            "Reflection",
            "Prompt Intellisense",
            "Session Files",
            "Terminal",
            "FTP",
            "Port Forwarding"
        };
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        DateTimeOffset now = DateTimeOffset.UtcNow;
        foreach (string serviceName in serviceNames) {
            var service = CreateServiceMetricItem(serviceName, "-", "-", "-", now);
            foreach (ServicePropertySource source in BuildServicePropertySources(service)) {
                if (!source.AllowWrites || source.Target == null)
                    continue;

                string key = source.Category + "|" + source.Target.GetType().FullName;
                if (seen.Add(key))
                    yield return source;
            }
        }
    }

    private void ApplyServicePropertyOverridesToKnownTargets(string reason) {
        if (_settings.ServicePropertyOverrides == null || _settings.ServicePropertyOverrides.Count == 0)
            return;

        int applied = 0;
        foreach (ServicePropertySource source in BuildKnownServicePropertySources()) {
            PropertyInfo[] properties;
            try {
                properties = source.Target.GetType().GetProperties(BindingFlags.Public | BindingFlags.Instance);
            } catch {
                continue;
            }

            foreach (PropertyInfo property in properties) {
                if (!source.AllowWrites ||
                    source.Filter != null && !source.Filter(property) ||
                    !IsInspectableServiceProperty(property) ||
                    !property.CanWrite ||
                    property.SetMethod?.IsPublic != true ||
                    !IsEditableServicePropertyType(property.PropertyType) ||
                    IsSensitiveServiceProperty(property))
                    continue;

                string overrideKey = BuildServicePropertyOverrideKey(source.Category, property.Name);
                if (!_settings.ServicePropertyOverrides.TryGetValue(overrideKey, out string? persistedValue))
                    continue;

                if (!TryConvertServicePropertyValue(persistedValue, property.PropertyType, out object? convertedValue, out _))
                    continue;

                try {
                    property.SetValue(source.Target, convertedValue);
                    applied++;
                } catch {
                }
            }
        }

        if (applied > 0) {
            _jackOnnxToolDefinitions = JackOnnxLlmRuntimeToolRegistration.CreateDefinitions(_jackOnnxToolOptions);
            UpdateLlmRuntimeCapabilityLine();
            if (_uiReady)
                AppendServiceEventLine("Workstation", "Applied " + applied.ToString(CultureInfo.InvariantCulture) + " saved service propert" + (applied == 1 ? "y" : "ies") + " during " + reason + ".");
        }
    }

    private object? TryGetChatServerPropertyTarget() {
        try {
            return _proxy.IsChatServerCreated ? _proxy.ChatServer : null;
        } catch {
            return null;
        }
    }

    private static bool PropertyNameContainsAny(PropertyInfo property, params string[] tokens) {
        string name = property.Name ?? "";
        return tokens.Any(token => !string.IsNullOrWhiteSpace(token) && name.IndexOf(token, StringComparison.OrdinalIgnoreCase) >= 0);
    }

    private static bool IsInspectableServiceProperty(PropertyInfo property) {
        if (property.GetMethod?.IsPublic != true)
            return false;
        if (property.GetIndexParameters().Length != 0)
            return false;
        return IsDisplayableServicePropertyType(property.PropertyType);
    }

    private static bool IsDisplayableServicePropertyType(Type type) {
        Type effectiveType = Nullable.GetUnderlyingType(type) ?? type;
        if (effectiveType.IsEnum)
            return true;
        if (effectiveType == typeof(string) ||
            effectiveType == typeof(bool) ||
            effectiveType == typeof(DateTime) ||
            effectiveType == typeof(DateTimeOffset) ||
            effectiveType == typeof(TimeSpan) ||
            effectiveType == typeof(Uri))
            return true;

        TypeCode code = Type.GetTypeCode(effectiveType);
        return code is TypeCode.Byte or TypeCode.SByte or TypeCode.Int16 or TypeCode.UInt16 or TypeCode.Int32 or TypeCode.UInt32 or TypeCode.Int64 or TypeCode.UInt64 or TypeCode.Single or TypeCode.Double or TypeCode.Decimal;
    }

    private static bool IsEditableServicePropertyType(Type type) {
        Type effectiveType = Nullable.GetUnderlyingType(type) ?? type;
        return IsDisplayableServicePropertyType(type) &&
               effectiveType != typeof(DateTime) &&
               effectiveType != typeof(DateTimeOffset) &&
               effectiveType != typeof(Uri);
    }

    private static bool IsSensitiveServiceProperty(PropertyInfo property) {
        string name = property.Name ?? "";
        return name.IndexOf("token", StringComparison.OrdinalIgnoreCase) >= 0 ||
               name.IndexOf("password", StringComparison.OrdinalIgnoreCase) >= 0 ||
               name.IndexOf("secret", StringComparison.OrdinalIgnoreCase) >= 0 ||
               name.IndexOf("key", StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static string FormatServicePropertyValue(object? value) {
        if (value == null)
            return "";
        return value switch {
            bool boolean => boolean ? "true" : "false",
            DateTime dateTime => dateTime.ToString("yyyy-MM-dd HH:mm:ss", CultureInfo.CurrentCulture),
            DateTimeOffset dateTimeOffset => dateTimeOffset.ToLocalTime().ToString("yyyy-MM-dd HH:mm:ss zzz", CultureInfo.CurrentCulture),
            TimeSpan timeSpan => timeSpan.ToString(),
            IFormattable formattable => formattable.ToString(null, CultureInfo.InvariantCulture) ?? "",
            _ => value.ToString() ?? ""
        };
    }

    private static bool ServicePropertyMatchesSearch(ReflectedServicePropertyRow row, string query) {
        if (string.IsNullOrWhiteSpace(query))
            return true;

        return row.Category.IndexOf(query, StringComparison.OrdinalIgnoreCase) >= 0 ||
               row.Property.Name.IndexOf(query, StringComparison.OrdinalIgnoreCase) >= 0 ||
               row.DisplayValue.IndexOf(query, StringComparison.OrdinalIgnoreCase) >= 0 ||
               row.Property.PropertyType.Name.IndexOf(query, StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private void AddServicePropertyGroup(string category, IReadOnlyList<ReflectedServicePropertyRow> rows) {
        var panel = new StackPanel();
        var container = new Border {
            Margin = new Thickness(0, 0, 0, 8),
            BorderThickness = new Thickness(1),
            BorderBrush = new SolidColorBrush(Color.FromRgb(47, 62, 80)),
            Background = new SolidColorBrush(Color.FromRgb(10, 15, 23)),
            Child = panel
        };

        panel.Children.Add(new Border {
            Background = new SolidColorBrush(Color.FromRgb(30, 39, 52)),
            Padding = new Thickness(7, 3, 7, 3),
            Child = new TextBlock {
                Text = category,
                Foreground = new SolidColorBrush(Color.FromRgb(226, 235, 247)),
                FontSize = 11,
                FontWeight = FontWeights.SemiBold
            }
        });

        for (int i = 0; i < rows.Count; i++) {
            panel.Children.Add(CreateServicePropertyRowElement(rows[i], i));
        }

        ServiceOptionsPanel.Children.Add(container);
    }

    private FrameworkElement CreateServicePropertyRowElement(ReflectedServicePropertyRow row, int index) {
        var grid = new Grid {
            Background = new SolidColorBrush(index % 2 == 0 ? Color.FromRgb(13, 19, 29) : Color.FromRgb(16, 23, 34))
        };
        grid.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(158) });
        grid.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(1, GridUnitType.Star) });

        var nameBlock = new TextBlock {
            Text = row.Property.Name,
            Foreground = new SolidColorBrush(Color.FromRgb(187, 202, 221)),
            FontSize = 11,
            Padding = new Thickness(7, 4, 8, 4),
            TextTrimming = TextTrimming.CharacterEllipsis,
            ToolTip = row.Property.PropertyType.Name
        };
        Grid.SetColumn(nameBlock, 0);
        grid.Children.Add(nameBlock);

        FrameworkElement editor = CreateServicePropertyEditor(row);
        Grid.SetColumn(editor, 1);
        grid.Children.Add(editor);

        return new Border {
            BorderThickness = new Thickness(0, 1, 0, 0),
            BorderBrush = new SolidColorBrush(Color.FromRgb(34, 46, 62)),
            Child = grid
        };
    }

    private FrameworkElement CreateServicePropertyEditor(ReflectedServicePropertyRow row) {
        var binding = new ReflectedServicePropertyBinding(row.ServiceName, row.Category, row.OverrideKey, row.Target, row.Property, row.DisplayValue, row.CanWrite);
        Type effectiveType = Nullable.GetUnderlyingType(row.Property.PropertyType) ?? row.Property.PropertyType;

        if (row.Sensitive) {
            return new TextBlock {
                Text = row.DisplayValue,
                Foreground = new SolidColorBrush(Color.FromRgb(159, 177, 200)),
                FontSize = 11,
                Padding = new Thickness(6, 4, 6, 4),
                FontFamily = new FontFamily("Consolas")
            };
        }

        if (effectiveType == typeof(bool)) {
            var checkBox = new CheckBox {
                IsChecked = row.Value is bool boolean && boolean,
                IsEnabled = row.CanWrite,
                Tag = binding,
                Margin = new Thickness(6, 2, 6, 2),
                VerticalAlignment = VerticalAlignment.Center,
                HorizontalAlignment = HorizontalAlignment.Left
            };
            checkBox.Checked += ServicePropertyCheckBox_Changed;
            checkBox.Unchecked += ServicePropertyCheckBox_Changed;
            return checkBox;
        }

        if (effectiveType.IsEnum) {
            var comboBox = new ComboBox {
                ItemsSource = Enum.GetNames(effectiveType),
                SelectedItem = row.Value?.ToString() ?? "",
                IsEnabled = row.CanWrite,
                Tag = binding,
                Margin = new Thickness(4, 2, 6, 2),
                MinHeight = 22,
                FontSize = 11
            };
            comboBox.SelectionChanged += ServicePropertyComboBox_SelectionChanged;
            return comboBox;
        }

        var textBox = new TextBox {
            Text = row.DisplayValue,
            IsReadOnly = !row.CanWrite,
            Tag = binding,
            Margin = new Thickness(4, 2, 6, 2),
            Padding = new Thickness(5, 1, 5, 1),
            MinHeight = 22,
            Background = new SolidColorBrush(row.CanWrite ? Color.FromRgb(7, 10, 16) : Color.FromRgb(13, 19, 29)),
            BorderBrush = row.CanWrite ? new SolidColorBrush(Color.FromRgb(58, 77, 99)) : Brushes.Transparent,
            Foreground = new SolidColorBrush(row.CanWrite ? Color.FromRgb(241, 247, 255) : Color.FromRgb(174, 190, 210)),
            FontFamily = new FontFamily("Consolas"),
            FontSize = 11
        };
        textBox.LostFocus += ServicePropertyTextBox_LostFocus;
        textBox.KeyDown += ServicePropertyTextBox_KeyDown;
        return textBox;
    }

    private void ServicePropertyTextBox_LostFocus(object sender, RoutedEventArgs e) {
        if (sender is TextBox textBox)
            ApplyServicePropertyTextBoxValue(textBox);
    }

    private void ServicePropertyTextBox_KeyDown(object sender, System.Windows.Input.KeyEventArgs e) {
        if (e.Key != Key.Enter || sender is not TextBox textBox)
            return;

        ApplyServicePropertyTextBoxValue(textBox);
        e.Handled = true;
    }

    private void ServicePropertyCheckBox_Changed(object sender, RoutedEventArgs e) {
        if (sender is CheckBox checkBox &&
            checkBox.Tag is ReflectedServicePropertyBinding binding &&
            binding.CanWrite) {
            ApplyReflectedServicePropertyValue(binding, checkBox.IsChecked.GetValueOrDefault(false));
        }
    }

    private void ServicePropertyComboBox_SelectionChanged(object sender, SelectionChangedEventArgs e) {
        if (sender is ComboBox comboBox &&
            comboBox.Tag is ReflectedServicePropertyBinding binding &&
            binding.CanWrite &&
            comboBox.SelectedItem is string selected) {
            ApplyReflectedServicePropertyValue(binding, selected);
        }
    }

    private void ApplyServicePropertyTextBoxValue(TextBox textBox) {
        if (textBox.Tag is not ReflectedServicePropertyBinding binding || !binding.CanWrite)
            return;
        if (string.Equals(textBox.Text, binding.LastDisplayValue, StringComparison.Ordinal))
            return;

        ApplyReflectedServicePropertyValue(binding, textBox.Text ?? "");
    }

    private void ApplyReflectedServicePropertyValue(ReflectedServicePropertyBinding binding, object rawValue) {
        try {
            if (!TryConvertServicePropertyValue(rawValue, binding.Property.PropertyType, out object? convertedValue, out string error)) {
                AppendServiceEventLine(binding.ServiceName, "Property update rejected for " + binding.Property.Name + ": " + error);
                return;
            }

            binding.Property.SetValue(binding.Target, convertedValue);
            _settings.ServicePropertyOverrides ??= new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            _settings.ServicePropertyOverrides[binding.OverrideKey] = FormatServicePropertyValue(convertedValue);
            if (ReferenceEquals(binding.Target, _settings)) {
                ApplySettingsToUi(_settings);
            } else if (ReferenceEquals(binding.Target, _jackOnnxToolOptions)) {
                _jackOnnxToolDefinitions = JackOnnxLlmRuntimeToolRegistration.CreateDefinitions(_jackOnnxToolOptions);
                UpdateLlmRuntimeCapabilityLine();
            }
            PersistSettingsToDisk(_settings, applyToServices: true);

            AppendServiceEventLine(binding.ServiceName, "Property updated: " + binding.Category + "." + binding.Property.Name + " = " + FormatServicePropertyValue(convertedValue));
            RefreshServicesPanel();
        } catch (Exception ex) {
            AppendServiceEventLine(binding.ServiceName, "Property update failed for " + binding.Property.Name + ": " + TrimForDisplay(ex.Message, 180));
        }
    }

    private static bool TryConvertServicePropertyValue(object rawValue, Type targetType, out object? convertedValue, out string error) {
        Type nullableType = Nullable.GetUnderlyingType(targetType);
        Type effectiveType = nullableType ?? targetType;
        string text = rawValue?.ToString() ?? "";

        if (nullableType != null && string.IsNullOrWhiteSpace(text)) {
            convertedValue = null;
            error = "";
            return true;
        }

        try {
            if (effectiveType == typeof(string)) {
                convertedValue = text;
            } else if (effectiveType == typeof(bool)) {
                if (rawValue is bool boolean) {
                    convertedValue = boolean;
                } else if (string.Equals(text, "enabled", StringComparison.OrdinalIgnoreCase) || string.Equals(text, "yes", StringComparison.OrdinalIgnoreCase) || text == "1") {
                    convertedValue = true;
                } else if (string.Equals(text, "disabled", StringComparison.OrdinalIgnoreCase) || string.Equals(text, "no", StringComparison.OrdinalIgnoreCase) || text == "0") {
                    convertedValue = false;
                } else {
                    convertedValue = bool.Parse(text);
                }
            } else if (effectiveType.IsEnum) {
                convertedValue = Enum.Parse(effectiveType, text, ignoreCase: true);
            } else if (effectiveType == typeof(TimeSpan)) {
                convertedValue = TimeSpan.Parse(text, CultureInfo.InvariantCulture);
            } else {
                TypeConverter converter = TypeDescriptor.GetConverter(effectiveType);
                convertedValue = converter.ConvertFromString(null, CultureInfo.InvariantCulture, text);
            }

            error = "";
            return true;
        } catch (Exception ex) {
            convertedValue = null;
            error = TrimForDisplay(ex.Message, 120);
            return false;
        }
    }

    private void AddServiceActionRow(params Button[] buttons) {
        if (ServiceOptionsPanel == null)
