    private Button CreateServiceActionButton(string content, Action action, bool isEnabled = true) {
        var button = new Button {
            Content = content,
            Padding = new Thickness(8, 4, 8, 4),
            Margin = new Thickness(0, 0, 8, 8),
            MinHeight = 26,
            IsEnabled = isEnabled
        };
        button.Click += (_, _) => {
            try {
                action();
            } catch (Exception ex) {
                AppendServiceEventLine(_selectedServiceMetric?.Name ?? "Services", "Action failed: " + TrimForDisplay(ex.Message, 160));
            }
        };
        return button;
    }

    private Button CreateServiceAsyncActionButton(string content, Func<Task> action, bool isEnabled = true) {
        var button = new Button {
            Content = content,
            Padding = new Thickness(8, 4, 8, 4),
            Margin = new Thickness(0, 0, 8, 8),
            MinHeight = 26,
            IsEnabled = isEnabled
        };
        button.Click += async (_, _) => {
            try {
                button.IsEnabled = false;
                await action();
            } catch (Exception ex) {
                AppendServiceEventLine(_selectedServiceMetric?.Name ?? "Services", "Action failed: " + TrimForDisplay(ex.Message, 160));
            } finally {
