                RefreshMetrics();
            }
        };
        return button;
    }

    private void RenderSelectedServiceEventLog() {
        if (ServiceEventLogTextBox == null)
            return;

        var serviceNames = GetSelectedServiceNames().ToList();
        var entries = serviceNames
            .SelectMany(serviceName => GetServiceEventLog(serviceName).Select(line => new { ServiceName = serviceName, Line = line }))
            .OrderBy(entry => entry.Line, StringComparer.Ordinal)
            .ToList();
        string logSignature =
            string.Join("\u001F", serviceNames.Select(NormalizeServiceName)) +
            "\u001E" +
            string.Join("\u001F", entries.Select(entry => NormalizeServiceName(entry.ServiceName) + "\u001D" + entry.Line));
        if (string.Equals(logSignature, _selectedServiceLogSignature, StringComparison.Ordinal))
            return;

        _selectedServiceLogSignature = logSignature;
        ServiceEventLogTextBox.Document.Blocks.Clear();
        var paragraph = new Paragraph {
            LineHeight = 16,
            Margin = new Thickness(0)
        };

        int rendered = 0;
        foreach (var entry in entries) {
            string normalizedLine = TrimForDisplay(entry.Line, 1200);
            AppendSyntaxLogLine(paragraph, "[" + entry.ServiceName + "] " + normalizedLine);
            paragraph.Inlines.Add(new LineBreak());
            rendered++;
        }

        if (rendered == 0) {
            AppendSyntaxLogLine(paragraph, "No events yet for selected services.");
            paragraph.Inlines.Add(new LineBreak());
            ServiceEventLogTextBox.Document.Blocks.Add(paragraph);
            return;
        }

        ServiceEventLogTextBox.Document.Blocks.Add(paragraph);
        ServiceEventLogTextBox.CaretPosition = ServiceEventLogTextBox.Document.ContentEnd;
        ServiceEventLogTextBox.ScrollToEnd();
    }

    private Queue<string> GetServiceEventLog(string serviceName) {
        string normalizedName = NormalizeServiceName(serviceName);
        if (string.IsNullOrWhiteSpace(normalizedName))
            return new Queue<string>();
        if (!_serviceEventLogByName.TryGetValue(normalizedName, out Queue<string>? lines)) {
            lines = new Queue<string>();
            _serviceEventLogByName[normalizedName] = lines;
        }

        return lines;
    }

    private void AppendServiceEventLine(string serviceName, string line) {
        string normalizedName = NormalizeServiceName(serviceName);
        if (string.IsNullOrWhiteSpace(normalizedName))
            return;
        if (string.IsNullOrWhiteSpace(line))
            return;

        Queue<string> lines = GetServiceEventLog(normalizedName);
        string timestamp = DateTimeOffset.UtcNow.ToLocalTime().ToString("HH:mm:ss.fff", CultureInfo.InvariantCulture);
        lines.Enqueue(timestamp + "  " + TrimForDisplay(line, 1020));
        while (lines.Count > MaxServiceEventLines)
            lines.Dequeue();

        _servicePulseUtc[normalizedName] = DateTimeOffset.UtcNow;
        if (ShouldMirrorServiceLogToDebugger(normalizedName))
            AppendServiceLogToDebugger(normalizedName, timestamp + "  " + TrimForDisplay(line, 1020));

        if (_selectedServiceLogNames.Contains(normalizedName) ||
            (_selectedServiceMetric != null && ServiceNameEquals(_selectedServiceMetric.Name, normalizedName)))
            RenderSelectedServiceEventLog();
    }

    private void ClearServiceEventLog(string serviceName) {
        string normalizedName = NormalizeServiceName(serviceName);
        if (string.IsNullOrWhiteSpace(normalizedName))
            return;
        if (_serviceEventLogByName.TryGetValue(normalizedName, out Queue<string>? lines))
            lines.Clear();
        RenderSelectedServiceEventLog();
    }

    private void ServiceCopySnapshotButton_Click(object sender, RoutedEventArgs e) {
