    private List<PipelineNodeItem> BuildPipelineItems() {
        string modelRuntimeName = GetModelRuntimeServiceName();
        string[] names = _activePipelineKind switch {
            "web-chat" => new[] { "HTTP", "Workstation", modelRuntimeName },
            "agent" => new[] { "HTTP", "Agent Tools", "Workstation", modelRuntimeName },
            "companion" => new[] { "HTTP", "Companion", "Workstation", modelRuntimeName },
            "internet-search" => new[] { "Client", "Workstation", "Internet Search", modelRuntimeName },
            "reflection" => new[] { "Client", "Workstation", "Reflection", modelRuntimeName },
            "prompt-intellisense" => new[] { "Prompt", "Prompt Intellisense", "HTTP" },
            "terminal" => new[] { "HTTP", "Terminal", "Workstation", modelRuntimeName },
            "ftp" => new[] { "HTTP", "FTP", "Session Files" },
            "vs-copilot" => new[] { "VS Copilot", "Workstation", modelRuntimeName },
            _ => _proxy.IsListening
                ? new[] { "VS Copilot", "Workstation", modelRuntimeName }
                : new[] { "Waiting", "Workstation", modelRuntimeName }
        };
        if (GetSelectedModelRuntimeProvider() == RuntimeProviderLlmRuntime && names.Contains(modelRuntimeName, StringComparer.OrdinalIgnoreCase))
            names = names.Concat(new[] { "JackONNX" }).ToArray();

        var items = new List<PipelineNodeItem>();
        for (int i = 0; i < names.Length; i++) {
            bool last = i == names.Length - 1;
            items.Add(new PipelineNodeItem {
                Name = names[i],
                Detail = GetPipelineNodeDetail(names[i]),
                ArrowVisibility = last ? Visibility.Collapsed : Visibility.Visible,
                BackgroundBrush = i == 0 ? new SolidColorBrush(Color.FromRgb(19, 39, 54)) : new SolidColorBrush(Color.FromRgb(17, 25, 36)),
                BorderBrush = names[i].Equals(modelRuntimeName, StringComparison.OrdinalIgnoreCase) ? _lmStatusBrush : new SolidColorBrush(Color.FromRgb(67, 94, 116))
            });
        }

        return items;
    }

