    private string GetChatServerClientText() {
        if (!_proxy.IsChatServerCreated)
            return "Chat clients: -";

        try {
            return "Chat clients: " + _proxy.ChatServer.Clients.Count;
        } catch {
            return "Chat clients: unavailable";
        }
    }

    private string GetChatServerByteText() {
        if (!_proxy.IsChatServerCreated)
            return "HTTP bytes: -";

        try {
            long received = _proxy.ChatServer.HttpTotalBytesReceived;
            long sent = _proxy.ChatServer.HttpTotalBytesSent;
            return FormatChatServerByteText(received, sent, true);
        } catch {
            return "HTTP bytes: unavailable";
        }
    }

    private (long Received, long Sent, bool Available) GetChatServerBytes() {
        if (!_proxy.IsChatServerCreated)
            return (0, 0, false);

        try {
            return (_proxy.ChatServer.HttpTotalBytesReceived, _proxy.ChatServer.HttpTotalBytesSent, true);
        } catch {
            return (0, 0, false);
        }
    }

    private void UpdateChatBandwidthMetrics() {
        (long received, long sent, bool available) = GetChatServerBytes();
        if (!available) {
            ResetChatBandwidthMetrics();
            return;
        }

        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (!_lastChatBandwidthSampleUtc.HasValue ||
            received < _lastChatBandwidthBytesIn ||
            sent < _lastChatBandwidthBytesOut) {
            _lastChatBandwidthSampleUtc = now;
            _lastChatBandwidthBytesIn = Math.Max(0, received);
            _lastChatBandwidthBytesOut = Math.Max(0, sent);
            _chatBandwidthInSnapshot = _chatBandwidthInTracker.Update(0, received);
            _chatBandwidthOutSnapshot = _chatBandwidthOutTracker.Update(0, sent);
            return;
        }

        double elapsedSeconds = Math.Max(0.001, (now - _lastChatBandwidthSampleUtc.Value).TotalSeconds);
        long receivedDelta = Math.Max(0, received - _lastChatBandwidthBytesIn);
        long sentDelta = Math.Max(0, sent - _lastChatBandwidthBytesOut);
        double inboundKbps = Math.Max(0, receivedDelta * 8.0 / elapsedSeconds / 1000.0);
        double outboundKbps = Math.Max(0, sentDelta * 8.0 / elapsedSeconds / 1000.0);

        _lastChatBandwidthSampleUtc = now;
        _lastChatBandwidthBytesIn = received;
        _lastChatBandwidthBytesOut = sent;
        _chatBandwidthInSnapshot = _chatBandwidthInTracker.Update(inboundKbps, received);
        _chatBandwidthOutSnapshot = _chatBandwidthOutTracker.Update(outboundKbps, sent);

        if (receivedDelta > 0 || sentDelta > 0)
            PulseService("Web Client UI", "JACK");
    }

    private void ResetChatBandwidthMetrics() {
        _lastChatBandwidthSampleUtc = null;
        _lastChatBandwidthBytesIn = 0;
        _lastChatBandwidthBytesOut = 0;
        _chatBandwidthInTracker.Reset();
        _chatBandwidthOutTracker.Reset();
        _chatBandwidthInSnapshot = BandwidthMetricSnapshot.Empty("Inbound");
        _chatBandwidthOutSnapshot = BandwidthMetricSnapshot.Empty("Outbound");
    }

    private void UpdateHealthMetrics() {
        UpdateGpuHealthMetrics();
        UpdateRamHealthMetric();
        UpdateCpuHealthMetric();
        UpdateNetworkHealthMetrics();
        UpdateIoHealthMetric();
        UpdateTokenPerformanceMetrics();
    }

    private void UpdateGpuHealthMetrics() {
        DateTimeOffset now = DateTimeOffset.UtcNow;
        TimeSpan refreshInterval = IsLinuxWorkstationHardwareBridgeMode()
            ? TimeSpan.FromSeconds(12)
            : TimeSpan.FromSeconds(4);
        if (!_gpuHealthRefreshInProgress && now - _lastGpuHealthSampleUtc >= refreshInterval) {
            _lastGpuHealthSampleUtc = now;
            _gpuHealthRefreshInProgress = true;
            _ = Task.Run(RefreshGpuHealthSnapshot)
                .ContinueWith(task => {
                    if (task.IsFaulted)
                        SetGpuHealthUnavailable();
                    _gpuHealthRefreshInProgress = false;
                    TryBeginOnUi(UpdateGpuHealthDisplay, "GPU health refresh");
                }, TaskScheduler.Default);
        }

        UpdateGpuHealthDisplay();
    }

    private void UpdateGpuHealthDisplay() {
        GpuUtilizationHealthText.Text = _gpuUtilizationHealthText;
        VramUsageHealthText.Text = _vramUsageHealthText;
        ApplyPercentProgressBar(GpuUtilizationProgressBar, _gpuUtilizationPercent, "GPU utilization");
        ApplyPercentProgressBar(VramUsageProgressBar, _vramUsagePercent, "VRAM usage");
    }

    private void RefreshGpuHealthSnapshot() {
        if (IsLinuxWorkstationHardwareBridgeMode() && TryRefreshGpuHealthSnapshotFromLinuxServerHardware())
            return;

        try {
            var startInfo = new ProcessStartInfo {
                FileName = "nvidia-smi",
                Arguments = "--query-gpu=utilization.gpu,memory.used,memory.total --format=csv,noheader,nounits",
                UseShellExecute = false,
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                CreateNoWindow = true
            };

            using Process? process = Process.Start(startInfo);
            if (process == null) {
                SetGpuHealthUnavailable();
                return;
            }

            if (!process.WaitForExit(750)) {
                TryKillProcess(process);
                SetGpuHealthUnavailable();
                return;
            }

            string output = process.StandardOutput.ReadToEnd();
            if (process.ExitCode != 0 || string.IsNullOrWhiteSpace(output)) {
                SetGpuHealthUnavailable();
                return;
            }

            string? firstLine = output
                .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)
                .FirstOrDefault();
            if (string.IsNullOrWhiteSpace(firstLine)) {
                SetGpuHealthUnavailable();
                return;
            }

            string[] parts = firstLine.Split(',').Select(part => part.Trim()).ToArray();
            if (parts.Length < 3 ||
                !double.TryParse(parts[0], NumberStyles.Float, CultureInfo.InvariantCulture, out double utilization) ||
                !double.TryParse(parts[1], NumberStyles.Float, CultureInfo.InvariantCulture, out double memoryUsedMb) ||
                !double.TryParse(parts[2], NumberStyles.Float, CultureInfo.InvariantCulture, out double memoryTotalMb) ||
                memoryTotalMb <= 0) {
                SetGpuHealthUnavailable();
                return;
            }

            double memoryPercent = Math.Clamp(memoryUsedMb / memoryTotalMb * 100.0, 0, 100);
            _gpuUtilizationPercent = Math.Clamp(utilization, 0, 100);
            _vramUsagePercent = memoryPercent;
            _gpuUtilizationHealthText = FormatPercent(utilization);
            _vramUsageHealthText = memoryUsedMb.ToString("0", CultureInfo.CurrentCulture) + "/" +
                                   memoryTotalMb.ToString("0", CultureInfo.CurrentCulture) + " MB (" +
                                   FormatPercent(memoryPercent) + ")";
        } catch {
            SetGpuHealthUnavailable();
        }
    }

    private bool TryRefreshGpuHealthSnapshotFromLinuxServerHardware() {
        foreach (string url in EnumerateLinuxServerHardwareMetricUrls()) {
            try {
                using var client = CreateNetworkHttpClient(TimeSpan.FromMilliseconds(1200));
                using HttpResponseMessage response = client.GetAsync(url).GetAwaiter().GetResult();
                if (!response.IsSuccessStatusCode)
                    continue;

                string body = response.Content.ReadAsStringAsync().GetAwaiter().GetResult();
                using JsonDocument document = JsonDocument.Parse(body);
                if (!document.RootElement.TryGetProperty("gpu", out JsonElement gpu))
                    continue;
                if (TryApplyGpuHealthSnapshotFromServerHardware(gpu))
                    return true;
            } catch {
            }
        }

        return false;
    }

    private bool TryApplyGpuHealthSnapshotFromServerHardware(JsonElement gpu) {
        bool available = ReadGpuHealthJsonBool(gpu, "available");
        double? percent = ReadGpuHealthJsonNullableDouble(gpu, "percent");
        double? vramPercent = ReadGpuHealthJsonNullableDouble(gpu, "vramPercent");
        string text = ReadGpuHealthJsonString(gpu, "text");
        string vramText = ReadGpuHealthJsonString(gpu, "vramText");
        ulong vramUsedBytes = ReadGpuHealthJsonUInt64(gpu, "vramUsedBytes");
        ulong vramTotalBytes = ReadGpuHealthJsonUInt64(gpu, "vramTotalBytes");

        if (!available && !percent.HasValue && !vramPercent.HasValue && vramTotalBytes == 0)
            return false;

        double safePercent = percent.HasValue ? Math.Clamp(percent.Value, 0, 100) : 0;
        double safeVramPercent = vramPercent.HasValue ? Math.Clamp(vramPercent.Value, 0, 100) : 0;
        _gpuUtilizationPercent = safePercent;
        _vramUsagePercent = safeVramPercent;
        _gpuUtilizationHealthText = string.IsNullOrWhiteSpace(text) ? FormatPercent(safePercent) : text;
        if (!string.IsNullOrWhiteSpace(vramText)) {
            _vramUsageHealthText = vramText;
        } else if (vramTotalBytes > 0) {
            _vramUsageHealthText = FormatBytes(ToDisplayByteCount(vramUsedBytes)) + "/" +
                                   FormatBytes(ToDisplayByteCount(vramTotalBytes)) + " (" +
                                   FormatPercent(safeVramPercent) + ")";
        } else {
            _vramUsageHealthText = FormatPercent(safeVramPercent);
        }

        return true;
    }

    private bool IsLinuxWorkstationHardwareBridgeMode() {
        return IsWineSafeWpfMode() ||
               IsWineEnvironment() ||
               !string.IsNullOrWhiteSpace(Environment.GetEnvironmentVariable("JACKLLM_SERVER_HARDWARE_URL")) ||
               !string.IsNullOrWhiteSpace(Environment.GetEnvironmentVariable("JACKLLM_WORKSTATION_HARDWARE_URL"));
    }

    private IEnumerable<string> EnumerateLinuxServerHardwareMetricUrls() {
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        foreach (string variable in new[] { "JACKLLM_SERVER_HARDWARE_URL", "JACKLLM_WORKSTATION_HARDWARE_URL" }) {
            string configured = NormalizeServerHardwareMetricUrl(Environment.GetEnvironmentVariable(variable));
            if (!string.IsNullOrWhiteSpace(configured) && seen.Add(configured))
                yield return configured;
        }

        foreach (string runtimeBaseUrl in new[] {
                     GetExternalModelManagerRuntimeBaseUrl(),
                     _proxy?.LocalModelRuntime?.OpenAiBaseUrl ?? "",
                     _embeddedLlmRuntime?.OpenAiBaseUrl ?? ""
                 }) {
            string inferred = BuildServerHardwareMetricUrlFromRuntimeBaseUrl(runtimeBaseUrl);
            if (!string.IsNullOrWhiteSpace(inferred) && seen.Add(inferred))
                yield return inferred;
        }

        const string defaultNativeWorkstation = "http://127.0.0.1:12437/api/server-hardware";
        if (seen.Add(defaultNativeWorkstation))
            yield return defaultNativeWorkstation;
    }

    private static string BuildServerHardwareMetricUrlFromRuntimeBaseUrl(string? runtimeBaseUrl) {
        runtimeBaseUrl = (runtimeBaseUrl ?? "").Trim();
        if (string.IsNullOrWhiteSpace(runtimeBaseUrl) ||
            !Uri.TryCreate(runtimeBaseUrl, UriKind.Absolute, out Uri? runtimeUri) ||
            string.IsNullOrWhiteSpace(runtimeUri.Host) ||
            runtimeUri.Port <= 0)
            return "";

        int hardwarePort = runtimeUri.Port + 2;
        if (hardwarePort <= 0 || hardwarePort > 65535)
            return "";

        var builder = new UriBuilder(runtimeUri.Scheme, runtimeUri.Host, hardwarePort) {
            Path = "api/server-hardware",
            Query = ""
        };
        return builder.Uri.ToString();
    }

    private static string NormalizeServerHardwareMetricUrl(string? value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "";
        if (value.IndexOf("://", StringComparison.Ordinal) < 0)
            value = "http://" + value.TrimStart('/');
        if (!Uri.TryCreate(value, UriKind.Absolute, out Uri? uri) || string.IsNullOrWhiteSpace(uri.Host))
            return "";

        var builder = new UriBuilder(uri);
        string path = (builder.Path ?? "").TrimEnd('/');
        if (!path.EndsWith("/api/server-hardware", StringComparison.OrdinalIgnoreCase))
            path += "/api/server-hardware";
        builder.Path = path.TrimStart('/');
        builder.Query = "";
        return builder.Uri.ToString();
    }

    private static bool IsWineEnvironment() {
        foreach (string variable in new[] { "WINEPREFIX", "WINELOADERNOEXEC", "WINEDLLPATH", "WINEDEBUG" }) {
            if (!string.IsNullOrWhiteSpace(Environment.GetEnvironmentVariable(variable)))
                return true;
        }

        return false;
    }

    private static string ReadGpuHealthJsonString(JsonElement element, string propertyName) {
        if (!element.TryGetProperty(propertyName, out JsonElement value) ||
            value.ValueKind == JsonValueKind.Null ||
            value.ValueKind == JsonValueKind.Undefined)
            return "";
        if (value.ValueKind == JsonValueKind.String)
            return value.GetString() ?? "";
        return value.ToString();
    }

    private static bool ReadGpuHealthJsonBool(JsonElement element, string propertyName) {
        if (!element.TryGetProperty(propertyName, out JsonElement value))
            return false;
        if (value.ValueKind == JsonValueKind.True)
            return true;
        if (value.ValueKind == JsonValueKind.False)
            return false;
        return bool.TryParse(value.ToString(), out bool parsed) && parsed;
    }

    private static double? ReadGpuHealthJsonNullableDouble(JsonElement element, string propertyName) {
        if (!element.TryGetProperty(propertyName, out JsonElement value) ||
            value.ValueKind == JsonValueKind.Null ||
            value.ValueKind == JsonValueKind.Undefined)
            return null;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetDouble(out double number))
            return double.IsNaN(number) || double.IsInfinity(number) ? 0 : Math.Max(0, number);
        if (double.TryParse(value.ToString(), NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed))
            return double.IsNaN(parsed) || double.IsInfinity(parsed) ? 0 : Math.Max(0, parsed);
        return null;
    }

    private static ulong ReadGpuHealthJsonUInt64(JsonElement element, string propertyName) {
        if (!element.TryGetProperty(propertyName, out JsonElement value) ||
            value.ValueKind == JsonValueKind.Null ||
            value.ValueKind == JsonValueKind.Undefined)
            return 0;
        if (value.ValueKind == JsonValueKind.Number) {
            if (value.TryGetUInt64(out ulong unsigned))
                return unsigned;
            if (value.TryGetDouble(out double number))
                return number <= 0 ? 0 : (ulong)Math.Round(Math.Min(number, 18446744073709551615.0));
        }
        return ulong.TryParse(value.ToString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out ulong parsed) ? parsed : 0;
    }

    private void SetGpuHealthUnavailable() {
        _gpuUtilizationPercent = 0;
        _vramUsagePercent = 0;
        _gpuUtilizationHealthText = "unavailable";
        _vramUsageHealthText = "unavailable";
    }

    private static void TryKillProcess(Process process) {
        try {
            process.Kill(entireProcessTree: true);
        } catch {
        }
    }

    private void UpdateRamHealthMetric() {
        var status = new MemoryStatusEx {
            Length = (uint)Marshal.SizeOf<MemoryStatusEx>()
        };

        if (!GlobalMemoryStatusEx(ref status) || status.TotalPhys == 0) {
            RamUsageHealthText.Text = "unavailable";
            _ramUsagePercent = 0;
            ApplyPercentProgressBar(RamUsageProgressBar, 0, "RAM usage unavailable");
            return;
        }

        ulong used = status.TotalPhys > status.AvailPhys ? status.TotalPhys - status.AvailPhys : 0;
        _ramUsagePercent = Math.Clamp(status.MemoryLoad, 0, 100);
        RamUsageHealthText.Text = FormatPercent(status.MemoryLoad) + " (" +
                                  FormatBytes(ToDisplayByteCount(used)) + "/" +
                                  FormatBytes(ToDisplayByteCount(status.TotalPhys)) + ")";
        ApplyPercentProgressBar(RamUsageProgressBar, _ramUsagePercent, "RAM usage");
    }

    private void UpdateCpuHealthMetric() {
        if (!GetSystemTimes(out NativeFileTime idleTime, out NativeFileTime kernelTime, out NativeFileTime userTime)) {
            CpuUsageHealthText.Text = "unavailable";
            _cpuUsagePercent = 0;
            ApplyPercentProgressBar(CpuUsageProgressBar, 0, "CPU usage unavailable");
            return;
        }

        ulong idleTicks = ToUInt64(idleTime);
        ulong kernelTicks = ToUInt64(kernelTime);
        ulong userTicks = ToUInt64(userTime);
        if (!_lastCpuIdleTicks.HasValue ||
            !_lastCpuKernelTicks.HasValue ||
            !_lastCpuUserTicks.HasValue ||
            idleTicks < _lastCpuIdleTicks.Value ||
            kernelTicks < _lastCpuKernelTicks.Value ||
            userTicks < _lastCpuUserTicks.Value) {
            _lastCpuIdleTicks = idleTicks;
            _lastCpuKernelTicks = kernelTicks;
            _lastCpuUserTicks = userTicks;
            CpuUsageHealthText.Text = "measuring";
            _cpuUsagePercent = 0;
            ApplyPercentProgressBar(CpuUsageProgressBar, 0, "CPU usage measuring");
            return;
        }

        ulong idleDelta = idleTicks - _lastCpuIdleTicks.Value;
        ulong kernelDelta = kernelTicks - _lastCpuKernelTicks.Value;
        ulong userDelta = userTicks - _lastCpuUserTicks.Value;
        ulong totalDelta = kernelDelta + userDelta;
        double usagePercent = totalDelta == 0
            ? 0
            : Math.Clamp((1.0 - idleDelta / (double)totalDelta) * 100.0, 0, 100);

        _lastCpuIdleTicks = idleTicks;
        _lastCpuKernelTicks = kernelTicks;
        _lastCpuUserTicks = userTicks;
        _cpuUsagePercent = usagePercent;
        CpuUsageHealthText.Text = FormatPercent(usagePercent);
        ApplyPercentProgressBar(CpuUsageProgressBar, _cpuUsagePercent, "CPU usage");
    }

    private void UpdateNetworkHealthMetrics() {
        ScheduleNetworkHealthSampleIfDue();
        if (!TryConsumeNetworkHealthSample(out long bytesUp, out long bytesDown, out DateTimeOffset sampleUtc, out bool failed)) {
            ApplyNetworkHealthText();
            return;
        }

        if (failed) {
            ResetNetworkHealthMetrics();
            return;
        }

        if (!_lastNetworkSampleUtc.HasValue ||
            bytesUp < _lastNetworkBytesUp ||
            bytesDown < _lastNetworkBytesDown) {
            _lastNetworkSampleUtc = sampleUtc;
            _lastNetworkBytesUp = Math.Max(0, bytesUp);
            _lastNetworkBytesDown = Math.Max(0, bytesDown);
            _networkUpSnapshot = _networkUpTracker.Update(0, bytesUp);
            _networkDownSnapshot = _networkDownTracker.Update(0, bytesDown);
            ApplyNetworkHealthText();
            return;
        }

        double elapsedSeconds = Math.Max(0.001, (sampleUtc - _lastNetworkSampleUtc.Value).TotalSeconds);
        long upDelta = Math.Max(0, bytesUp - _lastNetworkBytesUp);
        long downDelta = Math.Max(0, bytesDown - _lastNetworkBytesDown);
        double upKbps = Math.Max(0, upDelta * 8.0 / elapsedSeconds / 1000.0);
        double downKbps = Math.Max(0, downDelta * 8.0 / elapsedSeconds / 1000.0);

        _lastNetworkSampleUtc = sampleUtc;
        _lastNetworkBytesUp = bytesUp;
        _lastNetworkBytesDown = bytesDown;
        _networkUpSnapshot = _networkUpTracker.Update(upKbps, bytesUp);
        _networkDownSnapshot = _networkDownTracker.Update(downKbps, bytesDown);
        ApplyNetworkHealthText();
    }

    private void ScheduleNetworkHealthSampleIfDue() {
        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (_networkHealthRefreshInProgress ||
            now - _lastNetworkHealthRefreshStartedUtc < TimeSpan.FromSeconds(2))
            return;

        _lastNetworkHealthRefreshStartedUtc = now;
        _networkHealthRefreshInProgress = true;
        _ = Task.Run(() => {
                bool ok = TryGetNetworkByteTotals(out long bytesUp, out long bytesDown);
                DateTimeOffset sampleUtc = DateTimeOffset.UtcNow;
                lock (_networkHealthSampleLock) {
                    _pendingNetworkHealthBytesUp = bytesUp;
                    _pendingNetworkHealthBytesDown = bytesDown;
                    _pendingNetworkHealthSampleUtc = sampleUtc;
                    _pendingNetworkHealthSampleFailed = !ok;
                    _pendingNetworkHealthSampleAvailable = true;
                }
            })
            .ContinueWith(task => {
                if (task.IsFaulted) {
                    lock (_networkHealthSampleLock) {
                        _pendingNetworkHealthBytesUp = 0;
                        _pendingNetworkHealthBytesDown = 0;
                        _pendingNetworkHealthSampleUtc = DateTimeOffset.UtcNow;
                        _pendingNetworkHealthSampleFailed = true;
                        _pendingNetworkHealthSampleAvailable = true;
                    }
                }

                _networkHealthRefreshInProgress = false;
                TryBeginOnUi(UpdateNetworkHealthMetrics, "Network health refresh", DispatcherPriority.Background);
            }, TaskScheduler.Default);
    }

    private bool TryConsumeNetworkHealthSample(out long bytesUp, out long bytesDown, out DateTimeOffset sampleUtc, out bool failed) {
        lock (_networkHealthSampleLock) {
            if (!_pendingNetworkHealthSampleAvailable) {
                bytesUp = 0;
                bytesDown = 0;
                sampleUtc = DateTimeOffset.MinValue;
                failed = false;
                return false;
            }

            bytesUp = _pendingNetworkHealthBytesUp;
            bytesDown = _pendingNetworkHealthBytesDown;
            sampleUtc = _pendingNetworkHealthSampleUtc == DateTimeOffset.MinValue ? DateTimeOffset.UtcNow : _pendingNetworkHealthSampleUtc;
            failed = _pendingNetworkHealthSampleFailed;
            _pendingNetworkHealthSampleAvailable = false;
            return true;
        }
    }

    private void ResetNetworkHealthMetrics() {
        _lastNetworkSampleUtc = null;
        _lastNetworkBytesUp = 0;
        _lastNetworkBytesDown = 0;
        _networkUpTracker.Reset();
        _networkDownTracker.Reset();
        _networkUpSnapshot = BandwidthMetricSnapshot.Empty("Network Up");
        _networkDownSnapshot = BandwidthMetricSnapshot.Empty("Network Down");
        ApplyNetworkHealthText();
    }

    private void ApplyNetworkHealthText() {
        NetworkUpHealthText.Text = FormatKbps(_networkUpSnapshot.LiveKbps);
        NetworkDownHealthText.Text = FormatKbps(_networkDownSnapshot.LiveKbps);
        ApplyBandwidthProgressBar(NetworkUpProgressBar, _networkUpSnapshot);
        ApplyBandwidthProgressBar(NetworkDownProgressBar, _networkDownSnapshot);
    }

    private void UpdateIoHealthMetric() {
        if (!TryGetProcessIoBytes(out ulong readBytes, out ulong writeBytes, out ulong totalBytes)) {
            ResetIoHealthMetric();
            return;
        }

        DateTimeOffset now = DateTimeOffset.UtcNow;
        if (!_lastIoSampleUtc.HasValue ||
            readBytes < _lastIoReadBytes ||
            writeBytes < _lastIoWriteBytes) {
            _lastIoSampleUtc = now;
            _lastIoReadBytes = readBytes;
            _lastIoWriteBytes = writeBytes;
            _ioReadBytesPerSecond = 0;
            _ioWriteBytesPerSecond = 0;
            _ioSnapshot = _ioTracker.Update(0, ToDisplayByteCount(totalBytes));
            ApplyIoHealthText();
            return;
        }

        double elapsedSeconds = Math.Max(0.001, (now - _lastIoSampleUtc.Value).TotalSeconds);
        ulong readDelta = readBytes - _lastIoReadBytes;
        ulong writeDelta = writeBytes - _lastIoWriteBytes;
        ulong totalDelta = SaturatingAdd(readDelta, writeDelta);
        _ioReadBytesPerSecond = Math.Max(0, readDelta / elapsedSeconds);
        _ioWriteBytesPerSecond = Math.Max(0, writeDelta / elapsedSeconds);
        double bytesPerSecond = Math.Max(0, totalDelta / elapsedSeconds);

        _lastIoSampleUtc = now;
        _lastIoReadBytes = readBytes;
        _lastIoWriteBytes = writeBytes;
        _ioSnapshot = _ioTracker.Update(bytesPerSecond, ToDisplayByteCount(totalBytes));
        ApplyIoHealthText();
    }

    private void ResetIoHealthMetric() {
        _lastIoSampleUtc = null;
        _lastIoReadBytes = 0;
        _lastIoWriteBytes = 0;
        _ioReadBytesPerSecond = 0;
        _ioWriteBytesPerSecond = 0;
        _ioTracker.Reset();
        _ioSnapshot = RateMetricSnapshot.Empty("I/O");
        ApplyIoHealthText();
    }

    private void ApplyIoHealthText() {
        IoReadHealthText.Text = FormatBytesPerSecond(_ioReadBytesPerSecond);
        IoWriteHealthText.Text = FormatBytesPerSecond(_ioWriteBytesPerSecond);
        IoTotalHealthText.Text = FormatBytesPerSecond(_ioSnapshot.LiveBytesPerSecond);
        ApplyRateProgressBar(IoProgressBar, _ioSnapshot);
    }

    private void UpdateTokenPerformanceMetrics() {
        try {
            ChatPerformanceDiagnosticsSnapshot snapshot = _proxy.GetChatPerformanceDiagnostics();
            long totalTokens = Math.Max(0, snapshot.TotalTokensUsed);
            DateTimeOffset now = DateTimeOffset.UtcNow;

            if (!_lastTokenPerformanceSampleUtc.HasValue ||
                totalTokens < _lastTokenPerformanceTotal) {
                _lastTokenPerformanceSampleUtc = now;
                _lastTokenPerformanceTotal = totalTokens;
                ResetTokenRateSamples();
            } else {
                double elapsedHours = Math.Max(1.0 / 3600000.0, (now - _lastTokenPerformanceSampleUtc.Value).TotalHours);
                long tokenDelta = Math.Max(0, totalTokens - _lastTokenPerformanceTotal);
                AddTokenRateSample(tokenDelta <= 0 ? 0 : tokenDelta / elapsedHours);
                _lastTokenPerformanceSampleUtc = now;
                _lastTokenPerformanceTotal = totalTokens;
            }

            string rateText = FormatTokensPerHour(_tokenRatePerHour);
            string totalText = FormatTokenCount(totalTokens);
            string totalExact = totalTokens.ToString("N0", CultureInfo.CurrentCulture);
            string ownerText = snapshot.OwnerCount == 1 ? "1 owner" : snapshot.OwnerCount.ToString("N0", CultureInfo.CurrentCulture) + " owners";

            TokenRateHealthText.Text = rateText;
            TokenRateHealthText.ToolTip = "Rolling token throughput: " + rateText + Environment.NewLine +
                                          "Total charged tokens: " + totalExact;
            ApplyTokenRateProgressBar(TokenRateHealthProgressBar, _tokenRatePerHour, GetTokenRateProgressMaximum());
            TokenTotalHealthText.Text = totalText;
            TokenTotalHealthText.ToolTip = "Total charged tokens: " + totalExact + Environment.NewLine +
                                           "Tracked across " + ownerText + ".";
        } catch {
            ResetTokenRateSamples();
            TokenRateHealthText.Text = "unavailable";
            TokenRateHealthText.ToolTip = "Token throughput unavailable";
            ApplyTokenRateProgressBar(TokenRateHealthProgressBar, 0, GetTokenRateProgressMaximum());
            TokenTotalHealthText.Text = "unavailable";
            TokenTotalHealthText.ToolTip = "Total token diagnostics unavailable";
        }
    }

    private void AddTokenRateSample(double tokensPerHour) {
        if (double.IsNaN(tokensPerHour) || double.IsInfinity(tokensPerHour))
            tokensPerHour = 0;

        _tokenRateSamples.Enqueue(Math.Max(0, tokensPerHour));
        while (_tokenRateSamples.Count > TokenRateSampleWindow)
            _tokenRateSamples.Dequeue();
        _tokenRatePerHour = _tokenRateSamples.Count == 0 ? 0 : _tokenRateSamples.Average();
        UpdateAdvertisedTokenRatePolicy();
    }

    private void ResetTokenRateSamples() {
        _tokenRateSamples.Clear();
        _tokenRatePerHour = 0;
        UpdateAdvertisedTokenRatePolicy();
    }

    private static void ApplyPercentProgressBar(System.Windows.Controls.ProgressBar progressBar, double percent, string label) {
        double value = double.IsNaN(percent) || double.IsInfinity(percent) ? 0 : Math.Clamp(percent, 0, 100);
        progressBar.Minimum = 0;
        progressBar.Maximum = 100;
        progressBar.Value = value;
        progressBar.ToolTip = label + ": " + FormatPercent(value);
    }

    private long GetTokenRateProgressMaximum() {
        long configuredMax = Math.Max(0, _settings?.TokenRateRequestMax ?? 0);
        long currentRate = Math.Max(0, (long)Math.Ceiling(double.IsNaN(_tokenRatePerHour) || double.IsInfinity(_tokenRatePerHour) ? 0 : _tokenRatePerHour));
        return Math.Max(1000, Math.Max(configuredMax, currentRate));
    }

    private static void ApplyTokenRateProgressBar(System.Windows.Controls.ProgressBar progressBar, double tokensPerHour, long maximumTokensPerHour) {
        double value = double.IsNaN(tokensPerHour) || double.IsInfinity(tokensPerHour) ? 0 : Math.Max(0, tokensPerHour);
        double maximum = Math.Max(1000, maximumTokensPerHour);
        progressBar.Minimum = 0;
        progressBar.Maximum = maximum;
        progressBar.Value = Math.Min(value, maximum);
        progressBar.ToolTip = "Average tokens/hour: " + FormatTokensPerHour(value) + Environment.NewLine +
                              "Meter scale: " + FormatTokensPerHour(maximum);
    }

    private static void ApplyBandwidthProgressBar(System.Windows.Controls.ProgressBar progressBar, BandwidthMetricSnapshot snapshot) {
        progressBar.Minimum = snapshot.MinimumKbps;
        progressBar.Maximum = snapshot.MaximumKbps;
        progressBar.Value = snapshot.ValueKbps;
        progressBar.ToolTip = snapshot.ToolTip;
    }

    private static void ApplyRateProgressBar(System.Windows.Controls.ProgressBar progressBar, RateMetricSnapshot snapshot) {
        progressBar.Minimum = snapshot.MinimumBytesPerSecond;
        progressBar.Maximum = snapshot.MaximumBytesPerSecond;
        progressBar.Value = snapshot.ValueBytesPerSecond;
        progressBar.ToolTip = snapshot.ToolTip;
    }

    private static bool TryGetNetworkByteTotals(out long bytesUp, out long bytesDown) {
        bytesUp = 0;
        bytesDown = 0;
        bool found = false;

        try {
            foreach (NetworkInterface networkInterface in NetworkInterface.GetAllNetworkInterfaces()) {
                if (networkInterface.OperationalStatus != OperationalStatus.Up ||
                    networkInterface.NetworkInterfaceType == NetworkInterfaceType.Loopback ||
                    networkInterface.NetworkInterfaceType == NetworkInterfaceType.Tunnel)
                    continue;

                IPv4InterfaceStatistics statistics = networkInterface.GetIPv4Statistics();
                bytesUp = SaturatingAdd(bytesUp, Math.Max(0, statistics.BytesSent));
                bytesDown = SaturatingAdd(bytesDown, Math.Max(0, statistics.BytesReceived));
                found = true;
            }
        } catch {
            return false;
        }

        return found;
    }

    private static bool TryGetProcessIoBytes(out ulong readBytes, out ulong writeBytes, out ulong totalBytes) {
        readBytes = 0;
        writeBytes = 0;
        totalBytes = 0;
        try {
            using Process currentProcess = Process.GetCurrentProcess();
            if (!GetProcessIoCounters(currentProcess.Handle, out ProcessIoCounters counters))
                return false;

            readBytes = counters.ReadTransferCount;
            writeBytes = counters.WriteTransferCount;
            totalBytes = SaturatingAdd(readBytes, writeBytes);
            return true;
        } catch {
            return false;
        }
    }

    private static bool TryQueryNvidiaGpu(out string name, out double memoryUsedMb, out double memoryTotalMb) {
        name = "";
        memoryUsedMb = 0;
        memoryTotalMb = 0;

        try {
            var startInfo = new ProcessStartInfo {
                FileName = "nvidia-smi",
                Arguments = "--query-gpu=name,memory.used,memory.total --format=csv,noheader,nounits",
                UseShellExecute = false,
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                CreateNoWindow = true
            };

            using Process? process = Process.Start(startInfo);
            if (process == null)
                return false;
            if (!process.WaitForExit(750)) {
                TryKillProcess(process);
                return false;
            }

            string output = process.StandardOutput.ReadToEnd();
            if (process.ExitCode != 0 || string.IsNullOrWhiteSpace(output))
                return false;

            string? firstLine = output.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries).FirstOrDefault();
            if (string.IsNullOrWhiteSpace(firstLine))
                return false;

            string[] parts = firstLine.Split(',').Select(part => part.Trim()).ToArray();
            if (parts.Length < 3)
                return false;

            name = string.Join(", ", parts.Take(parts.Length - 2)).Trim();
            return double.TryParse(parts[^2], NumberStyles.Float, CultureInfo.InvariantCulture, out memoryUsedMb) &&
                   double.TryParse(parts[^1], NumberStyles.Float, CultureInfo.InvariantCulture, out memoryTotalMb) &&
                   memoryTotalMb > 0;
        } catch {
            return false;
        }
    }

    private static string GetRamAvailableText() {
        var status = new MemoryStatusEx {
            Length = (uint)Marshal.SizeOf<MemoryStatusEx>()
        };

        if (!GlobalMemoryStatusEx(ref status) || status.TotalPhys == 0)
            return "";

        return FormatBytes(ToDisplayByteCount(status.AvailPhys)) + " free / " +
               FormatBytes(ToDisplayByteCount(status.TotalPhys));
    }

    private static string GetStorageAvailableText() {
        try {
            string root = Path.GetPathRoot(AppContext.BaseDirectory) ?? "";
            if (string.IsNullOrWhiteSpace(root))
                return "";

            var drive = new DriveInfo(root);
            if (!drive.IsReady || drive.TotalSize <= 0)
                return "";

            return FormatBytes(drive.AvailableFreeSpace) + " free / " + FormatBytes(drive.TotalSize);
        } catch {
            return "";
        }
    }

    private static string GetCpuName() {
        try {
            using RegistryKey? key = Registry.LocalMachine.OpenSubKey(@"HARDWARE\DESCRIPTION\System\CentralProcessor\0");
            string? name = key?.GetValue("ProcessorNameString") as string;
            if (!string.IsNullOrWhiteSpace(name))
                return name.Trim();
        } catch {
        }

        return "";
    }

