    }

    private void InitializeStaticText() {
        _lmEndpointText = "Endpoint: http://localhost:" + LocalLmStudioProxyPort + "/v1/chat/completions";
        _proxyEndpointText = "JACK: http://localhost:" + ServerPort + "/v1/chat/completions";
        _chatUiEndpointText = "Web UI: http://localhost:" + ChatServerPort + "/";
        _vsEndpointText = "Endpoint: http://localhost:" + ServerPort + "/v1/responses";
    }

    private void SetStatus(string text) {
        if (StatusBarText == null)
            return;

        string status = FormatSingleLineStatus(text, 240);
        StatusBarText.Text = status;
        StatusBarText.ToolTip = status;
    }

    private static string FormatSingleLineStatus(string? text, int maxLength) {
        string normalized = string.Join(" ", (text ?? "")
            .Replace('\t', ' ')
            .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)
            .Select(part => part.Trim())
            .Where(part => part.Length > 0));

        return string.IsNullOrWhiteSpace(normalized)
            ? "Ready"
            : TrimForDisplay(normalized, maxLength);
    }

    private void StartImageRuntimeBootstrap() {
        _ = StartImageRuntimeBootstrapAsync();
    }

    private void StartWineSafeDeferredImageBootstrap() {
        if (_wineSafeDeferredImageBootstrapStarted || _isStopping || _shutdownCompleted)
            return;

        _wineSafeDeferredImageBootstrapStarted = true;
        _ = Task.Run(async () => {
            try {
                await Task.Delay(TimeSpan.FromSeconds(3)).ConfigureAwait(false);
                TryBeginOnUi(() => {
                    UpdateImagePipelineStatus("Checking Linux CUDA/PyTorch runtime...", true);
                    AppendServiceEventLine("JackONNX", "Deferred Wine-safe CUDA/PyTorch bootstrap started.");
                }, "Deferred image bootstrap start");

                bool nativeCudaReady = false;
                try {
                    nativeCudaReady = await EnsureLinuxCudaPytorchSelfInstallAsync(CancellationToken.None).ConfigureAwait(false);
                } catch (Exception ex) {
                    string message = "Native Linux CUDA/PyTorch check failed; continuing with JackONNX Python bootstrap: " + TrimForDisplay(ex.Message, 180);
                    TryBeginOnUi(() => {
                        UpdateImagePipelineStatus(message, true);
                        AppendServiceEventLine("JackONNX", message);
                    }, "Deferred image bootstrap compatibility failure");
                }

                TryBeginOnUi(() => {
                    if (nativeCudaReady) {
                        AppendServiceEventLine("JackONNX", "Linux CUDA/PyTorch runtime is ready through native LlmRuntime.");
                    }

                    StartImageRuntimeBootstrap();
                }, "Deferred image bootstrap handoff");
            } catch (Exception ex) {
                TryBeginOnUi(() => {
                    string message = "Deferred CUDA/PyTorch bootstrap failed: " + TrimForDisplay(ex.Message, 220);
                    UpdateImagePipelineStatus(message, false);
                    AppendServiceEventLine("JackONNX", message);
                }, "Deferred image bootstrap failure");
            }
        });
    }

    private async Task StartImageRuntimeBootstrapAsync(
        IProgress<StartupLoadingProgress>? startupProgress = null,
        CancellationToken startupCancellationToken = default,
        bool waitForCompletion = false) {
        try {
            if (_pythonBootstrapCancellation != null) {
                _pythonBootstrapCancellation.Cancel();
                _pythonBootstrapCancellation.Dispose();
            }

            _pythonBootstrapCancellation = CancellationTokenSource.CreateLinkedTokenSource(startupCancellationToken);
            CancellationToken bootstrapToken = _pythonBootstrapCancellation.Token;
            double pythonProgressValue = 88;
            IProgress<string> progress = new InlineProgress<string>(status => {
                TryBeginOnUi(() => UpdateImagePipelineStatus(status, true), "Image bootstrap progress");
                if (startupProgress != null) {
                    pythonProgressValue = Math.Min(97, pythonProgressValue + 1.5);
                    ReportStartup(startupProgress, pythonProgressValue, "Preparing Python image assets", status, isIndeterminate: true);
                }
            });
            _pythonBootstrapTask = Task.Run(() => BootstrapImageRuntimeAsync(progress, bootstrapToken), bootstrapToken);
            if (waitForCompletion) {
                await _pythonBootstrapTask;
                startupCancellationToken.ThrowIfCancellationRequested();
            }
        } catch (OperationCanceledException) when (startupCancellationToken.IsCancellationRequested) {
            throw;
        } catch (OperationCanceledException) {
            UpdateImagePipelineStatus("Image bootstrap canceled.", false);
        } catch (Exception ex) {
            UpdateImagePipelineStatus("Image runtime bootstrap failed to start: " + ex.Message, false);
        }
    }

    private void CancelImageRuntimeBootstrap() {
        if (_pythonBootstrapCancellation == null)
            return;

        try {
            _pythonBootstrapCancellation.Cancel();
            _pythonBootstrapCancellation.Dispose();
        } catch {
        }
        _pythonBootstrapCancellation = null;
    }

    private async Task BootstrapImageRuntimeAsync(IProgress<string> status, CancellationToken cancellationToken) {
        try {
            status.Report("Preparing image runtime bootstrap...");
            string pythonPath = await JackOnnxPythonDiffusersImageRunner.EnsureBundledPythonAsync(cancellationToken, status).ConfigureAwait(false);
            if (!cancellationToken.IsCancellationRequested && !string.IsNullOrWhiteSpace(pythonPath))
                await JackOnnxPythonDiffusersImageRunner.EnsureQwenDiffusersSupportAsync(pythonPath, cancellationToken, status).ConfigureAwait(false);

            if (!cancellationToken.IsCancellationRequested) {
                status.Report("Image pipeline ready.");
                TryBeginOnUi(() => {
                    SetImagePipelineIdle("Image pipeline is idle.");
                }, "Image bootstrap ready");
            }
        } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
            TryBeginOnUi(() => {
                SetImagePipelineIdle("Image bootstrap canceled.");
            }, "Image bootstrap canceled");
        } catch (Exception ex) {
            string message = TrimForDisplay(FirstNonEmpty(ex.Message, "Image runtime bootstrap failed."), 220);
            TryBeginOnUi(() => {
                SetImagePipelineIdle("Image pipeline failed: " + message);
            }, "Image bootstrap failure");
        }
    }

    private async Task<bool> EnsureLinuxCudaPytorchSelfInstallAsync(CancellationToken cancellationToken) {
        if (_linuxCudaPytorchSelfInstallTask != null && !_linuxCudaPytorchSelfInstallTask.IsCompleted)
        {
            await _linuxCudaPytorchSelfInstallTask.ConfigureAwait(false);
            return true;
        }

        _linuxCudaPytorchSelfInstallTask = EnsureLinuxCudaPytorchSelfInstallCoreAsync(cancellationToken);
        await _linuxCudaPytorchSelfInstallTask.ConfigureAwait(false);
        return true;
    }

    private async Task EnsureLinuxCudaPytorchSelfInstallCoreAsync(CancellationToken cancellationToken) {
        string runtimeBaseUrl = GetExternalModelManagerRuntimeBaseUrl();
        if (string.IsNullOrWhiteSpace(runtimeBaseUrl))
            runtimeBaseUrl = _proxy?.LocalModelRuntime?.OpenAiBaseUrl ?? "";
        if (string.IsNullOrWhiteSpace(runtimeBaseUrl))
        {
            _linuxNativeCudaPytorchReady = false;
            _linuxNativeCudaPytorchStatusLine = "No LlmRuntime endpoint is configured.";
            AppendServiceEventLine("JackONNX", "Linux CUDA/PyTorch self-install skipped because no LlmRuntime endpoint is configured.");
            return;
        }

        runtimeBaseUrl = runtimeBaseUrl.TrimEnd('/');
        string compatibilityUrl = runtimeBaseUrl + "/api/v1/runtime/compatibility";
        using var client = CreateNetworkHttpClient(TimeSpan.FromMinutes(50));
        using HttpResponseMessage compatibilityResponse = await client.GetAsync(compatibilityUrl, cancellationToken).ConfigureAwait(false);
        string compatibilityBody = await compatibilityResponse.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
        if (!compatibilityResponse.IsSuccessStatusCode) {
            _linuxNativeCudaPytorchReady = false;
            _linuxNativeCudaPytorchStatusLine = "Compatibility check unavailable.";
            TryBeginOnUi(() => {
                string message = "LlmRuntime compatibility check is unavailable; JackONNX will repair its Python runtime directly. HTTP " +
                    ((int)compatibilityResponse.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TrimForDisplay(compatibilityBody, 180);
                UpdateImagePipelineStatus(message, true);
                AppendServiceEventLine("JackONNX", message);
            }, "Linux CUDA compatibility unavailable");
            return;
        }

        if (TryReadJsonBool(compatibilityBody, "isGpuGenerationEnabled") ||
            TryReadJsonString(compatibilityBody, "status").Equals("ok", StringComparison.OrdinalIgnoreCase))
        {
            string message = FirstNonEmpty(TryReadJsonString(compatibilityBody, "message"), "Linux CUDA-enabled PyTorch is ready.");
            _linuxNativeCudaPytorchReady = true;
            _linuxNativeCudaPytorchStatusLine = message;
            TryBeginOnUi(() => {
                UpdateImagePipelineStatus(message, false);
                AppendServiceEventLine("JackONNX", message);
            }, "Linux CUDA compatibility ready");
            return;
        }

        bool needsRepair = TryReadJsonBool(compatibilityBody, "requiresPytorchRepair") ||
                           TryReadJsonBool(compatibilityBody, "generationDisabled") ||
                           !TryReadJsonBool(compatibilityBody, "isGpuGenerationEnabled");
        if (!needsRepair)
            return;

        _linuxNativeCudaPytorchReady = false;
        _linuxNativeCudaPytorchStatusLine = "Repair required.";

        TryBeginOnUi(() => {
            UpdateImagePipelineStatus("Installing Linux CUDA-enabled PyTorch through native LlmRuntime...", true);
            AppendServiceEventLine("JackONNX", "Installing Linux CUDA-enabled PyTorch through native LlmRuntime.");
        }, "Linux CUDA install start");

        string installUrl = runtimeBaseUrl + LlmRuntimeCompatibilityService.LinuxCudaPytorchInstallEndpoint;
        using var content = new System.Net.Http.StringContent("{}", Encoding.UTF8, "application/json");
        using HttpResponseMessage installResponse = await client.PostAsync(installUrl, content, cancellationToken).ConfigureAwait(false);
        string installBody = await installResponse.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
        if (!installResponse.IsSuccessStatusCode)
            throw new InvalidOperationException("Linux CUDA/PyTorch install failed: HTTP " + ((int)installResponse.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TrimForDisplay(installBody, 360));

        string installStatus = TryReadJsonString(installBody, "status");
        string installMessage = FirstNonEmpty(TryReadJsonString(installBody, "message"), "Linux CUDA/PyTorch install completed.");
        _linuxNativeCudaPytorchReady = installStatus.Equals("installed", StringComparison.OrdinalIgnoreCase) ||
                                       installMessage.IndexOf("ready", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                       installMessage.IndexOf("compatible", StringComparison.OrdinalIgnoreCase) >= 0;
        _linuxNativeCudaPytorchStatusLine = installMessage;
        TryBeginOnUi(() => {
            UpdateImagePipelineStatus(installMessage, !installStatus.Equals("installed", StringComparison.OrdinalIgnoreCase));
            AppendServiceEventLine("JackONNX", installMessage);
        }, "Linux CUDA install result");
    }

    private void SetImagePipelineIdle(string status) {
        if (!Dispatcher.CheckAccess()) {
            TryBeginOnUi(() => SetImagePipelineIdle(status), "Image pipeline idle");
            return;
        }

        UpdateImagePipelineStatus(status, false);
        StartImagePipelineStatusFade();
    }

    private void UpdateImagePipelineStatus(string status, bool inProgress) {
        if (!Dispatcher.CheckAccess()) {
            TryBeginOnUi(() => UpdateImagePipelineStatus(status, inProgress), "Image pipeline status");
            return;
        }

        if (_isStopping || _shutdownCompleted)
            return;

        bool warning = IsImagePipelineCompatibilityWarning(status);
        string statusLine = warning && !status.TrimStart().StartsWith("\u26A0", StringComparison.Ordinal)
            ? "\u26A0 " + status
            : status;
        SetStatus(statusLine);
        StopImagePipelineStatusAnimation();

        if (ImagePipelineStatusPanel == null || ImagePipelineStatusText == null)
            return;

        if (_pipelineStatusFadeStoryboard != null) {
            _pipelineStatusFadeStoryboard.Stop();
            _pipelineStatusFadeStoryboard = null;
        }

        ImagePipelineStatusPanel.Opacity = 1;
        ImagePipelineStatusText.Text = statusLine;
        ApplyImagePipelineWarningState(warning);
    }

    private void ApplyImagePipelineWarningState(bool warning) {
        if (ImagePipelineActionPanel != null)
            ImagePipelineActionPanel.Visibility = warning ? Visibility.Visible : Visibility.Collapsed;
        if (ImagePipelineStatusPanel != null) {
            ImagePipelineStatusPanel.BorderBrush = warning
                ? new SolidColorBrush(Color.FromRgb(248, 113, 113))
                : new SolidColorBrush(Color.FromRgb(51, 78, 102));
            ImagePipelineStatusPanel.Background = warning
                ? new SolidColorBrush(Color.FromRgb(54, 18, 29))
                : new SolidColorBrush(Color.FromArgb(0x26, 0x11, 0x1F, 0x2A));
            ImagePipelineStatusPanel.Effect = warning
                ? new DropShadowEffect {
                    Color = Color.FromRgb(248, 113, 113),
                    BlurRadius = 14,
                    ShadowDepth = 0,
                    Opacity = 0.55
                }
                : null;
        }
    }

    private static bool IsImagePipelineCompatibilityWarning(string status) {
        string text = (status ?? "").ToLowerInvariant();
        return text.Contains("cuda") ||
               text.Contains("pytorch") ||
               text.Contains("torch") ||
               text.Contains("cpu-only") ||
               text.Contains("gpu image generation is disabled") ||
               text.Contains("generation is disabled") ||
               text.Contains("python runtime");
    }

