    private async void RepairPytorchButton_Click(object sender, RoutedEventArgs e) {
        await BeginRepairPytorchFromWarningAsync().ConfigureAwait(false);
    }

    private async Task BeginRepairPytorchFromWarningAsync() {
        if (RepairPytorchButton != null)
            RepairPytorchButton.IsEnabled = false;
        try {
            UpdateImagePipelineStatus("Repairing PyTorch CUDA runtime...", true);
            if (IsWineSafeWpfMode() && !string.IsNullOrWhiteSpace(GetExternalModelManagerRuntimeBaseUrl())) {
                await EnsureLinuxCudaPytorchSelfInstallAsync(CancellationToken.None).ConfigureAwait(false);
                TryBeginOnUi(() => SetImagePipelineIdle("Linux CUDA-enabled PyTorch is ready through native LlmRuntime."), "PyTorch repair ready");
                return;
            }

            var service = new LlmRuntimeCompatibilityService(new LlmRuntimeOptions {
                CompatibilityConfigPath = Path.Combine(GetGuiUserDataRoot(), "LlmRuntime.compatibility.json")
            });
            string pythonExecutable = JackOnnxPythonDiffusersImageRunner.DefaultPreferredImageGenerationPythonExecutable;
            LlmRuntimeCompatibilityStatus before = service.GetStatus(pythonExecutable, CancellationToken.None, forceRefresh: true);
            if (before.RequiresPytorchRepair && before.Diagnostics.RecommendedPytorch == null && RuntimeCompatibilityNeedsLegacyCudaPython(before)) {
                var progress = new InlineProgress<string>(status => TryBeginOnUi(() => UpdateImagePipelineStatus(status, true), "legacy PyTorch repair progress"));
                string legacyPython = await JackOnnxPythonDiffusersImageRunner.EnsureCudaLegacyPythonRuntimeAsync(CancellationToken.None, progress).ConfigureAwait(false);
                LlmRuntimeCompatibilityStatus repaired = service.GetStatus(legacyPython, CancellationToken.None, forceRefresh: true);
                string message = repaired.IsGpuGenerationEnabled
                    ? "Legacy CUDA-enabled PyTorch is ready for image generation at " + legacyPython + "."
                    : repaired.Message;
                TryBeginOnUi(() => SetImagePipelineIdle(message), "legacy PyTorch repair result");
            } else {
                LlmPytorchRepairResult result = await service.RepairPytorchAsync(pythonExecutable).ConfigureAwait(false);
                TryBeginOnUi(() => SetImagePipelineIdle(result.Message), "PyTorch repair result");
            }
        } catch (Exception ex) {
            TryBeginOnUi(() => UpdateImagePipelineStatus("PyTorch repair failed: " + TrimForDisplay(ex.Message, 260), false), "PyTorch repair failure");
        } finally {
            TryBeginOnUi(() => {
                if (RepairPytorchButton != null)
                    RepairPytorchButton.IsEnabled = true;
                _lastImageRuntimeCompatibilityRefreshUtc = DateTimeOffset.MinValue;
                RefreshImageRuntimeCompatibilityWarningIfDue();
            }, "PyTorch repair button reset");
        }
    }

    private static bool RuntimeCompatibilityNeedsLegacyCudaPython(LlmRuntimeCompatibilityStatus status) {
        if (status == null)
            return false;

        string pythonVersion = status.Diagnostics?.Python?.Version ?? "";
        bool pythonTooNewForLegacyCuda = TryParseMajorMinorVersion(pythonVersion, out Version? version) &&
                                         version != null &&
                                         version.Major == 3 &&
                                         version.Minor >= 12;
        bool legacyGpu = false;
        foreach (LlmDetectedGpu gpu in status.Diagnostics?.Gpus ?? Array.Empty<LlmDetectedGpu>()) {
            if (!gpu.IsNvidia)
                continue;
            if (!double.TryParse(gpu.ComputeCapability, NumberStyles.Float, CultureInfo.InvariantCulture, out double capability))
                continue;
            if (capability > 0 && capability < 7.5) {
                legacyGpu = true;
                break;
            }
        }

        return pythonTooNewForLegacyCuda && legacyGpu;
    }

    private static bool TryParseMajorMinorVersion(string value, out Version? version) {
        version = null;
        Match match = Regex.Match(value ?? "", @"(\d+)\.(\d+)(?:\.(\d+))?");
        if (!match.Success)
            return false;

        int major = int.Parse(match.Groups[1].Value, CultureInfo.InvariantCulture);
        int minor = int.Parse(match.Groups[2].Value, CultureInfo.InvariantCulture);
        int patch = match.Groups[3].Success ? int.Parse(match.Groups[3].Value, CultureInfo.InvariantCulture) : 0;
        version = new Version(major, minor, patch);
        return true;
    }

    private static string TryReadJsonString(string json, string propertyName) {
        try {
            using JsonDocument document = JsonDocument.Parse(json);
            if (document.RootElement.TryGetProperty(propertyName, out JsonElement value)) {
                if (value.ValueKind == JsonValueKind.String)
                    return value.GetString() ?? "";
                if (value.ValueKind != JsonValueKind.Null && value.ValueKind != JsonValueKind.Undefined)
                    return value.ToString();
            }
        } catch {
        }

        return "";
    }

    private static bool TryReadJsonBool(string json, string propertyName) {
        try {
            using JsonDocument document = JsonDocument.Parse(json);
            if (!document.RootElement.TryGetProperty(propertyName, out JsonElement value))
                return false;
            if (value.ValueKind == JsonValueKind.True)
                return true;
            if (value.ValueKind == JsonValueKind.False)
                return false;
            return bool.TryParse(value.ToString(), out bool parsed) && parsed;
        } catch {
            return false;
        }
    }

    private void StartImagePipelineStatusAnimation() {
        if (ImagePipelineRgbBar == null || ImagePipelineGlare == null ||
            ImagePipelineRgbBarTransform == null || ImagePipelineGlareTransform == null ||
            ImagePipelineProgressContainer == null) {
            return;
        }

        StopImagePipelineStatusAnimation();

        double containerWidth = ImagePipelineProgressContainer.ActualWidth;
        if (containerWidth <= 0)
            containerWidth = 240;
        double barWidth = ImagePipelineRgbBar.ActualWidth > 0 ? ImagePipelineRgbBar.ActualWidth : ImagePipelineRgbBar.Width;
        if (barWidth <= 0)
            barWidth = 140;
        double glareWidth = ImagePipelineGlare.ActualWidth > 0 ? ImagePipelineGlare.ActualWidth : ImagePipelineGlare.Width;
        if (glareWidth <= 0)
            glareWidth = 70;

        var storyboard = new Storyboard();
        var rgb = new DoubleAnimation {
            From = containerWidth,
            To = -barWidth,
            Duration = TimeSpan.FromSeconds(2.4),
            RepeatBehavior = RepeatBehavior.Forever
        };
        Storyboard.SetTarget(rgb, ImagePipelineRgbBarTransform);
        Storyboard.SetTargetProperty(rgb, new PropertyPath(TranslateTransform.XProperty));
        storyboard.Children.Add(rgb);

        var glare = new DoubleAnimation {
            From = containerWidth + glareWidth * 1.25,
            To = -glareWidth * 1.25,
            Duration = TimeSpan.FromSeconds(1.7),
            BeginTime = TimeSpan.FromMilliseconds(250),
            RepeatBehavior = RepeatBehavior.Forever
        };
        Storyboard.SetTarget(glare, ImagePipelineGlareTransform);
        Storyboard.SetTargetProperty(glare, new PropertyPath(TranslateTransform.XProperty));
        storyboard.Children.Add(glare);

        _pipelineStatusStoryboard = storyboard;
        storyboard.Begin();
    }

    private void StopImagePipelineStatusAnimation() {
        if (_pipelineStatusStoryboard == null)
            return;

        try {
            _pipelineStatusStoryboard.Stop();
            _pipelineStatusStoryboard.Remove();
        } catch {
        }

        if (ImagePipelineRgbBarTransform != null)
            ImagePipelineRgbBarTransform.X = 0;
        if (ImagePipelineGlareTransform != null)
            ImagePipelineGlareTransform.X = 0;
        _pipelineStatusStoryboard = null;
    }

    private void StartImagePipelineStatusFade() {
        if (ImagePipelineStatusPanel == null)
            return;
        if (ImagePipelineActionPanel != null && ImagePipelineActionPanel.Visibility == Visibility.Visible)
            return;

        if (_pipelineStatusFadeStoryboard != null) {
            _pipelineStatusFadeStoryboard.Stop();
            _pipelineStatusFadeStoryboard = null;
        }

        ImagePipelineStatusPanel.Opacity = 1;
    }

    private static string TrimForDisplay(string text, int maxLength) {
        text = (text ?? "").Trim();
        return text.Length <= maxLength ? text : text[..maxLength] + "...";
    }

    private static double ParseDouble(string? text, double fallback) {
        return double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out double value)
            ? value
            : fallback;
    }

    private static long ParseLong(string? text, long fallback) {
        return long.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out long value)
            ? value
            : fallback;
    }

    private static int ParseInt(string? text, int fallback) {
        return int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int value)
            ? value
            : fallback;
    }

    private static int NormalizeShellAgentPoolSize(int value) {
        return Math.Max(4, Math.Min(32, value <= 0 ? 8 : value));
    }

    private static string FormatDuration(TimeSpan value) {
        if (value.TotalHours >= 1)
            return value.ToString(@"hh\:mm\:ss");
        return value.ToString(@"mm\:ss");
    }

    private static string FormatBytes(long bytes) {
        string[] units = { "B", "KB", "MB", "GB" };
        double value = Math.Max(0, bytes);
        int unit = 0;
        while (value >= 1024 && unit < units.Length - 1) {
            value /= 1024;
            unit++;
        }
        return value.ToString(unit == 0 ? "0" : "0.0") + " " + units[unit];
    }

    private static string FormatMegabytes(double megabytes) {
        double value = Math.Max(0, megabytes);
        if (value >= 1024)
            return (value / 1024.0).ToString("0.0", CultureInfo.CurrentCulture) + " GB";
        return value.ToString("0", CultureInfo.CurrentCulture) + " MB";
    }

    private static string FormatPercent(double percent) {
        double value = double.IsNaN(percent) || double.IsInfinity(percent) ? 0 : Math.Clamp(percent, 0, 100);
        return value.ToString("0", CultureInfo.CurrentCulture) + "%";
    }

    private static string FormatKbps(double kbps) {
        double value = SanitizeBandwidthValue(kbps);
        return value.ToString(value >= 100 ? "0" : "0.0", CultureInfo.CurrentCulture) + " kbps";
    }

    private static string FormatBytesPerSecond(double bytesPerSecond) {
        double value = SanitizeRateValue(bytesPerSecond);
        string[] units = { "B/s", "KB/s", "MB/s", "GB/s" };
        int unit = 0;
        while (value >= 1024 && unit < units.Length - 1) {
            value /= 1024;
            unit++;
        }

        string format = unit == 0 ? "0" : value >= 100 ? "0" : "0.0";
        return value.ToString(format, CultureInfo.CurrentCulture) + " " + units[unit];
    }

    private static string FormatTokensPerHour(double tokensPerHour) {
        return FormatTokenAmount(tokensPerHour) + "/hr";
    }

    private static string FormatTokenCount(long tokens) {
        return FormatTokenAmount(tokens);
    }

    private static string FormatTokenAmount(double tokens) {
        double value = double.IsNaN(tokens) || double.IsInfinity(tokens) ? 0 : Math.Max(0, tokens);
        string[] units = { "", "K", "M", "B", "T" };
        int unit = 0;
        while (value >= 1000 && unit < units.Length - 1) {
            value /= 1000;
            unit++;
        }

        string format = unit == 0 ? "0" : value >= 100 ? "0" : "0.0";
        return value.ToString(format, CultureInfo.CurrentCulture) + units[unit];
    }

    private static long ToDisplayByteCount(ulong bytes) {
        return bytes > long.MaxValue ? long.MaxValue : (long)bytes;
    }

    private static long SaturatingAdd(long left, long right) {
        if (right > long.MaxValue - left)
            return long.MaxValue;
        return left + right;
    }

    private static ulong SaturatingAdd(ulong left, ulong right) {
        if (right > ulong.MaxValue - left)
            return ulong.MaxValue;
        return left + right;
    }

    private static ulong ToUInt64(NativeFileTime value) {
        return ((ulong)(uint)value.HighDateTime << 32) | (uint)value.LowDateTime;
    }

    private static double SanitizeBandwidthValue(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            return 0;
        return Math.Max(0, value);
    }

    private static double SanitizeRateValue(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            return 0;
        return Math.Max(0, value);
    }

    private static bool TryEnableAccentBlur(IntPtr handle) {
        try {
            var accent = new AccentPolicy {
                AccentState = AccentState.AccentEnableBlurBehind,
                AccentFlags = 2,
                GradientColor = unchecked((int)0xA8160F0A)
            };
            int accentSize = Marshal.SizeOf<AccentPolicy>();
            IntPtr accentPtr = Marshal.AllocHGlobal(accentSize);
            try {
                Marshal.StructureToPtr(accent, accentPtr, false);
                var data = new WindowCompositionAttributeData {
                    Attribute = WindowCompositionAttribute.WcaAccentPolicy,
                    Data = accentPtr,
                    SizeOfData = accentSize
                };
                return SetWindowCompositionAttribute(handle, ref data) != 0;
            } finally {
                Marshal.FreeHGlobal(accentPtr);
            }
        } catch {
            return false;
        }
    }

    private static bool TryEnableDwmBlur(IntPtr handle) {
        try {
            var blur = new DwmBlurBehind {
                Flags = DwmBbEnable,
                Enable = true,
                BlurRegion = IntPtr.Zero,
                TransitionOnMaximized = true
            };
            bool enabled = DwmEnableBlurBehindWindow(handle, ref blur) == 0;
            var margins = new DwmMargins {
                LeftWidth = -1,
                RightWidth = -1,
                TopHeight = -1,
                BottomHeight = -1
            };
            return DwmExtendFrameIntoClientArea(handle, ref margins) == 0 || enabled;
        } catch {
            return false;
        }
    }

    private void ApplyNativeCornerPreference(bool maximized) {
        IntPtr handle = new WindowInteropHelper(this).Handle;
        if (handle == IntPtr.Zero)
            return;

        try {
            int preference = maximized
                ? (int)DwmWindowCornerPreference.DoNotRound
                : (int)DwmWindowCornerPreference.Round;
            _ = DwmSetWindowAttribute(
                handle,
                DwmWindowAttribute.WindowCornerPreference,
                ref preference,
                sizeof(int));
        } catch {
        }
    }

    private static void ApplyMaximizedWorkArea(IntPtr hwnd, IntPtr lParam) {
        IntPtr monitor = MonitorFromWindow(hwnd, MonitorDefaultToNearest);
        if (monitor == IntPtr.Zero)
            return;

        var monitorInfo = new MonitorInfo {
            Size = Marshal.SizeOf<MonitorInfo>()
        };
        if (!GetMonitorInfo(monitor, ref monitorInfo))
            return;

        var minMaxInfo = Marshal.PtrToStructure<MinMaxInfo>(lParam);
        NativeRect workArea = monitorInfo.WorkArea;
        NativeRect monitorArea = monitorInfo.MonitorArea;

        minMaxInfo.MaxPosition.X = workArea.Left - monitorArea.Left;
        minMaxInfo.MaxPosition.Y = workArea.Top - monitorArea.Top;
        minMaxInfo.MaxSize.X = workArea.Right - workArea.Left;
        minMaxInfo.MaxSize.Y = workArea.Bottom - workArea.Top;
        minMaxInfo.MaxTrackSize.X = minMaxInfo.MaxSize.X;
        minMaxInfo.MaxTrackSize.Y = minMaxInfo.MaxSize.Y;

        Marshal.StructureToPtr(minMaxInfo, lParam, true);
    }

    private const int WmGetMinMaxInfo = 0x0024;
    private const int DwmBbEnable = 0x1;
    private const int MonitorDefaultToNearest = 0x00000002;

