    private sealed class PromptInternalItem : INotifyPropertyChanged {
        private bool _isExpanded;
        private bool _isRunning;
        private Visibility _closeVisibility = Visibility.Collapsed;

        public string Id { get; init; } = "";
        public string Title { get; private set; } = "";
        public string SummaryLine { get; private set; } = "";
        public string DetailLine { get; private set; } = "";
        public string PromptText { get; private set; } = "";
        public string ReferencesText { get; private set; } = "";
        public string Signature { get; private set; } = "";

        public bool IsExpanded {
            get => _isExpanded;
            set {
                if (_isExpanded == value)
                    return;
                _isExpanded = value;
                if (_isExpanded)
                    CloseVisibility = Visibility.Visible;
                OnChanged(nameof(IsExpanded));
            }
        }

        public bool IsRunning {
            get => _isRunning;
            set {
                if (_isRunning == value)
                    return;
                _isRunning = value;
                OnChanged(nameof(IsRunning));
            }
        }

        public Visibility CloseVisibility {
            get => _closeVisibility;
            set {
                if (_closeVisibility == value)
                    return;
                _closeVisibility = value;
                OnChanged(nameof(CloseVisibility));
            }
        }

        public event PropertyChangedEventHandler? PropertyChanged;

        public static PromptInternalItem FromSnapshot(ActivePromptSessionDiagnosticsSnapshot snapshot, bool running) {
            var item = new PromptInternalItem { Id = snapshot.Id };
            item.Update(snapshot, running);
            return item;
        }

        public void Update(ActivePromptSessionDiagnosticsSnapshot snapshot, bool running) {
            IsRunning = running;
            Title = string.IsNullOrWhiteSpace(snapshot.Title) ? "LLM prompt" : snapshot.Title.Trim();
            string status = string.IsNullOrWhiteSpace(snapshot.Status) ? "Running" : snapshot.Status.Trim();
            string phase = string.IsNullOrWhiteSpace(snapshot.Phase) ? status : snapshot.Phase.Trim();
            string model = string.IsNullOrWhiteSpace(snapshot.Model) ? "model unknown" : snapshot.Model.Trim();
            string elapsed = FormatDuration(TimeSpan.FromSeconds(Math.Max(0, snapshot.ElapsedSeconds)));
            SummaryLine = status + " | " + phase + " | " + elapsed;
            DetailLine = "Source: " + (string.IsNullOrWhiteSpace(snapshot.Source) ? "LLM Prompt" : snapshot.Source.Trim()) +
                         " | Owner: " + (string.IsNullOrWhiteSpace(snapshot.OwnerKey) ? "owner unknown" : snapshot.OwnerKey.Trim()) +
                         " | Model: " + model +
                         " | Tokens: " + FormatTokenCount(snapshot.PromptTokenCount) +
                         (snapshot.PromptTokenBudget > 0 ? " / " + FormatTokenCount(snapshot.PromptTokenBudget) : "");
            PromptText = string.IsNullOrWhiteSpace(snapshot.PromptText)
                ? "(prompt text unavailable)"
                : snapshot.PromptText.Trim();
            ReferencesText = string.IsNullOrWhiteSpace(snapshot.ReferencesText)
                ? "(no references reported)"
                : snapshot.ReferencesText.Trim();
            Signature = snapshot.Id + "\u001F" + Title + "\u001F" + SummaryLine + "\u001F" + DetailLine + "\u001F" + PromptText + "\u001F" + ReferencesText + "\u001F" + running;
            CloseVisibility = IsExpanded || !running ? Visibility.Visible : Visibility.Collapsed;
            OnChanged(nameof(Title));
            OnChanged(nameof(SummaryLine));
            OnChanged(nameof(DetailLine));
            OnChanged(nameof(PromptText));
            OnChanged(nameof(ReferencesText));
            OnChanged(nameof(Signature));
        }

        private void OnChanged(string name) {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
        }

        private static string FormatTokenCount(long value) {
            value = Math.Max(0, value);
            if (value >= 1000000)
                return (value / 1000000.0).ToString(value >= 10000000 ? "0M" : "0.#M", CultureInfo.InvariantCulture);
            if (value >= 1000)
                return (value / 1000.0).ToString(value >= 10000 ? "0k" : "0.#k", CultureInfo.InvariantCulture);
            return value.ToString(CultureInfo.InvariantCulture);
        }
    }

    private sealed class ChatSessionListItem {
        public string Id { get; init; } = "";
        public string SessionId { get; init; } = "";
        public string Kind { get; init; } = "";
        public string OwnerKey { get; init; } = "";
        public string Title { get; init; } = "";
        public string OwnerLine { get; init; } = "";
        public string DetailLine { get; init; } = "";
        public string UpdatedLine { get; init; } = "";
        public string PromptTokenLine { get; init; } = "";
        public double PromptTokenPercent { get; init; }
        public bool IsLocked { get; init; }
        public bool IsStoredSession => string.Equals(Kind, "stored", StringComparison.OrdinalIgnoreCase);
        public string SearchText { get; init; } = "";
        public string Signature { get; init; } = "";

        public static ChatSessionListItem FromPromptSnapshot(ActivePromptSessionDiagnosticsSnapshot snapshot) {
            string title = string.IsNullOrWhiteSpace(snapshot.Title) ? "LLM prompt" : snapshot.Title.Trim();
            string source = string.IsNullOrWhiteSpace(snapshot.Source) ? "LLM Prompt" : snapshot.Source.Trim();
            string ownerKey = string.IsNullOrWhiteSpace(snapshot.OwnerKey) ? "" : snapshot.OwnerKey.Trim();
            string owner = string.IsNullOrWhiteSpace(ownerKey) ? "owner unknown" : ownerKey;
            string model = string.IsNullOrWhiteSpace(snapshot.Model) ? "model unknown" : snapshot.Model.Trim();
            string status = string.IsNullOrWhiteSpace(snapshot.Status) ? "Running" : snapshot.Status.Trim();
            string phase = string.IsNullOrWhiteSpace(snapshot.Phase) ? status : snapshot.Phase.Trim();
            string updated = FormatSessionDate(snapshot.UpdatedUtc);
            string elapsed = FormatDuration(TimeSpan.FromSeconds(Math.Max(0, snapshot.ElapsedSeconds)));

            return new ChatSessionListItem {
                Id = snapshot.Id,
                SessionId = snapshot.SessionId,
                Kind = "active",
                OwnerKey = ownerKey,
                Title = title,
                OwnerLine = source + " | Owner: " + owner,
                DetailLine = status + " | " + phase + " | " + model + " | " + elapsed,
                UpdatedLine = "Updated: " + updated,
                PromptTokenLine = FormatPromptTokenLine(snapshot.PromptTokenCount, snapshot.PromptTokenBudget),
                PromptTokenPercent = ComputePromptTokenPercent(snapshot.PromptTokenCount, snapshot.PromptTokenBudget),
                SearchText = BuildSearchText(title, owner, source, status, phase, model, "", snapshot.PromptTokenCount, snapshot.PromptTokenBudget),
                Signature = snapshot.Id + "\u001F" + snapshot.SessionId + "\u001F" + title + "\u001F" + owner + "\u001F" + source + "\u001F" + status + "\u001F" + phase + "\u001F" + snapshot.UpdatedUtc + "\u001F" + snapshot.ElapsedSeconds + "\u001F" + model + "\u001F" + snapshot.PromptTokenCount + "\u001F" + snapshot.PromptTokenBudget
            };
        }

        public static ChatSessionListItem FromTerminalPermissionSnapshot(TerminalPermissionRequestSnapshot snapshot) {
            string ownerKey = string.IsNullOrWhiteSpace(snapshot.OwnerKey) ? "" : snapshot.OwnerKey.Trim();
            string owner = string.IsNullOrWhiteSpace(ownerKey) ? "owner unknown" : ownerKey;
            string ip = string.IsNullOrWhiteSpace(snapshot.ClientIp) ? owner : snapshot.ClientIp.Trim();
            string shell = string.IsNullOrWhiteSpace(snapshot.Shell) ? "powershell" : snapshot.Shell.Trim();
            string command = snapshot.Command ?? "";
            string workingDirectory = string.IsNullOrWhiteSpace(snapshot.WorkingDirectory)
                ? "default working directory"
                : snapshot.WorkingDirectory.Trim();

            return new ChatSessionListItem {
                Id = "terminal-approval:" + snapshot.Id,
                SessionId = "",
                Kind = "terminal",
                OwnerKey = ownerKey,
                Title = "Pending terminal approval",
                OwnerLine = "Terminal | Owner: " + owner + " | IP: " + ip,
                DetailLine = shell + " | " + TrimForDisplay(command, 120),
                UpdatedLine = "Requested: " + FormatSessionDate(snapshot.CreatedUtc) + " | " + TrimPathForDisplay(workingDirectory, 64),
                PromptTokenLine = "Terminal approval",
                PromptTokenPercent = 0,
                SearchText = BuildSearchText("Pending terminal approval", owner, ip, shell, command, workingDirectory, "", 0, 0),
                Signature = "terminal-approval:" + snapshot.Id + "\u001F" + owner + "\u001F" + ip + "\u001F" + shell + "\u001F" + command + "\u001F" + workingDirectory + "\u001F" + snapshot.CreatedUtc
            };
        }

        public static ChatSessionListItem FromSnapshot(ChatSessionDiagnosticsSnapshot snapshot) {
            string title = string.IsNullOrWhiteSpace(snapshot.Title) ? "New chat" : snapshot.Title.Trim();
            string model = string.IsNullOrWhiteSpace(snapshot.Model) ? "model unknown" : snapshot.Model.Trim();
            string ownerKey = string.IsNullOrWhiteSpace(snapshot.OwnerKey) ? "" : snapshot.OwnerKey.Trim();
            string owner = string.IsNullOrWhiteSpace(ownerKey) ? "owner unknown" : ownerKey;
            string updated = FormatSessionDate(snapshot.UpdatedUtc);
            string state = (snapshot.Locked ? "locked" : "unlocked") +
                           (snapshot.TitleLocked ? " | renamed" : "") +
                           (string.IsNullOrWhiteSpace(snapshot.ClonedFromSessionId) ? "" : " | clone");

            return new ChatSessionListItem {
                Id = snapshot.Id,
                SessionId = snapshot.Id,
                Kind = "stored",
                OwnerKey = ownerKey,
                Title = title,
                OwnerLine = "Owner: " + owner,
                DetailLine = snapshot.MessageCount + " messages, " + snapshot.FileCount + " files, " + model + " | " + state,
                UpdatedLine = "Updated: " + updated,
                PromptTokenLine = FormatPromptTokenLine(snapshot.PromptTokenCount, snapshot.PromptTokenBudget),
                PromptTokenPercent = ComputePromptTokenPercent(snapshot.PromptTokenCount, snapshot.PromptTokenBudget),
                IsLocked = snapshot.Locked,
                SearchText = BuildSearchText(title, owner, model, state, snapshot.UpdatedUtc, snapshot.ClonedFromSessionId, snapshot.SavedUtc, snapshot.PromptTokenCount, snapshot.PromptTokenBudget),
                Signature = snapshot.Id + "\u001F" + title + "\u001F" + owner + "\u001F" + snapshot.UpdatedUtc + "\u001F" + snapshot.MessageCount + "\u001F" + snapshot.FileCount + "\u001F" + model + "\u001F" + state + "\u001F" + snapshot.SavedUtc + "\u001F" + snapshot.LockedUtc + "\u001F" + snapshot.ClonedFromSessionId + "\u001F" + snapshot.PromptTokenCount + "\u001F" + snapshot.PromptTokenBudget
            };
        }

        private static string BuildSearchText(params object[] values) {
            return string.Join(" ", values.Select(value => Convert.ToString(value, CultureInfo.InvariantCulture)).Where(value => !string.IsNullOrWhiteSpace(value)));
        }

        private static string FormatPromptTokenLine(long count, long budget) {
            if (count <= 0)
                return "Prompt tokens: 0";
            string budgetText = budget > 0 ? " / " + FormatTokenCount(budget) : "";
            return "Prompt tokens: " + FormatTokenCount(count) + budgetText;
        }

        private static double ComputePromptTokenPercent(long count, long budget) {
            if (count <= 0 || budget <= 0)
                return 0;
            return Math.Max(1, Math.Min(100, count * 100.0 / budget));
        }

        private static string FormatTokenCount(long value) {
            value = Math.Max(0, value);
            if (value >= 1000000)
                return (value / 1000000.0).ToString(value >= 10000000 ? "0M" : "0.#M", CultureInfo.InvariantCulture);
            if (value >= 1000)
                return (value / 1000.0).ToString(value >= 10000 ? "0k" : "0.#k", CultureInfo.InvariantCulture);
            return value.ToString(CultureInfo.InvariantCulture);
        }

        private static string FormatSessionDate(string value) {
            if (DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed))
                return parsed.ToLocalTime().ToString("M/d/yyyy h:mm:ss tt", CultureInfo.CurrentCulture);
            return string.IsNullOrWhiteSpace(value) ? "-" : value;
        }
    }

