    private sealed class TrustAbuseCaseItem {
        public string Id { get; init; } = "";
        public string Category { get; init; } = "";
        public string Severity { get; init; } = "";
        public string Status { get; init; } = "";
        public string OwnerKey { get; init; } = "";
        public string UserName { get; init; } = "";
        public string ServerId { get; init; } = "";
        public string ServerName { get; init; } = "";
        public string ExternalIp { get; init; } = "";
        public string Summary { get; init; } = "";
        public string Detail { get; init; } = "";
        public string Intervention { get; init; } = "";
        public string UpdatedUtc { get; init; } = "";
        public int ReputationDelta { get; init; }
        public bool IsOpen { get; init; }

        public string TitleLine {
            get {
                string status = string.IsNullOrWhiteSpace(Status) ? "open" : Status;
                string label = string.IsNullOrWhiteSpace(Summary) ? "Trust case" : Summary;
                return ToDisplayToken(Severity) + " " + ToDisplayToken(Category) + " | " + ToDisplayToken(status) + " | " + label;
            }
        }

        public string SubjectLine {
            get {
                string subject = !string.IsNullOrWhiteSpace(UserName) ? UserName :
                    !string.IsNullOrWhiteSpace(OwnerKey) ? OwnerKey :
                    !string.IsNullOrWhiteSpace(ServerName) ? ServerName :
                    !string.IsNullOrWhiteSpace(ServerId) ? ServerId :
                    "unknown subject";
                string server = string.IsNullOrWhiteSpace(ServerName) ? ServerId : ServerName;
                string endpoint = string.IsNullOrWhiteSpace(ExternalIp) ? "" : " | " + ExternalIp;
                string serverLine = string.IsNullOrWhiteSpace(server) ? "" : " | " + server;
                return subject + serverLine + endpoint;
            }
        }

        public string DetailLine {
            get {
                string reputation = ReputationDelta == 0 ? "" : " | rep " + ReputationDelta.ToString("+#;-#;0", CultureInfo.InvariantCulture);
                string intervention = string.IsNullOrWhiteSpace(Intervention) ? "" : " | " + ToDisplayToken(Intervention);
                string updated = string.IsNullOrWhiteSpace(UpdatedUtc) ? "" : " | " + UpdatedUtc;
                return TrimForDisplay(Detail, 150) + reputation + intervention + updated;
            }
        }

        public static TrustAbuseCaseItem FromSnapshot(TrustAbuseCaseSnapshot snapshot) {
            snapshot ??= new TrustAbuseCaseSnapshot();
            string status = string.IsNullOrWhiteSpace(snapshot.Status) ? "open" : snapshot.Status;
            bool isOpen = string.Equals(status, "open", StringComparison.OrdinalIgnoreCase) ||
                          string.Equals(status, "investigating", StringComparison.OrdinalIgnoreCase) ||
                          string.Equals(status, "pending", StringComparison.OrdinalIgnoreCase);
            return new TrustAbuseCaseItem {
                Id = snapshot.Id ?? "",
                Category = snapshot.Category ?? "",
                Severity = snapshot.Severity ?? "",
                Status = status,
                OwnerKey = snapshot.OwnerKey ?? "",
                UserName = snapshot.UserName ?? "",
                ServerId = snapshot.ServerId ?? "",
                ServerName = snapshot.ServerName ?? "",
                ExternalIp = snapshot.ExternalIp ?? "",
                Summary = snapshot.Summary ?? "",
                Detail = snapshot.Detail ?? "",
                Intervention = snapshot.Intervention ?? "",
                UpdatedUtc = snapshot.UpdatedUtc ?? snapshot.CreatedUtc ?? "",
                ReputationDelta = snapshot.ReputationDelta,
                IsOpen = isOpen
            };
        }

        private static string ToDisplayToken(string value) {
            value = string.IsNullOrWhiteSpace(value) ? "unknown" : value.Trim();
            value = value.Replace("_", " ").Replace("-", " ");
            return CultureInfo.CurrentCulture.TextInfo.ToTitleCase(value.ToLowerInvariant());
        }
    }

