        public string Title { get; init; } = "";
        public string Detail { get; init; } = "";

        public static RegistrationRequestItem FromSnapshot(WebAuthRegistrationRequestSnapshot snapshot) {
            string userName = string.IsNullOrWhiteSpace(snapshot.UserName) ? "unknown user" : snapshot.UserName;
            string ip = string.IsNullOrWhiteSpace(snapshot.ClientIp) ? "unknown IP" : snapshot.ClientIp;
            return new RegistrationRequestItem {
                Id = snapshot.Id,
                UserName = userName,
                ClientIp = ip,
                Title = "Registration requested by " + userName,
                Detail = "Client IP: " + ip + Environment.NewLine +
                         "Requested: " + (string.IsNullOrWhiteSpace(snapshot.RequestedUtc) ? "-" : snapshot.RequestedUtc)
            };
        }
    }

    private sealed class TokenRateRequestItem {
        public string Id { get; init; } = "";
        public string UserName { get; init; } = "";
        public string OwnerKey { get; init; } = "";
        public long RequestedTokenRate { get; init; }
        public string Title { get; init; } = "";
        public string Detail { get; init; } = "";

        public static TokenRateRequestItem FromSnapshot(TokenRateRequestSnapshot snapshot) {
            snapshot ??= new TokenRateRequestSnapshot();
            string userName = string.IsNullOrWhiteSpace(snapshot.UserName) ? "unknown user" : snapshot.UserName;
            string owner = string.IsNullOrWhiteSpace(snapshot.OwnerKey) ? "webauth:" + userName.Trim().ToLowerInvariant() : snapshot.OwnerKey;
            string ip = string.IsNullOrWhiteSpace(snapshot.ClientIp) ? "unknown IP" : snapshot.ClientIp;
            return new TokenRateRequestItem {
                Id = snapshot.Id,
                UserName = userName,
                OwnerKey = owner,
                RequestedTokenRate = Math.Max(0, snapshot.RequestedTokenRate),
                Title = "Token-rate requested by " + userName,
                Detail = "Requested: " + Math.Max(0, snapshot.RequestedTokenRate).ToString("N0", CultureInfo.CurrentCulture) + " tokens/hour" + Environment.NewLine +
                         "Advertised: " + Math.Max(0, snapshot.AdvertisedTokenRate).ToString("N0", CultureInfo.CurrentCulture) + " tokens/hour" + Environment.NewLine +
                         "Range: " + Math.Max(0, snapshot.MinTokenRate).ToString("N0", CultureInfo.CurrentCulture) +
                         " - " + Math.Max(0, snapshot.MaxTokenRate).ToString("N0", CultureInfo.CurrentCulture) + " | Client IP: " + ip
            };
        }
    }

    private sealed class WebAuthUserItem {
        public string UserName { get; init; } = "";
        public string OwnerKey { get; init; } = "";
        public string UserType { get; init; } = "";
        public bool AccountManaged { get; init; }
        public bool Enabled { get; init; }
        public bool IsAdministrator { get; init; }
        public string LastClientIp { get; init; } = "";
        public long TokenLimit { get; init; }
        public long TokensUsed { get; init; }
        public long TokensRemaining { get; init; }
        public bool Unlimited { get; init; }
        public string LastLoginUtc { get; init; } = "";
        public string MutedUntilUtc { get; init; } = "";
        public string BannedUntilUtc { get; init; } = "";
        public bool MuteUntilEnabled { get; init; }
        public bool BanUntilEnabled { get; init; }
        public bool IsMuted { get; init; }
        public bool IsBanned { get; init; }
        public int SessionCount { get; init; }
        public int ActiveSessionCount { get; init; }
        public string LastSessionUtc { get; init; } = "";
        public double GpuKw { get; init; }
        public double CpuKw { get; init; }
        public double GpuKwh { get; init; }
        public double CpuKwh { get; init; }
        public double TotalKwh { get; init; }
        public double TotalCostUsd { get; init; }
        public long StorageBytesUsed { get; init; }
        public long StorageLimitBytes { get; init; }
        public bool StorageUnlimited { get; init; }
        public bool IsCurrentSocketJackUser { get; init; }

        public string NameLine {
            get {
                string flags = "";
                if (IsCurrentSocketJackUser)
                    flags += " | signed in";
                if (AccountManaged)
                    flags += " | account";
                else if (!string.IsNullOrWhiteSpace(UserType))
                    flags += " | " + UserType;
                if (IsAdministrator)
                    flags += " | admin";
                if (!Enabled)
                    flags += " | disabled";
                if (IsBanned)
                    flags += " | banned";
                else if (IsMuted)
                    flags += " | muted";
                return UserName + " (" + OwnerKey + ")" + flags;
            }
        }

        public string TokenLine {
            get {
                return "Tokens " + TokensUsed.ToString("N0", CultureInfo.CurrentCulture) +
                       " | GPU " + FormatUsageKwh(GpuKwh) + " @ " + FormatUsageKw(GpuKw) +
                       " | CPU " + FormatUsageKwh(CpuKwh) + " @ " + FormatUsageKw(CpuKw);
            }
        }

        public string DetailLine {
            get {
                string ip = string.IsNullOrWhiteSpace(LastClientIp) ? "IP unknown" : "Last IP " + LastClientIp;
                string login = string.IsNullOrWhiteSpace(LastLoginUtc) ? "never logged in" : "last login " + FormatManagementDate(LastLoginUtc);
                string lastSession = string.IsNullOrWhiteSpace(LastSessionUtc) ? "no sessions yet" : "last session " + FormatManagementDate(LastSessionUtc);
                string sessions = ActiveSessionCount.ToString("N0", CultureInfo.CurrentCulture) + " active / " +
                                  SessionCount.ToString("N0", CultureInfo.CurrentCulture) + " stored sessions";
                return sessions + " | energy " + FormatUsageKwh(TotalKwh) + " | " + FormatStorageLine() + " | " + FormatUsageCost(TotalCostUsd) + " | " + ip + " | " + login + " | " + lastSession + " | " + StatusLine;
            }
        }

        public string StatusLine {
            get {
                if (IsBanned)
                    return BanUntilEnabled ? "banned until enabled" : "banned until " + FormatManagementDate(BannedUntilUtc);
                if (IsMuted)
                    return MuteUntilEnabled ? "muted until enabled" : "muted until " + FormatManagementDate(MutedUntilUtc);
                if (!Enabled)
                    return "disabled";
                return IsAdministrator ? "administrator" : "enabled";
            }
        }

        public static WebAuthUserItem FromSnapshot(WebAuthUserDiagnosticsSnapshot snapshot) {
            snapshot ??= new WebAuthUserDiagnosticsSnapshot();
            string userName = string.IsNullOrWhiteSpace(snapshot.UserName) ? "unknown" : snapshot.UserName;
            return new WebAuthUserItem {
                UserName = userName,
                OwnerKey = string.IsNullOrWhiteSpace(snapshot.OwnerKey) ? "webauth:" + userName.Trim().ToLowerInvariant() : snapshot.OwnerKey,
                UserType = "webauth",
                AccountManaged = true,
                Enabled = snapshot.Enabled,
                IsAdministrator = snapshot.IsAdministrator,
                LastClientIp = snapshot.LastClientIp ?? "",
                TokenLimit = Math.Max(0, snapshot.TokenLimit),
                TokensUsed = Math.Max(0, snapshot.TokensUsed),
                TokensRemaining = Math.Max(0, snapshot.TokensRemaining),
                Unlimited = snapshot.Unlimited,
                LastLoginUtc = snapshot.LastLoginUtc ?? "",
                MutedUntilUtc = snapshot.MutedUntilUtc ?? "",
                BannedUntilUtc = snapshot.BannedUntilUtc ?? "",
                MuteUntilEnabled = snapshot.MuteUntilEnabled,
                BanUntilEnabled = snapshot.BanUntilEnabled,
                IsMuted = snapshot.IsMuted,
                IsBanned = snapshot.IsBanned
            };
        }

        public static WebAuthUserItem FromSnapshot(ServerUserUsageDiagnosticsSnapshot snapshot) {
            snapshot ??= new ServerUserUsageDiagnosticsSnapshot();
            ChatUsageDiagnosticsSnapshot usage = snapshot.Usage ?? new ChatUsageDiagnosticsSnapshot();
            string ownerKey = string.IsNullOrWhiteSpace(snapshot.OwnerKey) ? usage.OwnerKey : snapshot.OwnerKey;
            string userName = FirstNonEmpty(snapshot.UserName, usage.UserName, ownerKey, "unknown");
            return new WebAuthUserItem {
                UserName = userName,
                OwnerKey = string.IsNullOrWhiteSpace(ownerKey) ? "unknown" : ownerKey,
                UserType = FirstNonEmpty(snapshot.UserType, usage.Authenticated ? "authenticated" : "local"),
                AccountManaged = snapshot.AccountManaged,
                Enabled = snapshot.Enabled,
                IsAdministrator = snapshot.IsAdministrator,
                LastClientIp = snapshot.LastClientIp ?? "",
                TokenLimit = Math.Max(0, snapshot.TokenLimit),
                TokensUsed = Math.Max(Math.Max(0, snapshot.TokensUsed), Math.Max(0, usage.TokensUsed)),
                TokensRemaining = Math.Max(0, snapshot.TokensRemaining),
                Unlimited = snapshot.Unlimited || usage.Unlimited,
                LastLoginUtc = snapshot.LastLoginUtc ?? "",
                MutedUntilUtc = snapshot.MutedUntilUtc ?? "",
                BannedUntilUtc = snapshot.BannedUntilUtc ?? "",
                MuteUntilEnabled = snapshot.MuteUntilEnabled,
                BanUntilEnabled = snapshot.BanUntilEnabled,
                IsMuted = snapshot.IsMuted,
                IsBanned = snapshot.IsBanned,
                SessionCount = Math.Max(0, snapshot.SessionCount),
                ActiveSessionCount = Math.Max(0, snapshot.ActiveSessionCount),
                LastSessionUtc = snapshot.LastSessionUtc ?? "",
                GpuKw = Math.Max(0, usage.GpuKw),
                CpuKw = Math.Max(0, usage.CpuKw),
                GpuKwh = Math.Max(0, usage.GpuKwh),
                CpuKwh = Math.Max(0, usage.CpuKwh),
                TotalKwh = Math.Max(0, usage.TotalKwh),
                TotalCostUsd = Math.Max(0, usage.TotalCostUsd),
                StorageBytesUsed = Math.Max(0, usage.StorageBytesUsed),
                StorageLimitBytes = Math.Max(0, usage.StorageLimitBytes),
                StorageUnlimited = usage.StorageUnlimited
            };
        }

        private string FormatStorageLine() {
            string used = FormatBytes(StorageBytesUsed);
            if (StorageUnlimited || StorageLimitBytes <= 0)
                return "storage " + used + " used";
            return "storage " + used + " / " + FormatBytes(StorageLimitBytes);
        }

        private static string FormatUsageKw(double value) {
            return Math.Max(0, value).ToString("0.###", CultureInfo.CurrentCulture) + " kW";
        }

        private static string FormatUsageKwh(double value) {
            return Math.Max(0, value).ToString("0.######", CultureInfo.CurrentCulture) + " kWh";
        }

        private static string FormatUsageCost(double value) {
            return value <= 0 ? "$0.00" : value.ToString("C4", CultureInfo.CurrentCulture);
        }
    }

    private sealed class FileTreeItem {
        public string DisplayName { get; init; } = "";
        public string Detail { get; init; } = "";
        public string Icon { get; init; } = "[file]";
        public Brush AccentBrush { get; init; } = Brushes.LightSteelBlue;
        public FontWeight FontWeight { get; init; } = FontWeights.Normal;
        public string SourcePath { get; init; } = "";
        public bool IsDirectory { get; init; }
        public bool CanRemove { get; init; }
        public Visibility ZipVisibility => IsDirectory ? Visibility.Visible : Visibility.Collapsed;
        public Visibility RemoveVisibility => CanRemove ? Visibility.Visible : Visibility.Collapsed;
        public bool IsExpanded { get; set; }
        public ObservableCollection<FileTreeItem> Children { get; } = new();
    }

    private sealed class BandwidthMetricTracker {
        private const int MaxSamples = 180;
        private readonly string _direction;
        private readonly Queue<double> _samples = new();
        private bool _hasRange;
        private double _rangeMinimumKbps;
        private double _rangeMaximumKbps;
        private double _recordedMinimumKbps;
        private double _recordedMaximumKbps;

        public BandwidthMetricTracker(string direction) {
            _direction = string.IsNullOrWhiteSpace(direction) ? "Bandwidth" : direction;
            Reset();
        }

        public void Reset() {
            _samples.Clear();
            _hasRange = false;
            _rangeMinimumKbps = 0;
            _rangeMaximumKbps = 100;
            _recordedMinimumKbps = double.NaN;
            _recordedMaximumKbps = 0;
        }

        public BandwidthMetricSnapshot Update(double liveKbps, long totalBytes) {
            liveKbps = SanitizeBandwidthValue(liveKbps);
            totalBytes = Math.Max(0, totalBytes);

            _samples.Enqueue(liveKbps);
            while (_samples.Count > MaxSamples)
                _samples.Dequeue();

            if (liveKbps > 0) {
                _recordedMinimumKbps = double.IsNaN(_recordedMinimumKbps)
                    ? liveKbps
                    : Math.Min(_recordedMinimumKbps, liveKbps);
            }
            _recordedMaximumKbps = Math.Max(_recordedMaximumKbps, liveKbps);

            double[] activeSamples = _samples.Where(sample => sample > 0).OrderBy(sample => sample).ToArray();
            double[] sortedSamples = activeSamples.Length > 0
                ? activeSamples
                : _samples.OrderBy(sample => sample).ToArray();

            double onePercentLow = Percentile(sortedSamples, 0.01);
            double onePercentHigh = Percentile(sortedSamples, 0.99);
            double targetMinimum = sortedSamples.Length == 0 ? 0 : Math.Min(liveKbps, onePercentLow);
            double targetMaximum = sortedSamples.Length == 0 ? Math.Max(1, liveKbps) : Math.Max(liveKbps, onePercentHigh);
            if (liveKbps <= 0)
                targetMinimum = 0;

            targetMinimum = SanitizeBandwidthValue(targetMinimum);
            targetMaximum = SanitizeBandwidthValue(targetMaximum);
            double minimumGap = Math.Max(1, targetMaximum * 0.08);
            if (targetMaximum - targetMinimum < minimumGap)
                targetMaximum = targetMinimum + minimumGap;

            if (!_hasRange) {
                _rangeMinimumKbps = targetMinimum;
                _rangeMaximumKbps = targetMaximum;
                _hasRange = true;
            } else {
                double minimumAlpha = targetMinimum < _rangeMinimumKbps ? 0.45 : 0.10;
                double maximumAlpha = targetMaximum > _rangeMaximumKbps ? 0.45 : 0.10;
                _rangeMinimumKbps = Interpolate(_rangeMinimumKbps, targetMinimum, minimumAlpha);
                _rangeMaximumKbps = Interpolate(_rangeMaximumKbps, targetMaximum, maximumAlpha);
            }

            _rangeMinimumKbps = SanitizeBandwidthValue(_rangeMinimumKbps);
            _rangeMaximumKbps = SanitizeBandwidthValue(_rangeMaximumKbps);
            if (_rangeMaximumKbps <= _rangeMinimumKbps)
                _rangeMaximumKbps = _rangeMinimumKbps + 1;

            double valueKbps = Math.Min(_rangeMaximumKbps, Math.Max(_rangeMinimumKbps, liveKbps));
            if (liveKbps > 0 && valueKbps <= _rangeMinimumKbps) {
                double visibleFloor = (_rangeMaximumKbps - _rangeMinimumKbps) * 0.05;
                valueKbps = Math.Min(_rangeMaximumKbps, _rangeMinimumKbps + Math.Max(0.01, visibleFloor));
            }

            return new BandwidthMetricSnapshot(
                _direction,
                liveKbps,
                _rangeMinimumKbps,
                _rangeMaximumKbps,
                valueKbps,
                double.IsNaN(_recordedMinimumKbps) ? 0 : _recordedMinimumKbps,
                _recordedMaximumKbps,
                onePercentLow,
                onePercentHigh,
                _samples.Count,
                totalBytes);
        }

        private static double Interpolate(double current, double target, double alpha) {
            alpha = Math.Min(1, Math.Max(0, alpha));
            return current + ((target - current) * alpha);
        }

        private static double Percentile(double[] sortedSamples, double percentile) {
            if (sortedSamples.Length == 0)
                return 0;

            double clampedPercentile = Math.Min(1, Math.Max(0, percentile));
            double position = clampedPercentile * (sortedSamples.Length - 1);
            int lower = Math.Max(0, Math.Min(sortedSamples.Length - 1, (int)Math.Floor(position)));
            int upper = Math.Max(0, Math.Min(sortedSamples.Length - 1, (int)Math.Ceiling(position)));
            if (lower == upper)
                return sortedSamples[lower];

            double weight = position - lower;
            return sortedSamples[lower] + ((sortedSamples[upper] - sortedSamples[lower]) * weight);
        }
    }

    private readonly struct BandwidthMetricSnapshot {
        public BandwidthMetricSnapshot(string direction, double liveKbps, double minimumKbps, double maximumKbps, double valueKbps, double recordedMinimumKbps, double recordedMaximumKbps, double onePercentLowKbps, double onePercentHighKbps, int sampleCount, long totalBytes) {
            Direction = string.IsNullOrWhiteSpace(direction) ? "Bandwidth" : direction;
            LiveKbps = SanitizeBandwidthValue(liveKbps);
            MinimumKbps = SanitizeBandwidthValue(minimumKbps);
            MaximumKbps = Math.Max(MinimumKbps + 1, SanitizeBandwidthValue(maximumKbps));
            ValueKbps = Math.Min(MaximumKbps, Math.Max(MinimumKbps, SanitizeBandwidthValue(valueKbps)));
            RecordedMinimumKbps = SanitizeBandwidthValue(recordedMinimumKbps);
            RecordedMaximumKbps = SanitizeBandwidthValue(recordedMaximumKbps);
            OnePercentLowKbps = SanitizeBandwidthValue(onePercentLowKbps);
            OnePercentHighKbps = SanitizeBandwidthValue(onePercentHighKbps);
            SampleCount = Math.Max(0, sampleCount);
            TotalBytes = Math.Max(0, totalBytes);
        }

        public string Direction { get; }
        public double LiveKbps { get; }
        public double MinimumKbps { get; }
        public double MaximumKbps { get; }
        public double ValueKbps { get; }
        public double RecordedMinimumKbps { get; }
        public double RecordedMaximumKbps { get; }
        public double OnePercentLowKbps { get; }
        public double OnePercentHighKbps { get; }
        public int SampleCount { get; }
        public long TotalBytes { get; }

        public string ToolTip =>
            Direction + Environment.NewLine +
            "Live: " + FormatKbps(LiveKbps) + Environment.NewLine +
            "Adaptive min/max: " + FormatKbps(MinimumKbps) + " / " + FormatKbps(MaximumKbps) + Environment.NewLine +
            "Recorded min/max: " + FormatKbps(RecordedMinimumKbps) + " / " + FormatKbps(RecordedMaximumKbps) + Environment.NewLine +
            "1% low/high: " + FormatKbps(OnePercentLowKbps) + " / " + FormatKbps(OnePercentHighKbps) + Environment.NewLine +
            "Total: " + FormatBytes(TotalBytes);

        public static BandwidthMetricSnapshot Empty(string direction) {
            return new BandwidthMetricSnapshot(direction, 0, 0, 100, 0, 0, 0, 0, 0, 0, 0);
        }
    }

    private sealed class RateMetricTracker {
        private const int MaxSamples = 60;
        private readonly string _name;
        private readonly Queue<double> _samples = new();
