    private sealed class ShellWebSocketTunnelClient : IDisposable {
        private static readonly TimeSpan ConnectTimeout = TimeSpan.FromSeconds(10);
        private static readonly TimeSpan HeartbeatInterval = TimeSpan.FromSeconds(15);
        private readonly string _relayId;
        private readonly string _name;
        private readonly Uri _tunnelUri;
        private readonly string _localHost;
        private readonly int _localPort;
        private readonly string _ownerToken;
        private readonly string _channelRole;
        private readonly SemaphoreSlim _sendLock = new(1, 1);
        private readonly ConcurrentDictionary<string, CancellationTokenSource> _pending = new(StringComparer.OrdinalIgnoreCase);
        private readonly ConcurrentDictionary<string, ProxyWebSocketSession> _webSockets = new(StringComparer.OrdinalIgnoreCase);
        private CancellationTokenSource? _cts;
        private Task? _runTask;
        private bool _disposed;
        private static readonly bool EnableTunnelDebugLog =
            string.Equals(Environment.GetEnvironmentVariable("SOCKETJACK_TUNNEL_DEBUG"), "1", StringComparison.OrdinalIgnoreCase);
        private static readonly object DebugLogLock = new();

        public ShellWebSocketTunnelClient(string relayId, string name, string tunnelUrl, string localHost, int localPort, string ownerToken, string channelRole = "") {
            _relayId = relayId ?? "";
            _name = string.IsNullOrWhiteSpace(name) ? "Shell WebSocket tunnel" : name;
            _tunnelUri = new Uri(tunnelUrl);
            _localHost = string.IsNullOrWhiteSpace(localHost) ? "127.0.0.1" : localHost.Trim();
            _localPort = localPort;
            _ownerToken = ownerToken ?? "";
            _channelRole = NormalizeShellWebSocketTunnelRole(channelRole);
        }

        public event EventHandler<ShellTunnelStatusEventArgs>? StatusChanged;

        public string ChannelRole => _channelRole;

        public void Start() {
            if (_disposed || _runTask != null)
                return;
            AppendDebugLog("starting tunnel " + _tunnelUri);
            _cts = new CancellationTokenSource();
            _runTask = Task.Run(() => RunAsync(_cts.Token));
        }

        private async Task RunAsync(CancellationToken cancellationToken) {
            int failures = 0;
            while (!cancellationToken.IsCancellationRequested) {
                using var socket = new ClientWebSocket();
                socket.Options.KeepAliveInterval = HeartbeatInterval;
                try {
                    RaiseStatus(false, false, "Connecting to " + _tunnelUri + ".");
                    using var connectCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
                    connectCts.CancelAfter(ConnectTimeout);
                    await socket.ConnectAsync(_tunnelUri, connectCts.Token).ConfigureAwait(false);
                    AppendDebugLog("connected socket " + _tunnelUri);
                    await SendJsonAsync(socket, new {
                        type = "hello",
                        relayId = _relayId,
                        ownerToken = _ownerToken,
                        ownerTokenHash = HashMasterServerOwnerToken(_ownerToken),
                        client = "JackLLM Workstation",
                        channelRole = _channelRole,
                        tunnelVersion = 1,
                        sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                    }, cancellationToken).ConfigureAwait(false);

                    WebSocketMessage ready = await ReceiveMessageAsync(socket, cancellationToken).ConfigureAwait(false);
                    string readyError = "";
                    if (ready.Type != WebSocketMessageType.Text || !IsReadyMessageOk(ready.Text, out readyError))
                        throw new InvalidOperationException(string.IsNullOrWhiteSpace(readyError) ? "Master did not accept the WebSocket tunnel." : readyError);

                    failures = 0;
                    AppendDebugLog("ready accepted relay=" + _relayId);
                    RaiseStatus(true, false, "Connected.");
                    using var heartbeatCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
                    Task heartbeatTask = RunHeartbeatAsync(socket, heartbeatCts.Token);
                    try {
                        Task receiveTask = ReceiveLoopAsync(socket, cancellationToken);
                        Task completedTask = await Task.WhenAny(receiveTask, heartbeatTask).ConfigureAwait(false);
                        if (completedTask == heartbeatTask && !heartbeatCts.IsCancellationRequested && socket.State == WebSocketState.Open) {
                            AppendDebugLog("heartbeat loop ended while receive loop was still open; aborting socket to reconnect");
                            try { socket.Abort(); } catch { }
                        }
                        await receiveTask.ConfigureAwait(false);
                    } finally {
                        try { heartbeatCts.Cancel(); } catch { }
                        try { await heartbeatTask.ConfigureAwait(false); } catch { }
                    }
                    if (!cancellationToken.IsCancellationRequested) {
                        AppendDebugLog("receive loop ended state=" + socket.State + " closeStatus=" + socket.CloseStatus + " closeDescription=" + TrimForDisplay(socket.CloseStatusDescription ?? "", 160));
                        throw new IOException("WebSocket tunnel closed" + (socket.CloseStatus.HasValue ? " (" + socket.CloseStatus.Value + ")" : "") + ".");
                    }
                } catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) {
                    break;
                } catch (Exception ex) {
                    failures++;
                    AppendDebugLog("disconnect " + ex.GetType().Name + ": " + ex.Message);
                    RaiseStatus(false, true, "Disconnected; TCP fallback recommended. " + TrimForDisplay(ex.Message, 160));
                    TimeSpan delay = TimeSpan.FromSeconds(Math.Min(12, Math.Max(1, failures * 2)));
                    try { await Task.Delay(delay, cancellationToken).ConfigureAwait(false); } catch { }
                }
            }
        }

        private async Task ReceiveLoopAsync(ClientWebSocket socket, CancellationToken cancellationToken) {
            while (!cancellationToken.IsCancellationRequested && socket.State == WebSocketState.Open) {
                WebSocketMessage message = await ReceiveMessageAsync(socket, cancellationToken).ConfigureAwait(false);
                if (message.Type == WebSocketMessageType.Close) {
                    AppendDebugLog("received close frame state=" + socket.State + " closeStatus=" + socket.CloseStatus + " closeDescription=" + TrimForDisplay(socket.CloseStatusDescription ?? "", 160));
                    break;
                }
                if (message.Type == WebSocketMessageType.Binary) {
                    _ = Task.Run(() => HandleTunnelBinaryMessageAsync(socket, message.Bytes, cancellationToken), cancellationToken);
                    continue;
                }
                if (message.Type != WebSocketMessageType.Text)
                    continue;

                using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(message.Text) ? "{}" : message.Text);
                JsonElement root = document.RootElement;
                string type = ReadJsonString(root, "type");
                if (type.Equals("request", StringComparison.OrdinalIgnoreCase)) {
                    AppendDebugLog("received request id=" + ReadJsonString(root, "id") + " method=" + ReadJsonString(root, "method") + " path=" + ReadJsonString(root, "path"));
                    JsonElement requestElement = root.Clone();
                    _ = Task.Run(() => HandleProxyRequestAsync(socket, requestElement, cancellationToken), cancellationToken);
                } else if (type.Equals("websocket-open", StringComparison.OrdinalIgnoreCase)) {
                    AppendDebugLog("received websocket-open id=" + ReadJsonString(root, "id") + " path=" + ReadJsonString(root, "path"));
                    JsonElement requestElement = root.Clone();
                    _ = Task.Run(() => HandleWebSocketOpenAsync(socket, requestElement, cancellationToken), cancellationToken);
                } else if (type.Equals("websocket-close", StringComparison.OrdinalIgnoreCase)) {
                    string id = ReadJsonString(root, "id");
                    if (!string.IsNullOrWhiteSpace(id) && _webSockets.TryRemove(id, out ProxyWebSocketSession? session))
                        await CloseProxyWebSocketSessionAsync(session).ConfigureAwait(false);
                } else if (type.Equals("cancel", StringComparison.OrdinalIgnoreCase)) {
                    string id = ReadJsonString(root, "id");
                    if (!string.IsNullOrWhiteSpace(id) && _pending.TryRemove(id, out CancellationTokenSource? pendingCts)) {
                        try { pendingCts.Cancel(); } catch { }
                    }
                }
            }
        }

        private async Task HandleProxyRequestAsync(ClientWebSocket socket, JsonElement root, CancellationToken tunnelCancellationToken) {
            string id = ReadJsonString(root, "id");
            if (string.IsNullOrWhiteSpace(id))
                return;

            using var requestCts = CancellationTokenSource.CreateLinkedTokenSource(tunnelCancellationToken);
            _pending[id] = requestCts;
            Stopwatch stopwatch = Stopwatch.StartNew();
            try {
                string method = FirstNonEmpty(ReadJsonString(root, "method"), "GET").ToUpperInvariant();
                string path = FirstNonEmpty(ReadJsonString(root, "path"), "/");
                string queryString = ReadJsonString(root, "queryString");
                string bodyBase64 = ReadJsonString(root, "bodyBase64");
                byte[] body = string.IsNullOrWhiteSpace(bodyBase64) ? Array.Empty<byte>() : Convert.FromBase64String(bodyBase64);
                Dictionary<string, string> headers = ReadJsonObjectStrings(root, "headers");
                string uriText = "http://" + _localHost + ":" + _localPort.ToString(CultureInfo.InvariantCulture) + path + (string.IsNullOrWhiteSpace(queryString) ? "" : "?" + queryString.TrimStart('?'));
                AppendDebugLog("local request id=" + id + " " + method + " " + uriText + " bodyBytes=" + body.Length.ToString(CultureInfo.InvariantCulture) + " bodyPreview=" + TrimForDisplay(Encoding.UTF8.GetString(body), 120));

                using LocalProxyResponse localResponse = await SendLocalProxyRequestAsync(method, uriText, headers, body, requestCts.Token).ConfigureAwait(false);
                AppendDebugLog("local response id=" + id + " status=" + localResponse.StatusCode.ToString(CultureInfo.InvariantCulture));
                Dictionary<string, string> responseHeaders = new(StringComparer.OrdinalIgnoreCase);
                foreach (KeyValuePair<string, string> header in localResponse.Headers)
                    responseHeaders[header.Key] = header.Value;
                string contentType = localResponse.ContentType;

                await SendJsonAsync(socket, new {
                    type = "response-start",
                    id,
                    statusCode = localResponse.StatusCode,
                    reasonPhrase = localResponse.ReasonPhrase,
                    contentType,
                    headers = responseHeaders,
                    sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                }, requestCts.Token).ConfigureAwait(false);

                using Stream responseStream = localResponse.Stream;
                byte[] buffer = new byte[GetShellProxyResponseBufferSize(contentType, path)];
                long sentBytes = 0;
                while (!requestCts.Token.IsCancellationRequested) {
                    int read = await responseStream.ReadAsync(buffer, 0, buffer.Length, requestCts.Token).ConfigureAwait(false);
                    if (read <= 0)
                        break;
                    sentBytes += read;
                    await SendBinaryChunkAsync(socket, id, buffer, read, requestCts.Token).ConfigureAwait(false);
                }

                stopwatch.Stop();
                await SendJsonAsync(socket, new {
                    type = "response-end",
                    id,
                    durationMs = ClampLatencyMilliseconds(stopwatch.Elapsed),
                    sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                }, CancellationToken.None).ConfigureAwait(false);
                AppendDebugLog("completed request id=" + id + " bytes=" + sentBytes.ToString(CultureInfo.InvariantCulture) + " durationMs=" + ClampLatencyMilliseconds(stopwatch.Elapsed).ToString(CultureInfo.InvariantCulture));
            } catch (OperationCanceledException) {
                AppendDebugLog("request canceled id=" + id);
                await TrySendErrorAsync(socket, id, 499, "Request canceled.").ConfigureAwait(false);
            } catch (Exception ex) {
                AppendDebugLog("request failed id=" + id + " " + ex.GetType().Name + ": " + ex.Message);
                await TrySendErrorAsync(socket, id, 502, ex.Message).ConfigureAwait(false);
            } finally {
                _pending.TryRemove(id, out _);
            }
        }

        private async Task HandleWebSocketOpenAsync(ClientWebSocket tunnelSocket, JsonElement root, CancellationToken tunnelCancellationToken) {
            string id = ReadJsonString(root, "id");
            if (string.IsNullOrWhiteSpace(id))
                return;

            ClientWebSocket? upstream = null;
            try {
                string path = NormalizeProxyWebSocketPath(ReadJsonString(root, "path"));
                string queryString = ReadJsonString(root, "queryString");
                Uri localUri = BuildLocalWebSocketUri(path, queryString);
                upstream = new ClientWebSocket();
                upstream.Options.KeepAliveInterval = TimeSpan.FromSeconds(15);
                foreach (KeyValuePair<string, string> header in ReadJsonObjectStrings(root, "headers")) {
                    if (!ShouldSkipProxyWebSocketHeader(header.Key))
                        upstream.Options.SetRequestHeader(header.Key, header.Value);
                }

                using var sessionCts = CancellationTokenSource.CreateLinkedTokenSource(tunnelCancellationToken);
                using var connectCts = CancellationTokenSource.CreateLinkedTokenSource(sessionCts.Token);
                connectCts.CancelAfter(ConnectTimeout);
                await upstream.ConnectAsync(localUri, connectCts.Token).ConfigureAwait(false);

                var session = new ProxyWebSocketSession(id, upstream, sessionCts);
                if (!_webSockets.TryAdd(id, session))
                    throw new InvalidOperationException("WebSocket tunnel session id collision.");

                upstream = null;
                await SendWebSocketReadyAsync(tunnelSocket, id, true, "").ConfigureAwait(false);
                _ = Task.Run(() => PumpProxyWebSocketToTunnelAsync(tunnelSocket, session), session.Cancellation);
            } catch (Exception ex) {
                try { upstream?.Dispose(); } catch { }
                await SendWebSocketReadyAsync(tunnelSocket, id, false, ex.Message).ConfigureAwait(false);
            }
        }

        private async Task HandleTunnelBinaryMessageAsync(ClientWebSocket tunnelSocket, byte[] payload, CancellationToken tunnelCancellationToken) {
            if (payload == null || payload.Length < 33)
                return;
            string id = Encoding.ASCII.GetString(payload, 0, 32).Trim();
            if (string.IsNullOrWhiteSpace(id) || !_webSockets.TryGetValue(id, out ProxyWebSocketSession? session))
                return;

            byte opcode = payload[32];
            byte[] framePayload = new byte[payload.Length - 33];
            Buffer.BlockCopy(payload, 33, framePayload, 0, framePayload.Length);
            try {
                await SendProxyWebSocketFrameToLocalAsync(session, opcode, framePayload, tunnelCancellationToken).ConfigureAwait(false);
            } catch (Exception ex) {
                await SendWebSocketErrorAsync(tunnelSocket, id, ex.Message).ConfigureAwait(false);
                if (_webSockets.TryRemove(id, out ProxyWebSocketSession? removed))
                    await CloseProxyWebSocketSessionAsync(removed).ConfigureAwait(false);
            }
        }

        private async Task SendProxyWebSocketFrameToLocalAsync(ProxyWebSocketSession session, byte opcode, byte[] payload, CancellationToken tunnelCancellationToken) {
            if (session.Socket.State != WebSocketState.Open)
                return;
            if ((opcode & 0x0F) == 0x8) {
                await CloseProxyWebSocketSessionAsync(session).ConfigureAwait(false);
                return;
            }

            WebSocketMessageType type = (opcode & 0x0F) == 0x1 ? WebSocketMessageType.Text : WebSocketMessageType.Binary;
            using CancellationTokenSource sendCts = CancellationTokenSource.CreateLinkedTokenSource(session.Cancellation, tunnelCancellationToken);
            await session.SendLock.WaitAsync(sendCts.Token).ConfigureAwait(false);
            try {
                await session.Socket.SendAsync(new ArraySegment<byte>(payload ?? Array.Empty<byte>()), type, true, sendCts.Token).ConfigureAwait(false);
            } finally {
                session.SendLock.Release();
            }
        }

        private async Task PumpProxyWebSocketToTunnelAsync(ClientWebSocket tunnelSocket, ProxyWebSocketSession session) {
            try {
                byte[] buffer = new byte[32 * 1024];
                while (!session.Cancellation.IsCancellationRequested && session.Socket.State == WebSocketState.Open) {
                    using var message = new MemoryStream();
                    WebSocketReceiveResult result;
                    do {
                        result = await session.Socket.ReceiveAsync(new ArraySegment<byte>(buffer), session.Cancellation).ConfigureAwait(false);
                        if (result.MessageType == WebSocketMessageType.Close) {
                            await SendWebSocketCloseAsync(tunnelSocket, session.Id).ConfigureAwait(false);
                            return;
                        }
                        if (result.Count > 0)
                            message.Write(buffer, 0, result.Count);
                    } while (!result.EndOfMessage);

                    byte opcode = result.MessageType == WebSocketMessageType.Text ? (byte)0x1 : (byte)0x2;
                    await SendWebSocketBinaryFrameAsync(tunnelSocket, session.Id, opcode, message.ToArray(), session.Cancellation).ConfigureAwait(false);
                }
            } catch (OperationCanceledException) {
            } catch (Exception ex) {
                await SendWebSocketErrorAsync(tunnelSocket, session.Id, ex.Message).ConfigureAwait(false);
            } finally {
                if (_webSockets.TryRemove(session.Id, out ProxyWebSocketSession? removed))
                    await CloseProxyWebSocketSessionAsync(removed).ConfigureAwait(false);
                await SendWebSocketCloseAsync(tunnelSocket, session.Id).ConfigureAwait(false);
            }
        }

        private Uri BuildLocalWebSocketUri(string path, string queryString) {
            var builder = new UriBuilder("ws", _localHost, _localPort, NormalizeProxyWebSocketPath(path));
            builder.Query = string.IsNullOrWhiteSpace(queryString) ? "" : queryString.TrimStart('?');
            return builder.Uri;
        }

        private static string NormalizeProxyWebSocketPath(string path) {
            if (string.IsNullOrWhiteSpace(path))
                return "/";
            path = path.Trim();
            return path.StartsWith("/", StringComparison.Ordinal) ? path : "/" + path;
        }

        private static bool ShouldSkipProxyWebSocketHeader(string name) {
            return string.IsNullOrWhiteSpace(name) ||
                   name.Equals("Host", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Connection", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Content-Length", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Transfer-Encoding", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Keep-Alive", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Upgrade", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Accept-Encoding", StringComparison.OrdinalIgnoreCase) ||
                   name.StartsWith("Sec-WebSocket", StringComparison.OrdinalIgnoreCase) ||
                   name.StartsWith("Proxy-", StringComparison.OrdinalIgnoreCase);
        }

        private async Task SendWebSocketReadyAsync(ClientWebSocket socket, string id, bool ok, string error) {
            await SendJsonAsync(socket, new {
                type = "websocket-ready",
                id,
                ok,
                error = error ?? "",
                sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            }, CancellationToken.None).ConfigureAwait(false);
        }

        private async Task SendWebSocketCloseAsync(ClientWebSocket socket, string id) {
            try {
                await SendJsonAsync(socket, new {
                    type = "websocket-close",
                    id,
                    sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                }, CancellationToken.None).ConfigureAwait(false);
            } catch {
            }
        }

        private async Task SendWebSocketErrorAsync(ClientWebSocket socket, string id, string error) {
            try {
                await SendJsonAsync(socket, new {
                    type = "websocket-error",
                    id,
                    error = error ?? "WebSocket tunnel target failed.",
                    sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                }, CancellationToken.None).ConfigureAwait(false);
            } catch {
            }
        }

        private async Task SendWebSocketBinaryFrameAsync(ClientWebSocket socket, string id, byte opcode, byte[] payload, CancellationToken cancellationToken) {
            payload ??= Array.Empty<byte>();
            byte[] framed = new byte[33 + payload.Length];
            byte[] idBytes = Encoding.ASCII.GetBytes((id ?? "").PadRight(32).Substring(0, 32));
            Buffer.BlockCopy(idBytes, 0, framed, 0, 32);
            framed[32] = opcode;
            if (payload.Length > 0)
                Buffer.BlockCopy(payload, 0, framed, 33, payload.Length);

            await _sendLock.WaitAsync(cancellationToken).ConfigureAwait(false);
            try {
                await socket.SendAsync(new ArraySegment<byte>(framed), WebSocketMessageType.Binary, true, cancellationToken).ConfigureAwait(false);
            } finally {
                _sendLock.Release();
            }
        }

        private static async Task CloseProxyWebSocketSessionAsync(ProxyWebSocketSession session) {
            try { session.CancellationSource.Cancel(); } catch { }
            try {
                if (session.Socket.State == WebSocketState.Open || session.Socket.State == WebSocketState.CloseReceived)
                    await session.Socket.CloseAsync(WebSocketCloseStatus.NormalClosure, "proxy closed", CancellationToken.None).ConfigureAwait(false);
            } catch {
                try { session.Socket.Abort(); } catch { }
            }
            try { session.Socket.Dispose(); } catch { }
            try { session.SendLock.Dispose(); } catch { }
            try { session.CancellationSource.Dispose(); } catch { }
        }

        private static int GetShellProxyResponseBufferSize(string contentType, string path) {
            return IsLowLatencyShellProxyResponse(contentType, path) ? 2048 : 16 * 1024;
        }

        private static bool IsLowLatencyShellProxyResponse(string contentType, string path) {
            string normalizedPath = (path ?? "").Split('?')[0].TrimEnd('/');
            if (normalizedPath.Equals("/api/chat-stream", StringComparison.OrdinalIgnoreCase) ||
                normalizedPath.Equals("/api/llm-client/chat-stream", StringComparison.OrdinalIgnoreCase) ||
                normalizedPath.Equals("/api/web-chat/ws", StringComparison.OrdinalIgnoreCase)) {
                return true;
            }
            string normalizedContentType = contentType ?? "";
            return normalizedContentType.IndexOf("text/event-stream", StringComparison.OrdinalIgnoreCase) >= 0 ||
                   normalizedContentType.IndexOf("application/x-ndjson", StringComparison.OrdinalIgnoreCase) >= 0 ||
                   normalizedContentType.IndexOf("application/json-seq", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private static async Task<LocalProxyResponse> SendLocalProxyRequestAsync(string method, string uriText, Dictionary<string, string> headers, byte[] body, CancellationToken cancellationToken) {
#pragma warning disable SYSLIB0014
            var request = (HttpWebRequest)WebRequest.Create(uriText);
#pragma warning restore SYSLIB0014
            request.Method = string.IsNullOrWhiteSpace(method) ? "GET" : method;
            request.AllowAutoRedirect = false;
            request.KeepAlive = false;
            request.ProtocolVersion = HttpVersion.Version11;
            request.Timeout = Timeout.Infinite;
            request.ReadWriteTimeout = Timeout.Infinite;
            request.AutomaticDecompression = DecompressionMethods.None;
            request.SendChunked = false;

            if (headers != null) {
                foreach (KeyValuePair<string, string> header in headers) {
                    string name = header.Key ?? "";
                    string value = header.Value ?? "";
                    if (ShouldSkipTunnelForwardHeader(name))
                        continue;
                    if (name.Equals("Accept", StringComparison.OrdinalIgnoreCase)) {
                        request.Accept = value;
                    } else if (name.Equals("User-Agent", StringComparison.OrdinalIgnoreCase)) {
                        request.UserAgent = value;
                    } else if (name.Equals("Referer", StringComparison.OrdinalIgnoreCase) || name.Equals("Referrer", StringComparison.OrdinalIgnoreCase)) {
                        request.Referer = value;
                    } else if (name.Equals("Content-Type", StringComparison.OrdinalIgnoreCase)) {
                        request.ContentType = value;
                    } else {
                        try { request.Headers[name] = value; } catch { }
                    }
                }
            }

            if (body != null && body.Length > 0) {
                if (string.IsNullOrWhiteSpace(request.ContentType))
                    request.ContentType = "application/octet-stream";
                request.ContentLength = body.Length;
                using CancellationTokenRegistration registration = cancellationToken.Register(() => {
                    try { request.Abort(); } catch { }
                });
                using Stream requestStream = await request.GetRequestStreamAsync().ConfigureAwait(false);
                await requestStream.WriteAsync(body, 0, body.Length, cancellationToken).ConfigureAwait(false);
            } else if (!request.Method.Equals("GET", StringComparison.OrdinalIgnoreCase) &&
                       !request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase)) {
                request.ContentLength = 0;
            }

            WebResponse response;
            try {
                response = await request.GetResponseAsync().ConfigureAwait(false);
            } catch (WebException ex) when (ex.Response != null) {
                response = ex.Response;
            }

            if (response is not HttpWebResponse httpResponse) {
                response.Dispose();
                throw new IOException("Local loopback response was not HTTP.");
            }

            var responseHeaders = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (string? key in httpResponse.Headers.AllKeys) {
                if (!string.IsNullOrWhiteSpace(key))
                    responseHeaders[key] = httpResponse.Headers[key] ?? "";
            }

            Stream responseStream = httpResponse.GetResponseStream() ?? Stream.Null;
            return new LocalProxyResponse(
                httpResponse,
                (int)httpResponse.StatusCode,
                httpResponse.StatusDescription ?? "",
                string.IsNullOrWhiteSpace(httpResponse.ContentType) ? "application/octet-stream" : httpResponse.ContentType,
                responseHeaders,
                responseStream);
        }

        private async Task RunHeartbeatAsync(ClientWebSocket socket, CancellationToken cancellationToken) {
            while (!cancellationToken.IsCancellationRequested && socket.State == WebSocketState.Open) {
                try {
                    await Task.Delay(HeartbeatInterval, cancellationToken).ConfigureAwait(false);
                    await SendJsonAsync(socket, new {
                        type = "heartbeat",
                        relayId = _relayId,
                        sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                    }, cancellationToken).ConfigureAwait(false);
                } catch (OperationCanceledException) {
                    break;
                } catch (Exception ex) {
                    AppendDebugLog("heartbeat failed " + ex.GetType().Name + ": " + ex.Message);
                    try { socket.Abort(); } catch { }
                    break;
                }
            }
        }

        private async Task TrySendErrorAsync(ClientWebSocket socket, string id, int statusCode, string message) {
            try {
                await SendJsonAsync(socket, new {
                    type = "error",
                    id,
                    statusCode,
                    error = message ?? "WebSocket tunnel request failed.",
                    sentUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                }, CancellationToken.None).ConfigureAwait(false);
            } catch {
            }
        }

        private async Task SendJsonAsync(ClientWebSocket socket, object payload, CancellationToken cancellationToken) {
            string json = JsonSerializer.Serialize(payload);
            byte[] bytes = Encoding.UTF8.GetBytes(json);
            await _sendLock.WaitAsync(cancellationToken).ConfigureAwait(false);
            try {
                await socket.SendAsync(new ArraySegment<byte>(bytes), WebSocketMessageType.Text, true, cancellationToken).ConfigureAwait(false);
            } finally {
                _sendLock.Release();
            }
        }

        private async Task SendBinaryChunkAsync(ClientWebSocket socket, string id, byte[] buffer, int count, CancellationToken cancellationToken) {
            byte[] payload = new byte[32 + count];
            byte[] idBytes = Encoding.ASCII.GetBytes((id ?? "").PadRight(32).Substring(0, 32));
            Buffer.BlockCopy(idBytes, 0, payload, 0, 32);
            Buffer.BlockCopy(buffer, 0, payload, 32, count);
            await _sendLock.WaitAsync(cancellationToken).ConfigureAwait(false);
            try {
                await socket.SendAsync(new ArraySegment<byte>(payload), WebSocketMessageType.Binary, true, cancellationToken).ConfigureAwait(false);
            } finally {
                _sendLock.Release();
            }
        }

        private static async Task<WebSocketMessage> ReceiveMessageAsync(ClientWebSocket socket, CancellationToken cancellationToken) {
            byte[] buffer = new byte[64 * 1024];
            using var memory = new MemoryStream();
            WebSocketReceiveResult result;
            do {
                result = await socket.ReceiveAsync(new ArraySegment<byte>(buffer), cancellationToken).ConfigureAwait(false);
                if (result.MessageType == WebSocketMessageType.Close)
                    return new WebSocketMessage(WebSocketMessageType.Close, "", Array.Empty<byte>());
                if (result.Count > 0)
                    memory.Write(buffer, 0, result.Count);
            } while (!result.EndOfMessage);

            byte[] bytes = memory.ToArray();
            string text = result.MessageType == WebSocketMessageType.Text ? Encoding.UTF8.GetString(bytes) : "";
            return new WebSocketMessage(result.MessageType, text, bytes);
        }

        private static bool IsReadyMessageOk(string text, out string error) {
            error = "";
            try {
                using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(text) ? "{}" : text);
                JsonElement root = document.RootElement;
                string type = ReadJsonString(root, "type");
                bool ok = ReadJsonBool(root, "ok", false);
                error = ReadJsonString(root, "error");
                return type.Equals("ready", StringComparison.OrdinalIgnoreCase) && ok;
            } catch (Exception ex) {
                error = ex.Message;
                return false;
            }
        }

        private static string NormalizeShellWebSocketTunnelRole(string value) {
            value = (value ?? "").Trim().ToLowerInvariant();
            if (value.Equals("chat", StringComparison.Ordinal) ||
                value.Equals("browser", StringComparison.Ordinal) ||
                value.Equals("api", StringComparison.Ordinal))
                return value;
            return "api";
        }

        private static bool ShouldSkipTunnelForwardHeader(string name) {
            return string.IsNullOrWhiteSpace(name) ||
                   name.Equals("Host", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Connection", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Content-Length", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Transfer-Encoding", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Keep-Alive", StringComparison.OrdinalIgnoreCase) ||
                   name.Equals("Upgrade", StringComparison.OrdinalIgnoreCase) ||
                   name.StartsWith("Proxy-", StringComparison.OrdinalIgnoreCase);
        }

        private static Dictionary<string, string> ReadJsonObjectStrings(JsonElement root, string name) {
            var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            if (!TryGetJsonProperty(root, name, out JsonElement obj) || obj.ValueKind != JsonValueKind.Object)
                return result;
            foreach (JsonProperty property in obj.EnumerateObject())
                result[property.Name] = property.Value.ValueKind == JsonValueKind.String ? property.Value.GetString() ?? "" : property.Value.ToString();
            return result;
        }

        private static string ReadJsonString(JsonElement root, string name) {
            if (!TryGetJsonProperty(root, name, out JsonElement value))
                return "";
            return value.ValueKind == JsonValueKind.String ? value.GetString() ?? "" : value.ToString();
        }

        private static bool ReadJsonBool(JsonElement root, string name, bool fallback) {
            if (!TryGetJsonProperty(root, name, out JsonElement value))
                return fallback;
            if (value.ValueKind == JsonValueKind.True)
                return true;
            if (value.ValueKind == JsonValueKind.False)
                return false;
            return bool.TryParse(value.ToString(), out bool parsed) ? parsed : fallback;
        }

        private void RaiseStatus(bool connected, bool fallbackRecommended, string message) {
            StatusChanged?.Invoke(this, new ShellTunnelStatusEventArgs(connected, fallbackRecommended, message));
        }

        private static void AppendDebugLog(string message) {
            if (!EnableTunnelDebugLog)
                return;
            try {
                string directory = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "SocketJack", "JackLLM");
                Directory.CreateDirectory(directory);
                string path = Path.Combine(directory, "ShellWebSocketTunnel.log");
                string line = DateTimeOffset.Now.ToString("O", CultureInfo.InvariantCulture) + " " + (message ?? "") + Environment.NewLine;
                lock (DebugLogLock)
                    File.AppendAllText(path, line);
            } catch {
            }
        }

        public void Dispose() {
            if (_disposed)
                return;
            _disposed = true;
            try { _cts?.Cancel(); } catch { }
            foreach (CancellationTokenSource pending in _pending.Values) {
                try { pending.Cancel(); } catch { }
                pending.Dispose();
            }
            _pending.Clear();
            _sendLock.Dispose();
        }

