                CancellationSource = cancellationSource;
            }

            public string Id { get; }
            public ClientWebSocket Socket { get; }
            public CancellationTokenSource CancellationSource { get; }
            public CancellationToken Cancellation => CancellationSource.Token;
            public SemaphoreSlim SendLock { get; } = new(1, 1);
        }

        private readonly record struct WebSocketMessage(WebSocketMessageType Type, string Text, byte[] Bytes);

        private sealed class LocalProxyResponse : IDisposable {
            private readonly HttpWebResponse _response;

            public LocalProxyResponse(HttpWebResponse response, int statusCode, string reasonPhrase, string contentType, Dictionary<string, string> headers, Stream stream) {
                _response = response;
                StatusCode = statusCode;
                ReasonPhrase = reasonPhrase ?? "";
                ContentType = string.IsNullOrWhiteSpace(contentType) ? "application/octet-stream" : contentType;
                Headers = headers ?? new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                Stream = stream ?? Stream.Null;
            }

            public int StatusCode { get; }
            public string ReasonPhrase { get; }
            public string ContentType { get; }
            public Dictionary<string, string> Headers { get; }
            public Stream Stream { get; }

            public void Dispose() {
                try { Stream.Dispose(); } catch { }
                try { _response.Dispose(); } catch { }
            }
        }
    }

    private sealed class ShellRelay : IDisposable {
        private readonly EventHandler<ReverseTcpRelayLogEventArgs> _tcpLogHandler;
        private readonly object _sync = new();
        private readonly List<ShellWebSocketTunnelClient> _additionalWebSocketTunnels = new();
        private bool _disposed;

        public ShellRelay(
            string id,
            string name,
            string masterHost,
            int publicPort,
            int agentPort,
            string targetHost,
            int targetPort,
            int poolSize,
            ReverseTcpRelayClient? client,
            ShellWebSocketTunnelClient? webSocketTunnel,
            EventHandler<ReverseTcpRelayLogEventArgs> tcpLogHandler) {
            Id = id ?? "";
            Name = string.IsNullOrWhiteSpace(name) ? "Relay" : name;
            MasterHost = masterHost ?? "";
            PublicPort = publicPort;
            AgentPort = agentPort;
            TargetHost = targetHost ?? "";
            TargetPort = targetPort;
            PoolSize = Math.Max(1, Math.Min(32, poolSize));
            Client = client;
            WebSocketTunnel = webSocketTunnel;
            _tcpLogHandler = tcpLogHandler;
        }

        public string Id { get; }
        public string Name { get; }
        public string MasterHost { get; }
        public int PublicPort { get; }
        public int AgentPort { get; }
        public string TargetHost { get; }
        public int TargetPort { get; }
        public int PoolSize { get; }
        public ReverseTcpRelayClient? Client { get; private set; }
        public ShellWebSocketTunnelClient? WebSocketTunnel { get; }

        public void AddAdditionalWebSocketTunnel(ShellWebSocketTunnelClient? client) {
            if (client == null)
                return;
            lock (_sync) {
                if (_disposed) {
                    try { client.Dispose(); } catch { }
                    return;
                }
                _additionalWebSocketTunnels.Add(client);
            }
        }

        public void EnsureTcpFallbackStarted() {
            lock (_sync) {
                if (_disposed || Client != null)
                    return;
                var client = new ReverseTcpRelayClient(Id, Name, MasterHost, AgentPort, TargetHost, TargetPort, PoolSize);
                client.Log += _tcpLogHandler;
                client.Start();
                Client = client;
            }
        }

        public void StopTcpFallback() {
            lock (_sync) {
                if (Client == null)
                    return;
                try { Client.Log -= _tcpLogHandler; } catch { }
                try { Client.Dispose(); } catch { }
                Client = null;
            }
        }

        public void Dispose() {
            lock (_sync) {
                _disposed = true;
                try { WebSocketTunnel?.Dispose(); } catch { }
                foreach (ShellWebSocketTunnelClient tunnel in _additionalWebSocketTunnels) {
                    try { tunnel.Dispose(); } catch { }
                }
                _additionalWebSocketTunnels.Clear();
                if (Client != null) {
                    try { Client.Log -= _tcpLogHandler; } catch { }
                    try { Client.Dispose(); } catch { }
                    Client = null;
                }
            }
        }
    }

