            get => _clientStatus;
            set {
                if (_clientStatus == value)
                    return;
                _clientStatus = value ?? "";
                OnChanged(nameof(ClientStatus));
            }
        }

        public string TitleText => (string.IsNullOrWhiteSpace(Name) ? Id : Name) + (Enabled ? " | enabled" : " | disabled");
        public string DetailText => FirstNonEmpty(Endpoint, ProxyPath, "SocketJack public " + PublicPort.ToString(CultureInfo.InvariantCulture)) +
                                    " | reverse JACK agent " + AgentPort.ToString(CultureInfo.InvariantCulture) +
                                    " -> local API " + ChatServerPort.ToString(CultureInfo.InvariantCulture);
        public string RuntimeText => (string.IsNullOrWhiteSpace(Status) ? "Unknown" : Status) +
                                     " | ws " + (WebSocketTunnelConnected ? WebSocketTunnelCount.ToString(CultureInfo.InvariantCulture) : "0") +
                                     " | master agents " + WaitingAgents.ToString(CultureInfo.InvariantCulture) +
                                     " | sessions " + ActiveSessions.ToString(CultureInfo.InvariantCulture);
        public string DebugText => _debugLines.Count == 0
            ? "No debug data for this shell instance yet."
            : string.Join(Environment.NewLine, _debugLines);

        public void AppendDebug(string line) {
            _debugLines.Add(line);
            while (_debugLines.Count > 300)
                _debugLines.RemoveAt(0);
            OnChanged(nameof(DebugText));
        }

        public static ShellRelayItem FromJson(JsonElement element) {
            var item = new ShellRelayItem {
                Id = GetJsonString(element, "id", ""),
                ServerId = GetJsonString(element, "serverId", ""),
                Name = GetJsonString(element, "name", ""),
                RouteName = GetJsonString(element, "routeName", ""),
                ProxyPath = GetJsonString(element, "proxyPath", ""),
                Endpoint = GetJsonString(element, "endpoint", ""),
                PublicPort = (int)GetJsonLong(element, "publicPort", 0),
                AgentPort = (int)GetJsonLong(element, "agentPort", 0),
                TargetHost = FirstNonEmpty(GetJsonString(element, "targetHost", ""), "127.0.0.1"),
                TargetPort = (int)GetJsonLong(element, "targetPort", 0),
                Enabled = GetJsonBool(element, "enabled", false),
                Status = GetJsonString(element, "status", ""),
                LastAgentSeenUtc = GetJsonString(element, "lastAgentSeenUtc", ""),
                ActiveSessions = (int)GetJsonLong(element, "activeSessions", 0),
                WaitingAgents = (int)GetJsonLong(element, "waitingAgents", 0),
                WaitingPublicClients = (int)GetJsonLong(element, "waitingPublicClients", 0),
                TransportMode = FirstNonEmpty(GetJsonString(element, "transportMode", ""), "websocketPreferred"),
                SupportsWebSocketTunnel = GetJsonBool(element, "supportsWebSocketTunnel", false),
                WebSocketTunnelUrl = GetJsonString(element, "webSocketTunnelUrl", ""),
                WebSocketTunnelConnected = GetJsonBool(element, "webSocketTunnelConnected", false),
                WebSocketTunnelCount = (int)GetJsonLong(element, "webSocketTunnelCount", 0),
                FallbackTcpEnabled = GetJsonBool(element, "fallbackTcpEnabled", true)
            };
            if (item.TargetPort <= 0)
                item.TargetPort = item.PublicPort;
            if (TryGetJsonProperty(element, "debugLines", out JsonElement debugLines) && debugLines.ValueKind == JsonValueKind.Array) {
                foreach (JsonElement line in debugLines.EnumerateArray()) {
                    string text = line.ValueKind == JsonValueKind.String ? line.GetString() ?? "" : line.ToString();
                    if (!string.IsNullOrWhiteSpace(text))
                        item.AppendDebug(text);
                }
            }
            return item;
        }

        private void OnChanged(string propertyName) {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }
    }

