        public string ModelId { get; set; } = "";
        public double TokensPerSecond {
            get => _tokensPerSecond;
            private set {
                _tokensPerSecond = value;
                OnChanged(nameof(TokensPerSecond));
                OnChanged(nameof(RatingLine));
                OnChanged(nameof(RatingBrush));
                OnChanged(nameof(RatingForegroundBrush));
                OnChanged(nameof(RowBorderBrush));
            }
        }
        public double TokensPerHour {
            get => _tokensPerHour;
            private set { _tokensPerHour = value; OnChanged(nameof(TokensPerHour)); }
        }
        public int OutputTokens {
            get => _outputTokens;
            private set { _outputTokens = value; OnChanged(nameof(OutputTokens)); }
        }
        public double DurationMs {
            get => _durationMs;
            private set { _durationMs = value; OnChanged(nameof(DurationMs)); }
        }
        public int Rating {
            get => _rating;
            private set {
                _rating = Math.Max(0, Math.Min(100, value));
                OnChanged(nameof(Rating));
                OnChanged(nameof(RatingLine));
                OnChanged(nameof(RatingBrush));
                OnChanged(nameof(RatingForegroundBrush));
                OnChanged(nameof(RowBorderBrush));
            }
        }
        public string BenchmarkedUtc {
            get => _benchmarkedUtc;
            private set { _benchmarkedUtc = value ?? ""; OnChanged(nameof(BenchmarkedUtc)); }
        }
        public string BenchmarkKind {
            get => _benchmarkKind;
            private set {
                _benchmarkKind = value ?? "";
                OnChanged(nameof(BenchmarkKind));
                OnChanged(nameof(DetailLine));
            }
        }
        public string BenchmarkPrompt {
            get => _benchmarkPrompt;
            private set { _benchmarkPrompt = value ?? ""; OnChanged(nameof(BenchmarkPrompt)); }
        }
        public bool SupportsImages {
            get => _supportsImages;
            private set {
                if (_supportsImages == value)
                    return;
                _supportsImages = value;
                OnChanged(nameof(SupportsImages));
            }
        }
        public bool SupportsTools {
            get => _supportsTools;
            private set {
                if (_supportsTools == value)
                    return;
                _supportsTools = value;
                OnChanged(nameof(SupportsTools));
            }
        }
        public bool SupportsImageGeneration {
            get => _supportsImageGeneration;
            private set {
                if (_supportsImageGeneration == value)
                    return;
                _supportsImageGeneration = value;
                OnChanged(nameof(SupportsImageGeneration));
            }
        }
        public bool SupportsAudioGeneration {
            get => _supportsAudioGeneration;
            private set {
                if (_supportsAudioGeneration == value)
                    return;
                _supportsAudioGeneration = value;
                OnChanged(nameof(SupportsAudioGeneration));
            }
        }
        public bool SupportsVideoGeneration {
            get => _supportsVideoGeneration;
            private set {
                if (_supportsVideoGeneration == value)
                    return;
                _supportsVideoGeneration = value;
                OnChanged(nameof(SupportsVideoGeneration));
            }
        }
        public bool RequiresPayment {
            get => _requiresPayment;
            private set {
                if (_requiresPayment == value)
                    return;
                _requiresPayment = value;
                OnChanged(nameof(RequiresPayment));
            }
        }
        public string StripePriceId {
            get => _stripePriceId;
            private set { _stripePriceId = value ?? ""; OnChanged(nameof(StripePriceId)); }
        }
        public string StripeAccount {
            get => _stripeAccount;
            private set { _stripeAccount = value ?? ""; OnChanged(nameof(StripeAccount)); }
        }
        public long StripeUnitAmountCents {
            get => _stripeUnitAmountCents;
            private set { _stripeUnitAmountCents = Math.Max(0L, value); OnChanged(nameof(StripeUnitAmountCents)); }
        }
        public string StripeCurrency {
            get => _stripeCurrency;
            private set { _stripeCurrency = FirstNonEmpty(value, "usd").ToLowerInvariant(); OnChanged(nameof(StripeCurrency)); }
        }
        public string PaymentStatus {
            get => _paymentStatus;
            private set { _paymentStatus = value ?? ""; OnChanged(nameof(PaymentStatus)); }
        }
        public bool CheckoutConfigured {
            get => _checkoutConfigured;
            private set { _checkoutConfigured = value; OnChanged(nameof(CheckoutConfigured)); }
        }
        public string Status {
            get => _status;
            set {
                _status = string.IsNullOrWhiteSpace(value) ? "Not benchmarked" : value;
                OnChanged(nameof(Status));
                OnChanged(nameof(DetailLine));
                OnChanged(nameof(StatusBrush));
                OnChanged(nameof(RowBackgroundBrush));
                OnChanged(nameof(RowBorderBrush));
            }
        }
        public bool IsRunning {
            get => _isRunning;
            private set {
                if (_isRunning == value)
                    return;
                _isRunning = value;
                OnChanged(nameof(IsRunning));
                OnChanged(nameof(StatusBrush));
                OnChanged(nameof(RowBackgroundBrush));
                OnChanged(nameof(RowBorderBrush));
            }
        }
        public bool CanBenchmark {
            get => _canBenchmark;
            set {
                if (_canBenchmark == value)
                    return;
                _canBenchmark = value;
                OnChanged(nameof(CanBenchmark));
            }
        }
        public string RatingLine => TokensPerSecond > 0 ? Rating.ToString(CultureInfo.InvariantCulture) + "/100" : "--/100";
        public Brush RatingBrush {
            get {
                if (TokensPerSecond <= 0)
                    return new SolidColorBrush(Color.FromRgb(78, 94, 116));

                byte red = (byte)Math.Round(229 * (100 - Rating) / 100.0);
                byte green = (byte)Math.Round(72 + (154 * Rating / 100.0));
                byte blue = (byte)Math.Round(72 - (38 * Rating / 100.0));
                return new SolidColorBrush(Color.FromRgb(red, green, blue));
            }
        }
        public Brush RatingForegroundBrush => TokensPerSecond > 0 && Rating >= 45
            ? new SolidColorBrush(Color.FromRgb(5, 16, 22))
            : new SolidColorBrush(Color.FromRgb(244, 251, 255));
        public Brush StatusBrush {
            get {
                if (IsRunning)
                    return new SolidColorBrush(Color.FromRgb(89, 214, 201));
                if (Status.StartsWith("Benchmark failed", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(255, 92, 122));
                if (Status.StartsWith("Canceled", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(255, 179, 90));
                if (TokensPerSecond > 0)
                    return new SolidColorBrush(Color.FromRgb(123, 231, 186));
                if (Status.Equals("Queued", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(159, 177, 200));
                return new SolidColorBrush(Color.FromRgb(159, 177, 200));
            }
        }
        public Brush RowBackgroundBrush => IsRunning
            ? new SolidColorBrush(Color.FromArgb(150, 22, 70, 72))
            : new SolidColorBrush(Color.FromArgb(136, 17, 25, 36));
        public Brush RowBorderBrush {
            get {
                if (IsRunning)
                    return new SolidColorBrush(Color.FromRgb(89, 214, 201));
                if (Status.StartsWith("Benchmark failed", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(255, 92, 122));
                if (TokensPerSecond > 0)
                    return RatingBrush;
                return new SolidColorBrush(Color.FromRgb(51, 78, 94));
            }
        }
        public string DetailLine => TokensPerSecond > 0
            ? FormatBenchmarkRate(BenchmarkKind, TokensPerSecond, TokensPerHour) + " | " +
              OutputTokens.ToString(CultureInfo.InvariantCulture) + (IsMediaBenchmark ? " output in " : " tokens in ") +
              (DurationMs / 1000d).ToString("0.00", CultureInfo.InvariantCulture) + "s"
            : Status;
        private bool IsMediaBenchmark => BenchmarkKind.Equals("image", StringComparison.OrdinalIgnoreCase) ||
                                         BenchmarkKind.Equals("audio", StringComparison.OrdinalIgnoreCase) ||
                                         BenchmarkKind.Equals("video", StringComparison.OrdinalIgnoreCase);

        public void BeginBenchmark(string status) {
            IsRunning = true;
            Status = status;
        }

        public void Apply(ModelBenchmarkResult result) {
            TokensPerSecond = Math.Max(0, result.TokensPerSecond);
            TokensPerHour = Math.Max(0, result.TokensPerHour);
            OutputTokens = Math.Max(0, result.OutputTokens);
            DurationMs = Math.Max(0, result.DurationMs);
            Rating = result.Rating;
            BenchmarkedUtc = result.BenchmarkedUtc;
            BenchmarkKind = result.BenchmarkKind;
            BenchmarkPrompt = result.BenchmarkPrompt;
            SupportsImages = SupportsImages || result.SupportsImages || ModelNameLikelySupportsImages(result.ModelId);
            SupportsTools = SupportsTools || result.SupportsTools || ModelNameLikelySupportsTools(result.ModelId);
            SupportsImageGeneration = SupportsImageGeneration || result.SupportsImageGeneration || ModelNameLikelySupportsImageGeneration(result.ModelId);
            SupportsAudioGeneration = SupportsAudioGeneration || result.SupportsAudioGeneration || ModelNameLikelySupportsAudioGeneration(result.ModelId);
            SupportsVideoGeneration = SupportsVideoGeneration || result.SupportsVideoGeneration || ModelNameLikelySupportsVideoGeneration(result.ModelId);
            ApplyPayment(result.RequiresPayment, result.StripePriceId, result.StripeAccount, result.StripeUnitAmountCents, result.StripeCurrency, result.PaymentStatus, result.CheckoutConfigured);
            IsRunning = false;
            Status = "Done: " + FormatBenchmarkRate(BenchmarkKind, TokensPerSecond, TokensPerHour) + ", score " + Rating.ToString(CultureInfo.InvariantCulture) + "/100";
            OnChanged(nameof(DetailLine));
            OnChanged(nameof(RatingForegroundBrush));
            OnChanged(nameof(RowBackgroundBrush));
            OnChanged(nameof(RowBorderBrush));
        }

        public void CancelBenchmark() {
            IsRunning = false;
            Status = "Canceled";
        }

        public void FailBenchmark(string status) {
            IsRunning = false;
            Status = status;
        }

        public void ApplyCapabilities(ModelCapabilityInfo capability) {
            if (capability == null)
                return;
            if (string.IsNullOrWhiteSpace(ModelId))
                ModelId = capability.ModelId ?? "";
            SupportsImages = SupportsImages || capability.SupportsImages || ModelNameLikelySupportsImages(ModelId);
            SupportsTools = SupportsTools || capability.SupportsTools || ModelNameLikelySupportsTools(ModelId);
            SupportsImageGeneration = SupportsImageGeneration || capability.SupportsImageGeneration || ModelNameLikelySupportsImageGeneration(ModelId);
            SupportsAudioGeneration = SupportsAudioGeneration || capability.SupportsAudioGeneration || ModelNameLikelySupportsAudioGeneration(ModelId);
            SupportsVideoGeneration = SupportsVideoGeneration || capability.SupportsVideoGeneration || ModelNameLikelySupportsVideoGeneration(ModelId);
            ApplyPayment(capability.RequiresPayment, capability.StripePriceId, capability.StripeAccount, capability.StripeUnitAmountCents, capability.StripeCurrency, capability.PaymentStatus, capability.CheckoutConfigured);
        }

        public ModelBenchmarkResult ToResult() {
            return new ModelBenchmarkResult {
                ModelId = ModelId,
                SupportsImages = SupportsImages,
                SupportsTools = SupportsTools,
                SupportsImageGeneration = SupportsImageGeneration,
                SupportsAudioGeneration = SupportsAudioGeneration,
                SupportsVideoGeneration = SupportsVideoGeneration,
                RequiresPayment = RequiresPayment,
                StripePriceId = StripePriceId,
                StripeAccount = StripeAccount,
                StripeUnitAmountCents = StripeUnitAmountCents,
                StripeCurrency = StripeCurrency,
                PaymentStatus = PaymentStatus,
                CheckoutConfigured = CheckoutConfigured,
                TokensPerSecond = TokensPerSecond,
                TokensPerHour = TokensPerHour,
                OutputTokens = OutputTokens,
                DurationMs = DurationMs,
                Rating = Rating,
                BenchmarkedUtc = BenchmarkedUtc,
                BenchmarkKind = BenchmarkKind,
                BenchmarkPrompt = BenchmarkPrompt
            };
        }

        private void ApplyPayment(bool requiresPayment, string stripePriceId, string stripeAccount, long unitAmountCents, string stripeCurrency, string paymentStatus, bool checkoutConfigured) {
            RequiresPayment = RequiresPayment || requiresPayment;
            StripePriceId = FirstNonEmpty(StripePriceId, stripePriceId);
            StripeAccount = FirstNonEmpty(StripeAccount, stripeAccount);
            if (StripeUnitAmountCents <= 0)
                StripeUnitAmountCents = unitAmountCents;
            StripeCurrency = FirstNonEmpty(StripeCurrency, stripeCurrency, "usd");
            PaymentStatus = FirstNonEmpty(PaymentStatus, paymentStatus);
            CheckoutConfigured = CheckoutConfigured || checkoutConfigured || !string.IsNullOrWhiteSpace(StripePriceId) || StripeUnitAmountCents > 0;
        }

        private void OnChanged(string propertyName) {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }
    }

    private sealed class ServerBrowserEntry {
        public string Id { get; set; } = "";
        public string OwnerUserName { get; set; } = "";
        public string DisplayName { get; set; } = "";
        public string Endpoint { get; set; } = "";
        public string ConnectHost { get; set; } = "";
        public int ProxyPort { get; set; } = ServerPort;
        public int ChatPort { get; set; } = ChatServerPort;
        public int LmStudioPort { get; set; } = LocalLmStudioProxyPort;
        public int FtpPort { get; set; } = FtpServerPort;
        public double CostFactor { get; set; } = 1;
        public string GpuName { get; set; } = "";
        public string GpuAvailable { get; set; } = "";
        public string CpuName { get; set; } = "";
        public string CpuAvailable { get; set; } = "";
        public string RamAvailable { get; set; } = "";
        public string StorageAvailable { get; set; } = "";
        public long StorageLimitMegabytes { get; set; } = DefaultHostStorageLimitMegabytes;
        public string AvailableResources { get; set; } = "";
        public string AvailableModels { get; set; } = "";
        public string ToolsAllowed { get; set; } = "";
        public string AvailableVram { get; set; } = "";
        public long MaxTokens { get; set; }
        public string ModelCapabilitiesJson { get; set; } = "";
        public string ModelBenchmarksJson { get; set; } = "";
        public bool RequiresPayment { get; set; }
        public string StripePriceId { get; set; } = "";
        public string StripeAccount { get; set; } = "";
        public long StripeUnitAmountCents { get; set; }
        public string StripeCurrency { get; set; } = "usd";
        public string PaymentStatus { get; set; } = "";
        public string LeaseStatus { get; set; } = "";
        public string LeaseId { get; set; } = "";
        public string LeaseExpiresUtc { get; set; } = "";
        public double HealthScore { get; set; }
        public string HealthTier { get; set; } = "";
        public string TrustTier { get; set; } = "";
        public bool HostSuspended { get; set; }
        public string StartedUtc { get; set; } = "";
        public long UptimeSeconds { get; set; }
        public string UpdatedUtc { get; set; } = "";
        public string LastStatus { get; set; } = "";
        public bool PublishEnabled { get; set; } = true;
        public bool IsOnline { get; set; } = true;
        public bool FromMasterList { get; set; }
        public bool IsLocalHost { get; set; }

        public void Normalize() {
            Id = NormalizeText(Id);
            OwnerUserName = NormalizeText(OwnerUserName);
            DisplayName = NormalizeText(DisplayName);
            ConnectHost = NormalizeText(ConnectHost);
            Endpoint = NormalizeText(Endpoint);
            GpuName = NormalizeText(GpuName);
            GpuAvailable = NormalizeText(GpuAvailable);
            CpuName = NormalizeText(CpuName);
            CpuAvailable = NormalizeText(CpuAvailable);
            RamAvailable = NormalizeText(RamAvailable);
            StorageAvailable = NormalizeText(StorageAvailable);
            StorageLimitMegabytes = MainWindow.ClampHostStorageLimitMegabytes(StorageLimitMegabytes);
            AvailableResources = NormalizeText(AvailableResources);
            AvailableModels = NormalizeText(AvailableModels);
            ToolsAllowed = NormalizeText(ToolsAllowed);
            AvailableVram = NormalizeText(AvailableVram);
            ModelCapabilitiesJson = NormalizeText(ModelCapabilitiesJson);
            ModelBenchmarksJson = NormalizeText(ModelBenchmarksJson);
            if (MaxTokens < 0)
                MaxTokens = 0;
            StripePriceId = NormalizeText(StripePriceId);
            StripeAccount = NormalizeText(StripeAccount);
            StripeCurrency = string.IsNullOrWhiteSpace(StripeCurrency) ? "usd" : StripeCurrency.Trim().ToLowerInvariant();
            PaymentStatus = NormalizeText(PaymentStatus);
            LeaseStatus = NormalizeText(LeaseStatus);
            LeaseId = NormalizeText(LeaseId);
            LeaseExpiresUtc = NormalizeText(LeaseExpiresUtc);
            HealthTier = NormalizeText(HealthTier);
            TrustTier = NormalizeText(TrustTier);
            if (HealthScore < 0)
                HealthScore = 0;
            if (HealthScore > 100)
                HealthScore = 100;
            StartedUtc = NormalizeText(StartedUtc);
            if (UptimeSeconds < 0)
                UptimeSeconds = 0;
            LastStatus = NormalizeText(LastStatus);
            if (HostSuspended && LastStatus.IndexOf("suspended", StringComparison.OrdinalIgnoreCase) < 0)
                LastStatus = string.IsNullOrWhiteSpace(LastStatus) ? "Suspended" : LastStatus + " | Suspended";
            if (MainWindow.IsServerBrowserOfflineStatus(LastStatus) || HostSuspended)
                IsOnline = false;
            if (string.IsNullOrWhiteSpace(ConnectHost))
                ConnectHost = NormalizeServerBrowserHost(Endpoint);
            if (string.IsNullOrWhiteSpace(DisplayName))
                DisplayName = string.IsNullOrWhiteSpace(ConnectHost) ? "JACK Host" : ConnectHost;
            if (ChatPort <= 0 || ChatPort > 65535)
                ChatPort = ChatServerPort;
            if (ProxyPort <= 0 || ProxyPort > 65535)
                ProxyPort = ServerPort;
            if (LmStudioPort <= 0 || LmStudioPort > 65535)
                LmStudioPort = LocalLmStudioProxyPort;
            if (FtpPort <= 0 || FtpPort > 65535)
                FtpPort = FtpServerPort;
            if (string.IsNullOrWhiteSpace(Endpoint) && !string.IsNullOrWhiteSpace(ConnectHost))
                Endpoint = BuildServerBrowserEndpoint(ConnectHost, ChatPort);
            CostFactor = MainWindow.ClampServerCostFactor(CostFactor);
            if (StripeUnitAmountCents < 0)
                StripeUnitAmountCents = 0;
            if (string.IsNullOrWhiteSpace(UpdatedUtc))
                UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
        }

        public ServerBrowserEntry Clone() {
            return new ServerBrowserEntry {
                Id = Id,
                OwnerUserName = OwnerUserName,
                DisplayName = DisplayName,
                Endpoint = Endpoint,
                ConnectHost = ConnectHost,
                ProxyPort = ProxyPort,
                ChatPort = ChatPort,
                LmStudioPort = LmStudioPort,
                FtpPort = FtpPort,
                CostFactor = CostFactor,
                GpuName = GpuName,
                GpuAvailable = GpuAvailable,
                CpuName = CpuName,
                CpuAvailable = CpuAvailable,
                RamAvailable = RamAvailable,
                StorageAvailable = StorageAvailable,
                StorageLimitMegabytes = StorageLimitMegabytes,
                AvailableResources = AvailableResources,
                AvailableModels = AvailableModels,
                ToolsAllowed = ToolsAllowed,
                AvailableVram = AvailableVram,
                MaxTokens = MaxTokens,
                ModelCapabilitiesJson = ModelCapabilitiesJson,
                ModelBenchmarksJson = ModelBenchmarksJson,
                RequiresPayment = RequiresPayment,
                StripePriceId = StripePriceId,
                StripeAccount = StripeAccount,
                StripeUnitAmountCents = StripeUnitAmountCents,
                StripeCurrency = StripeCurrency,
                PaymentStatus = PaymentStatus,
                LeaseStatus = LeaseStatus,
                LeaseId = LeaseId,
                LeaseExpiresUtc = LeaseExpiresUtc,
                HealthScore = HealthScore,
                HealthTier = HealthTier,
                TrustTier = TrustTier,
                HostSuspended = HostSuspended,
                StartedUtc = StartedUtc,
                UptimeSeconds = UptimeSeconds,
                UpdatedUtc = UpdatedUtc,
                LastStatus = LastStatus,
                PublishEnabled = PublishEnabled,
                IsOnline = IsOnline,
                FromMasterList = FromMasterList,
                IsLocalHost = IsLocalHost
            };
        }

        private static string NormalizeText(string value) {
            return (value ?? "").Trim();
        }
    }

    private sealed class ServerBrowserItem : INotifyPropertyChanged {
        private ServerBrowserEntry _entry;
        private bool _optionsExpanded;

        public ServerBrowserItem(ServerBrowserEntry entry) {
            _entry = (entry ?? new ServerBrowserEntry()).Clone();
            _entry.Normalize();
        }

        public event PropertyChangedEventHandler? PropertyChanged;

        public string DisplayName => _entry.DisplayName;
        public string NameLine => _entry.DisplayName + " | cost x" + _entry.CostFactor.ToString("0.###", CultureInfo.InvariantCulture);
        public string EndpointLine => _entry.Endpoint + " | VS " + _entry.ProxyPort + " | Chat " + _entry.ChatPort + " | LM " + _entry.LmStudioPort;
        public string ModelCountLine => CountModels(_entry).ToString(CultureInfo.InvariantCulture) + " models";
        public string ToolsSupportLine => HasToolSupport(_entry) ? "tools yes" : "tools no";
        public string ImageSupportLine => HasImageSupport(_entry) ? "images yes" : "images no";
        public string TokenCostLine {
            get {
                string tokens = _entry.MaxTokens > 0
                    ? _entry.MaxTokens.ToString("N0", CultureInfo.CurrentCulture) + " tok"
                    : "tokens ?";
                return "cost x" + _entry.CostFactor.ToString("0.###", CultureInfo.InvariantCulture) + " | " + tokens;
            }
        }
        public string OwnerLine => string.IsNullOrWhiteSpace(_entry.OwnerUserName) ? "SocketJack account required" : "Owner " + _entry.OwnerUserName;
        public string StatusLine {
            get {
                string status = (_entry.IsOnline ? "Online" : "Offline") + (string.IsNullOrWhiteSpace(_entry.LastStatus) ? "" : " | " + _entry.LastStatus);
                if (!string.IsNullOrWhiteSpace(_entry.HealthTier))
                    status += " | " + _entry.HealthTier + (_entry.HealthScore > 0 ? " " + _entry.HealthScore.ToString("0", CultureInfo.InvariantCulture) + "/100" : "");
                if (_entry.HostSuspended)
                    status += " | Suspended";
                return status;
            }
        }
        public string UptimeLine {
            get {
                long seconds = _entry.UptimeSeconds;
                if (seconds <= 0 &&
                    DateTimeOffset.TryParse(_entry.StartedUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset started))
                    seconds = Math.Max(0, (long)Math.Floor((DateTimeOffset.UtcNow - started.ToUniversalTime()).TotalSeconds));
                return seconds > 0 ? "Uptime " + FormatUptime(seconds) : "Uptime pending";
            }
        }
        public string TopModelLine {
            get {
                string model = GetTopModelName(_entry);
                return string.IsNullOrWhiteSpace(model) ? "Top model unknown" : "Top: " + model;
            }
        }
        public string CompactResourceLine {
            get {
                var parts = new List<string>();
                if (!string.IsNullOrWhiteSpace(_entry.GpuName))
                    parts.Add("GPU " + TrimForDisplay(_entry.GpuName, 28));
                if (!string.IsNullOrWhiteSpace(_entry.AvailableVram))
                    parts.Add("VRAM " + TrimForDisplay(_entry.AvailableVram, 18));
                else if (!string.IsNullOrWhiteSpace(_entry.GpuAvailable))
                    parts.Add("GPU use " + TrimForDisplay(_entry.GpuAvailable, 18));
                if (!string.IsNullOrWhiteSpace(_entry.RamAvailable))
                    parts.Add("RAM " + TrimForDisplay(_entry.RamAvailable, 18));
                if (!string.IsNullOrWhiteSpace(_entry.StorageAvailable))
                    parts.Add("Storage " + TrimForDisplay(_entry.StorageAvailable, 18));
                return parts.Count == 0 ? "Resources minimized" : string.Join(" | ", parts.Take(4));
            }
        }
        public string InformationLine {
            get {
                var parts = new List<string> {
                    StatusLine,
                    ResourceLine,
                    ModelLine,
                    LeaseLine,
                    UptimeLine
                };
                string trust = string.IsNullOrWhiteSpace(_entry.TrustTier) ? "" : "Trust " + _entry.TrustTier;
                if (!string.IsNullOrWhiteSpace(trust))
                    parts.Add(trust);
                return string.Join(" | ", parts.Where(part => !string.IsNullOrWhiteSpace(part)));
            }
        }
        public string ModelLine {
            get {
                string models = string.IsNullOrWhiteSpace(_entry.AvailableModels) ? "Unknown" : _entry.AvailableModels;
                string tools = string.IsNullOrWhiteSpace(_entry.ToolsAllowed) ? "Unknown" : _entry.ToolsAllowed;
                return "Models: " + models + " | Tools: " + tools;
            }
        }
        public string ResourceLine {
            get {
                string gpu = string.IsNullOrWhiteSpace(_entry.GpuName) ? "GPU n/a" : "GPU " + _entry.GpuName;
                if (!string.IsNullOrWhiteSpace(_entry.GpuAvailable))
                    gpu += " (" + _entry.GpuAvailable + ")";
                string cpu = string.IsNullOrWhiteSpace(_entry.CpuName) ? "CPU n/a" : "CPU " + _entry.CpuName;
                if (!string.IsNullOrWhiteSpace(_entry.CpuAvailable))
                    cpu += " (" + _entry.CpuAvailable + ")";
                string ram = string.IsNullOrWhiteSpace(_entry.RamAvailable) ? "" : " | RAM " + _entry.RamAvailable;
                string storage = string.IsNullOrWhiteSpace(_entry.StorageAvailable) ? "" : " | Storage " + _entry.StorageAvailable;
                string sessionStorage = " | Session " + FormatStorageLimitMegabytes(_entry.StorageLimitMegabytes);
                return gpu + " | " + cpu + ram + storage + sessionStorage;
            }
        }
        public string PaymentLine {
            get {
                string payment = _entry.RequiresPayment ? "Stripe required" : "No payment required";
                if (!string.IsNullOrWhiteSpace(_entry.StripePriceId))
                    payment += " | " + _entry.StripePriceId;
                else if (_entry.StripeUnitAmountCents > 0)
                    payment += " | " + (_entry.StripeUnitAmountCents / 100.0).ToString("C", CultureInfo.CurrentCulture);
                if (!string.IsNullOrWhiteSpace(_entry.PaymentStatus))
                    payment += " | " + _entry.PaymentStatus;
                if (!string.IsNullOrWhiteSpace(_entry.LastStatus))
                    payment += " | " + _entry.LastStatus;
                payment += _entry.PublishEnabled ? " | Publish enabled" : " | Publish disabled";
                return payment;
            }
        }
        public string LeaseLine {
            get {
                if (!_entry.RequiresPayment)
                    return string.IsNullOrWhiteSpace(_entry.LeaseStatus) ? "Free lease" : "Free | " + _entry.LeaseStatus;

                string price = _entry.StripeUnitAmountCents > 0
                    ? (_entry.StripeUnitAmountCents / 100.0).ToString("C", CultureInfo.CurrentCulture)
                    : "price pending";
                string checkout = ServerHasCheckoutConfigured(_entry) ? "checkout ready" : "needs setup";
                string status = string.IsNullOrWhiteSpace(_entry.LeaseStatus) ? "pending lease" : _entry.LeaseStatus;
                return price + " | " + checkout + " | " + status;
            }
        }
        public Brush StatusBrush => _entry.IsOnline ? (_entry.RequiresPayment ? Brushes.Gold : Brushes.LimeGreen) : Brushes.SlateGray;
        public Visibility OptionsVisibility => _optionsExpanded ? Visibility.Visible : Visibility.Collapsed;
        public bool OptionsExpanded {
            get => _optionsExpanded;
            set {
                if (_optionsExpanded == value)
                    return;

                _optionsExpanded = value;
                OnPropertyChanged(nameof(OptionsExpanded));
                OnPropertyChanged(nameof(OptionsVisibility));
            }
        }
        public bool PublishEnabled {
            get => _entry.PublishEnabled;
            set {
                if (_entry.PublishEnabled == value)
                    return;

                _entry.PublishEnabled = value;
                RaiseAllPropertiesChanged();
            }
        }
        public bool IsLocalHost => _entry.IsLocalHost;

        public override string ToString() {
            return string.IsNullOrWhiteSpace(DisplayName) ? "JACK Host" : DisplayName;
        }

        public bool Matches(ServerBrowserEntry entry) {
            if (entry == null)
                return false;
            return string.Equals(BuildServerBrowserEntryKey(_entry), BuildServerBrowserEntryKey(entry), StringComparison.OrdinalIgnoreCase);
        }

        public void UpdateFrom(ServerBrowserEntry entry) {
            if (entry == null)
                return;

            bool publishEnabled = entry.IsLocalHost ? entry.PublishEnabled : _entry.PublishEnabled;
            bool isLocalHost = _entry.IsLocalHost || entry.IsLocalHost;
            _entry = entry.Clone();
            _entry.Normalize();
            _entry.PublishEnabled = publishEnabled;
            _entry.IsLocalHost = isLocalHost;
            RaiseAllPropertiesChanged();
        }

        public ServerBrowserEntry ToEntry() {
            return _entry.Clone();
        }

        private static string FormatUptime(long totalSeconds) {
            if (totalSeconds <= 0)
                return "0s";

            TimeSpan span = TimeSpan.FromSeconds(totalSeconds);
            if (span.TotalDays >= 1)
                return ((int)span.TotalDays).ToString(CultureInfo.InvariantCulture) + "d " + span.Hours.ToString(CultureInfo.InvariantCulture) + "h";
            if (span.TotalHours >= 1)
                return ((int)span.TotalHours).ToString(CultureInfo.InvariantCulture) + "h " + span.Minutes.ToString(CultureInfo.InvariantCulture) + "m";
            if (span.TotalMinutes >= 1)
                return ((int)span.TotalMinutes).ToString(CultureInfo.InvariantCulture) + "m " + span.Seconds.ToString(CultureInfo.InvariantCulture) + "s";
            return span.Seconds.ToString(CultureInfo.InvariantCulture) + "s";
        }

        private void RaiseAllPropertiesChanged() {
            OnPropertyChanged(nameof(DisplayName));
            OnPropertyChanged(nameof(NameLine));
            OnPropertyChanged(nameof(EndpointLine));
            OnPropertyChanged(nameof(ModelCountLine));
            OnPropertyChanged(nameof(ToolsSupportLine));
            OnPropertyChanged(nameof(ImageSupportLine));
            OnPropertyChanged(nameof(TokenCostLine));
            OnPropertyChanged(nameof(OwnerLine));
            OnPropertyChanged(nameof(StatusLine));
            OnPropertyChanged(nameof(UptimeLine));
            OnPropertyChanged(nameof(TopModelLine));
            OnPropertyChanged(nameof(CompactResourceLine));
            OnPropertyChanged(nameof(InformationLine));
            OnPropertyChanged(nameof(ModelLine));
            OnPropertyChanged(nameof(ResourceLine));
            OnPropertyChanged(nameof(PaymentLine));
            OnPropertyChanged(nameof(LeaseLine));
            OnPropertyChanged(nameof(StatusBrush));
            OnPropertyChanged(nameof(PublishEnabled));
        }

        private static int CountModels(ServerBrowserEntry entry) {
            return SplitModelNames(entry).Count;
        }

        private static IReadOnlyList<string> SplitModelNames(ServerBrowserEntry entry) {
            var names = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (string part in (entry.AvailableModels ?? "").Split(new[] { ',', ';', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)) {
                string name = part.Trim();
                if (!string.IsNullOrWhiteSpace(name))
                    names[name] = name;
            }

            foreach (ModelBenchmarkSummary benchmark in ReadBenchmarkSummaries(entry)) {
                if (!string.IsNullOrWhiteSpace(benchmark.ModelName))
                    names[benchmark.ModelName] = benchmark.ModelName;
            }
            foreach (ModelCapabilitySummary capability in ReadCapabilitySummaries(entry)) {
                if (!string.IsNullOrWhiteSpace(capability.ModelName))
                    names[capability.ModelName] = capability.ModelName;
            }

            return names.Values.ToList();
        }

        private static string GetTopModelName(ServerBrowserEntry entry) {
            ModelBenchmarkSummary best = ReadBenchmarkSummaries(entry)
                .OrderByDescending(item => item.Rating)
                .FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(best.ModelName))
                return best.Rating > 0
                    ? best.ModelName + " (" + best.Rating.ToString(CultureInfo.InvariantCulture) + "/100)"
                    : best.ModelName;

            return SplitModelNames(entry).FirstOrDefault() ?? "";
        }

        private static bool HasToolSupport(ServerBrowserEntry entry) {
            string tools = (entry.ToolsAllowed ?? "").Trim();
            if (!string.IsNullOrWhiteSpace(tools) && !IsNoneLike(tools))
                return true;
            if (ReadCapabilitySummaries(entry).Any(capability => capability.SupportsTools))
                return true;

            return SplitModelNames(entry).Any(name =>
                name.IndexOf("tool", StringComparison.OrdinalIgnoreCase) >= 0 ||
                name.IndexOf("function", StringComparison.OrdinalIgnoreCase) >= 0);
        }

        private static bool HasImageSupport(ServerBrowserEntry entry) {
            foreach (ModelBenchmarkSummary benchmark in ReadBenchmarkSummaries(entry)) {
                if (benchmark.SupportsImages)
                    return true;
            }
            foreach (ModelCapabilitySummary capability in ReadCapabilitySummaries(entry)) {
                if (capability.SupportsImages)
                    return true;
            }

            return SplitModelNames(entry).Any(name =>
                name.IndexOf("vision", StringComparison.OrdinalIgnoreCase) >= 0 ||
                name.IndexOf("image", StringComparison.OrdinalIgnoreCase) >= 0 ||
                name.IndexOf("visual", StringComparison.OrdinalIgnoreCase) >= 0 ||
                name.IndexOf("multimodal", StringComparison.OrdinalIgnoreCase) >= 0 ||
                name.IndexOf("llava", StringComparison.OrdinalIgnoreCase) >= 0 ||
                name.IndexOf("pixtral", StringComparison.OrdinalIgnoreCase) >= 0 ||
                name.IndexOf("moondream", StringComparison.OrdinalIgnoreCase) >= 0);
        }

        private static bool IsNoneLike(string value) {
            value = (value ?? "").Trim();
            return value.Length == 0 ||
                   value.Equals("none", StringComparison.OrdinalIgnoreCase) ||
                   value.Equals("unknown", StringComparison.OrdinalIgnoreCase) ||
                   value.Equals("n/a", StringComparison.OrdinalIgnoreCase) ||
                   value.Equals("false", StringComparison.OrdinalIgnoreCase);
        }

        private static IReadOnlyList<ModelBenchmarkSummary> ReadBenchmarkSummaries(ServerBrowserEntry entry) {
            var summaries = new List<ModelBenchmarkSummary>();
            string raw = entry.ModelBenchmarksJson ?? "";
            if (string.IsNullOrWhiteSpace(raw))
                return summaries;

            try {
                using JsonDocument document = JsonDocument.Parse(raw);
                if (document.RootElement.ValueKind != JsonValueKind.Array)
                    return summaries;

                foreach (JsonElement element in document.RootElement.EnumerateArray()) {
                    string modelName = FirstNonEmpty(
                        GetJsonString(element, "modelId", ""),
                        GetJsonString(element, "ModelId", ""),
                        GetJsonString(element, "model", ""),
                        GetJsonString(element, "Model", ""));
                    summaries.Add(new ModelBenchmarkSummary(
                        modelName,
                        (int)GetJsonLong(element, "rating", GetJsonLong(element, "Rating", 0)),
                        GetJsonBool(element, "supportsImages", false) ||
                        GetJsonBool(element, "SupportsImages", false) ||
                        GetJsonBool(element, "supportsVision", false) ||
                        GetJsonBool(element, "SupportsVision", false) ||
                        GetJsonBool(element, "multimodal", false) ||
                        GetJsonBool(element, "Multimodal", false)));
                }
            } catch {
            }

            return summaries;
        }

        private static IReadOnlyList<ModelCapabilitySummary> ReadCapabilitySummaries(ServerBrowserEntry entry) {
            var summaries = new List<ModelCapabilitySummary>();
            string raw = entry.ModelCapabilitiesJson ?? "";
            if (string.IsNullOrWhiteSpace(raw))
                return summaries;

            try {
                using JsonDocument document = JsonDocument.Parse(raw);
                if (document.RootElement.ValueKind != JsonValueKind.Array)
                    return summaries;

                foreach (JsonElement element in document.RootElement.EnumerateArray()) {
                    string modelName = FirstNonEmpty(
                        GetJsonString(element, "modelId", ""),
                        GetJsonString(element, "ModelId", ""),
                        GetJsonString(element, "id", ""),
                        GetJsonString(element, "model", ""),
                        GetJsonString(element, "Model", ""));
                    summaries.Add(new ModelCapabilitySummary(
                        modelName,
                        GetJsonBool(element, "supportsImages", false) ||
                        GetJsonBool(element, "SupportsImages", false) ||
                        GetJsonBool(element, "supportsVision", false) ||
                        GetJsonBool(element, "SupportsVision", false) ||
                        GetJsonBool(element, "multimodal", false) ||
                        GetJsonBool(element, "Multimodal", false),
                        GetJsonBool(element, "supportsTools", false) ||
                        GetJsonBool(element, "SupportsTools", false) ||
                        GetJsonBool(element, "toolUse", false) ||
                        GetJsonBool(element, "ToolUse", false) ||
                        GetJsonBool(element, "functionCalling", false) ||
                        GetJsonBool(element, "FunctionCalling", false)));
                }
            } catch {
            }

            return summaries;
        }

        private readonly struct ModelBenchmarkSummary {
            public ModelBenchmarkSummary(string modelName, int rating, bool supportsImages) {
                ModelName = modelName ?? "";
                Rating = Math.Max(0, Math.Min(100, rating));
                SupportsImages = supportsImages;
            }

            public string ModelName { get; }
            public int Rating { get; }
            public bool SupportsImages { get; }
        }

        private readonly struct ModelCapabilitySummary {
            public ModelCapabilitySummary(string modelName, bool supportsImages, bool supportsTools) {
                ModelName = modelName ?? "";
                SupportsImages = supportsImages;
                SupportsTools = supportsTools;
            }

            public string ModelName { get; }
            public bool SupportsImages { get; }
            public bool SupportsTools { get; }
        }

        private void OnPropertyChanged(string name) {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
        }
    }

