    private sealed class RemoteSessionFileCloneItem : INotifyPropertyChanged {
        public RemoteSessionFileCloneItem(RemoteSessionFileCloneSnapshot snapshot) {
            Update(snapshot);
        }

        public event PropertyChangedEventHandler? PropertyChanged;

        public string Id { get; private set; } = "";
        public string RemotePath { get; private set; } = "";
        public string RemoteUrl { get; private set; } = "";
        public string LocalPath { get; private set; } = "";
        public string FileName { get; private set; } = "";
        public string Status { get; private set; } = "";
        public long Bytes { get; private set; }
        public string Sha256 { get; private set; } = "";
        public string UpdatedUtc { get; private set; } = "";
        public string Error { get; private set; } = "";

        public string SizeText => FormatBytes(Bytes);
        public string HashShort => string.IsNullOrWhiteSpace(Sha256) ? "" : Sha256.Length <= 16 ? Sha256 : Sha256.Substring(0, 16);
        public string UpdatedText => FormatTimestamp(UpdatedUtc);
        public bool IsCancelable => Status.Equals("Downloading", StringComparison.OrdinalIgnoreCase) ||
                                    Status.Equals("Queued", StringComparison.OrdinalIgnoreCase) ||
                                    Status.Equals("Canceling", StringComparison.OrdinalIgnoreCase);
        public bool IsTerminal => Status.Equals("Complete", StringComparison.OrdinalIgnoreCase) ||
                                  Status.Equals("Failed", StringComparison.OrdinalIgnoreCase) ||
                                  Status.Equals("Canceled", StringComparison.OrdinalIgnoreCase) ||
                                  Status.Equals("Changed Locally", StringComparison.OrdinalIgnoreCase) ||
                                  Status.Equals("Deleted Locally", StringComparison.OrdinalIgnoreCase) ||
                                  Status.Equals("Local", StringComparison.OrdinalIgnoreCase);

        public Brush StatusBrush {
            get {
                if (Status.Equals("Complete", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(38, 155, 95));
                if (Status.Equals("Downloading", StringComparison.OrdinalIgnoreCase) ||
                    Status.Equals("Canceling", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(0, 120, 212));
                if (Status.Equals("Failed", StringComparison.OrdinalIgnoreCase) ||
                    Status.Equals("Deleted Locally", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(196, 43, 28));
                if (Status.Equals("Changed Locally", StringComparison.OrdinalIgnoreCase) ||
                    Status.Equals("Local", StringComparison.OrdinalIgnoreCase))
                    return new SolidColorBrush(Color.FromRgb(241, 155, 56));
                return new SolidColorBrush(Color.FromRgb(118, 131, 144));
            }
        }

        public void Update(RemoteSessionFileCloneSnapshot snapshot) {
            if (snapshot == null)
                return;
            Id = snapshot.Id ?? "";
            RemotePath = snapshot.RemotePath ?? "";
            RemoteUrl = snapshot.RemoteUrl ?? "";
            LocalPath = snapshot.LocalPath ?? "";
            FileName = string.IsNullOrWhiteSpace(snapshot.FileName) ? Path.GetFileName(LocalPath) : snapshot.FileName;
            Status = snapshot.Status ?? "";
            Bytes = snapshot.Bytes;
            Sha256 = snapshot.Sha256 ?? "";
            UpdatedUtc = snapshot.UpdatedUtc ?? "";
            Error = snapshot.Error ?? "";
            OnPropertyChanged(nameof(Id));
            OnPropertyChanged(nameof(RemotePath));
            OnPropertyChanged(nameof(RemoteUrl));
            OnPropertyChanged(nameof(LocalPath));
            OnPropertyChanged(nameof(FileName));
            OnPropertyChanged(nameof(Status));
            OnPropertyChanged(nameof(Bytes));
            OnPropertyChanged(nameof(Sha256));
            OnPropertyChanged(nameof(UpdatedUtc));
            OnPropertyChanged(nameof(Error));
            OnPropertyChanged(nameof(SizeText));
            OnPropertyChanged(nameof(HashShort));
            OnPropertyChanged(nameof(UpdatedText));
            OnPropertyChanged(nameof(StatusBrush));
            OnPropertyChanged(nameof(IsCancelable));
            OnPropertyChanged(nameof(IsTerminal));
        }

        private void OnPropertyChanged(string propertyName) {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }

        private static string FormatTimestamp(string value) {
            if (DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset timestamp))
                return timestamp.ToLocalTime().ToString("g", CultureInfo.CurrentCulture);
            return "";
        }
    }

