    private sealed class WpfChatAttachmentItem {
        public string Name { get; private set; } = "";
        public string Type { get; private set; } = "application/octet-stream";
        public long Size { get; private set; }
        public bool IsImage { get; private set; }
        public string DataUrl { get; private set; } = "";
        public string TextPreview { get; private set; } = "";
        public string DisplayLine => (IsImage ? "Image: " : "File: ") + Name + " | " + Type + " | " + FormatBytes(Size);

        public static WpfChatAttachmentItem FromPath(string path) {
            if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
                throw new FileNotFoundException("Attachment was not found.", path);

            byte[] bytes = File.ReadAllBytes(path);
            string name = Path.GetFileName(path);
            string type = GuessMimeType(name);
            bool isImage = type.StartsWith("image/", StringComparison.OrdinalIgnoreCase);
            return new WpfChatAttachmentItem {
                Name = name,
                Type = type,
                Size = bytes.LongLength,
                IsImage = isImage,
                DataUrl = "data:" + type + ";base64," + Convert.ToBase64String(bytes),
                TextPreview = isImage ? "" : ReadTextPreview(path, type, bytes.LongLength)
            };
        }

        private static string ReadTextPreview(string path, string type, long size) {
            if (size > 128 * 1024 || !LooksTextLike(path, type))
                return "";
            try {
                return File.ReadAllText(path);
            } catch {
                return "";
            }
        }

        private static bool LooksTextLike(string path, string type) {
            if ((type ?? "").StartsWith("text/", StringComparison.OrdinalIgnoreCase))
                return true;
            string ext = Path.GetExtension(path ?? "").ToLowerInvariant();
            return new[] { ".cs", ".vb", ".js", ".ts", ".css", ".html", ".htm", ".json", ".xml", ".md", ".txt", ".sql", ".ps1", ".py", ".yml", ".yaml", ".ini", ".config" }.Contains(ext);
        }

        private static string GuessMimeType(string name) {
            string ext = Path.GetExtension(name ?? "").ToLowerInvariant();
            return ext switch {
                ".png" => "image/png",
                ".jpg" or ".jpeg" => "image/jpeg",
                ".gif" => "image/gif",
                ".webp" => "image/webp",
                ".bmp" => "image/bmp",
                ".avif" => "image/avif",
                ".heic" => "image/heic",
                ".heif" => "image/heif",
                ".txt" => "text/plain",
                ".md" => "text/markdown",
                ".json" => "application/json",
                ".xml" => "application/xml",
                ".html" or ".htm" => "text/html",
                ".css" => "text/css",
                ".js" => "text/javascript",
                ".csv" => "text/csv",
                _ => "application/octet-stream"
            };
        }
    }

